'use strict';

// ── Local fallback constants (also used by tests) ────────────────────────────

// Archon and Claude share the same session runtime slot
const _ARCHON_ALIAS_IDS = ['archon', 'claude'];

// Per-runtime identity: platform = the tool/platform name shown by default on a chip;
// persona = the self-given name each runtime chose for itself (revealed on hover + in
// the profile drawer). The Claude Code runtime shows "Claude" on the chip and reveals
// "Archon" (its self-given name) on hover / when its profile is opened.
const _RUNTIME_IDENTITY = {
  hermes:   { platform: 'Hermes',   persona: 'Optimus',     lane: 'persistent', role: 'coordination partner — Discord lane' },
  openclaw: { platform: 'OpenClaw', persona: 'Sygnal',      lane: 'persistent', role: 'schedule executor — AOR runner' },
  archon:   { platform: 'Claude',   persona: 'Archon',      lane: 'session',    role: 'implementation runtime — Claude Code' },
  claude:   { platform: 'Claude',   persona: 'Archon',      lane: 'session',    role: 'implementation runtime — Claude Code' },
  codex:    { platform: 'Codex',    persona: 'Axiom-Codex', lane: 'session',    role: 'bounded development runtime' },
};

function _runtimeIdentity(id) {
  return _RUNTIME_IDENTITY[String(id || '').toLowerCase()] || null;
}
// Persona (self-given) name — falls back to a profile display_name, then a formatted id.
function _runtimePersona(id, profile) {
  const ident = _runtimeIdentity(id);
  if (ident) return ident.persona;
  if (profile && (profile.personal_name || profile.display_name)) return profile.personal_name || profile.display_name;
  return String(id || 'runtime').replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
}
// Platform (tool) name — the label shown on the chip by default.
function _runtimePlatform(id, profile) {
  const ident = _runtimeIdentity(id);
  if (ident) return ident.platform;
  if (profile && profile.runtime_adapter) return profile.runtime_adapter;
  return String(id || 'runtime').replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
}

