function productFacingCopy(text) {
  return String(text || '')
    .replace(/\bRead-only\b/g, 'Inspect')
    .replace(/\bread-only\b/g, 'inspect')
    .replace(/\bRead only\b/g, 'Inspect')
    .replace(/\bread only\b/g, 'inspect')
    .replace(/\bDry[- ]run\b/g, 'Proposal')
    .replace(/\bdry[- ]run\b/g, 'proposal')
    .replace(/\bBuild Logs\b/g, 'History / Audit')
    .replace(/\bbuild logs\b/g, 'activity history')
    .replace(/\bQA \/ Proof\b/g, 'Quality Review')
    .replace(/\bQuality Review \/ Proof\b/g, 'Quality Review')
    .replace(/\bProof\b/g, 'Evidence')
    .replace(/\bproof\b/g, 'evidence')
    .replace(/\bnot mounted in this pass\b/g, 'not available from this page')
    .replace(/\bnot mounted\b/g, 'not available here')
    .replace(/\bNot mounted\b/g, 'Not available here')
    .replace(/\bimplementation\b/g, 'product')
    .replace(/\bImplementation\b/g, 'Product')
    .replace(/\bPreview runner ready\b/g, 'Action check ready')
    .replace(/\bRuntime Daemons\b/g, 'Runtime Services')
    .replace(/\bdaemon\b/g, 'runtime service')
    .replace(/\bDaemon\b/g, 'Runtime Service')
    .replace(/\bApproval-gated\b/g, 'Approval required')
    .replace(/\bapproval-gated\b/g, 'needs approval')
    .replace(/\bMVP\b/g, 'local product')
    .replace(/\bmvp\b/g, 'local product');
}

(function normalizeStudioProductFeatureCatalog() {
  const seen = new Set();
  for (let i = STUDIO_FEATURE_CATALOG.length - 1; i >= 0; i -= 1) {
    const id = STUDIO_FEATURE_CATALOG[i] && STUDIO_FEATURE_CATALOG[i].id;
    if (!id) continue;
    if (seen.has(id)) STUDIO_FEATURE_CATALOG.splice(i, 1);
    else seen.add(id);
  }
  STUDIO_FEATURE_CATALOG.forEach(item => Object.assign(item, STUDIO_PRODUCT_FEATURE_OVERRIDES[item.id] || {}));
  STUDIO_FEATURE_CATALOG.forEach(item => {
    item.status = productFacingCopy(item.status);
    item.actions = productFacingCopy(item.actions);
    item.description = productFacingCopy(item.description);
  });
  Object.keys(STUDIO_FEATURE_BY_ID).forEach(key => delete STUDIO_FEATURE_BY_ID[key]);
  STUDIO_FEATURE_CATALOG.forEach(item => { STUDIO_FEATURE_BY_ID[item.id] = item; });
})();


