// Performance guards — the full vault can be 7k+ nodes. Per-node text sprites
// (GPU textures) and a never-freezing physics sim are great at medium scale but
// punishing at very large scale, so they auto-disable past these thresholds.
const TEXT_SPRITE_MAX_NODES = 800;   // at/below this: a dedicated sprite per node (simple path).
                                     // Above this we switch to the camera-windowed label pool
                                     // below, which keeps LOD text working at any scale by
                                     // recycling a bounded number of GPU textures.
const LABEL_POOL_SIZE       = 220;   // max simultaneous text labels in the windowed pool —
                                     // only the nodes nearest the camera get a live label.
const MOTION_MAX_NODES      = 400;   // above this: let the sim settle so onEngineStop fires
                                     // and the camera locks (infinite ticking off-frames the
                                     // graph on QtWebEngine's software WebGL). Larger graphs
                                     // get subtle motion via low-frequency reheat instead.
const REHEAT_MAX_NODES      = 4000;  // above MOTION_MAX_NODES and up to this: periodic gentle
                                     // reheat keeps the graph "never fully still" cheaply

// Debounced zoom-to-fit — coalesces rapid calls from onEngineStop + applyGraphFilters resets
function _scheduleGraphZoomToFit(delay) {
  clearTimeout(_graphZoomTimer);
  _graphZoomTimer = setTimeout(() => {
    if (graph3d) {
      graph3d.zoomToFit(600, 50);
      updateGraphLabelVisibility();
    }
    _graphZoomTimer = null;
  }, typeof delay === 'number' ? delay : 300);
}
