// ── Style system init ─────────────────────────────────────────────────────────
async function initStyleSystem() {
  try {
    const [regResp, settingsResp] = await Promise.all([
      window.pywebview.api.get_graph_style_registry(),
      window.pywebview.api.get_graph_settings(),
    ]);
    if (regResp && regResp.ok && window.GraphStyles) {
      window.GraphStyles.setStyleRegistry(regResp.data);
      _registryLoaded = true;
    }
    if (settingsResp && settingsResp.ok) {
      _currentSettings = settingsResp.data;
      if (window.GraphStyles) window.GraphStyles.setStyleSettings(settingsResp.data);
      if (window.InspectorTabs) window.InspectorTabs.setInspectorSettings(settingsResp.data.inspector || {});
      syncGraphLocalFocusControls();
    }
  } catch (_) {
    // fail-open — use fallback constants
  }
}

// ── Preset loading ────────────────────────────────────────────────────────────
async function loadPresetsAndRender() {
  try {
    const resp = await window.pywebview.api.list_graph_presets();
    if (resp && resp.ok && window.GraphPresets) {
      window.GraphPresets.renderPresetBar(
        resp.data.presets || [],
        window.GraphPresets.getCurrentPresetId ? window.GraphPresets.getCurrentPresetId() : null,
        _applyPreset,
        _saveCurrentGraphPreset,
        _deleteGraphPreset
      );
    }
  } catch (_) {}
}

async function _applyPreset(preset) {
  if (!_currentSettings) {
    const r = await window.pywebview.api.get_graph_settings();
    if (r && r.ok) _currentSettings = r.data;
  }
  if (_currentSettings && window.GraphPresets && window.GraphStyles) {
    _currentSettings = window.GraphPresets.applyPresetPatch(_currentSettings, preset);
    _activePresetFilters = (preset && preset.filters) || null;
    window.GraphStyles.setStyleSettings(_currentSettings);
    if (graph3d) {
      graph3d.nodeColor(_graphNodeColor);
      const _gc = document.getElementById('graph-3d');
      if (_gc) graph3d.width(_gc.clientWidth).height(_gc.clientHeight);
    }
    if (window.GraphFilters && window.GraphFilters.applyPresetFilters && _activePresetFilters) {
      window.GraphFilters.applyPresetFilters(graphFilters, _activePresetFilters);
    }
    applyGraphFilters();
    return true;
  }
  return false;
}

async function _saveCurrentGraphPreset() {
  if (!_currentSettings) {
    const r = await window.pywebview.api.get_graph_settings();
    if (r && r.ok) _currentSettings = r.data;
  }
  const label = prompt('Preset name');
  if (!label) return false;
  const slug = label.toLowerCase().trim().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 64);
  if (!slug) {
    alert('Preset name must contain letters or numbers.');
    return false;
  }
  const description = prompt('Preset description', 'User-saved Studio graph view') || '';
  const resp = await window.pywebview.api.save_graph_preset(slug, label.trim(), description, _currentSettings || {}, graphFiltersForPreset());
  if (resp && resp.ok) {
    await loadPresetsAndRender();
    return true;
  }
  alert('Preset save failed: ' + ((resp && resp.error && resp.error.message) || 'unknown error'));
  return false;
}

function graphFiltersForPreset() {
  const toArray = set => Array.from(set || []).sort();
  return {
    query: graphFilters.query || '',
    node_types: toArray(graphFilters.nodeTypes),
    node_families: toArray(graphFilters.nodeFamilies),
    node_subtypes: toArray(graphFilters.nodeSubtypes),
    trust_states: toArray(graphFilters.trustStates),
    domains: toArray(graphFilters.domains),
    projects: toArray(graphFilters.projects),
    source_classes: toArray(graphFilters.sourceClasses),
    generated_canonical: toArray(graphFilters.generatedCanonical),
    confidence: toArray(graphFilters.confidence),
    statuses: toArray(graphFilters.statuses),
    recency: toArray(graphFilters.recency),
    relations: toArray(graphFilters.relations),
    edge_layers: toArray(graphFilters.edgeLayers),
    warnings: toArray(graphFilters.warnings),
  };
}

async function _saveCurrentFilterRule(kind, value) {
  const labelDefault = kind && value ? `Filter ${filterLabel(kind)} ${filterLabel(value)}` : 'Graph Filter Rule';
  const label = prompt('Filter rule preset name', labelDefault);
  if (!label) return false;
  const slug = label.toLowerCase().trim().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 64);
  if (!slug) {
    alert('Preset name must contain letters or numbers.');
    return false;
  }
  const resp = await window.pywebview.api.save_graph_preset(
    slug,
    label.trim(),
    `Saved from active filter chip: ${kind || 'filter'}=${value || 'current'}`,
    {},
    graphFiltersForPreset()
  );
  if (resp && resp.ok) {
    await loadPresetsAndRender();
    return true;
  }
  alert('Filter rule save failed: ' + ((resp && resp.error && resp.error.message) || 'unknown error'));
  return false;
}

async function _deleteGraphPreset(preset) {
  if (!preset || preset.builtin) return false;
  if (!confirm(`Delete graph preset "${preset.label || preset.id}"?`)) return false;
  const resp = await window.pywebview.api.delete_graph_preset(preset.id);
  if (resp && resp.ok) {
    await loadPresetsAndRender();
    return true;
  }
  alert('Preset delete failed: ' + ((resp && resp.error && resp.error.message) || 'unknown error'));
  return false;
}

