function productizeUiCopy(value) {
  let next = String(value ?? '');
  for (const [pattern, replacement] of PRODUCT_COPY_REPLACEMENTS) {
    next = next.replace(pattern, replacement);
  }
  return next;
}

function productLabel(value, fallback = '-') {
  if (value === null || value === undefined || value === '') return fallback;
  const raw = String(value);
  const key = raw.toLowerCase().trim();
  const labels = {
    'blocked_review_required': 'Review required',
    'unscanned-quarantine': 'Needs review',
    'pending_operator_review': 'Needs review',
    'pending_human_review': 'Needs review',
    'pending-review': 'Needs review',
    'review-gated': 'Review required',
    'approval-gated': 'Approval required',
    'read-only': 'Inspect',
    'read_only': 'Inspect',
    'read only': 'Inspect',
    'unknown': 'Unknown',
    'local-ready': 'Local ready',
    'local-artifacts': 'Local records',
    'metadata_policy_only': 'Metadata policy',
    'metadata_policy_only_delete_blocked': 'Metadata-only, deletion blocked',
    'approval_preview_only': 'Approval preview',
    'readiness_only': 'Readiness check',
    'request_writer': 'Approval request',
    'decision_writer': 'Decision writer',
    'available': 'Available',
    'available_no_text_extraction': 'Available without text extraction',
    'available_click_to_capture': 'Available after click',
    'available_drag_select_to_capture': 'Available after drag selection',
    'available_active_window_capture': 'Available for active window',
    'available_select_artifact': 'Available after selecting artifact',
    'settings_configurable': 'Configurable in Settings',
    'disabled_in_settings': 'Disabled in Settings',
    'not_configured': 'Not configured',
    'blocked_not_built': 'Blocked, not built',
    'blocked_secret_like': 'Blocked: secret-like text',
    'downstream_approval_gated': 'Approval required downstream',
    'available_local_engine': 'Local engine available',
    'available_local_engine_required': 'Local engine required',
    'active_chaseos_browser_ready_for_markdown': 'Active ChaseOS browser ready for Markdown',
    'display_region_capture_ready_for_markdown': 'Display region ready for Markdown',
    'active_window_capture_ready_for_markdown': 'Active window ready for Markdown',
    'active_chaseos_browser_state_saved': 'Active ChaseOS browser state saved',
    'chaseos_owned_active_artifact_only': 'ChaseOS-owned active browser artifact only',
    'covered_by_chaseos_browser_or_screen_capture': 'Covered by ChaseOS browser or screen capture',
    'covered_by_screen_or_discord_artifact': 'Covered by screen capture or Discord artifact',
    'studio_window_shortcuts_configurable': 'Studio-window shortcuts configurable',
    'release_ready_explicit_capture_paths_verified': 'Release ready for explicit capture paths',
    'partial_core_verified_optional_collectors_blocked': 'Core verified, optional collectors governed',
    'verified': 'Verified',
    'engine_available': 'Engine available',
    'engine_required': 'Engine required',
    'fixture_proof_required': 'Fixture verification required',
    'exact_approval_required': 'Exact approval required',
    'approval_gated': 'Approval required',
    'blocked': 'Blocked',
    'open': 'Open',
    'unverified_on_this_host': 'Unverified on this host',
    'skipped': 'Not needed',
    'not_installed': 'Not installed',
    'not_listed': 'Not listed',
    'not_applicable': 'Not applicable',
    'not-applicable': 'Not applicable',
    'not_ingested': 'Not ingested',
    'not_queued': 'Not queued',
    'raw_ingested': 'Saved to raw quarantine',
    'duplicate': 'Duplicate found',
    'no_text_extracted': 'No text extracted',
    'missing_local_engine': 'Missing local engine',
    'blocked_missing_local_engine': 'Missing local engine',
    'command_failed': 'Command failed',
    'command_timeout': 'Command timed out',
    'local_mvp_complete': 'Local build complete',
    'mvp_foundation_ready': 'Local foundation ready',
  };
  if (labels[key]) return labels[key];
  const spaced = productizeUiCopy(raw).replace(/[_-]+/g, ' ').replace(/\s+/g, ' ').trim();
  if (!spaced) return fallback;
  return spaced.charAt(0).toUpperCase() + spaced.slice(1);
}

function captureMarkdownOperatorText(value, fallback = '') {
  if (value === null || value === undefined || value === '') return fallback;
  return productizeUiCopy(String(value));
}

function captureMarkdownBlockerLabel(value) {
  return productLabel(value, '');
}

function captureMarkdownBlockerList(blockers) {
  return (blockers || [])
    .map(captureMarkdownBlockerLabel)
    .filter(Boolean);
}

function captureMarkdownBlockerText(blockers, fallback = '') {
  const labels = captureMarkdownBlockerList(blockers);
  return labels.length ? labels.join(', ') : fallback;
}

function captureMarkdownResponseError(resp, data, fallback = 'Action blocked.') {
  const explicit = (resp && resp.error && resp.error.message) || (data && data.message) || '';
  if (explicit) return captureMarkdownOperatorText(explicit);
  return captureMarkdownBlockerText((data && data.blockers) || [], fallback);
}

function operatorSurfaceOverview(title, body, metrics = []) {
  return `<section class="operator-surface-overview">` +
    `<div class="operator-surface-copy">` +
      `<strong>${escHtml(productizeUiCopy(title))}</strong>` +
      `<span>${escHtml(productizeUiCopy(body))}</span>` +
    `</div>` +
    `<div class="operator-surface-metrics">` +
      metrics.map(item =>
        `<span><b>${escHtml(productizeUiCopy(String(item.value ?? '-')))}</b>${escHtml(productizeUiCopy(item.label || ''))}` +
        (item.note ? `<em>${escHtml(productizeUiCopy(item.note))}</em>` : '') +
        `</span>`
      ).join('') +
    `</div>` +
  `</section>`;
}

function operatorSurfaceCards(items) {
  return `<div class="operator-surface-card-grid">` +
    items.map(item =>
      `<article class="operator-surface-card" data-operator-card="${escAttr(item.id || item.title || '')}" data-operator-card-title="${escAttr(productizeUiCopy(item.title || ''))}" data-operator-card-status="${escAttr(productizeUiCopy(item.status || ''))}" data-operator-card-owner="${escAttr(productizeUiCopy(item.owner || ''))}" data-operator-card-ref="${escAttr(item.ref || item.id || '')}">` +
        `<div class="operator-surface-card-head">` +
          `<span>${escHtml(productizeUiCopy(item.title || ''))}</span>` +
          `<strong>${escHtml(productizeUiCopy(item.status || 'Inspect'))}</strong>` +
        `</div>` +
        `<p>${escHtml(productizeUiCopy(item.body || ''))}</p>` +
        `<div class="operator-surface-card-meta">` +
          (item.meta || []).map(meta => `<span>${escHtml(productizeUiCopy(meta))}</span>`).join('') +
        `</div>` +
      `</article>`
    ).join('') +
  `</div>`;
}

function operatorSurfaceLaneList(title, items) {
  if (!items.length) return '';
  return `<section class="operator-surface-lanes">` +
    `<h3>${escHtml(productizeUiCopy(title))}</h3>` +
    items.map(item =>
      `<div class="operator-surface-lane">` +
        `<span>${escHtml(productizeUiCopy(item.label || item.title || ''))}</span>` +
        `<strong>${escHtml(productizeUiCopy(item.status || 'Inspect'))}</strong>` +
        `<em>${escHtml(productizeUiCopy(item.note || ''))}</em>` +
      `</div>`
    ).join('') +
  `</section>`;
}

