function productSyncFallbackHtml(panelId) {
  const feature = STUDIO_FEATURE_BY_ID[panelId] || {};
  const fallback = STUDIO_PRODUCT_SYNC_FALLBACKS[panelId] || {
    title: feature.label || 'Studio surface',
    body: feature.description || 'Local-first surface is syncing state. Actions remain governed by the owning feature.',
    metrics: [
      { label: 'state', value: 'Sync', note: 'local readback' },
      { label: 'posture', value: feature.status || 'Inspect', note: 'bounded action' },
      { label: 'authority', value: 'Gated', note: 'no expansion' },
    ],
    cards: [
      { id: `${panelId}-readback`, title: 'Local Readback', status: 'Sync', body: 'The page is preparing local evidence and will hydrate when the bridge responds.', meta: ['Local', 'Evidence', 'Bounded'] },
      { id: `${panelId}-boundary`, title: 'Authority Boundary', status: 'Governed', body: 'Unsafe actions stay proposal-only, approval-gated, blocked, or unavailable.', meta: ['Approval', 'No mutation', 'No external action'] },
    ],
  };
  return operatorSurfaceOverview(fallback.title, fallback.body, fallback.metrics || []) +
    operatorSurfaceCards(fallback.cards || []) +
    `<div class="product-sync-note">Syncing local state. The page remains usable for orientation while live records load.</div>`;
}

function renderProductSyncFallback(panelId, body, statusEl, statusText = 'Syncing') {
  if (!body) return;
  body.innerHTML = productSyncFallbackHtml(panelId);
  wireOperatorSurfaceCards(body, panelId, (STUDIO_FEATURE_BY_ID[panelId] || {}).family || 'Studio');
  if (statusEl) {
    statusEl.textContent = statusText;
    statusEl.className = 'panel-status-pill status-loading';
  }
}

function studioApiResultWithTimeout(factory, label, timeoutMs = 6000) {
  const request = Promise.resolve()
    .then(factory)
    .catch(error => ({
      ok: false,
      error: { message: error && error.message ? error.message : String(error) },
    }));
  const timeout = new Promise(resolve => {
    window.setTimeout(() => resolve({
      ok: false,
      timed_out: true,
      error: { message: `${label} is still syncing local state` },
    }), timeoutMs);
  });
  return Promise.race([request, timeout]);
}

function wireOperatorSurfaceCards(root, panel, owner = 'Studio') {
  if (!root) return;
  root.querySelectorAll('.operator-surface-card[data-operator-card]').forEach(card => {
    card.addEventListener('click', () => {
      renderObjectInspectorProductContext({
        id: card.dataset.operatorCard || card.dataset.operatorCardTitle || panel || 'surface',
        label: card.dataset.operatorCardTitle || 'Surface',
        type: 'Surface',
        kicker: 'Selected Surface',
        panel,
        status: card.dataset.operatorCardStatus || 'Inspect',
        ownerLabel: 'Area',
        owner: card.dataset.operatorCardOwner || owner,
        timeLabel: 'Posture',
        time: 'inspection',
        ref: card.dataset.operatorCardRef || '',
        openLabel: 'Open Surface',
        note: 'Selecting this card updates the inspector only. It does not start runs, consume approvals, write memory, or mutate project records.',
      });
    });
  });
}

function shouldSkipProductCopyElement(node) {
  const element = node && node.nodeType === Node.ELEMENT_NODE ? node : node && node.parentElement;
  return !element || Boolean(element.closest('script, style, code, pre, kbd, samp'));
}

function shouldSkipProductCopyTextNode(node) {
  const element = node && node.nodeType === Node.ELEMENT_NODE ? node : node && node.parentElement;
  return !element || Boolean(element.closest('script, style, code, pre, kbd, samp, textarea, input, select'));
}

function productizeTextNode(node) {
  if (!node || node.nodeType !== Node.TEXT_NODE || shouldSkipProductCopyTextNode(node)) return;
  const next = productizeUiCopy(node.nodeValue || '');
  if (next !== node.nodeValue) node.nodeValue = next;
}

function productizeElementAttributes(element) {
  if (!element || element.nodeType !== Node.ELEMENT_NODE || shouldSkipProductCopyElement(element)) return;
  PRODUCT_COPY_ATTRS.forEach(attr => {
    if (!element.hasAttribute(attr)) return;
    const current = element.getAttribute(attr);
    const next = productizeUiCopy(current);
    if (next !== current) element.setAttribute(attr, next);
  });
}

function productizeNodeTree(root) {
  if (!root) return;
  if (root.nodeType === Node.TEXT_NODE) {
    productizeTextNode(root);
    return;
  }
  if (root.nodeType !== Node.ELEMENT_NODE && root.nodeType !== Node.DOCUMENT_FRAGMENT_NODE) return;
  if (root.nodeType === Node.ELEMENT_NODE) productizeElementAttributes(root);
  const walker = document.createTreeWalker(root, NodeFilter.SHOW_ELEMENT | NodeFilter.SHOW_TEXT);
  let node = walker.nextNode();
  while (node) {
    if (node.nodeType === Node.TEXT_NODE) productizeTextNode(node);
    else productizeElementAttributes(node);
    node = walker.nextNode();
  }
}

function initProductCopyPolish() {
  const root = document.body;
  if (!root || window.__chaseosProductCopyPolishMounted) return;
  window.__chaseosProductCopyPolishMounted = true;
  productizeNodeTree(root);
  const observer = new MutationObserver(mutations => {
    mutations.forEach(mutation => {
      if (mutation.type === 'characterData') productizeTextNode(mutation.target);
      if (mutation.type === 'attributes') productizeElementAttributes(mutation.target);
      mutation.addedNodes.forEach(node => productizeNodeTree(node));
    });
  });
  observer.observe(root, {
    childList: true,
    subtree: true,
    characterData: true,
    attributes: true,
    attributeFilter: PRODUCT_COPY_ATTRS,
  });
}

// ── QA / diagnostics helper (safe to call from runJavaScript) ────────────────
window.__chaseosGraphDiag = function () {
  try {
    const renderer = graph3d && graph3d.renderer && graph3d.renderer();
    const gl = renderer && renderer.getContext && renderer.getContext();
    const canvas = renderer && renderer.domElement;
    const gData = graph3d && graph3d.graphData && graph3d.graphData();
    const container = document.getElementById('graph-3d');
    const statusEl = document.getElementById('status-bar-text') || document.querySelector('.status-text');
    const topStatusEl = document.getElementById('top-status') || document.querySelector('[data-status]');
    const bodySnippet = document.body ? document.body.innerText.slice(0, 300) : '';
    // Grab canvas as a data-URL so Python can decode it as a PNG for visual proof
    let canvas_png = null;
    if (canvas) {
      try { canvas_png = canvas.toDataURL('image/png'); } catch (_) {}
    }
    return {
      graph3d_exists:        !!graph3d,
      graph_loaded:          graphLoaded,
      all_nodes:             _graphAllNodes.length,
      all_links:             _graphAllLinks.length,
      rendered_nodes:        (gData && gData.nodes) ? gData.nodes.length : 0,
      renderer_exists:       !!renderer,
      webgl_context:         !!gl,
      canvas_w:              canvas ? canvas.width  : 0,
      canvas_h:              canvas ? canvas.height : 0,
      current_panel:         currentPanel,
      container_exists:      !!container,
      container_w:           container ? container.clientWidth  : 0,
      container_h:           container ? container.clientHeight : 0,
      forcegraph3d_type:     typeof ForceGraph3D,
      pywebview_api_ok:      !!(window.pywebview && window.pywebview.api),
      status_text:           statusEl ? statusEl.textContent : '',
      top_status_text:       topStatusEl ? topStatusEl.textContent : '',
      load_trace:            window.__loadGraphTrace || [],
      load_running:          !!window.__loadGraphRunning,
      canvas_png:            canvas_png,
      body_snippet:          bodySnippet,
    };
  } catch (e) { return { ok: false, error: String(e) }; }
};

window.__onShellReady = async function () {
  try {
    initNav();
    initShellFraming();
    initInspectorCollapse();
    initSidebarResize();
    initGraphProductChrome();
    initFeatureHelp();
    initProductCopyPolish();
    initSettingsModal();
    if (window.ApprovalModal) window.ApprovalModal.initApprovalModal();
    _initNodeInspectorWorkspace();
    _initIntakePanel();
    _initSICPanel();
    _initAORPanel();
    _initSchedulesPanel();
    _initPulseScheduleProofPanel();
    _initPulseEnqueuePanel();
    _initPhase11ChatPanel();
    _initSiteOpsPanel();
    _initAcquisitionPanel();
    _initCaptureMarkdownPanel();
    _initBusPanel();
    _initBuildLogsPanel();
    _initDecisionLedgerPanel();
    _initPivotLogPanel();
    _initFeatureFilterPanel();
    _initWorkflowRegistryPanel();
    _initWorkflowPacksPanel();
    _initRoleCardsPanel();
    _initRuntimeMemoryInspectorPanel();
    wireOperatorSurfaceCards(document.getElementById('panel-qa-proof'), 'qa-proof', 'Governance / Advanced');
    const panelRegistryReady = loadPanelRegistry().catch(err => {
      console.warn('Panel registry init deferred', err);
      return null;
    });
    const styleSystemReady = initStyleSystem().catch(err => {
      console.warn('Style system init deferred', err);
      return null;
    });
    const presetsReady = loadPresetsAndRender().catch(err => {
      console.warn('Graph preset init deferred', err);
      return null;
    });
    initKeyboardShortcuts();
    loadCaptureHotkeySettings().catch(err => console.warn('Capture shortcut settings init deferred', err));
    loadCaptureLocalImageTextSettings().catch(err => console.warn('Capture local image text settings init deferred', err));
    try {
      showPanel(defaultRoutePanel());
    } catch (err) {
      console.error('Default Studio route failed to open', err);
    }
    setTopStatus('Local shell ready', 'observe');
    Promise.allSettled([panelRegistryReady, styleSystemReady, presetsReady]).then(() => {
      productizeNodeTree(document.body);
    });
    if (window.ApprovalModal) window.ApprovalModal.refreshApprovalBadge();
    refreshRuntimeStatusPill();
    setInterval(refreshRuntimeStatusPill, 30000);
    // Sync companion data from backend now that the pywebview bridge is ready
    if (window.CompanionSystem && typeof window.CompanionSystem.initBackendSync === 'function') {
      window.CompanionSystem.initBackendSync();
    }
  } catch (err) {
    console.error('Studio shell initialization degraded', err);
    setTopStatus('Local shell ready', 'observe');
  } finally {
    hideLoading();
  }
};

