// ── Vault file watcher live-refresh ───────────────────────────────────────────
window.onVaultChange = function (event) {
  const path = (event && event.path) || '';
  const isGraph = /\.(md|yaml)$/i.test(path);
  const isProject = /01_PROJECTS/i.test(path) || /00_HOME\/Now/i.test(path);
  const isApproval = /studio\/approvals/i.test(path);
  const isQuarantine = /00_QUARANTINE/i.test(path);

  if (isGraph && graphLoaded) {
    graphLoaded = false;
    loadGraph();
  }
  if (isProject && projectWorkspaceLoaded) {
    projectWorkspaceLoaded = false;
    sprintFocusLoaded = false;
    if (currentPanel === 'project-workspace') { loadProjectWorkspace(); loadSprintFocus(); }
  }
  if (isApproval && window.ApprovalModal) {
    window.ApprovalModal.refreshApprovalBadge();
  }
  if (isQuarantine && currentPanel === 'intake') {
    loadIntake();
  }
  if (isQuarantine && currentPanel === 'capture-markdown') {
    captureMarkdownLoaded = false;
    loadCaptureMarkdownPanel(true);
  }
  refreshRuntimeStatusPill();
};

// ── Navigation ────────────────────────────────────────────────────────────────

function initFeatureHelp() {
  const openBtn = document.getElementById('topbar-feature-help-btn');
  const closeBtn = document.getElementById('feature-help-close');
  const backdrop = document.getElementById('feature-help-backdrop');
  renderFeatureHelpCatalog();
  hydrateNavFeatureHelp();
  hydratePanelHelpButtons();
  if (openBtn) openBtn.addEventListener('click', () => openFeatureHelp());
  if (closeBtn) closeBtn.addEventListener('click', closeFeatureHelp);
  if (backdrop) backdrop.addEventListener('click', closeFeatureHelp);
  document.addEventListener('keydown', (event) => {
    if (event.key === 'Escape') closeFeatureHelp();
  });
}

function renderFeatureHelpCatalog() {
  const body = document.getElementById('feature-help-body');
  if (!body) return;
  const families = STUDIO_FEATURE_CATALOG.reduce((acc, item) => {
    (acc[item.family] = acc[item.family] || []).push(item);
    return acc;
  }, {});
  body.innerHTML = Object.entries(families).map(([family, items]) => `
    <section class="feature-help-family" data-feature-family="${escAttr(family)}">
      <h3>${escHtml(family)}</h3>
      <div class="feature-help-card-grid">
        ${items.map(item => `
          <article class="feature-help-card" id="feature-help-card-${escAttr(item.id)}" data-feature-id="${escAttr(item.id)}" data-action-status="${escAttr(item.status)}">
            <div class="feature-help-card-head">
              <span class="feature-help-icon">${escHtml(item.icon || '?')}</span>
              <div>
                <h4>${escHtml(item.label)}</h4>
                <span class="feature-help-status">${escHtml(item.status)}</span>
              </div>
            </div>
            <p>${escHtml(item.description)}</p>
            <div class="feature-help-actions">${escHtml(item.actions)}</div>
          </article>
        `).join('')}
      </div>
    </section>
  `).join('');
}

function hydrateNavFeatureHelp() {
  document.querySelectorAll('.nav-btn[data-panel]').forEach(btn => {
    const item = STUDIO_FEATURE_BY_ID[btn.dataset.panel];
    const labelEl = btn.querySelector('.nav-label');
    const labelText = (item && item.label) || (labelEl && labelEl.textContent.trim()) || btn.dataset.panel;
    btn.dataset.navLabel = labelText;
    if (!item) return;
    btn.dataset.featureFamily = item.family;
    btn.dataset.actionStatus = item.status;
    btn.setAttribute('aria-label', `${item.label}: ${item.status}. ${item.description}`);
    btn.setAttribute('title', `${item.label} — ${item.status}: ${item.description}`);
  });
}

function hydratePanelHelpButtons() {
  STUDIO_FEATURE_CATALOG.forEach(item => {
    const panel = document.getElementById('panel-' + item.id) || (item.id === 'node-inspector' ? document.getElementById('inspector') : null);
    if (!panel || panel.querySelector('.panel-help-btn')) return;
    const row = panel.querySelector('.panel-title-row') || panel.querySelector('#inspector-header');
    if (!row) return;
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'panel-help-btn';
    btn.textContent = '?';
    btn.title = `${item.label} help — ${item.status}`;
    btn.setAttribute('aria-label', `${item.label} help`);
    btn.addEventListener('click', (event) => {
      event.stopPropagation();
      openFeatureHelp(item.id);
    });
    row.appendChild(btn);
  });
}

function openFeatureHelp(featureId) {
  const drawer = document.getElementById('feature-help-drawer');
  const backdrop = document.getElementById('feature-help-backdrop');
  if (!drawer) return;
  drawer.classList.add('open');
  drawer.setAttribute('aria-hidden', 'false');
  if (backdrop) backdrop.classList.add('open');
  if (featureId) {
    document.querySelectorAll('.feature-help-card.is-focused').forEach(card => card.classList.remove('is-focused'));
    const card = document.getElementById('feature-help-card-' + featureId);
    if (card) {
      card.classList.add('is-focused');
      card.scrollIntoView({ block: 'nearest' });
    }
  }
}

function closeFeatureHelp() {
  const drawer = document.getElementById('feature-help-drawer');
  const backdrop = document.getElementById('feature-help-backdrop');
  if (drawer) {
    drawer.classList.remove('open');
    drawer.setAttribute('aria-hidden', 'true');
  }
  if (backdrop) backdrop.classList.remove('open');
}

function initNav() {
  document.querySelectorAll('.nav-btn[data-panel]').forEach(btn => {
    btn.addEventListener('click', () => showPanel(btn.dataset.panel, { updateHash: true }));
  });
  window.addEventListener('hashchange', () => {
    const routed = routePanelFromHash();
    if (routed) showPanel(routed, { updateHash: false });
  });
  const collapseBtn = document.getElementById('sidebar-collapse-btn');
  if (collapseBtn) {
    const PREF_KEY = 'chaseos_sidebar_collapsed';
    const shell = document.getElementById('shell');
    const syncSidebarCollapse = (collapsed) => {
      if (!shell) return;
      shell.classList.toggle('sidebar-collapsed', collapsed);
      collapseBtn.setAttribute('aria-expanded', String(!collapsed));
      collapseBtn.setAttribute('title', collapsed ? 'Expand sidebar' : 'Collapse sidebar');
      collapseBtn.setAttribute('aria-label', collapsed ? 'Expand sidebar' : 'Collapse sidebar');
    };
    syncSidebarCollapse(localStorage.getItem(PREF_KEY) === '1');
    collapseBtn.addEventListener('click', () => {
      const collapsed = !shell.classList.contains('sidebar-collapsed');
      syncSidebarCollapse(collapsed);
      localStorage.setItem(PREF_KEY, collapsed ? '1' : '0');
    });
  }
  const devToggle = document.getElementById('dev-tools-toggle');
  const devItems = document.getElementById('dev-tools-items');
  if (devToggle && devItems) {
    const DEV_PREF = 'chaseos_dev_tools_expanded';
    if (localStorage.getItem(DEV_PREF) === '1') {
      devItems.style.display = '';
      devToggle.textContent = '▾';
      devToggle.setAttribute('aria-expanded', 'true');
    }
    devToggle.addEventListener('click', () => {
      const open = devItems.style.display !== 'none';
      devItems.style.display = open ? 'none' : '';
      devToggle.textContent = open ? '▸' : '▾';
      devToggle.setAttribute('aria-expanded', String(!open));
      localStorage.setItem(DEV_PREF, open ? '0' : '1');
    });
  }
}

// ── Inspector collapse toggle ─────────────────────────────
function initInspectorCollapse() {
  const btn = document.getElementById('inspector-collapse-btn');
  const tab = document.getElementById('inspector-collapsed-tab');
  if (btn) btn.addEventListener('click', toggleInspector);
  if (tab) {
    tab.addEventListener('click', toggleInspector);
    tab.addEventListener('keydown', e => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggleInspector(); } });
  }
  if (localStorage.getItem('chaseos_inspector_collapsed') === '1') {
    document.getElementById('object-inspector')?.classList.add('inspector-collapsed');
    document.getElementById('shell')?.classList.add('inspector-collapsed');
  }
}

function toggleInspector() {
  const inspector = document.getElementById('object-inspector');
  const shell = document.getElementById('shell');
  if (!inspector) return;
  const isCollapsed = inspector.classList.toggle('inspector-collapsed');
  shell?.classList.toggle('inspector-collapsed', isCollapsed);
  localStorage.setItem('chaseos_inspector_collapsed', isCollapsed ? '1' : '0');
  const btn = document.getElementById('inspector-collapse-btn');
  if (btn) btn.setAttribute('title', isCollapsed ? 'Expand inspector' : 'Collapse inspector');
}

// ── Side-rail drag-to-resize ─────────────────────────────
function initSidebarResize() {
  const shell = document.getElementById('shell');
  if (!shell) return;

  const inspector = document.getElementById('object-inspector');
  const clamp = (v, lo, hi) => Math.max(lo, Math.min(hi, v));

  // Each rail can be dragged from its expanded range all the way down to the
  // icon-only / collapsed state. When the pointer drops below `snap`, the rail
  // snaps into the same collapsed class the toggle button uses (icon-only nav
  // on the left, rail tab on the right); dragging back out past `snap` expands
  // it again. expandedMin keeps a sensible floor for the non-collapsed width.
  const RAILS = [
    {
      handleId: 'sidebar-resize-handle', cssVar: '--sidebar-w',
      widthKey: 'chaseos_sidebar_w', collapseKey: 'chaseos_sidebar_collapsed',
      expandedMin: 150, max: 480, snap: 120, side: 'left',
      setCollapsed: (on) => shell.classList.toggle('sidebar-collapsed', on),
      isCollapsed: () => shell.classList.contains('sidebar-collapsed'),
    },
    {
      handleId: 'inspector-resize-handle', cssVar: '--object-inspector-w',
      widthKey: 'chaseos_inspector_w', collapseKey: 'chaseos_inspector_collapsed',
      expandedMin: 220, max: 560, snap: 150, side: 'right',
      setCollapsed: (on) => {
        inspector?.classList.toggle('inspector-collapsed', on);
        shell.classList.toggle('inspector-collapsed', on);
      },
      isCollapsed: () => shell.classList.contains('inspector-collapsed'),
    },
  ];

  RAILS.forEach((rail) => {
    const handle = document.getElementById(rail.handleId);
    if (!handle) return;

    // Restore persisted expanded width (collapse state is restored elsewhere).
    const saved = parseInt(localStorage.getItem(rail.widthKey) || '', 10);
    if (Number.isFinite(saved)) {
      shell.style.setProperty(rail.cssVar, clamp(saved, rail.expandedMin, rail.max) + 'px');
    }

    let dragging = false;

    const onMove = (e) => {
      if (!dragging) return;
      const rect = shell.getBoundingClientRect();
      const w = rail.side === 'left'
        ? (e.clientX - rect.left)
        : (rect.right - e.clientX);
      if (w <= rail.snap) {
        // Snap into the icon-only / collapsed state. Keep the last expanded
        // width in the var so re-expanding restores it.
        rail.setCollapsed(true);
      } else {
        rail.setCollapsed(false);
        shell.style.setProperty(rail.cssVar, clamp(w, rail.expandedMin, rail.max) + 'px');
      }
    };

    const onUp = () => {
      if (!dragging) return;
      dragging = false;
      shell.classList.remove('rail-resizing');
      handle.classList.remove('dragging');
      window.removeEventListener('pointermove', onMove);
      window.removeEventListener('pointerup', onUp);
      const collapsed = rail.isCollapsed();
      localStorage.setItem(rail.collapseKey, collapsed ? '1' : '0');
      if (!collapsed) {
        const cur = parseInt(getComputedStyle(shell).getPropertyValue(rail.cssVar), 10);
        if (Number.isFinite(cur)) localStorage.setItem(rail.widthKey, String(cur));
      }
    };

    handle.addEventListener('pointerdown', (e) => {
      if (e.button !== 0) return;
      e.preventDefault();
      dragging = true;
      shell.classList.add('rail-resizing');
      handle.classList.add('dragging');
      window.addEventListener('pointermove', onMove);
      window.addEventListener('pointerup', onUp);
    });

    // Double-click resets to the default width (and un-collapses).
    handle.addEventListener('dblclick', () => {
      rail.setCollapsed(false);
      shell.style.removeProperty(rail.cssVar);
      localStorage.removeItem(rail.widthKey);
      localStorage.setItem(rail.collapseKey, '0');
    });
  });
}

// ── Inspector page-action handler ────────────────────────
function handleInspectorPageAction(panelId, action) {
  const NAV_MAP = {
    'go-approvals':  'approval-center',
    'go-runs':       'aor',
    'go-graph':      'graph',
    'go-capture':    'capture-markdown',
    'go-intake':     'intake',
    'go-runtimes':   'runtime-cockpit',
    'go-schedules':  'schedule',
    'go-memory':     'runtime-memory-inspector',
    'go-history':    'audit-history',
    'go-inspector':  'node-inspector',
    'go-hygiene':    'graph-hygiene',
    'go-provenance': 'provenance-explorer',
  };
  if (action === 'refresh-dashboard') { loadCommandCenterHome(); return; }
  const target = NAV_MAP[action];
  if (target) { showPanel(target, { updateHash: true }); return; }
  setStatus(`Action "${action}" — use the panel controls for available operations.`, 'observe');
}

// ── Inspector page-action button renderer ─────────────────
function inspectorPageActionBtn(a) {
  const safe = a.safe !== false;
  const authority = a.authority || (safe ? 'direct-safe' : 'approval-gated');
  const cls = safe ? '' : ' oi-gated';
  const disabled = a.disabled ? ' disabled' : '';
  const authorityLabel = safe ? 'safe' : 'gated';
  return `<button class="oi-page-action-btn${cls}" type="button" data-action="${escAttr(a.id)}" data-authority="${authority}" title="${escAttr(a.hint || a.label)}"${disabled}>${escHtml(a.label)}<span class="oi-action-authority">${authorityLabel}</span></button>`;
}

function initShellFraming() {
  const routeButton = (id, panel) => {
    const el = document.getElementById(id);
    if (el) el.addEventListener('click', () => showPanel(panel, { updateHash: true }));
  };
  routeButton('topbar-workspace-btn', 'project-workspace');
  routeButton('topbar-runs-btn', 'aor');
  routeButton('topbar-approvals-btn', 'approval-center');
  routeButton('topbar-review-btn', 'pulse-enqueue');

  const commandInput = document.getElementById('global-command-input');
  if (commandInput) {
    const openSearch = () => {
      if (typeof _openQuickSwitch === 'function') _openQuickSwitch();
    };
    commandInput.addEventListener('focus', openSearch);
    commandInput.addEventListener('keydown', (event) => {
      if ((event.ctrlKey || event.metaKey) && event.key.toLowerCase() === 'k') {
        event.preventDefault();
        openSearch();
      }
      if (event.key === 'Enter') {
        event.preventDefault();
        showPanel('graph', { updateHash: true });
        setTimeout(() => document.getElementById('graph-search')?.focus(), 50);
      }
    });
  }

  const quickCreate = document.getElementById('topbar-quick-create-btn');
  if (quickCreate) {
    quickCreate.addEventListener('click', () => {
      setStatus('Quick create is proposal-only. Open Graph and use Create node to queue approval.', 'observe');
      showPanel('graph', { updateHash: true });
    });
  }
}

function syncGraphFilterToggleState() {
  const filterPanel = document.getElementById('graph-filter-panel');
  const filterToggle = document.getElementById('graph-filter-toggle');
  if (!filterPanel || !filterToggle) return;
  filterToggle.setAttribute('aria-expanded', String(!filterPanel.hidden));
  filterToggle.classList.toggle('active', !filterPanel.hidden);
}

function setGraphFilterPanelOpen(open) {
  const filterPanel = document.getElementById('graph-filter-panel');
  if (!filterPanel) return;
  filterPanel.hidden = !open;
  syncGraphFilterToggleState();
}

function toggleGraphFilterPanel() {
  const filterPanel = document.getElementById('graph-filter-panel');
  if (!filterPanel) return;
  setGraphFilterPanelOpen(filterPanel.hidden);
}

function syncGraphLocalFocusControls() {
  const depth = graphLocalFocusDepth();
  document.querySelectorAll('[data-graph-focus-depth]').forEach(btn => {
    const btnDepth = Number(btn.dataset.graphFocusDepth);
    const active = Number.isFinite(btnDepth) && btnDepth === depth;
    btn.classList.toggle('active', active);
    btn.setAttribute('aria-pressed', String(active));
  });
}

function setGraphLocalFocusDepth(depth) {
  const normalized = _numberSetting(Number(depth), 1, 0, 6);
  _graphLocalFocusDepthOverride = normalized;
  syncGraphLocalFocusControls();
  applyGraphFilters();
  if (_focusedGraphNodeId) {
    const label = normalized > 0 ? `${normalized} hop local graph` : 'all graph nodes';
    setStatus(`Graph focus set to ${label}.`, 'observe');
  }
}

function initGraphProductChrome() {
  const routeButton = (id, panel) => {
    const el = document.getElementById(id);
    if (el) el.addEventListener('click', () => showPanel(panel, { updateHash: true }));
  };
  routeButton('graph-open-inspector', 'node-inspector');
  routeButton('graph-open-hygiene', 'graph-hygiene');
  routeButton('graph-open-provenance', 'provenance-explorer');

  const quickSwitch = document.getElementById('graph-quick-switch-btn');
  if (quickSwitch) quickSwitch.addEventListener('click', () => _openQuickSwitch());

  const filterToggle = document.getElementById('graph-filter-toggle');
  if (filterToggle) filterToggle.addEventListener('click', () => toggleGraphFilterPanel());

  // Quality chip — click opens performance settings tab
  const qualityChip = document.getElementById('graph-quality-chip');
  if (qualityChip) {
    qualityChip.addEventListener('click', () => openSettingsModal({ tab: 'performance' }));
    // Reflect current setting on load
    const initPreset = (_currentSettings && _currentSettings.performance && _currentSettings.performance.quality_preset) || 'balanced';
    _updateQualityChip(initPreset);
  }

  // 2D / 3D view toggle
  const dimToggle = document.getElementById('graph-dim-toggle');
  if (dimToggle) {
    dimToggle.addEventListener('click', () => setGraphDimensions(_graph2DMode ? 3 : 2));
    _syncDimToggleButton();
  }

  document.querySelectorAll('[data-graph-focus-depth]').forEach(btn => {
    btn.addEventListener('click', () => setGraphLocalFocusDepth(btn.dataset.graphFocusDepth));
  });
  syncGraphFilterToggleState();
  syncGraphLocalFocusControls();
}

function _syncDimToggleButton() {
  const btn = document.getElementById('graph-dim-toggle');
  if (!btn) return;
  btn.textContent = _graph2DMode ? '2D' : '3D';
  btn.dataset.dim = _graph2DMode ? '2d' : '3d';
  btn.classList.toggle('active', _graph2DMode);
}

// Switch the live graph between 2D (flat) and 3D (spatial). Re-heats the
// simulation so nodes redistribute into the new dimensionality.
function setGraphDimensions(dims) {
  _graph2DMode = (Number(dims) === 2);
  _syncDimToggleButton();
  if (!graph3d) return;
  try {
    graph3d.numDimensions(_graph2DMode ? 2 : 3);
    graph3d.d3ReheatSimulation();
  } catch (_) {}
  _scheduleGraphZoomToFit(700);
}

function graphNodeContext(nodeLike) {
  const source = nodeLike || {};
  const raw = source._raw || source;
  const props = raw.properties || source.properties || {};
  const id = String(source.id || raw.id || '');
  const path = source.source_path || props.path || props.source_path || raw.path || '';
  return {
    kind: 'node',
    id,
    label: source.display_label || source.label || raw.label || raw.title || id || 'Node',
    path,
    nodeType: source.node_type || raw.node_type || 'unknown',
    family: source.node_family || raw.node_family || raw.node_type || 'unknown',
    trust: source.trust_state || props.trust_state || 'raw',
    domain: source.domain || inferNodeDomain(raw),
    project: source.project || props.project || raw.project || 'unknown',
    status: source.status || raw.status || props.status || 'unknown',
    provenance: source.provenance_state || props.provenance_state || 'unknown',
  };
}

function nodeInspectorDataContext(data) {
  const selected = (data && (data.selected_node || data.node)) || data || {};
  const props = selected.properties || {};
  return graphNodeContext(Object.assign({}, selected, {
    source_path: props.path || props.source_path || selected.path || '',
    trust_state: props.trust_state || selected.trust_state || 'raw',
    domain: props.domain || selected.domain,
    project: props.project || selected.project,
    status: props.status || selected.status,
    provenance_state: props.provenance_state || selected.provenance_state,
  }));
}

function resetObjectInspector() {
  _selectedObjectContext = null;
  const kicker = document.getElementById('object-inspector-kicker');
  const state = document.getElementById('object-inspector-state');
  const body = document.getElementById('object-inspector-body');
  if (kicker) kicker.textContent = 'Inspector';
  if (state) { state.textContent = 'Standby'; state.className = 'object-inspector-state'; }
  if (!body) return;
  body.innerHTML = `<p class="oi-no-selection-hint">Select a run, task, approval, node, artifact, or memory item inside the current page.</p>`;
}

function resetObjectInspectorForPanel(panelId) {
  _selectedObjectContext = null;
  const feature = STUDIO_FEATURE_BY_ID[panelId] || {};
  const label = feature.label || filterLabel(panelId || 'Current page');
  const description = feature.description || 'Inspect items on this page.';
  const pageConfig = INSPECTOR_PAGE_CONFIGS[panelId] || {};
  const kicker = document.getElementById('object-inspector-kicker');
  const state = document.getElementById('object-inspector-state');
  const body = document.getElementById('object-inspector-body');
  if (kicker) kicker.textContent = label;
  if (state) {
    const statusText = feature.status || 'Ready';
    state.textContent = statusText;
    state.className = 'object-inspector-state';
    if (statusText === 'Live') state.classList.add('badge-live');
    else if (statusText === 'Approval required') state.classList.add('badge-gated');
    else if (statusText === 'Read-only') state.classList.add('badge-ro');
  }
  if (!body) return;
  const actions = pageConfig.actions || [];
  const actionsHtml = actions.length
    ? `<div class="oi-action-list">${actions.map(inspectorPageActionBtn).join('')}</div>`
    : `<p class="oi-no-selection-hint">Interact with page content to see contextual actions.</p>`;
  body.innerHTML = `
    <div class="oi-page-context">
      <div class="object-inspector-node-title">${escHtml(label)}</div>
      <p class="oi-page-desc">${escHtml(description)}</p>
      ${pageConfig.posture ? `<div class="oi-posture-note">${escHtml(pageConfig.posture)}</div>` : ''}
      ${actionsHtml}
    </div>`;
  body.querySelectorAll('.oi-page-action-btn').forEach(btn => {
    btn.addEventListener('click', () => handleInspectorPageAction(panelId, btn.dataset.action));
  });
}

function objectActionButton(action, label, enabled, title) {
  const disabled = enabled ? '' : ' disabled';
  const safeTitle = title ? ` title="${escAttr(title)}"` : '';
  return `<button type="button" data-object-action="${escAttr(action)}"${disabled}${safeTitle}>${escHtml(label)}</button>`;
}

function renderObjectInspectorNodeContext(context) {
  if (!context || !context.id) return;
  _selectedObjectContext = context;
  const kicker = document.getElementById('object-inspector-kicker');
  const state = document.getElementById('object-inspector-state');
  const body = document.getElementById('object-inspector-body');
  const isMarkdownDoc = context.kind === 'markdown' || context.nodeType === 'markdown_doc';
  if (kicker) kicker.textContent = isMarkdownDoc ? 'Selected Document' : 'Selected Node';
  if (state) state.textContent = 'Inspect';
  if (!body) return;

  const ref = context.path || context.id;
  const note = isMarkdownDoc
    ? 'Local document actions stay inside Docs / Inspector. Deletion, archive, task creation, and memory attachment remain gated or unmounted.'
    : 'Direct-safe inspection only. Graph mutation, archive, delete, task creation, and memory attachment remain gated or unmounted.';
  const actionGrid = isMarkdownDoc
    ? `
        ${objectActionButton('open-docs', 'Open', true, 'Open this document in Docs / Inspector')}
        ${objectActionButton('copy-ref', 'Copy Path', Boolean(ref), 'Copy the document path')}
        ${objectActionButton('view-provenance', 'Provenance', true, 'Open provenance browser')}
        ${objectActionButton('attach-chat', 'Attach', false, 'Attachment flow is not available from this page')}
        ${objectActionButton('create-task', 'Create Task', false, 'Task creation from document context is not available from this page')}
        ${objectActionButton('archive', 'Archive', false, 'Archive requires approval')}
        ${objectActionButton('delete', 'Delete', false, 'Delete requires approval')}`
    : `
        ${objectActionButton('open-docs', 'Open', true, 'Open this node in Docs / Inspector')}
        ${objectActionButton('focus-graph', 'Focus Graph', true, 'Show this node in the graph local view')}
        ${objectActionButton('pin-focus', 'Pin Focus', true, 'Pin this node in the current graph session only')}
        ${objectActionButton('view-provenance', 'Provenance', true, 'Open provenance browser')}
        ${objectActionButton('copy-ref', 'Copy ID / Path', Boolean(ref), 'Copy the node ID or source path')}
        ${objectActionButton('attach-chat', 'Attach', false, 'Attachment flow is not available from this page')}
        ${objectActionButton('create-task', 'Create Task', false, 'Task creation from node context is not available from this page')}
        ${objectActionButton('archive', 'Archive', false, 'Archive requires approval')}
        ${objectActionButton('delete', 'Delete', false, 'Delete requires approval')}`;
  body.innerHTML = `
    <div class="object-inspector-node" data-selected-node-id="${escAttr(context.id)}">
      <div class="object-inspector-node-title">${escHtml(context.label)}</div>
      <div class="object-inspector-meta-grid">
        <span>Type</span><strong>${escHtml(filterLabel(context.nodeType || 'unknown'))}</strong>
        <span>Family</span><strong>${escHtml(filterLabel(context.family || 'unknown'))}</strong>
        <span>Trust</span><strong>${escHtml(context.trust || 'raw')}</strong>
        <span>Domain</span><strong>${escHtml(context.domain || 'unknown')}</strong>
      </div>
      <div class="object-inspector-node-path">${escHtml(ref || 'No path available')}</div>
      <div class="object-inspector-note">${escHtml(note)}</div>
      <div class="object-inspector-button-grid" aria-label="Selected node actions">
        ${actionGrid}
      </div>
    </div>`;

  body.querySelectorAll('[data-object-action]').forEach(btn => {
    btn.addEventListener('click', () => handleObjectInspectorAction(btn.dataset.objectAction));
  });
}

function handleObjectInspectorAction(action) {
  const ctx = _selectedObjectContext;
  if (!ctx || !ctx.id) return;
  if (action === 'open-docs') {
    if ((ctx.kind === 'markdown' || ctx.nodeType === 'markdown_doc') && typeof window.openMarkdownDocument === 'function') {
      window.openMarkdownDocument(ctx.path || ctx.id.replace(/^markdown:/, ''));
      showPanel('node-inspector', { updateHash: true });
      return;
    }
    if (window.InspectorTabs) window.InspectorTabs.openNodeTab(ctx, { source: 'object-inspector', navigate: true });
    else inspectNode(ctx.id, ctx.label);
    showPanel('node-inspector', { updateHash: true });
    return;
  }
  if (action === 'focus-graph') {
    focusGraphOnNodeContext(ctx);
    return;
  }
  if (action === 'pin-focus') {
    pinGraphNodeInSession(ctx);
    return;
  }
  if (action === 'view-provenance') {
    showPanel('provenance-explorer', { updateHash: true });
    setStatus(`Provenance browser opened for ${ctx.label}.`, 'observe');
    return;
  }
  if (action === 'copy-ref') {
    copyObjectInspectorRef(ctx);
  }
}

function focusGraphOnNodeContext(ctx) {
  _focusedGraphNodeId = String(ctx.id);
  if (graphLocalFocusDepth() === 0) _graphLocalFocusDepthOverride = 1;
  syncGraphLocalFocusControls();
  showPanel('graph', { updateHash: true });
  const focusNow = () => {
    const node = _graphAllNodes.find(n => String(n.id) === String(ctx.id));
    if (node) _focusGraphNode(node, { inspect: false });
    else applyGraphFilters();
  };
  setTimeout(focusNow, graphLoaded ? 50 : 450);
}

function pinGraphNodeInSession(ctx) {
  if (!_currentSettings) _currentSettings = {};
  if (!_currentSettings.layout) _currentSettings.layout = {};
  if (!Array.isArray(_currentSettings.layout.pinned_nodes)) _currentSettings.layout.pinned_nodes = [];
  const id = String(ctx.id);
  if (!_currentSettings.layout.pinned_nodes.map(String).includes(id)) {
    _currentSettings.layout.pinned_nodes.push(id);
  }
  applyGraphPinnedNodes();
  setStatus(`Pinned ${ctx.label} for this graph session. Save Settings is still the governed persistence path.`, 'observe');
}

async function copyObjectInspectorRef(ctx) {
  const ref = ctx.path || ctx.id || '';
  if (!ref) return;
  try {
    if (navigator.clipboard && navigator.clipboard.writeText) {
      await navigator.clipboard.writeText(ref);
      setStatus('Copied node ID / path.', 'observe');
      return;
    }
  } catch (_) {}
  setStatus('Clipboard unavailable in this shell context.', 'warn');
}

function renderObjectInspectorRuntimeContext(context) {
  if (!context || !context.id) return;
  _selectedObjectContext = context;
  const kicker = document.getElementById('object-inspector-kicker');
  const state = document.getElementById('object-inspector-state');
  const body = document.getElementById('object-inspector-body');
  if (kicker) kicker.textContent = context.kicker || 'Selected Runtime Object';
  if (state) state.textContent = context.state || 'Inspect';
  if (!body) return;

  const ref = context.ref || context.path || context.id;
  const openLabel = context.openLabel || 'Open Detail';
  const canOpen = Boolean(context.panel && (context.filename || context.scheduleId || context.id));
  body.innerHTML = `
    <div class="object-inspector-node" data-selected-runtime-object="${escAttr(context.id)}">
      <div class="object-inspector-node-title">${escHtml(context.label || context.id)}</div>
      <div class="object-inspector-meta-grid">
        <span>Type</span><strong>${escHtml(context.type || 'runtime object')}</strong>
        <span>Status</span><strong>${escHtml(context.status || 'unknown')}</strong>
        <span>Runtime</span><strong>${escHtml(context.runtime || 'unknown')}</strong>
        <span>Time</span><strong>${escHtml(context.time || '—')}</strong>
      </div>
      <div class="object-inspector-node-path">${escHtml(ref || 'No ID or path available')}</div>
      <div class="object-inspector-note">${escHtml(context.note || 'Direct-safe inspection only. Runtime dispatch, retry, approval consumption, schedule mutation, and Agent Bus writes remain gated or unmounted.')}</div>
      <div class="object-inspector-button-grid" aria-label="Selected runtime object actions">
        ${objectActionButton('runtime-open-detail', openLabel, canOpen, 'Open the selected object on its owning page')}
        ${objectActionButton('runtime-copy-ref', 'Copy ID / Path', Boolean(ref), 'Copy the object ID or evidence path')}
        ${objectActionButton('runtime-attach', 'Attach', false, 'Attachment flow is not available from this page')}
        ${objectActionButton('runtime-create-task', 'Create Task', false, 'Task creation from runtime objects is not available from this page')}
        ${objectActionButton('runtime-retry', 'Retry / Resume', false, 'Retry and resume are not executed from this view')}
        ${objectActionButton('runtime-approve', 'Approve', false, 'Approval consumption remains in governed approval flows')}
        ${objectActionButton('runtime-dispatch', 'Dispatch', false, 'Runtime and Agent Bus dispatch are not granted here')}
        ${objectActionButton('runtime-archive', 'Archive', false, 'Archive requires approval or is not available here')}
      </div>
    </div>`;

  body.querySelectorAll('[data-object-action]').forEach(btn => {
    btn.addEventListener('click', () => handleRuntimeObjectInspectorAction(btn.dataset.objectAction));
  });
}

function runtimeObjectTime(value) {
  return value ? String(value).replace('T', ' ').slice(0, 19) : '—';
}

async function copyRuntimeObjectInspectorRef(ctx) {
  const ref = ctx && (ctx.ref || ctx.path || ctx.id) || '';
  if (!ref) return;
  try {
    if (navigator.clipboard && navigator.clipboard.writeText) {
      await navigator.clipboard.writeText(ref);
      setStatus('Copied object ID / path.', 'observe');
      return;
    }
  } catch (_) {}
  setStatus('Clipboard unavailable in this shell context.', 'warn');
}

function handleRuntimeObjectInspectorAction(action) {
  const ctx = _selectedObjectContext;
  if (!ctx || !ctx.id) return;
  if (action === 'runtime-open-detail') {
    if (ctx.panel === 'aor' && ctx.filename) {
      showPanel('aor', { updateHash: true });
      loadAORDetail(ctx.filename);
      return;
    }
    if (ctx.panel === 'schedules' && ctx.scheduleId) {
      showPanel('schedules', { updateHash: true });
      schedulesDetailId = ctx.scheduleId;
      loadScheduleDetail(ctx.scheduleId);
      return;
    }
    if (ctx.panel) {
      showPanel(ctx.panel, { updateHash: true });
      return;
    }
  }
  if (action === 'runtime-copy-ref') copyRuntimeObjectInspectorRef(ctx);
}

