function handleProductObjectInspectorAction(action) {
  const ctx = _selectedObjectContext;
  if (!ctx || !ctx.id) return;
  if (action === 'product-open-detail') {
    if (ctx.panel) {
      showPanel(ctx.panel, { updateHash: true });
      if (ctx.panel === 'sic' && ctx.slug) loadSICWorkspaceDetail(ctx.slug);
      if (ctx.panel === 'runtime-memory-inspector' && ctx.runtimeId) loadRuntimeMemoryDetail(ctx.runtimeId);
    }
    return;
  }
  if (action === 'product-provenance') {
    showPanel('provenance-explorer', { updateHash: true });
    setStatus(`Provenance browser opened for ${ctx.label || ctx.id}.`, 'observe');
    return;
  }
  if (action === 'product-copy-ref') copyProductObjectInspectorRef(ctx);
}

function routeForPanel(id) {
  return panelRoutes[id] || ('#/' + id);
}

function panelFromRoute(route) {
  const raw = String(route || '').replace(/^#\/?/, '').trim();
  return raw && document.getElementById('panel-' + raw) ? raw : '';
}

function routePanelFromHash() {
  return panelFromRoute(window.location && window.location.hash ? window.location.hash : '');
}

function defaultRoutePanel() {
  return routePanelFromHash() || 'dashboard';
}

function showPanel(id, opts = {}) {
  const panel = document.getElementById('panel-' + id);
  const btn = document.querySelector(`.nav-btn[data-panel="${id}"]`);
  if (!panel) return false;
  const previousPanel = currentPanel;
  document.querySelectorAll('.panel').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.nav-btn').forEach(b => {
    b.classList.remove('active');
    b.removeAttribute('aria-current');
  });
  panel.classList.add('active');
  resetPanelScroll(panel);
  if (btn) {
    btn.classList.add('active');
    btn.setAttribute('aria-current', 'page');
  }
  currentPanel = id;
  document.body.classList.toggle('chat-page-active', id === 'chat');
  if (previousPanel !== id) resetObjectInspectorForPanel(id);
  if (opts.updateHash && window.location && window.location.hash !== routeForPanel(id)) {
    window.location.hash = routeForPanel(id);
  }
  if (!window.location || !window.location.hash) {
    history.replaceState(null, '', routeForPanel(id));
  }
  const runPanelLoader = (loader) => {
    if (opts.deferLoad) window.setTimeout(loader, 0);
    else loader();
  };
  if (id === 'graph' && !graphLoaded) runPanelLoader(loadGraph);
  if (id === 'dashboard') runPanelLoader(loadCommandCenterHome);
  if (id === 'studio-status') runPanelLoader(loadStudioStatusPanel);
  if (id === 'app-launcher') runPanelLoader(loadAppLauncher);
  if (id === 'browser-runtime') runPanelLoader(loadBrowserRuntime);
  if (id === 'workspace-entry') runPanelLoader(loadWorkspaceEntry);
  if (id === 'node-inspector') runPanelLoader(loadDocsInspectorPanel);
  if (id === 'settings') runPanelLoader(loadSettingsRuntimeControls);
  if (id === 'chat') {
    // Pick up composer prefill from Home panel (stored by _submitComposer)
    let _composerPrefill = '';
    try { _composerPrefill = sessionStorage.getItem('chaseos.composer.prefill') || ''; sessionStorage.removeItem('chaseos.composer.prefill'); } catch (_) {}
    runPanelLoader(() => {
      if (_composerPrefill) loadPhase11ChatPanel(_composerPrefill);
      else loadPhase11ChatPanel();
      _startChatAvailabilityPolling();
    });
  } else { _stopChatAvailabilityPolling(); }
  if (id === 'approval-center') runPanelLoader(loadApprovalCenter);
  if (id === 'runtime-cockpit') runPanelLoader(loadRuntimeCockpit);
  if (id === 'provenance-explorer') runPanelLoader(loadProvenanceExplorer);
  if (id === 'memory-ledger') runPanelLoader(loadMemoryLedger);
  if (id === 'context-import') runPanelLoader(loadContextImportPanel);
  if (id === 'agent-identity') runPanelLoader(loadAgentIdentity);
  if (id === 'runtime-navigation') runPanelLoader(loadRuntimeNavigation);
  if (id === 'runtime-support-loops') runPanelLoader(loadRuntimeSupportLoops);
  if (id === 'project-workspace') runPanelLoader(() => { loadProjectWorkspace(); loadSprintFocus(); });
  if (id === 'chaser-forge') runPanelLoader(loadChaserForgePanel);
  if (id === 'workflow-packs') runPanelLoader(loadWorkflowPacksPanel);
  if (id === 'intake') runPanelLoader(loadIntake);
  if (id === 'capture-markdown') runPanelLoader(loadCaptureMarkdownPanel);
  if (id === 'sic') runPanelLoader(loadSIC);
  if (id === 'aor') runPanelLoader(loadAOR);
  if (id === 'schedules') runPanelLoader(loadSchedules);
  if (id === 'pulse-schedule-proof') runPanelLoader(loadPulseScheduleProof);
  if (id === 'pulse-enqueue') runPanelLoader(loadPulseEnqueue);
  if (id === 'siteops') runPanelLoader(loadSiteOps);
  if (id === 'acquisition') runPanelLoader(loadAcquisition);
  if (id === 'bus') runPanelLoader(loadBus);
  if (id === 'build-logs') runPanelLoader(loadBuildLogs);
  if (id === 'decision-ledger') runPanelLoader(loadDecisionLedger);
  if (id === 'pivot-log') runPanelLoader(loadPivotLog);
  if (id === 'feature-filter') runPanelLoader(loadFeatureFilter);
  if (id === 'workflow-registry') runPanelLoader(loadWorkflowRegistry);
  if (id === 'role-cards') runPanelLoader(loadRoleCards);
  if (id === 'runtime-memory-inspector') runPanelLoader(loadRuntimeMemoryInspector);
  if (id === 'graph-hygiene' && !_graphHygieneLoaded) runPanelLoader(loadGraphHygienePanel);
  return true;
}

function activatePanelForQa(id, routeHash) {
  const panel = document.getElementById('panel-' + id);
  const btn = document.querySelector(`.nav-btn[data-panel="${id}"]`);
  if (!panel) {
    return { ok: false, shown: false, panel_id: id, active_panel_id: '', error: 'missing_panel' };
  }
  document.querySelectorAll('.panel').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.nav-btn').forEach(b => {
    b.classList.remove('active');
    b.removeAttribute('aria-current');
  });
  panel.classList.add('active');
  resetPanelScroll(panel);
  if (btn) {
    btn.classList.add('active');
    btn.setAttribute('aria-current', 'page');
  }
  currentPanel = id;
  document.body.classList.toggle('chat-page-active', id === 'chat');
  const nextHash = routeHash || routeForPanel(id);
  if (nextHash && window.location && window.location.hash !== nextHash) {
    try {
      window.history.replaceState(null, '', nextHash);
    } catch (_) {
      window.location.hash = nextHash;
    }
  }
  window.setTimeout(() => {
    try { showPanel(id, { updateHash: false, deferLoad: true }); } catch (_) {}
  }, 0);
  return {
    ok: true,
    shown: true,
    panel_id: id,
    active_panel_id: 'panel-' + id,
    hash: window.location ? window.location.hash : '',
  };
}

function resetPanelScroll(panel) {
  if (!panel) return;
  const reset = () => {
    panel.scrollTop = 0;
    panel.querySelectorAll('.capture-markdown-panel, .siteops-panel, .acquisition-panel, .bus-panel, .workflow-packs-tab-body, .chaser-forge-grid, .graph-hygiene-panel').forEach(el => {
      el.scrollTop = 0;
    });
  };
  reset();
  window.requestAnimationFrame(reset);
}

// Expose globally for inspectorTabs.js / markdownRenderer.js navigation
window.showPanel = showPanel;
window.__chaseosActivatePanelForQa = activatePanelForQa;
window.inspectNode = inspectNode;

// ── Loading overlay ───────────────────────────────────────────────────────────
function hideLoading() {
  const el = document.getElementById('loading-overlay');
  if (el) {
    el.classList.add('hidden');
    el.setAttribute('aria-hidden', 'true');
    el.hidden = true;
    el.style.display = 'none';
    el.remove();
  }
  const msg = document.getElementById('status-message');
  if (msg && /starting/i.test(msg.textContent || '')) {
    setStatus('Studio ready', 'observe');
  }
}

function setStatus(text, cls) {
  const pill = document.getElementById('status-pill');
  const msg  = document.getElementById('status-message');
  const labels = {
    loading: 'SYNC',
    ready: 'READY',
    observe: 'OBSERVE',
    error: 'ATTENTION',
    warn: 'REVIEW',
  };
  if (pill) {
    pill.className = 'status-pill ' + (cls || '');
    pill.textContent = labels[cls] || (cls ? cls.toUpperCase() : 'OBSERVE');
  }
  if (msg)  msg.textContent = text || '';
}

function setTopStatus(text, cls) {
  const el = document.getElementById('topbar-status');
  if (el) { el.className = cls || ''; el.textContent = text; }
}

window.setTimeout(() => {
  if (document.getElementById('loading-overlay')) {
    hideLoading();
    setTopStatus('Local shell ready', 'observe');
  }
}, 8000);

// Native shell panel registry: read-only or approval-gated contract metadata for mounted/future panels.
async function loadPanelRegistry() {
  const el = document.getElementById('panel-registry-status');
  if (!window.pywebview || !window.pywebview.api || !window.pywebview.api.get_panel_registry) {
    if (el) el.textContent = 'Panel registry unavailable';
    return null;
  }
  try {
    const resp = await window.pywebview.api.get_panel_registry();
    if (!resp || !resp.ok) {
      if (el) el.textContent = 'Panel registry failed';
      return null;
    }
    panelRegistry = resp.data || {};
    const readiness = panelRegistry.readiness || {};
    const panels = panelRegistry.panels || [];
    if (el) {
      el.textContent = `${readiness.mounted_panel_count || 0} Studio surfaces ready`;
      el.dataset.registryReady = String(!!readiness.native_shell_panel_registry_ready);
      el.dataset.safeOrApprovalGated = String(!!readiness.all_declared_panels_safe_or_approval_gated);
    }
    return panelRegistry;
  } catch (_) {
    if (el) el.textContent = 'Panel registry error';
    return null;
  }
}

// ── Graph shape/style helpers ─────────────────────────────────────────────────

// nodeShape: kept for test compatibility (referenced by test_app_js_has_pass10b_graph_visual_mappings)
function nodeShape(nodeType) {
  if (window.GraphStyles && _registryLoaded) {
    const reg = window.GraphStyles.getRegistry();
    const family = (reg.node_type_to_family || {})[nodeType] || 'entity_object';
    const famDef = (reg.node_families || {})[family] || {};
    return famDef.shape || 'ellipse';
  }
  return 'ellipse';
}

// edgeStyleFamily: kept for test compatibility
function edgeStyleFamily(relation) {
  const rel = String(relation || '');
  if (rel.startsWith('contains_') || rel === 'has_tag') return 'structural';
  if (rel.includes('unresolved') || rel.includes('external')) return 'suggested_semantic';
  if (rel.includes('runtime') || rel.includes('workflow') || rel.includes('agent')) return 'runtime_action';
  return 'explicit';
}

function normalizeGraphEdgeLayer(layer) {
  if (window.GraphStyles && window.GraphStyles.normalizeEdgeLayer) {
    return window.GraphStyles.normalizeEdgeLayer(layer);
  }
  const raw = String(layer || 'explicit').trim().toLowerCase().replace(/\s+/g, '_').replace(/-/g, '_');
  if (raw === 'runtime') return 'runtime_action';
  if (raw === 'suggested' || raw === 'semantic') return 'suggested_semantic';
  if (['explicit', 'structural', 'suggested_semantic', 'runtime_action'].includes(raw)) return raw;
  return 'explicit';
}

function filterLabel(id) {
  return String(id || '').replace(/_/g, ' ').replace(/\b\w/g, ch => ch.toUpperCase());
}

