    const src = String(link.source && link.source.id != null ? link.source.id : link.source);
    const tgt = String(link.target && link.target.id != null ? link.target.id : link.target);
    _degreeById.set(src, (_degreeById.get(src) || 0) + 1);
    _degreeById.set(tgt, (_degreeById.get(tgt) || 0) + 1);
