// Archon + Claude are the same session runtime (Archon = Claude Code session identity).
// All runtime profiles shown individually using their self-named identity.
// Persistent (24/7) runtimes sort first; within each group sort alphabetically.
function _sortRuntimes(runtimes) {
  return [...runtimes].sort((a, b) => {
    const aP = ((a && a.lane_class) === 'persistent') ? 0 : 1;
    const bP = ((b && b.lane_class) === 'persistent') ? 0 : 1;
    if (aP !== bP) return aP - bP;
    return ((a && a.runtime_id) || '').localeCompare((b && b.runtime_id) || '');
  });
}

function homeShell({ runtimes, openBusTasks, totalBusTasks, pendingApprovals, reviewQueue,
                     graphNodes, graphEdges, attention, recentAudit, recentChats,
                     enabledSchedules, totalSchedules, nowContent }) {
  const companionState = pendingApprovals > 0 ? 'alert' : 'idle';
  window._homeState = { nowContent, attention, pendingApprovals, graphNodes, graphEdges };

  // Sort: persistent (24/7) runtimes first, then alphabetical — all show with self-named identity
  let displayRuntimes = [];
  try { displayRuntimes = _sortRuntimes(runtimes || []); } catch (_) { displayRuntimes = (runtimes || []).slice(); }

  // Build chips defensively — one bad runtime object must not blank the whole strip
  let chipsHtml = '';
  try {
    chipsHtml = displayRuntimes.length > 0
      ? displayRuntimes.map(r => { try { return homeRuntimeChip(r); } catch (_) { return ''; } }).join('')
      : `<span class="home-runtime-empty">Local shell ready</span>`;
  } catch (_) {
    chipsHtml = `<span class="home-runtime-empty">Local shell ready</span>`;
  }

  // Build activity section defensively
  let activityHtml = '';
  try { activityHtml = homeActivitySection(recentAudit || [], recentChats || []); }
  catch (_) { activityHtml = `<section class="home-activity-section"></section>`; }

  return (
    `<div class="home-layout">` +

    // Row 1: Runtime strip — chips + ambient toggle (companion moved to main-row)
    `<div class="home-runtime-strip">` +
    `<span class="home-runtime-strip-label">Runtimes</span>` +
    chipsHtml +
    `<span class="home-runtime-strip-spacer" aria-hidden="true"></span>` +
    `<div class="home-ambient-toggle" aria-label="Ambient background">` +
    `<span class="home-ambient-toggle-label">Ambient</span>` +
    `<button class="home-ambient-btn" data-ambient="off" title="Ambient off">Off</button>` +
    `<button class="home-ambient-btn" data-ambient="opt1" title="Aurora fog">Fog</button>` +
    `<button class="home-ambient-btn" data-ambient="opt2" title="Breathing glow">Glow</button>` +
    `</div>` +
    `</div>` +

    // Appearance panel (fixed flyout — positioned by JS)
    `<div class="home-appearance-panel" id="home-appearance-panel" hidden>` +
    `<div class="home-appearance-header">` +
    `<span class="home-appearance-title">Appearance</span>` +
    `<button class="icon-btn home-appearance-close" id="home-appearance-close" title="Close">✕</button>` +
    `</div>` +
    `<div class="home-appearance-body">` +
    `<div class="home-appearance-row"><label class="home-appearance-label" for="hap-accent">Accent color</label>` +
    `<input type="color" class="home-appearance-swatch" id="hap-accent" value="#39e6d2" title="Primary accent"></div>` +
    `<div class="home-appearance-row"><label class="home-appearance-label" for="hap-secondary">Secondary color</label>` +
    `<input type="color" class="home-appearance-swatch" id="hap-secondary" value="#7c5cff" title="Secondary / memory graph"></div>` +
    `<button class="home-appearance-reset" id="hap-reset">Reset defaults</button>` +
    `</div>` +
    `</div>` +

    // Row 2: Sprint strip (Now.md)
    (nowContent
      ? `<div class="home-now-strip"><span class="home-now-label">Sprint</span><span class="home-now-content">${escHtml(nowContent)}</span></div>`
      : '') +

    // Row 2B: Home composer
    homeComposer() +

    // Row 3: 4 metric chips
    `<div class="home-metric-row">` +
    homeMetricChip('Active runs',   openBusTasks,     `${totalBusTasks} bus tasks`,   openBusTasks > 0 ? 'info' : 'idle',    'aor') +
    homeMetricChip('Approvals',     pendingApprovals, 'pending decisions',              pendingApprovals > 0 ? 'warn' : 'ok',  'approval-center') +
    homeMetricChip('Review queue',  reviewQueue,      'items needing review',            reviewQueue > 0 ? 'caution' : 'ok',   'intake') +
    homeMetricChip('Graph',         graphNodes,       `${graphEdges} edges`,            'info',                                'graph') +
    `</div>` +

    // Row 4: 3-column main area — attention | launch | companion
    `<div class="home-main-row">` +
    `<section class="home-attention-col">` +
    `<div class="home-col-header">Needs attention</div>` +
    attention.slice(0, 5).map(item => homeAttentionItem(item)).join('') +
    `</section>` +
    `<section class="home-launch-col">` +
    `<div class="home-col-header">Quick launch</div>` +
    `<div class="home-launch-grid">` +
    homeLaunchBtn('Graph',    'graph',                    'safe') +
    homeLaunchBtn('Approvals','approval-center',          'safe') +
    homeLaunchBtn('Intake',   'intake',                   'gated') +
    homeLaunchBtn('Schedules','schedules',                'safe') +
    homeLaunchBtn('Bus',      'bus',                      'safe') +
    homeLaunchBtn('Memory',   'runtime-memory-inspector', 'safe') +
    homeLaunchBtn('Pulse',    'pulse-enqueue',            'safe') +
    homeLaunchBtn('Chat',     'chat',                     'draft') +
    `</div>` +
    `</section>` +
    // Companion column — runtime mascot with status indicator
    homeCompanionColumn(pendingApprovals) +
    `</div>` +

    // Row 5: Activity section — 2-column (Agent Activity + Recent Chats) — fills remaining space
    activityHtml +

    // Floating appearance button — bottom-right corner of home panel
    `<button class="home-appearance-btn home-appearance-btn--corner" id="home-appearance-btn" ` +
    `title="Customize appearance" aria-label="Appearance settings" aria-expanded="false">` +
    `<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" ` +
    `stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">` +
    `<circle cx="12" cy="12" r="3"/>` +
    `<path d="M12 1v4M12 19v4M4.22 4.22l2.83 2.83M16.95 16.95l2.83 2.83"/>` +
    `<path d="M1 12h4M19 12h4M4.22 19.78l2.83-2.83M16.95 7.05l2.83-2.83"/>` +
    `</svg>` +
    `</button>` +

    `</div>`
  );
}

// Profile-driven runtime chip — each profile shows its own self-named identity.
// Core 24/7 runtimes (hermes + openclaw) get gold/amber treatment and pulsing ring.
// Other persistent runtimes get teal treatment. Session runtimes are subdued.
function homeRuntimeChip(r) {
  const id = (r && r.runtime_id) ? r.runtime_id : String(r);
  const platformName = _runtimePlatform(id, r);
  const personaName  = _runtimePersona(id, r);
  const ident = _runtimeIdentity(id);
  const role = (ident && ident.role) || (r && r.primary_role) || '';
  const isPersistent = ((r && r.lane_class) === 'persistent') || (ident && ident.lane === 'persistent');
  const isCore24x7 = id === 'hermes' || id === 'openclaw';
  const hasProfile = r ? (r.has_profile !== false) : true;

  const laneClass = isCore24x7
    ? 'home-runtime-chip--persistent home-runtime-chip--core-247'
    : isPersistent ? 'home-runtime-chip--persistent'
    : 'home-runtime-chip--session';

  // Core 24/7: gold badge + pulsing outer ring. Other persistent: teal badge.
  const badge = isCore24x7
    ? `<span class="runtime-lane-badge runtime-lane-badge--core">24/7</span>` +
      `<span class="runtime-pulse-ring runtime-pulse-ring--core" aria-hidden="true"></span>`
    : isPersistent
    ? `<span class="runtime-lane-badge">24/7</span>` +
      `<span class="runtime-pulse-ring" aria-hidden="true"></span>`
    : '';
  const dot = hasProfile ? '●' : '○';
  const tooltip = `${platformName} → ${personaName}${role ? ' — ' + role : ''}\nClick to view profile`;

  // Two stacked name spans — the chip shows the platform name and flips to the
  // self-given persona name on hover (CSS-driven in .home-runtime-chip-name).
  const nameHtml =
    `<span class="home-runtime-chip-name">` +
    `<span class="hrc-name-platform">${escHtml(platformName)}</span>` +
    `<span class="hrc-name-persona">${escHtml(personaName)}</span>` +
    `</span>`;

  return `<span class="home-runtime-chip ${escAttr(laneClass)}" title="${escAttr(tooltip)}" ` +
    `data-runtime-chip="${escAttr(id)}" tabindex="0" role="button" aria-label="View ${escAttr(personaName)} profile">` +
    `<span class="home-runtime-dot">${dot}</span>` +
    `${nameHtml}${badge}` +
    `</span>`;
}

function homeMetricChip(label, value, sub, tone, panelId) {
  return `<button class="home-metric home-metric--${escAttr(tone || 'info')}" type="button" ` +
    `data-home-nav="${escAttr(panelId || '')}">` +
    `<span class="home-metric-label">${escHtml(label)}</span>` +
    `<strong class="home-metric-value">${escHtml(String(value))}</strong>` +
    `<small class="home-metric-sub">${escHtml(sub || '')}</small>` +
    `</button>`;
}

function homeAttentionItem(item) {
  const toneClass = `home-attention-item--${escAttr(item.tone || 'info')}`;
  if (!item.target) {
    return `<div class="home-attention-item home-attention-item--ok">` +
      `<span class="home-attention-dot">✓</span><span>${escHtml(item.label)}</span>` +
      `</div>`;
  }
  return `<button class="home-attention-item ${toneClass}" type="button" data-home-nav="${escAttr(item.target)}">` +
    `<span class="home-attention-dot">›</span><span>${escHtml(item.label)}</span>` +
    `</button>`;
}

// v2 — with icon and tooltip
function homeLaunchBtn(label, panelId, posture) {
  const cls = posture === 'draft' ? 'home-launch-btn--draft'
    : posture === 'gated' ? 'home-launch-btn--gated'
    : 'home-launch-btn--safe';
  const postureLabel = posture === 'draft' ? 'Start draft'
    : posture === 'gated' ? 'Review'
    : 'Open';
  const icon = _LAUNCH_ICONS[panelId] || '';
  const tooltip = _LAUNCH_TOOLTIPS[panelId] || label;
  return `<button class="home-launch-btn ${cls}" type="button" data-home-nav="${escAttr(panelId)}" title="${escAttr(tooltip)}">` +
    (icon ? `<span class="home-launch-icon" aria-hidden="true">${icon}</span>` : '') +
    `<span class="home-launch-label">${escHtml(label)}</span>` +
    `<small class="home-launch-posture">${escHtml(postureLabel)}</small>` +
    `</button>`;
}

// v3 — activity card with type badge, colored left border, human-readable date
function homeActivityCard(filename) {
  const title = commandCenterArtifactTitle(filename);
  const dateMatch = String(filename).match(/^(\d{4}-\d{2}-\d{2})/);
  const dateLabel = dateMatch ? dateMatch[1] : '';
  // Derive a human-friendly relative label from filename date
  let dateDisplay = dateLabel;
  if (dateLabel) {
    try {
      const d = new Date(dateLabel);
      const today = new Date();
      const diffDays = Math.round((today - d) / 86400000);
      dateDisplay = diffDays === 0 ? 'Today'
        : diffDays === 1 ? 'Yesterday'
        : diffDays < 7  ? `${diffDays}d ago`
        : dateLabel;
    } catch (_) {}
  }
  // Infer type from filename — drives border color via data-act-type attribute
  const fn = String(filename).toLowerCase();
  const actType = fn.includes('build') ? 'BL'
    : fn.includes('studio') ? 'ST'
    : fn.includes('agent') ? 'AG'
    : fn.includes('phase') ? 'PH'
    : fn.includes('sbp') || fn.includes('pulse') ? 'PL'
    : fn.includes('bus') ? 'BU'
    : 'LOG';
  const typeLabel = actType === 'BL' ? 'Build' : actType === 'ST' ? 'Studio'
    : actType === 'AG' ? 'Agent' : actType === 'PH' ? 'Phase'
    : actType === 'PL' ? 'Pulse' : actType === 'BU' ? 'Bus' : 'Log';

  return `<button class="home-activity-card" type="button" data-home-nav="build-logs" ` +
    `data-act-type="${escAttr(actType)}" title="${escAttr(String(filename))}">` +
    `<span class="home-activity-icon" aria-hidden="true" title="${escAttr(typeLabel)}">${escHtml(actType)}</span>` +
    `<span class="home-activity-meta">` +
    `<span class="home-activity-title">${escHtml(title)}</span>` +
    (dateDisplay ? `<span class="home-activity-stamp">${escHtml(dateDisplay)}</span>` : '') +
    `</span>` +
    `</button>`;
}

// Keep legacy alias in case any stale code path references it
function homeActivityChip(filename) { return homeActivityCard(filename); }

// Activity section — 2-column: Agent Activity (left) + Recent Chats (right, wired from backend)
function homeActivitySection(recentAudit, recentChats) {
  const actCards = recentAudit.length > 0
    ? recentAudit.map(f => homeActivityCard(f)).join('')
    : `<div class="home-activity-empty">No recent runtime activity</div>`;

  // Recent chats from backend (chat thread conversations)
  const displayChats = (recentChats || []).filter(c => !_chatThreadLooksLikeVerification(c));
  let chatsHtml;
  if (displayChats.length > 0) {
    chatsHtml = displayChats.slice(0, 4).map(c => {
      const title = c.title || c.thread_id || 'Untitled chat';
      const msgCount = c.message_count || 0;
      const rLabel = c.runtime_label || c.runtime_id || '';
      const lastAt = c.last_message_at_utc || c.updated_at_utc || '';
      let dateDisplay = '';
      if (lastAt) {
        try {
          const d = new Date(lastAt);
          const diffMs = Date.now() - d.getTime();
          const diffMin = Math.floor(diffMs / 60000);
          dateDisplay = diffMin < 1 ? 'Just now'
            : diffMin < 60 ? `${diffMin}m ago`
            : diffMin < 1440 ? `${Math.floor(diffMin / 60)}h ago`
            : diffMin < 10080 ? `${Math.floor(diffMin / 1440)}d ago`
            : d.toLocaleDateString();
        } catch (_) {}
      }
      return `<button class="home-chat-row" type="button" data-home-nav="chat" ` +
        `data-thread-id="${escAttr(c.thread_id || '')}" title="${escAttr(title)}">` +
        `<div class="home-chat-row-icon" aria-hidden="true">` +
        `<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" ` +
        `stroke-linecap="round" stroke-linejoin="round">` +
        `<path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>` +
        `</div>` +
        `<div class="home-chat-row-meta">` +
        `<span class="home-chat-row-title">${escHtml(title)}</span>` +
        `<span class="home-chat-row-sub">${msgCount ? escHtml(String(msgCount) + ' msg') : ''}` +
        (rLabel ? ` · ${escHtml(rLabel)}` : '') +
        (dateDisplay ? ` · ${escHtml(dateDisplay)}` : '') +
        `</span>` +
        `</div>` +
        `</button>`;
    }).join('') +
    `<button class="home-activity-chat-cta" type="button" data-home-nav="chat" ` +
    `style="margin-top:6px;align-self:flex-start;">+ New chat</button>`;
    chatsHtml = `<div class="home-activity-chats-list">` + chatsHtml + `</div>`;
  } else {
    chatsHtml =
      `<div class="home-activity-chats-empty">` +
      `<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" ` +
      `stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">` +
      `<path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>` +
      `<span>No recent chats</span>` +
      `<button class="home-activity-chat-cta" type="button" data-home-nav="chat">Open Chat</button>` +
      `</div>`;
  }

  return (
    `<section class="home-activity-section">` +
    `<div class="home-activity-grid">` +
    `<div class="home-activity-col">` +
    `<div class="home-col-header home-activity-col-header">Agent Activity</div>` +
    `<div class="home-activity-strip">` + actCards + `</div>` +
    `</div>` +
    `<div class="home-activity-col">` +
    `<div class="home-col-header home-activity-col-header">Recent Chats</div>` +
    `<div class="home-activity-chats-col">` + chatsHtml + `</div>` +
    `</div>` +
    `</div>` +
    `</section>`
  );
}

// ChaseOS companion — humanoid character with CSS animations (R21 redesign).
// Lives in the main-row companion column. State-aware: idle (teal) / alert (amber).
// Animations: subtle blink + look left/right sequence on a 7s loop.
// Click triggers bounce gesture. No drawer. No provider calls.
function homeCompanion(state) {
  const stateClass = state === 'alert' ? 'companion--alert'
    : state === 'happy' ? 'companion--happy'
    : '';
  const stateLabel = state === 'alert' ? 'Action needed — check approvals' : 'Systems operational';
  return (
    `<div class="home-companion-wrap ${escAttr(stateClass)}" ` +
    `title="ChaseOS · ${escAttr(stateLabel)}" ` +
    `aria-label="ChaseOS system status: ${escAttr(stateLabel)}" ` +
    `data-companion-wrap="1">` +
    `<div class="home-companion">` +
    `<div class="home-companion-glow"></div>` +
    // Humanoid head structure
    `<div class="companion-head">` +
    // Antenna with pulsing tip
    `<div class="companion-antenna"><div class="companion-antenna-tip"></div></div>` +
    // Face plate with eyes and mouth
    `<div class="companion-face-plate">` +
    `<div class="companion-eye-row">` +
    `<div class="companion-eye companion-eye--left"><div class="companion-pupil"></div></div>` +
    `<div class="companion-eye companion-eye--right"><div class="companion-pupil"></div></div>` +
    `</div>` +
    `<div class="companion-mouth"></div>` +
    `</div>` +
    `</div>` +
    `</div>` +
    `</div>`
  );
}

// Companion column — dedicated card in the main-row, holds the runtime mascot + status.
// Delegates to CompanionSystem if available, falls back to legacy orb.
function homeCompanionColumn(pendingApprovals) {
  if (window.CompanionSystem && typeof window.CompanionSystem.renderHomeCompanionColumn === 'function') {
    return window.CompanionSystem.renderHomeCompanionColumn(pendingApprovals || 0);
  }
  // Legacy fallback
  const state = (pendingApprovals > 0) ? 'alert' : 'ready';
  const stateLabel = state === 'alert' ? '⚠ Action' : '✓ Ready';
  const stateTone  = state === 'alert' ? 'companion-status--alert' : 'companion-status--ok';
  return (
    `<div class="home-companion-col">` +
    homeCompanion(state) +
    `<span class="companion-status-label ${escAttr(stateTone)}">${escHtml(stateLabel)}</span>` +
    `</div>`
  );
}

