function ventureopsCommandCenterPanel(panel) {
  const summary = (panel || {}).summary || {};
  const missing = ((panel || {}).real_world_missing_requirements || []).slice(0, 4);
  return `<div class="command-center-ventureops">` +
    `<div class="command-center-section-head"><h3>VentureOps readiness</h3><span>${escHtml((panel || {}).status || 'unknown')}</span></div>` +
    `<div class="command-center-health-grid">` +
    commandCenterMetric('Local evidence', summary.feature_implementation_complete ? 'complete' : 'open', 'product lane', summary.feature_implementation_complete ? 'ok' : 'warn') +
    commandCenterMetric('Real delivery', summary.real_world_delivery_revenue_complete ? 'complete' : 'blocked', 'operator evidence required', summary.real_world_delivery_revenue_complete ? 'ok' : 'warn') +
    commandCenterMetric('Revenue safe', summary.safe_to_mark_real_world_delivery_revenue_complete ? 'yes' : 'no', 'proof gate', summary.safe_to_mark_real_world_delivery_revenue_complete ? 'ok' : 'warn') +
    commandCenterMetric('Checks', `${summary.hardening_checks_passed || 0}/${summary.hardening_check_count || 0}`, 'hardening', 'info') +
    `</div>` +
    `<div class="command-center-list">` +
    (missing.map(item => `<div class="command-center-action-row"><div><strong>Missing fact</strong><span>${escHtml(String(item))}</span></div></div>`).join('') || commandCenterEmpty('No missing real-use facts reported.')) +
    `</div>` +
    `</div>`;
}

function wireCommandCenter(root) {
  const tabs = root.querySelectorAll('[data-command-center-tab]');
  const panels = root.querySelectorAll('[data-command-center-panel]');
  tabs.forEach(tab => {
    tab.addEventListener('click', () => {
      const target = tab.dataset.commandCenterTab;
      tabs.forEach(item => {
        const selected = item === tab;
        item.classList.toggle('active', selected);
        item.setAttribute('aria-selected', selected ? 'true' : 'false');
      });
      panels.forEach(panel => {
        panel.hidden = panel.dataset.commandCenterPanel !== target;
      });
    });
  });
  root.querySelectorAll('[data-command-center-open]').forEach(button => {
    button.addEventListener('click', () => {
      const panel = button.dataset.commandCenterOpen;
      if (panel && typeof window.showPanel === 'function') window.showPanel(panel);
    });
  });
  const input = root.querySelector('#command-center-command-input');
  if (input) {
    input.addEventListener('keydown', event => {
      if (event.key === 'Enter') {
        event.preventDefault();
        if (typeof window.showPanel === 'function') window.showPanel('chat');
      }
    });
  }
}

// ── Studio Status panel ───────────────────────────────────────────────────────

async function loadStudioStatusPanel() {
  const body = document.getElementById('studio-status-body');
  if (!body) return;
  body.innerHTML = panelLoading('Loading Studio status…');
  try {
    const resp = await window.pywebview.api.get_studio_status();
    if (!resp || !resp.ok) {
      body.innerHTML = `<div class="studio-status-error">${escHtml((resp && resp.error && resp.error.message) || 'Status unavailable')}</div>`;
      return;
    }
    const d = resp.data || {};
    const product = d.product || {};
    const ventureops = d.ventureops || {};
    const summary = product.summary || {};
    const evidence = product.evidence || {};
    const releaseLanes = product.open_release_lanes || [];
    const actionCenter = product.action_center || {};
    const voSummary = ventureops.summary || {};
    const missing = (ventureops.real_world_missing_requirements || []).slice(0, 6);

    const productClass = product.release_grade_complete ? 'ok' : (product.internal_portable_mvp_closed ? 'partial' : 'open');

    body.innerHTML =
      `<div class="sstatus-layout">` +

      // Product build status
      `<section class="sstatus-section">` +
      `<div class="sstatus-section-head">Product build</div>` +
      `<div class="sstatus-metric-row">` +
      studioStatusMetric('Local build', product.internal_portable_mvp_closed ? 'Closed' : 'Open', product.internal_portable_mvp_closed ? 'ok' : 'warn') +
      studioStatusMetric('Release grade', product.release_grade_complete ? 'Complete' : 'Open', product.release_grade_complete ? 'ok' : 'warn') +
      studioStatusMetric('Open lanes', String(summary.release_grade_open_lane_count || releaseLanes.length || 0), 'info') +
      studioStatusMetric('Blockers', String(summary.blocker_count || 0), summary.blocker_count ? 'warn' : 'ok') +
      `</div>` +
      `<div class="sstatus-headline">${escHtml(product.headline || 'Studio build status')}</div>` +
      `<div class="sstatus-current-status">${escHtml(product.current_status || 'unknown')}</div>` +
      `</section>` +

      // Evidence paths
      (evidence.closure_gate_path || evidence.decision_packet_path
        ? `<section class="sstatus-section">` +
          `<div class="sstatus-section-head">Evidence</div>` +
          studioStatusEvidenceRow('Closure gate', evidence.closure_gate_path) +
          studioStatusEvidenceRow('Decision packet', evidence.decision_packet_path) +
          studioStatusEvidenceRow('Manual acceptance', evidence.manual_acceptance_path) +
          `</section>`
        : '') +

      // VentureOps readiness
      `<section class="sstatus-section">` +
      `<div class="sstatus-section-head">VentureOps readiness</div>` +
      `<div class="sstatus-metric-row">` +
      studioStatusMetric('Local evidence', voSummary.feature_implementation_complete ? 'Complete' : 'Open', voSummary.feature_implementation_complete ? 'ok' : 'warn') +
      studioStatusMetric('Real delivery', voSummary.real_world_delivery_revenue_complete ? 'Complete' : 'Blocked', voSummary.real_world_delivery_revenue_complete ? 'ok' : 'warn') +
      studioStatusMetric('Hardening', `${voSummary.hardening_checks_passed || 0}/${voSummary.hardening_check_count || 0}`, 'info') +
      `</div>` +
      (missing.length ? `<div class="sstatus-section-head" style="margin-top:8px">Missing requirements</div>` +
        `<ul class="sstatus-missing-list">${missing.map(item => `<li>${escHtml(String(item))}</li>`).join('')}</ul>` : '') +
      `</section>` +

      // Release lanes (collapsible)
      (releaseLanes.length
        ? `<section class="sstatus-section">` +
          `<details>` +
          `<summary class="sstatus-section-head">Release lanes (${releaseLanes.length})</summary>` +
          `<div class="sstatus-lane-list">` +
          releaseLanes.slice(0, 12).map(lane =>
            `<div class="sstatus-lane">` +
            `<div class="sstatus-lane-title">${escHtml(lane.label || lane.id || 'lane')}</div>` +
            `<div class="sstatus-lane-status sstatus-lane-status--${escAttr((lane.status || 'open').toLowerCase().replace(/\s+/g, '-'))}">${escHtml(lane.status || 'open')}</div>` +
            `<code class="sstatus-lane-cmd">${escHtml(lane.preview_command || 'No preview command')}</code>` +
            `</div>`
          ).join('') +
          `</div></details>` +
          `</section>`
        : '') +

      `</div>`;

    setStatus('Studio Status loaded', 'observe');
  } catch (err) {
    body.innerHTML = `<div class="studio-status-error">${escHtml(err.message || 'Unavailable')}</div>`;
  }
}

function studioStatusMetric(label, value, tone) {
  return `<div class="sstatus-metric sstatus-metric--${escAttr(tone || 'info')}">` +
    `<span>${escHtml(label)}</span><strong>${escHtml(String(value))}</strong>` +
    `</div>`;
}

function studioStatusEvidenceRow(label, path) {
  if (!path) return '';
  return `<div class="sstatus-evidence-row"><span>${escHtml(label)}</span><code>${escHtml(path)}</code></div>`;
}

// ── Reusable daemon runtime cards ─────────────────────────────────────────────
// Used by Dashboard and Settings — generic start/stop/status for any runtime.

const _DAEMON_RUNTIME_META = {
  hermes:   { name: 'Hermes',   icon: 'H', tooltip: 'Hermes AI runtime — handles review, synthesis, chat, and coordination tasks via the Agent Bus. Runs in the background as a 24/7 poll loop.' },
  openclaw: { name: 'OpenClaw', icon: 'O', tooltip: 'OpenClaw runtime — Windows-native operator automation runtime. Dispatches briefings, hygiene tasks, and scheduled workflows via the Agent Bus.' },
};

// prefix = '' (default, for dashboard) or a string like 'settings' to namespace IDs
// and avoid conflicts when both panels exist in the DOM simultaneously.
function _daemonId(prefix, name, runtimeId) {
  return prefix ? `${prefix}-${name}-${runtimeId}` : `${name}-${runtimeId}`;
}

function _buildDaemonCardHtml(runtimeId, prefix) {
  const pfx = prefix || '';
  const meta = _DAEMON_RUNTIME_META[runtimeId] || { name: runtimeId, icon: runtimeId[0].toUpperCase(), tooltip: '' };
  const rcId     = _daemonId(pfx, 'daemon-rc',        runtimeId);
  const modeId   = _daemonId(pfx, 'daemon-mode',      runtimeId);
  const statusId = _daemonId(pfx, 'daemon-rc-status', runtimeId);
  const startId  = _daemonId(pfx, 'daemon-rc-start',  runtimeId);
  const stopId   = _daemonId(pfx, 'daemon-rc-stop',   runtimeId);
  const hintId   = _daemonId(pfx, 'daemon-hint',      runtimeId);
  return `<div class="daemon-runtime-card daemon-stopped" id="${rcId}" title="${escAttr(meta.tooltip)}">
    <div class="daemon-runtime-card-header">
      <div class="daemon-runtime-icon">${escHtml(meta.icon)}</div>
      <div>
        <div class="daemon-runtime-name">${escHtml(meta.name)}</div>
        <div class="daemon-runtime-mode" id="${modeId}">-</div>
      </div>
    </div>
    <div class="daemon-runtime-status" id="${statusId}">Checking...</div>
    <div class="daemon-runtime-actions">
      <button id="${startId}" class="daemon-btn daemon-btn--start" type="button">Start</button>
      <button id="${stopId}"  class="daemon-btn daemon-btn--stop"  type="button" style="display:none">Stop</button>
    </div>
    <div class="daemon-runtime-install-hint" id="${hintId}" style="display:none"></div>
  </div>`;
}

function _daemonRuntimeModeLabel(runtimeId, data, mode, label) {
  const port = data.gateway_port_listening;
  const source = data.status_source || 'status';
  const base = label || (mode === 'windows' ? 'Windows' : mode === 'wsl' ? 'WSL' : (_DAEMON_RUNTIME_META[runtimeId] || {}).name || runtimeId);
  const portText = port ? `port ${port}` : (data.gateway_ports_checked || []).length ? `checked ${(data.gateway_ports_checked || []).join(', ')}` : '';
  return [base, portText, source !== 'none' ? source.replace(/_/g, ' ') : ''].filter(Boolean).join(' / ');
}

function _daemonRuntimeStatusLabel(data) {
  if (data.status === 'running' && data.heartbeat_online) {
    return 'Online';
  }
  if (data.status === 'running' && data.gateway_port_online && data.coordination_watch_state_stale) {
    return 'Online / sync needed';
  }
  if (data.status === 'running' && data.gateway_port_online) {
    return 'Online / syncing';
  }
  if (data.status === 'running') {
    return 'Starting';
  }
  if (data.heartbeat_freshness === 'stale') return 'Sync needed';
  return 'Offline';
}

function _daemonStartButtonLabel(data, fallbackLabel) {
  if (data && data.gateway_port_online && !data.heartbeat_online && data.coordination_watch_state_stale) {
    return 'Sync';
  }
  if (data && data.gateway_port_online && !data.heartbeat_online) return 'Sync';
  if (data && data.status === 'running' && !data.heartbeat_online) return 'Sync';
  return fallbackLabel || 'Start';
}

async function _refreshDaemonCard(runtimeId, prefix) {
  const pfx = prefix || '';
  const card      = document.getElementById(_daemonId(pfx, 'daemon-rc',        runtimeId));
  const statusEl  = document.getElementById(_daemonId(pfx, 'daemon-rc-status', runtimeId));
  const modeEl    = document.getElementById(_daemonId(pfx, 'daemon-mode',      runtimeId));
  const startBtn  = document.getElementById(_daemonId(pfx, 'daemon-rc-start',  runtimeId));
  const stopBtn   = document.getElementById(_daemonId(pfx, 'daemon-rc-stop',   runtimeId));
  const hintEl    = document.getElementById(_daemonId(pfx, 'daemon-hint',      runtimeId));
  if (!card) return;
  try {
    const resp = await window.pywebview.api.get_daemon_status(runtimeId);
    const data   = (resp && resp.ok && resp.data) || {};
    const status = data.status || 'not_running';
    const mode   = data.hermes_mode || '';
    const label  = data.hermes_label || '';
    if (modeEl) {
      modeEl.textContent = _daemonRuntimeModeLabel(runtimeId, data, mode, label);
    }
    if (status === 'running') {
      const heartbeatLive = !!data.heartbeat_online;
      const gatewayOnly = !!data.gateway_port_online && !heartbeatLive;
      card.className = gatewayOnly ? 'daemon-runtime-card daemon-degraded' : 'daemon-runtime-card daemon-running';
      if (statusEl) {
        statusEl.textContent = _daemonRuntimeStatusLabel(data);
        statusEl.className = 'daemon-runtime-status ' + (gatewayOnly ? 'status--warning' : 'status--running');
      }
      if (startBtn) {
        startBtn.textContent = gatewayOnly ? _daemonStartButtonLabel(data, 'Start') : 'Start';
        startBtn.style.display = heartbeatLive ? 'none' : '';
      }
      if (stopBtn)  stopBtn.style.display  = heartbeatLive ? '' : 'none';
    } else {
      card.className = 'daemon-runtime-card daemon-stopped';
      if (statusEl) { statusEl.textContent = _daemonRuntimeStatusLabel(data); statusEl.className = 'daemon-runtime-status status--stopped'; }
      if (startBtn) { startBtn.textContent = 'Start'; startBtn.style.display = ''; }
      if (stopBtn)  stopBtn.style.display  = 'none';
    }
    if (hintEl) {
      if (mode === 'unavailable') {
        hintEl.textContent = 'hermes not installed — run: pip install hermes-agent';
        hintEl.style.display = '';
      } else if (data.coordination_watch_state_stale) {
        hintEl.textContent = 'coordination watch state is stale; repair heartbeat will relaunch the selected-vault watch loop';
        hintEl.style.display = '';
      } else {
        hintEl.style.display = 'none';
      }
    }
  } catch (_) {
    if (statusEl) { statusEl.textContent = 'Status unavailable'; statusEl.className = 'daemon-runtime-status'; }
  }
}

function _wireDaemonCard(runtimeId, prefix) {
  const pfx      = prefix || '';
  const startBtn = document.getElementById(_daemonId(pfx, 'daemon-rc-start',  runtimeId));
  const stopBtn  = document.getElementById(_daemonId(pfx, 'daemon-rc-stop',   runtimeId));
  const statusEl = document.getElementById(_daemonId(pfx, 'daemon-rc-status', runtimeId));

  if (startBtn) startBtn.addEventListener('click', async () => {
    startBtn.disabled = true;
    if (statusEl) { statusEl.textContent = 'Requesting approval…'; statusEl.className = 'daemon-runtime-status status--starting'; }
    try {
      // Phase 1: request approval (N-2 gate — daemon spawn requires confirmation)
      const resp = await window.pywebview.api.start_runtime_daemon(runtimeId, false, '');
      if (!resp) {
        if (statusEl) { statusEl.textContent = 'No response'; statusEl.className = 'daemon-runtime-status status--stopped'; }
        startBtn.disabled = false;
        return;
      }
      if (resp.status === 'requires_approval' && resp.approval && resp.approval.approval_id) {
        // Show approval modal; on approve, execute phase 2 (spawn with approval_id)
        const approvalId = resp.approval.approval_id;
        if (statusEl) { statusEl.textContent = 'Awaiting approval…'; statusEl.className = 'daemon-runtime-status status--starting'; }
        if (typeof showApprovalModal === 'function') {
          showApprovalModal(resp.approval, async (resolvedData) => {
            if ((resolvedData || {}).decision === 'approved') {
              if (statusEl) { statusEl.textContent = 'Starting…'; statusEl.className = 'daemon-runtime-status status--starting'; }
              try {
                // Phase 2: spawn with confirmed approval_id
                const execResp = await window.pywebview.api.start_runtime_daemon(runtimeId, false, approvalId);
                if (!execResp || !execResp.ok) {
                  if (statusEl) { statusEl.textContent = (execResp && execResp.error && execResp.error.message) || 'Start failed'; statusEl.className = 'daemon-runtime-status status--stopped'; }
                } else {
                  await _refreshDaemonCard(runtimeId, pfx);
                }
              } catch (err2) {
                if (statusEl) { statusEl.textContent = 'Error: ' + escHtml(err2.message || err2); statusEl.className = 'daemon-runtime-status status--stopped'; }
              }
            } else {
              // Rejected or cancelled
              if (statusEl) { statusEl.textContent = 'Cancelled'; statusEl.className = 'daemon-runtime-status status--stopped'; }
            }
            startBtn.disabled = false;
          });
        } else {
          // Fallback if ApprovalModal not available
          if (statusEl) { statusEl.textContent = 'Approval required — use Approval Center'; statusEl.className = 'daemon-runtime-status status--stopped'; }
          startBtn.disabled = false;
        }
        return; // button re-enabled by callback
      }
      if (!resp.ok) {
        if (statusEl) { statusEl.textContent = (resp.error && resp.error.message) || 'Start failed'; statusEl.className = 'daemon-runtime-status status--stopped'; }
      } else {
        await _refreshDaemonCard(runtimeId, pfx);
      }
    } catch (err) {
      if (statusEl) { statusEl.textContent = 'Error: ' + escHtml(err.message || err); statusEl.className = 'daemon-runtime-status status--stopped'; }
    }
    startBtn.disabled = false;
  });

  if (stopBtn) stopBtn.addEventListener('click', async () => {
    stopBtn.disabled = true;
    if (statusEl) { statusEl.textContent = 'Requesting stop approval…'; statusEl.className = 'daemon-runtime-status status--starting'; }
    try {
      const resp = await window.pywebview.api.stop_runtime_daemon(runtimeId, '');
      if (resp && resp.status === 'requires_approval' && resp.approval && resp.approval.approval_id) {
        const approvalId = resp.approval.approval_id;
        if (statusEl) { statusEl.textContent = 'Awaiting stop approval…'; statusEl.className = 'daemon-runtime-status status--starting'; }
        if (typeof showApprovalModal === 'function') {
          showApprovalModal(resp.approval, async (resolvedData) => {
            if ((resolvedData || {}).decision === 'approved') {
              if (statusEl) { statusEl.textContent = 'Stopping…'; statusEl.className = 'daemon-runtime-status status--starting'; }
              try {
                const execResp = await window.pywebview.api.stop_runtime_daemon(runtimeId, approvalId);
                if (!execResp || !execResp.ok) {
                  if (statusEl) { statusEl.textContent = (execResp && execResp.error && execResp.error.message) || 'Stop failed'; statusEl.className = 'daemon-runtime-status status--stopped'; }
                } else {
                  await _refreshDaemonCard(runtimeId, pfx);
                }
              } catch (err2) {
                if (statusEl) { statusEl.textContent = 'Error: ' + escHtml(err2.message || err2); statusEl.className = 'daemon-runtime-status status--stopped'; }
              }
            } else {
              if (statusEl) { statusEl.textContent = 'Stop cancelled'; statusEl.className = 'daemon-runtime-status status--running'; }
            }
            stopBtn.disabled = false;
          });
          return;
        }
        if (statusEl) { statusEl.textContent = 'Stop approval required — use Approval Center'; statusEl.className = 'daemon-runtime-status status--stopped'; }
        stopBtn.disabled = false;
        return;
      }
      if (!resp || !resp.ok) {
        if (statusEl) { statusEl.textContent = (resp && resp.error && resp.error.message) || 'Stop failed'; statusEl.className = 'daemon-runtime-status status--stopped'; }
      } else {
        await _refreshDaemonCard(runtimeId, pfx);
      }
    } catch (err) {
      if (statusEl) { statusEl.textContent = 'Error: ' + escHtml(err.message || err); statusEl.className = 'daemon-runtime-status'; }
    }
    stopBtn.disabled = false;
  });

  _refreshDaemonCard(runtimeId, pfx);
}

function _buildDaemonSection(containerId, prefix) {
  const container = document.getElementById(containerId);
  if (!container) return;
  const pfx = prefix || '';
  const section = document.createElement('div');
  section.className = 'daemon-section';
  section.innerHTML =
    `<div class="daemon-section-title">Runtime Services</div>` +
    `<div class="daemon-card-grid">` +
    _buildDaemonCardHtml('hermes',   pfx) +
    _buildDaemonCardHtml('openclaw', pfx) +
    `</div>`;
  container.appendChild(section);
  _wireDaemonCard('hermes',   pfx);
  _wireDaemonCard('openclaw', pfx);
}

function _gatewayControlsId(prefix, name, runtimeId, componentId) {
  const parts = [prefix || 'runtime-gateway', name, runtimeId, componentId].filter(Boolean);
  return parts.join('-');
}

function _startupModeLabel(mode) {
  const value = String(mode || 'manual');
  if (value === 'chaseos_start') return 'Start with ChaseOS';
  if (value === 'system_start') return 'Start with Windows';
  return 'Manual';
}

function _componentStatusText(component) {
  const status = component.status || {};
  if (status.running) {
    if (component.component_id === 'gateway') {
      const port = status.gateway_port_listening ? ` on port ${status.gateway_port_listening}` : '';
      return `Live${port}`;
    }
    if (status.heartbeat_online) return `Heartbeat ${status.heartbeat_freshness || 'live'}`;
    if (status.pid) return `Process pid ${status.pid}`;
    return 'Running';
  }
  if (component.component_id === 'gateway' && component.system_start_registered) {
    return 'Registered for Windows startup';
  }
  return 'Stopped';
}

function _componentStatusClass(component) {
  const status = component.status || {};
  if (status.running) return 'status--running';
  if (component.component_id === 'gateway' && component.system_start_registered) return 'status--warning';
  return 'status--stopped';
}

function _renderRuntimeGatewayComponent(runtime, component, prefix) {
  const runtimeId = runtime.runtime_id || '';
  const componentId = component.component_id || '';
  const statusCls = _componentStatusClass(component);
  const statusText = _componentStatusText(component);
  const modes = component.startup_modes || ['manual', 'chaseos_start'];
  const selectId = _gatewayControlsId(prefix, 'mode', runtimeId, componentId);
  const launchId = _gatewayControlsId(prefix, 'launch', runtimeId, componentId);
  const stopId = _gatewayControlsId(prefix, 'stop', runtimeId, componentId);
  const statusId = _gatewayControlsId(prefix, 'status', runtimeId, componentId);
  const modeHtml = modes.map(mode => (
    `<option value="${escAttr(mode)}"${mode === component.startup_mode ? ' selected' : ''}>${escHtml(_startupModeLabel(mode))}</option>`
  )).join('');
  const launcherHint = componentId === 'gateway' && component.status && component.status.target_path
    ? `<span>${escHtml(component.status.target_path)}</span>`
    : '';
  return `<div class="runtime-gateway-component" data-runtime-id="${escAttr(runtimeId)}" data-component-id="${escAttr(componentId)}">
    <div class="runtime-gateway-component-main">
      <div>
        <div class="runtime-gateway-component-name">${escHtml(component.component_label || componentId)}</div>
        <div class="runtime-gateway-component-path">${launcherHint}</div>
      </div>
      <div id="${statusId}" class="daemon-runtime-status ${statusCls}">${escHtml(statusText)}</div>
    </div>
    <div class="runtime-gateway-component-actions">
      <select id="${selectId}" class="runtime-gateway-mode-select" aria-label="${escAttr(component.component_label || componentId)} startup mode">
        ${modeHtml}
      </select>
      <button id="${launchId}" class="daemon-btn daemon-btn--start" type="button">Launch</button>
      <button id="${stopId}" class="daemon-btn daemon-btn--stop" type="button">Stop</button>
    </div>
  </div>`;
}

function _renderHermesGatewayConfigControls(config, prefix) {
  const status = config.status && typeof config.status === 'object' ? config.status : {};
  const binding = config.chaseos_operator_binding || {};
  const statusText = status.gateway_ready === true
    ? 'Gateway config ready'
    : status.allowlist_status
      ? `Allowlist ${status.allowlist_status}`
      : 'Allowlist not checked';
  const bindingText = binding.available
    ? 'ChaseOS operator binding detected'
    : 'ChaseOS operator binding missing';
  const checkId = _gatewayControlsId(prefix, 'hermes-config-check', 'hermes', 'gateway');
  const addId = _gatewayControlsId(prefix, 'hermes-config-add-operator', 'hermes', 'gateway');
  const inputId = _gatewayControlsId(prefix, 'hermes-config-allowed-users', 'hermes', 'gateway');
  const setId = _gatewayControlsId(prefix, 'hermes-config-set-users', 'hermes', 'gateway');
  const statusId = _gatewayControlsId(prefix, 'hermes-config-status', 'hermes', 'gateway');
  return `<div class="runtime-gateway-component hermes-gateway-config-control">
    <div class="runtime-gateway-component-main">
      <div>
        <div class="runtime-gateway-component-name">Hermes Gateway Allowlist</div>
        <div class="runtime-gateway-component-path">${escHtml(bindingText)}</div>
      </div>
      <div id="${statusId}" class="daemon-runtime-status status--warning">${escHtml(statusText)}</div>
    </div>
    <div class="runtime-gateway-component-actions">
      <button id="${checkId}" class="daemon-btn" type="button">Check</button>
      <button id="${addId}" class="daemon-btn daemon-btn--start" type="button">Add ChaseOS Operator</button>
      <input id="${inputId}" class="runtime-gateway-mode-select" type="text" placeholder="Allowed IDs" aria-label="Hermes gateway allowed IDs">
      <button id="${setId}" class="daemon-btn" type="button">Set IDs</button>
    </div>
  </div>`;
}

function _renderRuntimeGatewayControls(data, prefix) {
  const runtimes = data.runtimes || [];
  const hermesConfig = data.hermes_gateway_config || {};
  if (!runtimes.length) {
    return `<div class="runtime-gateway-empty">No Hermes or OpenClaw lifecycle records found.</div>`;
  }
  return `<div class="runtime-gateway-control-grid">` +
    runtimes.map(runtime => {
      const components = runtime.components || [];
      return `<div class="daemon-runtime-card runtime-gateway-card">
        <div class="daemon-runtime-card-header">
          <div class="daemon-runtime-icon">${escHtml(runtime.runtime_id === 'openclaw' ? 'O' : 'H')}</div>
          <div>
            <div class="daemon-runtime-name">${escHtml(runtime.runtime_name || runtime.runtime_id)}</div>
            <div class="daemon-runtime-mode">${escHtml([runtime.platform, runtime.lifecycle_mode].filter(Boolean).join(' / '))}</div>
          </div>
        </div>
        <div class="runtime-gateway-components">
          ${components.map(component => _renderRuntimeGatewayComponent(runtime, component, prefix)).join('')}
          ${runtime.runtime_id === 'hermes' ? _renderHermesGatewayConfigControls(hermesConfig, prefix) : ''}
        </div>
      </div>`;
    }).join('') +
    `</div>`;
}

async function _loadRuntimeGatewayControls(containerId, prefix) {
  const container = document.getElementById(containerId);
  if (!container || !window.pywebview || !window.pywebview.api || !window.pywebview.api.get_runtime_gateway_controls) return;
  container.innerHTML = panelLoading();
  try {
    const resp = await window.pywebview.api.get_runtime_gateway_controls();
    if (!resp || !resp.ok) {
      container.innerHTML = `<div class="runtime-gateway-empty">${escHtml((resp && resp.error && resp.error.message) || 'Runtime gateway controls unavailable')}</div>`;
      return;
    }
    const data = resp.data || {};
    container.innerHTML = _renderRuntimeGatewayControls(data, prefix || 'settings');
    _wireRuntimeGatewayControls(containerId, prefix || 'settings');
  } catch (err) {
    container.innerHTML = `<div class="runtime-gateway-empty">${escHtml(err.message || err)}</div>`;
  }
}

function _wireRuntimeGatewayControls(containerId, prefix) {
  const container = document.getElementById(containerId);
  if (!container) return;
  container.querySelectorAll('.runtime-gateway-component').forEach(row => {
    const runtimeId = row.dataset.runtimeId || '';
    const componentId = row.dataset.componentId || '';
    const statusEl = document.getElementById(_gatewayControlsId(prefix, 'status', runtimeId, componentId));
    const launchBtn = document.getElementById(_gatewayControlsId(prefix, 'launch', runtimeId, componentId));
    const stopBtn = document.getElementById(_gatewayControlsId(prefix, 'stop', runtimeId, componentId));
    const modeSelect = document.getElementById(_gatewayControlsId(prefix, 'mode', runtimeId, componentId));

    if (launchBtn) launchBtn.addEventListener('click', async () => {
      launchBtn.disabled = true;
      if (statusEl) { statusEl.textContent = 'Launching...'; statusEl.className = 'daemon-runtime-status status--starting'; }
      try {
        const resp = await window.pywebview.api.launch_runtime_component(runtimeId, componentId);
        if (!resp || !resp.ok) {
          if (statusEl) { statusEl.textContent = (resp && resp.error && resp.error.message) || 'Launch failed'; statusEl.className = 'daemon-runtime-status status--stopped'; }
        } else {
          setStatus(`${runtimeId} ${componentId} launch requested.`, 'observe');
          await _loadRuntimeGatewayControls(containerId, prefix);
          if (typeof _refreshDaemonCard === 'function') _refreshDaemonCard(runtimeId, 'settings');
        }
      } catch (err) {
        if (statusEl) { statusEl.textContent = 'Error: ' + (err.message || err); statusEl.className = 'daemon-runtime-status status--stopped'; }
      }
      launchBtn.disabled = false;
    });

    if (stopBtn) stopBtn.addEventListener('click', async () => {
      stopBtn.disabled = true;
      if (statusEl) { statusEl.textContent = 'Stopping...'; statusEl.className = 'daemon-runtime-status status--starting'; }
      try {
        const resp = await window.pywebview.api.stop_runtime_component(runtimeId, componentId);
        if (!resp || !resp.ok) {
          if (statusEl) { statusEl.textContent = (resp && resp.error && resp.error.message) || 'Stop failed'; statusEl.className = 'daemon-runtime-status status--warning'; }
        } else {
          setStatus(`${runtimeId} ${componentId} stop requested.`, 'observe');
          await _loadRuntimeGatewayControls(containerId, prefix);
        }
      } catch (err) {
        if (statusEl) { statusEl.textContent = 'Error: ' + (err.message || err); statusEl.className = 'daemon-runtime-status status--warning'; }
      }
      stopBtn.disabled = false;
    });

    if (modeSelect) modeSelect.addEventListener('change', async () => {
      modeSelect.disabled = true;
      const mode = modeSelect.value || 'manual';
      if (statusEl) { statusEl.textContent = `Setting ${_startupModeLabel(mode)}...`; statusEl.className = 'daemon-runtime-status status--starting'; }
      try {
        const applySystemStart = componentId === 'gateway';
        const resp = await window.pywebview.api.set_runtime_component_startup_mode(runtimeId, componentId, mode, applySystemStart);
        if (!resp || !resp.ok) {
          if (statusEl) { statusEl.textContent = (resp && resp.error && resp.error.message) || 'Mode update failed'; statusEl.className = 'daemon-runtime-status status--warning'; }
        } else {
          setStatus(`${runtimeId} ${componentId} mode: ${_startupModeLabel(mode)}.`, 'observe');
          await _loadRuntimeGatewayControls(containerId, prefix);
        }
      } catch (err) {
        if (statusEl) { statusEl.textContent = 'Error: ' + (err.message || err); statusEl.className = 'daemon-runtime-status status--warning'; }
      }
      modeSelect.disabled = false;
    });
  });

  const checkBtn = document.getElementById(_gatewayControlsId(prefix, 'hermes-config-check', 'hermes', 'gateway'));
  const addBtn = document.getElementById(_gatewayControlsId(prefix, 'hermes-config-add-operator', 'hermes', 'gateway'));
  const input = document.getElementById(_gatewayControlsId(prefix, 'hermes-config-allowed-users', 'hermes', 'gateway'));
  const setBtn = document.getElementById(_gatewayControlsId(prefix, 'hermes-config-set-users', 'hermes', 'gateway'));
  const configStatus = document.getElementById(_gatewayControlsId(prefix, 'hermes-config-status', 'hermes', 'gateway'));

  async function runHermesConfigAction(action, allowedUsers) {
    if (!window.pywebview || !window.pywebview.api || !window.pywebview.api.apply_hermes_gateway_config_control) return;
    if (configStatus) { configStatus.textContent = 'Working...'; configStatus.className = 'daemon-runtime-status status--starting'; }
    const resp = await window.pywebview.api.apply_hermes_gateway_config_control(action, allowedUsers || '', false);
    if (!resp || !resp.ok) {
      if (configStatus) {
        configStatus.textContent = (resp && resp.error && resp.error.message) || 'Config action failed';
        configStatus.className = 'daemon-runtime-status status--warning';
      }
      return;
    }
    const data = resp.data || {};
    const status = data.status || data;
    const ready = status.gateway_ready === true;
    if (configStatus) {
      configStatus.textContent = ready ? 'Gateway config ready' : `Allowlist ${status.allowlist_status || 'updated'}`;
      configStatus.className = `daemon-runtime-status ${ready ? 'status--running' : 'status--warning'}`;
    }
    setStatus('Hermes gateway allowlist action recorded.', 'observe');
  }

  if (checkBtn) checkBtn.addEventListener('click', async () => {
    checkBtn.disabled = true;
    try { await runHermesConfigAction('check_status', ''); } catch (err) {
      if (configStatus) { configStatus.textContent = 'Error: ' + (err.message || err); configStatus.className = 'daemon-runtime-status status--warning'; }
    }
    checkBtn.disabled = false;
  });

  if (addBtn) addBtn.addEventListener('click', async () => {
    addBtn.disabled = true;
    try { await runHermesConfigAction('add_chaseos_operator', ''); } catch (err) {
      if (configStatus) { configStatus.textContent = 'Error: ' + (err.message || err); configStatus.className = 'daemon-runtime-status status--warning'; }
    }
    addBtn.disabled = false;
  });

  if (setBtn) setBtn.addEventListener('click', async () => {
    setBtn.disabled = true;
    try { await runHermesConfigAction('set_gateway_allowed_users', input ? input.value : ''); } catch (err) {
      if (configStatus) { configStatus.textContent = 'Error: ' + (err.message || err); configStatus.className = 'daemon-runtime-status status--warning'; }
    }
    setBtn.disabled = false;
  });
}

async function _applyRuntimeGatewayControlsOnChaseOSStart() {
  if (!window.pywebview || !window.pywebview.api || !window.pywebview.api.apply_runtime_chaseos_start_preferences) return;
  if (window.__runtimeGatewayChaseOSStartApplied) return;
  window.__runtimeGatewayChaseOSStartApplied = true;
  try {
    const resp = await window.pywebview.api.apply_runtime_chaseos_start_preferences(true);
    const data = (resp && resp.ok && resp.data) || {};
    if (data.launch_count > 0) {
      setStatus(`Runtime startup ready: ${data.launch_count} launch request${data.launch_count === 1 ? '' : 's'} available.`, 'observe');
    }
  } catch (_) {}
}

// ── Graph search ──────────────────────────────────────────────────────────────
function dashboardMetric(panel, primaryKey, fallbackKey) {
  const source = panel || {};
  const value = source[primaryKey];
  if (value !== undefined && value !== null) return value;
  const fallback = source[fallbackKey];
  if (fallback !== undefined && fallback !== null) return fallback;
  return 0;
}

function studioHomeMetric(label, value) {
  return `<div class="studio-home-metric">` +
    `<span>${escHtml(label)}</span>` +
    `<strong>${escHtml(String(value))}</strong>` +
    `</div>`;
}

function studioEvidenceRow(label, path) {
  return `<div class="studio-home-evidence-row">` +
    `<span>${escHtml(label)}</span>` +
    `<strong>${escHtml(path || 'missing')}</strong>` +
    `</div>`;
}

function ventureopsHomePanel(panel) {
  const summary = (panel || {}).summary || {};
  const guide = (panel || {}).operator_guide || {};
  const usecase = (panel || {}).real_world_test_usecase || {};
  const authority = (panel || {}).authority || {};
  const steps = (panel || {}).rehearsal_steps || [];
  const checks = (panel || {}).hardening_checks || [];
  const commands = (panel || {}).safe_commands || [];
  const missing = ((panel || {}).real_world_missing_requirements || []).slice(0, 8);
  const entrypoints = (panel || {}).studio_entrypoints || [];
  return `<section class="studio-home-lanes studio-home-ventureops" data-surface="${escAttr((panel || {}).surface || '')}">` +
    `<div class="studio-home-section-title">${escHtml((panel || {}).headline || 'VentureOps real-use hardening')}</div>` +
    `<div class="studio-home-status">${escHtml((panel || {}).status || 'unknown')}</div>` +
    `<div class="studio-home-action-summary">` +
    studioHomeMetric('Local implementation', summary.feature_implementation_complete ? 'complete' : 'open') +
    studioHomeMetric('Tests need evidence', summary.operator_evidence_required_for_tests ? 'yes' : 'no') +
    studioHomeMetric('Real delivery', summary.real_world_delivery_revenue_complete ? 'complete' : 'blocked') +
    studioHomeMetric('Revenue safe', summary.safe_to_mark_real_world_delivery_revenue_complete ? 'yes' : 'no') +
    studioHomeMetric('Missing facts', summary.real_world_missing_requirement_count || 0) +
    studioHomeMetric('Checks', `${summary.hardening_checks_passed || 0}/${summary.hardening_check_count || 0}`) +
    `</div>` +
    `<div class="studio-home-lane-grid">` +
    entrypoints.map(entry =>
      `<div class="studio-home-lane">` +
      `<div class="studio-home-lane-title">${escHtml(entry.label || entry.id || 'Studio entrypoint')}</div>` +
      `<div class="studio-home-lane-detail">${escHtml(entry.url || '')}</div>` +
      `<code class="studio-home-lane-command">${escHtml(entry.command || '')}</code>` +
      `<code class="studio-home-lane-command">${escHtml(entry.dry_run_command || '')}</code>` +
      `</div>`
    ).join('') +
    `</div>` +
    `<div class="studio-home-lane-grid">` +
    checks.map(check =>
      `<div class="studio-home-lane">` +
      `<div class="studio-home-lane-title">${escHtml(check.id || 'check')}</div>` +
      `<div class="studio-home-lane-status">${escHtml(check.ok ? 'ok' : 'blocked')}</div>` +
      `<div class="studio-home-lane-detail">${escHtml(check.detail || '')}</div>` +
      `</div>`
    ).join('') +
    `</div>` +
    `<div class="studio-home-preview-grid">` +
    steps.map(step =>
      `<div class="studio-home-preview-row">` +
      `<strong>${escHtml(step.id || 'step')}</strong>` +
      `<span>${escHtml(step.operator_action || '')}</span>` +
      `<code>${escHtml(step.expected_result || '')}</code>` +
      `</div>`
    ).join('') +
    `</div>` +
    `<section class="studio-home-evidence">` +
    studioEvidenceRow('Guide', `${guide.path || 'missing'} exists=${guide.exists ? 'true' : 'false'}`) +
    studioEvidenceRow('Use case', usecase.title || 'AI Runtime Governance Audit') +
    studioEvidenceRow('Authority', `external=${authority.external_send_allowed ? 'allowed' : 'blocked'} provider=${authority.provider_calls_allowed ? 'allowed' : 'blocked'} payment=${authority.payment_mutation_allowed ? 'allowed' : 'blocked'} revenue=${authority.revenue_claim_allowed ? 'allowed' : 'blocked'}`) +
    `</section>` +
    `<div class="studio-home-preview-grid">` +
    commands.map(command => `<div class="studio-home-preview-row"><strong>Safe command</strong><code>${escHtml(command)}</code></div>`).join('') +
    missing.map(item => `<div class="studio-home-preview-row"><strong>Missing fact</strong><span>${escHtml(String(item))}</span></div>`).join('') +
    `</div>` +
    `</section>`;
}

async function runStudioActionCenterPreviews() {
  const button = document.getElementById('studio-action-center-preview-btn');
  const result = document.getElementById('studio-action-center-preview-result');
  if (!button || !result) return;
  button.disabled = true;
  result.textContent = 'Running safe previews...';
  try {
    const resp = await window.pywebview.api.get_action_center_preview_runner(true);
    if (!resp.ok) {
      result.textContent = (resp.error && resp.error.message) || 'Preview runner failed';
      return;
    }
    result.innerHTML = renderStudioActionCenterPreviewResult(resp.data || {});
  } catch (err) {
    result.textContent = err.message || 'Preview runner failed';
  } finally {
    button.disabled = false;
  }
}

function renderStudioActionCenterPreviewResult(data) {
  const lanes = data.lanes || [];
  const rows = lanes.map(lane => {
    const preview = lane.preview_result || {};
    const summary = preview.summary || {};
    const state = lane.runner_allowed
      ? (preview.json_parse_ok ? (preview.preview_ok ? 'ready' : 'blocked preview') : 'not run')
      : (lane.not_runnable_reason || 'not runnable');
    return `<div class="studio-home-preview-row">` +
      `<strong>${escHtml(lane.label || lane.lane_id || 'lane')}</strong>` +
      `<span>${escHtml(state)}</span>` +
      `<code>${escHtml(summary.status || summary.surface || lane.not_runnable_reason || '')}</code>` +
      `</div>`;
  }).join('');
  return `<div class="studio-home-preview-summary">` +
    studioHomeMetric('Preview commands run', data.preview_executed_count || 0) +
    studioHomeMetric('JSON parsed', data.preview_json_parse_count || 0) +
    studioHomeMetric('Blocked previews', data.blocked_preview_count || 0) +
    `</div>` +
    `<div class="studio-home-preview-grid">${rows}</div>`;
}

async function loadAppLauncher() {
  const body = document.getElementById('app-launcher-body');
  const summary = document.getElementById('app-launcher-summary');
  if (!body) return;
  renderAppLauncher({});
  if (summary) summary.innerHTML = 'Studio surface map available while local app status is checked.';
  try {
    const resp = await window.pywebview.api.get_app_launcher();
    if (!resp || !resp.ok) {
      body.innerHTML = `<div style="color:var(--ts-disputed);font-size:12px">${escHtml((resp && resp.error && resp.error.message) || 'Error')}</div>`;
      return;
    }
    renderAppLauncher(resp.data || {});
    if (summary) {
      const data = resp.data || {};
      summary.innerHTML = `${escHtml(data.app_count || 0)} registered apps - ${escHtml(data.support_port_count || 0)} local connections - status checked locally`;
    }
  } catch (err) {
    body.innerHTML = `<div style="color:var(--ts-disputed);font-size:12px">${escHtml(err.message)}</div>`;
  }
}

function renderAppLauncher(data) {
  const body = document.getElementById('app-launcher-body');
  if (!body) return;
  const apps = data.apps || [];
  body.innerHTML = apps.map(app => appLauncherCard(app)).join('') || appLauncherFallbackCatalog(data);
  body.querySelectorAll('.app-launcher-card').forEach(card => {
    card.addEventListener('click', evt => {
      if (evt.target.closest('a,button,details,summary')) return;
      const app = apps.find(item => String(item.id || '') === String(card.dataset.appId || '')) || {};
      const status = app.runtime_status || {};
      renderObjectInspectorProductContext({
        id: app.id || card.dataset.appId || 'studio-surface',
        label: app.title || app.id || 'Studio surface',
        type: 'Studio Surface',
        kicker: 'Selected Surface',
        panel: 'app-launcher',
        status: status.state || (app.read_only ? 'inspect' : 'confirmation-gated') || 'unknown',
        ownerLabel: 'Family',
        owner: app.family || 'Governance / Advanced',
        timeLabel: 'Authority',
        time: app.write_capable ? 'confirmation-gated' : 'inspect',
        ref: app.default_url || app.id || '',
        openLabel: 'Open Launcher',
        note: 'App Launcher is discovery-only. Opening a surface is direct-safe; launching, starting, or executing remains governed by each owning surface.',
      });
    });
  });
  wireOperatorSurfaceCards(body, 'app-launcher', 'App Launcher');
}

