function appLauncherCard(app) {
  const status = app.runtime_status || {};
  const actions = app.actions || [];
  const byId = Object.fromEntries(actions.map(action => [action.id, action]));
  const open = byId.open || {};
  const start = byId.start_request || {};
  const health = byId.health || {};
  const statusText = productLabel(status.state || 'unknown', 'Unknown');
  const checkedText = status.last_checked ? productizeUiCopy(status.last_checked) : 'Not checked';
  const statusNote = productizeUiCopy(status.reason || status.detail || 'Status checked locally.');
  return `<article class="app-launcher-card" data-app-id="${escAttr(app.id || '')}">` +
    `<div class="panel-kicker">${escHtml(app.read_only ? 'AVAILABLE' : 'CONFIRMATION REQUIRED')}</div>` +
    `<h3>${escHtml(app.title || app.id || 'Studio app')}</h3>` +
    `<p>${escHtml(productizeUiCopy(app.summary || 'Open this Studio surface from the local shell.'))}</p>` +
    `<div class="app-launcher-actions">` +
      `<a class="btn-primary" href="${escAttr(open.href || app.default_url || '#')}">Open</a>` +
      `<button class="btn-secondary" type="button" data-action="start-request" data-confirmation-required="${escAttr(String(start.requires_confirmation !== false))}" data-approved-backend-contract-only="${escAttr(String(start.approved_backend_contract_only !== false))}" data-executes-in-launcher="${escAttr(String(!!start.executes_in_launcher))}">Prepare</button>` +
      `<a class="btn-secondary" href="${escAttr(health.href || status.health_url || '#')}">Check</a>` +
      `<details class="app-launcher-authority"><summary class="btn-secondary">Details</summary><div>${escHtml(app.write_capable ? 'Changes require confirmation.' : 'Available for inspection.')}</div></details>` +
    `</div>` +
    `<div class="app-launcher-facts">` +
      `<div><span>Port</span><strong>${escHtml(app.default_port || 'Local')}</strong></div>` +
      `<div><span>Status</span><strong>${escHtml(statusText)}</strong></div>` +
      `<div><span>Checked</span><strong>${escHtml(checkedText)}</strong></div>` +
      `<div><span>Access</span><strong>${escHtml(app.write_capable ? 'Confirmation required' : 'Available')}</strong></div>` +
    `</div>` +
    `<details class="app-launcher-debug"><summary>Status details</summary><div>${escHtml(statusNote)}</div></details>` +
  `</article>`;
}

