function renderBrowserRuntimePanel(data) {
  const body = document.getElementById('browser-runtime-body');
  const status = document.getElementById('browser-runtime-status');
  if (!body) return;
  const summary = data.summary || {};
  const readiness = data.readiness || {};
  const launcherUpdate = data.launcher_update || {};
  const updateHtml = _renderLauncherUpdateSection(launcherUpdate);
  const authority = data.authority || {};
  const remaining = data.remaining_passes || [];
  const dependencies = data.external_dependencies || [];
  const panels = data.panels || [];
  const evidence = data.current_evidence || {};
  const blocked = data.blocked_reasons || [];
  if (status) status.textContent = summary.production_feature_done ? 'Ready' : 'Needs setup';

  const readinessLabel = summary.production_feature_done
    ? 'Ready'
    : (summary.bounded_mvp_done ? 'Local ready' : 'Needs setup');
  const cards = [
    { title: 'Readiness', value: readinessLabel, sub: 'browser lane' },
    { title: 'Local capability', value: summary.bounded_mvp_done ? 'Ready' : 'Blocked', sub: 'bounded path' },
    { title: 'Product lane', value: summary.production_feature_done ? 'Ready' : 'Blocked', sub: `${summary.blocker_count || blocked.length || 0} blockers` },
    { title: 'Remaining work', value: `${summary.remaining_major_passes_min || 0}-${summary.remaining_major_passes_max || 0}`, sub: 'groups' },
  ];

  body.innerHTML =
    operatorSurfaceOverview(
      'Browser runtime readiness',
      'Review browser automation capability without granting page control, connector calls, provider calls, or external delivery.',
      [
        { label: 'local capability', value: summary.bounded_mvp_done ? 'Ready' : 'Blocked', note: 'bounded path' },
        { label: 'product lane', value: summary.production_feature_done ? 'Ready' : 'Blocked', note: `${summary.blocker_count || blocked.length || 0} blockers` },
        { label: 'remaining work', value: `${summary.remaining_major_passes_min || 0}-${summary.remaining_major_passes_max || 0}`, note: 'groups' },
      ],
    ) +
    operatorSurfaceCards([
      {
        id: 'browser-runtime-authority',
        title: 'Safety Boundary',
        status: authority.launches_browser ? 'Configured' : 'Blocked',
        body: 'Browser launch, page control, connector calls, and model calls are separate governed actions.',
        meta: ['Launch approval', 'Connector approval', 'Model approval'],
      },
      {
        id: 'browser-runtime-evidence',
        title: 'Reference Records',
        status: Object.keys(evidence).length ? 'Available' : 'Waiting',
        body: 'Current readiness records and surface coverage are visible here for inspection.',
        meta: ['Readiness', 'Coverage', 'Dependencies'],
      },
      {
        id: 'browser-runtime-next',
        title: 'Next Safe Step',
        status: readiness.next_recommended_pass ? 'Named' : 'Review',
        body: productLabel(readiness.next_recommended_pass || 'Select a governed browser lane before any automation is allowed.'),
        meta: ['Plan', 'Approval', 'Audit'],
      },
    ]) +
    '<div class="browser-runtime-summary">' +
    cards.map(card =>
      `<div class="dash-card">` +
      `<div class="dash-card-title">${escHtml(card.title)}</div>` +
      `<div class="dash-card-value browser-runtime-card-value">${escHtml(String(card.value))}</div>` +
      `<div class="dash-card-sub">${escHtml(card.sub)}</div>` +
      `</div>`
    ).join('') +
    '</div>' +
    _browserRuntimeSection('Authority', [
      ['Inspection mode', authority.read_only],
      ['Browser launch', authority.launches_browser],
      ['CDP connect', authority.connects_cdp],
      ['MCP invoke', authority.invokes_mcp],
      ['Browser tool live', authority.runs_browser_use_cli_live],
      ['Skill activation', authority.activates_skills],
      ['Model calls', authority.provider_calls_allowed],
      ['Canonical mutation', authority.canonical_mutation_allowed],
    ]) +
    _browserRuntimeList('Blockers', blocked.map(item => ({ title: productLabel(item), sub: '' }))) +
    _browserRuntimeList('Remaining Steps', remaining.map(item => ({
      title: productLabel(item.label || item.pass_group || item.id || 'step'),
      sub: item.status || item.reason || item.description || '',
    }))) +
    _browserRuntimeList('External Dependencies', dependencies.map(item => ({
      title: productLabel(item.label || item.id || item.dependency || 'dependency'),
      sub: item.status || item.blocker || item.reason || '',
    }))) +
    _browserRuntimeList('Surface Coverage', panels.map(item => ({
      title: productLabel(item.label || item.panel_id),
      sub: `${item.ready_for_studio_mount ? 'Ready' : 'Blocked'} - ${item.purpose || ''}`,
    }))) +
    _browserRuntimeList('Reference Records', Object.entries(evidence).map(([key, value]) => ({
      title: productLabel(key),
      sub: value.exists ? 'Record available' : 'Record missing',
      ref: value.path || key,
    }))) +
    `<div class="browser-runtime-next">Next: ${escHtml(productLabel(readiness.next_recommended_pass || 'Review browser readiness'))}</div>`;

  wireOperatorSurfaceCards(body, 'browser-runtime', 'Advanced Runtime');
  body.querySelectorAll('.browser-runtime-list-item').forEach(item => {
    item.addEventListener('click', () => {
      renderObjectInspectorProductContext({
        id: item.dataset.govRef || item.dataset.govTitle || 'browser-runtime-item',
        label: item.dataset.govTitle || 'Browser runtime item',
        type: item.dataset.govType || 'Browser Runtime Evidence',
        kicker: 'Selected Browser Runtime Item',
        panel: 'browser-runtime',
        status: item.dataset.govStatus || 'read-only',
        ownerLabel: 'Surface',
        owner: 'Browser Runtime',
        timeLabel: 'Authority',
        time: 'no browser control',
        ref: item.dataset.govRef || item.dataset.govTitle || '',
        openLabel: 'Open Browser Runtime',
        note: 'Browser runtime records are inspectable only. Browser launch, page control, connector calls, and model calls remain blocked unless a separate governed lane proves them.',
      });
    });
  });
}

function _browserRuntimeValue(value) {
  if (value === true) return 'On';
  if (value === false) return 'Off';
  return productLabel(value, 'Unknown');
}

function _browserRuntimeSection(title, rows) {
  return `<div class="browser-runtime-section"><h3>${escHtml(title)}</h3>` +
    rows.map(([label, value]) =>
      `<div class="browser-runtime-row"><span>${escHtml(label)}</span><strong>${escHtml(_browserRuntimeValue(value))}</strong></div>`
    ).join('') +
    '</div>';
}

function _browserRuntimeList(title, items) {
  if (!items.length) return '';
  return `<div class="browser-runtime-section"><h3>${escHtml(title)}</h3><div class="browser-runtime-list">` +
    items.map(item =>
      `<div class="browser-runtime-list-item" data-gov-type="${escAttr(title)}" data-gov-title="${escAttr(item.title || '')}" data-gov-status="${escAttr(item.sub || 'read-only')}" data-gov-ref="${escAttr(item.ref || item.path || item.title || '')}">` +
      `<div>${escHtml(productLabel(item.title || '', ''))}</div>` +
      `<span>${escHtml(productizeUiCopy(item.sub || ''))}</span>` +
      `</div>`
    ).join('') +
    '</div></div>';
}

