      renderObjectInspectorProductContext({
        id: providerId,
        label: (pill.querySelector('.settings-info-pill-label') || {}).textContent || providerId,
        type: 'Provider Config',
        kicker: 'Selected Provider',
        panel: 'settings',
        status: state,
        ownerLabel: 'Surface',
        owner: 'Settings',
        timeLabel: 'Authority',
        time: 'secrets hidden',
        ref: providerId,
        openLabel: 'Open Settings',
        note: 'Settings displays provider/config posture only. Raw credentials are hidden; provider switching, live probes, host mutation, and config writes stay governed by existing lanes.',
      });
