// ── Chat adapter selector ─────────────────────────────────────────────────────

function initChatAdapterSelector() {
  document.querySelectorAll('#chat-adapter-selector .adapter-card').forEach(card => {
    card.addEventListener('click', () => _selectChatAdapter(card.dataset.adapter, { resetThread: true }));
    card.addEventListener('keydown', e => {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); _selectChatAdapter(card.dataset.adapter, { resetThread: true }); }
    });
  });
}

function _defaultChatThreadForRuntime(adapterId) {
  const key = String(adapterId || 'hermes').toLowerCase();
  if (key === 'openclaw') return 'runtime-ops-openclaw-chat';
  if (key === 'claude-code' || key === 'codex') return 'runtime-ops-codex-patches';
  return 'runtime-ops-hermes-chat';
}

function _chatAdapterForRuntimeId(runtimeId) {
  const key = String(runtimeId || '').toLowerCase();
  if (key === 'openclaw') return 'openclaw';
  if (key === 'claude-code' || key === 'codex') return 'claude-code';
  return 'hermes';
}

function _chatRuntimeIdForAdapter(adapterId) {
  const key = String(adapterId || 'hermes').toLowerCase();
  if (key === 'openclaw') return 'OpenClaw';
  if (key === 'claude-code' || key === 'codex') return 'Codex';
  return 'Hermes';
}

function _chatSlug(value, fallback) {
  const slug = String(value || '')
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9_-]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80);
  return slug || fallback || 'chat';
}

function _selectChatAdapter(adapterId, options = {}) {
  _selectedChatAdapter = adapterId || 'hermes';
  if (options.resetThread) {
    _selectedChatThreadId = '';
    _chatFolderOnlySelection = true;
  } else if (!_selectedChatThreadId) {
    _chatFolderOnlySelection = true;
  }
  document.querySelectorAll('#chat-adapter-selector .adapter-card').forEach(c => {
    const sel = c.dataset.adapter === _selectedChatAdapter;
    c.classList.toggle('adapter-card--selected', sel);
    c.setAttribute('aria-pressed', String(sel));
  });
  _updateChatAdapterStatus(_selectedChatAdapter);
  if (chatLoaded) {
    loadPhase11ChatPanel('', '', true);
  }
}

function _updateChatAdapterStatus(adapterId) {
  const banner = document.getElementById('chat-runtime-offline-banner');
  if (!banner) return;
  const info = _chatAvailabilityData[adapterId];
  if (info && info.is_bus_runtime && info.online && !info.heartbeat_online) {
    const label = { hermes: 'Hermes', openclaw: 'OpenClaw' }[adapterId] || adapterId;
    const port = info.gateway_port_listening ? ' on port ' + info.gateway_port_listening : '';
    banner.textContent = label + ' gateway live' + port + '. Heartbeat sync needed.';
    banner.classList.add('visible');
  } else if (info && info.is_bus_runtime && !info.online) {
    const label = { hermes: 'Hermes', openclaw: 'OpenClaw' }[adapterId] || adapterId;
    banner.textContent = label + ' offline.';
    banner.classList.add('visible');
  } else {
    banner.classList.remove('visible');
  }
  _refreshDaemonControlState(adapterId);
  _updateChatThreadRuntimeBadge(adapterId);
  _syncChatSendReadiness(adapterId);
}

async function _loadChatRuntimeAvailability() {
  try {
    const resp = await window.pywebview.api.get_chat_runtime_availability();
    const byAdapter = (resp && resp.ok && resp.data && resp.data.runtime_by_adapter) || {};
    _chatAvailabilityData = byAdapter;
    const pipMap = { hermes: 'adapter-pip-hermes', openclaw: 'adapter-pip-openclaw' };
    Object.entries(pipMap).forEach(([adapterId, pipId]) => {
      const pip = document.getElementById(pipId);
      if (!pip) return;
      pip.className = 'adapter-status-pip';
      const info = byAdapter[adapterId];
      if (info && info.pip_class) pip.classList.add(info.pip_class);
    });
    _updateChatAdapterStatus(_selectedChatAdapter);
    _renderChatRuntimeSyncPanel();
  } catch (_) {}
}

function _chatRuntimeDisplayName(adapterId) {
  return ({ hermes: 'Hermes', openclaw: 'OpenClaw', 'claude-code': 'Claude Code' }[adapterId]) || adapterId || 'Runtime';
}

function _chatRuntimeStatusModel(info) {
  if (!info) {
    return { label: '', tone: 'checking', hidden: true };
  }
  if (info.dispatch_ready && info.heartbeat_online && info.runtime_can_receive_chat) {
    return { label: 'Connected', tone: 'live' };
  }
  if (info.heartbeat_online) {
    return { label: 'Online', tone: 'live' };
  }
  if (info.gateway_port_online) {
    return { label: 'Sync needed', tone: 'warning' };
  }
  if (info.pid_alive) {
    return { label: 'Starting', tone: 'warning' };
  }
  return { label: 'Offline', tone: 'offline' };
}

function _chatRuntimeStatusIsVisible(status) {
  return !!(status && !status.hidden && String(status.label || '').trim());
}

function _chatRuntimeHasManagedHandle(info) {
  return !!(info && (
    info.heartbeat_online
    || info.gateway_port_online
    || (info.pid_alive && info.status_source !== 'wsl_process')
  ));
}

function _updateChatThreadRuntimeBadge(adapterId, statusOverride) {
  const runtime = adapterId || _selectedChatAdapter || 'hermes';
  const status = statusOverride || _chatRuntimeStatusModel(_chatAvailabilityData[runtime]);
  const runtimeNameEl = document.querySelector('.phase11-chat-thread-runtime [data-chat-runtime-name="true"]');
  const statusEl = document.querySelector('.phase11-chat-thread-runtime [data-chat-runtime-status="true"]');
  if (runtimeNameEl) runtimeNameEl.textContent = _chatRuntimeDisplayName(runtime);
  if (statusEl) {
    const visible = _chatRuntimeStatusIsVisible(status);
    statusEl.hidden = !visible;
    statusEl.setAttribute('aria-hidden', visible ? 'false' : 'true');
    statusEl.textContent = visible ? status.label : '';
    statusEl.className = 'is-' + (status.tone || 'checking');
  }
  _syncChatHeaderRuntimeControls(runtime);
}

function _chatRuntimeActionState(adapterId) {
  const runtime = adapterId || _selectedChatAdapter || 'hermes';
  const info = _chatAvailabilityData[runtime];
  const status = _chatRuntimeStatusModel(info);
  const hasRuntimeHandle = _chatRuntimeHasManagedHandle(info);
  const gatewayOnly = !!(info && info.gateway_port_online && !info.heartbeat_online);
  const name = _chatRuntimeDisplayName(runtime);
  let actionLabel = 'Connect';
  let caption = `${name} connection state is checking.`;
  if (status.tone === 'live') {
    actionLabel = 'Connected';
    caption = `${name} is available for chat.`;
  } else if (gatewayOnly) {
    actionLabel = 'Sync';
    caption = `${name} gateway is visible. Heartbeat sync is needed before chat.`;
  } else if (status.tone === 'warning') {
    actionLabel = 'Sync';
    caption = `${name} is starting or needs a fresh heartbeat.`;
  } else if (status.tone === 'offline') {
    caption = `${name} is offline. Connect from here or the Runtimes page.`;
  }
  return {
    status,
    hasRuntimeHandle,
    gatewayOnly,
    actionLabel,
    caption,
  };
}

function _chatRuntimeSwitchButtonsHtml() {
  return ['hermes', 'openclaw'].map(adapterId => {
    const state = _chatRuntimeActionState(adapterId);
    const selected = adapterId === (_selectedChatAdapter || 'hermes');
    const visibleStatus = _chatRuntimeStatusIsVisible(state.status) ? state.status.label : '';
    return `<button type="button" class="phase11-chat-runtime-switch ${selected ? 'is-selected' : ''} is-${escAttr(state.status.tone || 'checking')}" data-chat-inline-runtime="${escAttr(adapterId)}" aria-pressed="${selected ? 'true' : 'false'}" title="${escAttr(_chatRuntimeDisplayName(adapterId))}">
      <span>${escHtml(_chatRuntimeDisplayName(adapterId))}</span>
      <em data-chat-inline-runtime-status="${escAttr(adapterId)}">${escHtml(visibleStatus)}</em>
    </button>`;
  }).join('');
}

function _syncChatHeaderRuntimeControls(adapterId) {
  const runtime = adapterId || _selectedChatAdapter || 'hermes';
  document.querySelectorAll('[data-chat-inline-runtime]').forEach(button => {
    const target = button.getAttribute('data-chat-inline-runtime') || 'hermes';
    const state = _chatRuntimeActionState(target);
    const selected = target === runtime;
    button.classList.toggle('is-selected', selected);
    button.classList.remove('is-live', 'is-warning', 'is-offline', 'is-checking');
    button.classList.add('is-' + (state.status.tone || 'checking'));
    button.setAttribute('aria-pressed', selected ? 'true' : 'false');
    const statusEl = button.querySelector('[data-chat-inline-runtime-status]');
    if (statusEl) statusEl.textContent = _chatRuntimeStatusIsVisible(state.status) ? state.status.label : '';
  });
  const actionState = _chatRuntimeActionState(runtime);
  document.querySelectorAll('[data-chat-start-runtime-control]').forEach(button => {
    button.textContent = actionState.actionLabel;
    button.disabled = actionState.status.tone === 'live';
  });
  document.querySelectorAll('[data-chat-stop-runtime-control]').forEach(button => {
    button.disabled = !actionState.hasRuntimeHandle;
  });
  document.querySelectorAll('[data-chat-runtime-caption]').forEach(item => {
    item.textContent = actionState.caption;
  });
}

function _queueChatRuntimeControlRefresh() {
  _loadChatRuntimeAvailability()
    .then(() => {
      _refreshDaemonControlState(_selectedChatAdapter || 'hermes');
      _syncChatHeaderRuntimeControls(_selectedChatAdapter || 'hermes');
    })
    .catch(() => _syncChatHeaderRuntimeControls(_selectedChatAdapter || 'hermes'));
}

function _chatProductRuntimeBlocker(blocker, runtimeId) {
  const text = String(blocker || '').trim();
  const runtimeName = _chatRuntimeDisplayName(runtimeId || _selectedChatAdapter || 'hermes');
  if (!text) return '';
  if (
    /api[_\s-]*key|environment variable|ANTHROPIC|OPENAI|provider ['"`]?[a-z0-9_-]+['"`]?|model\(s\).*failed/i.test(text)
    || /agent bus|bus-result|provider\/model|hermes_watch|openclaw_watch|native chat bridge|backend bridge|execution is not mounted/i.test(text)
  ) {
    return `${runtimeName} needs its backend chat configuration completed before it can return live replies.`;
  }
  return text
    .replace(/\b[A-Z][A-Z0-9_]{6,}\b/g, 'backend setting')
    .replace(/\bAPI\b/g, 'backend');
}

function _chatDisplayMessageContent(content, runtimeId) {
  const text = String(content || '').trim();
  if (!text) return '';
  const runtimeName = _chatRuntimeDisplayName(runtimeId || _selectedChatAdapter || 'hermes');
  const unavailablePattern = /runtime execution is not currently active or returned no response|native Chat backend is not currently configured or authorized|live model text is not currently available|returned no live model text|provider\/model execution is not (?:mounted|available)|Hermes Agent Bus Chat is bus-result-only/i;
  if (unavailablePattern.test(text)) {
    const messageMatch = text.match(/Message:\s*([\s\S]*?)(?:\n\s*\n|$)/i);
    const blockerMatch = text.match(/Runtime blocker:\s*([\s\S]*?)\.\s+No vault mutations/i);
    const originalMessage = messageMatch && messageMatch[1] ? messageMatch[1].trim() : '';
    const blocker = blockerMatch && blockerMatch[1] ? blockerMatch[1].trim() : '';
    if (blocker) {
      return `${runtimeName} could not return a live reply yet.\n\n${_chatProductRuntimeBlocker(blocker, runtimeId)}`;
    }
    return originalMessage
      ? `${runtimeName} received the message. No runtime reply is available yet.\n\n"${originalMessage}"`
      : `${runtimeName} received the message. No runtime reply is available yet.`;
  }
  return text
    .replace(/^\[[^\]]+ bounded ack\]\s*/i, 'Message received. ')
    .replace(/^Chat message received and claimed\.\s*/i, 'Message received. ');
}

function _chatRuntimePortLabel(info) {
  if (!info) return 'Ports checking';
  if (info.gateway_port_listening) return 'Port ' + info.gateway_port_listening;
  const checked = info.gateway_ports_checked || [];
  if (checked.length) return 'Checked ' + checked.join(', ');
  return 'No declared port';
}

function _chatRuntimeHeartbeatLabel(info) {
  if (!info) return 'Checking';
  if (info.heartbeat_online) return 'Fresh';
  if (info.freshness === 'recent') return 'Recent';
  if (info.freshness === 'stale') return 'Needs sync';
  return 'Unavailable';
}

function _chatRuntimeSyncCardsHtml() {
  const adapters = ['hermes', 'openclaw'];
  return adapters.map(adapterId => {
    const info = _chatAvailabilityData[adapterId];
    const status = _chatRuntimeStatusModel(info);
    const blockers = ((info && info.blocked_reasons) || []).slice(0, 2).join('; ');
    return `<article class="phase11-chat-runtime-sync-card is-${escAttr(status.tone)}" data-adapter="${escAttr(adapterId)}">
      <div class="phase11-chat-runtime-sync-head">
        <strong>${escHtml(_chatRuntimeDisplayName(adapterId))}</strong>
        <span>${escHtml(status.label)}</span>
      </div>
      <dl>
        <div><dt>Port</dt><dd>${escHtml(_chatRuntimePortLabel(info))}</dd></div>
        <div><dt>Heartbeat</dt><dd>${escHtml(_chatRuntimeHeartbeatLabel(info))}</dd></div>
        <div><dt>Chat</dt><dd>${escHtml(info && info.dispatch_ready ? 'Ready' : 'Sync needed')}</dd></div>
      </dl>
      ${blockers ? `<p>${escHtml(blockers)}</p>` : ''}
    </article>`;
  }).join('');
}

function _phase11ChatRuntimeSyncHtml() {
  const selectedInfo = _chatAvailabilityData[_selectedChatAdapter || 'hermes'];
  const selectedStatus = _chatRuntimeStatusModel(selectedInfo);
  const heartbeat = _chatRuntimeHeartbeatLabel(selectedInfo);
  const port = _chatRuntimePortLabel(selectedInfo);
  return `<div class="phase11-chat-runtime-sync-overview">
    <div>
      <strong>${escHtml(_chatRuntimeDisplayName(_selectedChatAdapter || 'hermes'))}</strong>
      <span>${escHtml(selectedStatus.label)}</span>
    </div>
    <em>${escHtml(heartbeat)} heartbeat · ${escHtml(port)}</em>
  </div>
  <div class="phase11-chat-runtime-sync-grid">${_chatRuntimeSyncCardsHtml()}</div>`;
}

function _renderChatRuntimeSyncPanel() {
  const body = document.getElementById('phase11-chat-live-runtime-sync-body');
  if (!body) return;
  body.innerHTML = _phase11ChatRuntimeSyncHtml();
}

function _syncChatSendReadiness(adapterId) {
  const sendBtn = document.getElementById('chat-send-button');
  const note = document.getElementById('chat-authority-note');
  const info = _chatAvailabilityData[adapterId];
  if (!sendBtn || !note) return;
  if (!info || !info.is_bus_runtime) {
    sendBtn.disabled = false;
    note.textContent = 'Runtime state is checking; send path verifies Agent Bus readiness before dispatch.';
    return;
  }
  const ready = !!(info.dispatch_ready && info.heartbeat_online && info.runtime_can_receive_chat);
  sendBtn.disabled = !ready;
  if (ready) {
    note.textContent = _chatRuntimeDisplayName(adapterId) + ' has a live heartbeat and can receive chat tasks.';
  } else if (info.gateway_port_online) {
    note.textContent = _chatRuntimeDisplayName(adapterId) + ' gateway is visible; dispatch waits for a fresh Agent Bus heartbeat.';
  } else {
    note.textContent = _chatRuntimeDisplayName(adapterId) + ' is offline.';
  }
}

function _formatChatFileSize(bytes) {
  const value = Number(bytes || 0);
  if (!value) return '';
  if (value < 1024) return value + ' B';
  if (value < 1024 * 1024) return Math.round(value / 102.4) / 10 + ' KB';
  return Math.round(value / (1024 * 102.4)) / 10 + ' MB';
}

function _stageChatAttachments(fileList, kind) {
  const incoming = Array.from(fileList || []).map(file => ({
    attachment_id: 'att-' + Math.random().toString(16).slice(2, 10),
    name: file.name || 'attachment',
    kind: kind || (String(file.type || '').startsWith('image/') ? 'image' : 'file'),
    type: file.type || '',
    size: file.size || 0,
    content_stored: false
  }));
  _chatAttachments = _chatAttachments.concat(incoming).slice(0, 12);
  _renderChatAttachmentTray();
}

function _renderChatAttachmentTray() {
  const tray = document.getElementById('chat-attachment-tray');
  if (!tray) return;
  if (!_chatAttachments.length) {
    tray.innerHTML = '';
    tray.classList.remove('is-visible');
    return;
  }
  tray.classList.add('is-visible');
  tray.innerHTML = _chatAttachments.map((item, index) => {
    const size = _formatChatFileSize(item.size);
    return `<span class="chat-attachment-chip">
      <b>${escHtml(item.kind === 'image' ? 'Image' : 'File')}</b>
      ${escHtml(item.name || 'attachment')}
      ${size ? `<em>${escHtml(size)}</em>` : ''}
      <button type="button" data-chat-remove-attachment="${index}" aria-label="Remove attachment">x</button>
    </span>`;
  }).join('');
}

function _selectChatThread(threadId, runtimeId, workspaceId, folderId, folderLabel) {
  _selectedChatThreadId = threadId || _defaultChatThreadForRuntime(_selectedChatAdapter);
  _chatFolderOnlySelection = false;
  if (workspaceId) _selectedChatWorkspaceId = workspaceId;
  if (folderId) _selectedChatFolderId = folderId;
  if (folderLabel) _selectedChatFolderLabel = folderLabel;
  if (runtimeId) {
    _selectedChatAdapter = _chatAdapterForRuntimeId(runtimeId);
  }
  document.querySelectorAll('#chat-thread-navigator [data-chat-thread-id], #chat-preview-body [data-chat-thread-id]').forEach(item => {
    item.classList.toggle('is-selected', item.getAttribute('data-chat-thread-id') === _selectedChatThreadId);
  });
  if (window.pywebview && window.pywebview.api && window.pywebview.api.save_phase11_chat_route_state) {
    window.pywebview.api.save_phase11_chat_route_state(
      _selectedChatThreadId,
      '',
      _selectedChatWorkspaceId,
      '',
      _selectedChatFolderId
    ).catch(() => {});
  }
  _selectChatAdapter(_selectedChatAdapter);
}

function _selectChatFolder(workspaceId, folderId, folderLabel) {
  _selectedChatWorkspaceId = workspaceId || _selectedChatWorkspaceId || 'runtime-ops';
  _selectedChatFolderId = folderId || _selectedChatFolderId || 'runtime-control';
  _selectedChatFolderLabel = folderLabel || _selectedChatFolderLabel || _selectedChatFolderId;
  _selectedChatThreadId = '';
  _chatFolderOnlySelection = true;
  document.querySelectorAll('#chat-thread-navigator [data-chat-folder-target]').forEach(item => {
    const sameWorkspace = item.getAttribute('data-chat-workspace-id') === _selectedChatWorkspaceId;
    const sameFolder = item.getAttribute('data-chat-folder-id') === _selectedChatFolderId;
    item.classList.toggle('is-selected', sameWorkspace && sameFolder);
  });
  if (window.pywebview && window.pywebview.api && window.pywebview.api.save_phase11_chat_route_state) {
    window.pywebview.api.save_phase11_chat_route_state(
      '',
      '',
      _selectedChatWorkspaceId,
      '',
      _selectedChatFolderId
    ).catch(() => {});
  }
  loadPhase11ChatPanel('', '', true);
}

function _chatThreadMatchesAdapter(thread, adapterId) {
  if (!thread) return false;
  return _chatAdapterForRuntimeId(thread.runtime_id || thread.runtime_label || adapterId) === (adapterId || _selectedChatAdapter || 'hermes');
}

function _chatThreadHasMessages(thread) {
  return Number((thread && thread.message_count) || 0) > 0
    || ((thread && thread.conversation_messages) || []).length > 0;
}

function _chatThreadIsLocalConversation(thread) {
  return !!(thread && (
    thread.local_conversation_thread
    || thread.conversation_persisted
    || thread.conversation_state_persisted
    || thread.chat_transcript_persisted
    || (thread.native_state_persisted && thread.thread_kind === 'local_saved_chat_thread')
  ));
}

function _chatThreadLooksLikeVerification(thread) {
  const haystack = [
    thread && thread.thread_id,
    thread && thread.title,
    thread && thread.folder_label,
    thread && thread.latest_message_preview,
  ].join(' ').toLowerCase();
  return /\b(verification|diagnostic|diagnostics|test target|live ui verification|final live verification|background runtime service|studio live verification)\b/.test(haystack);
}

function _chatIsProductVisibleThread(thread) {
  const threadId = String((thread && thread.thread_id) || '');
  if (!threadId) return false;
  if (_chatThreadLooksLikeVerification(thread)) return false;
  return _chatThreadIsLocalConversation(thread) || _chatThreadHasMessages(thread);
}

function _chatFolderKey(workspaceId, folderId) {
  return `${workspaceId || 'workspace'}::${folderId || 'folder'}`;
}

function _chatIsProductVisibleFolder(folder, threads) {
  if (!folder) return false;
  if (folder.local_conversation_folder || folder.local_state_only || folder.native_state_persisted) return true;
  const workspaceId = folder.workspace_id || '';
  const folderId = folder.folder_id || '';
  return (threads || []).some(thread =>
    _chatIsProductVisibleThread(thread)
    && String(thread.workspace_id || '') === String(workspaceId)
    && String(thread.folder_id || '') === String(folderId)
  );
}

function _chatProductWorkspaceLabel(value) {
  const raw = String(value || '').trim();
  if (!raw) return 'Chats';
  if (raw === 'runtime-ops') return 'Runtime';
  return raw.replace(/-/g, ' ');
}

function _chatProductTitleCase(value) {
  const raw = String(value || '').replace(/[-_]+/g, ' ').trim();
  if (!raw) return '';
  return raw.replace(/\b[a-z]/g, char => char.toUpperCase());
}

function _chatProductFolderLabel(value) {
  const raw = String(value || '').trim();
  if (!raw) return 'Chats';
  if (raw === 'runtime-control' || raw.toLowerCase() === 'runtime control') return 'Runtime Chats';
  return _chatProductTitleCase(raw);
}

function _chatProductThreadTitle(thread) {
  const title = String((thread && thread.title) || '').trim();
  const threadId = String((thread && thread.thread_id) || '').trim();
  const runtimeId = _chatAdapterForRuntimeId((thread && (thread.runtime_id || thread.runtime_label)) || '');
  const titleRuntimeMatch = title.toLowerCase().match(/\b(hermes|openclaw)\b/);
  const titledRuntime = titleRuntimeMatch && titleRuntimeMatch[1];
  if (runtimeId && titledRuntime && titledRuntime !== runtimeId) {
    return runtimeId === 'openclaw' ? 'OpenClaw Chat' : 'Hermes Chat';
  }
  if (threadId === 'runtime-ops-hermes-chat' || title.toLowerCase() === 'runtime ops hermes chat') return 'Hermes Chat';
  if (threadId === 'runtime-ops-openclaw-chat' || title.toLowerCase() === 'runtime ops openclaw chat') return runtimeId === 'hermes' ? 'Hermes Chat' : 'OpenClaw Chat';
  if (title) return title;
  if (runtimeId === 'hermes') return 'Hermes Chat';
  if (runtimeId === 'openclaw') return 'OpenClaw Chat';
  return threadId || 'Thread';
}

function _chatProductThreadPreview(thread) {
  const count = Number((thread && thread.message_count) || 0);
  const raw = String((thread && thread.latest_message_preview) || '').trim();
  if (/bounded ack|runtime execution is not currently active or returned no response|native Chat backend is not currently configured or authorized|live model text is not currently available|returned no live model text|provider\/model execution is not (?:mounted|available)|Hermes Agent Bus Chat is bus-result-only/i.test(raw)) {
    return 'No live reply yet';
  }
  if (raw) return raw;
  return count ? `${count} message${count === 1 ? '' : 's'}` : 'New chat';
}

function _threadNavigatorRow(thread) {
  const threadId = thread.thread_id || '';
  const runtimeId = thread.runtime_id || '';
  const selected = threadId === _selectedChatThreadId;
  const latest = _chatProductThreadPreview(thread);
  const folderLabel = thread.folder_label || thread.folder_id || '';
  return `<button type="button" class="chat-thread-nav-row ${selected ? 'is-selected' : ''}" data-chat-thread-id="${escAttr(threadId)}" data-chat-runtime-id="${escAttr(runtimeId)}" data-chat-workspace-id="${escAttr(thread.workspace_id || '')}" data-chat-folder-id="${escAttr(thread.folder_id || '')}" data-chat-folder-label="${escAttr(folderLabel)}">
    <span><strong>${escHtml(_chatProductThreadTitle(thread))}</strong><em>${escHtml(latest)}</em></span>
    <b>${escHtml(runtimeId || 'Native')}</b>
  </button>`;
}

function _chatFolderRowsFromWorkspaces(chatWorkspaces, visibleThreads) {
  const folders = (chatWorkspaces && chatWorkspaces.folders) || [];
  const allThreads = (chatWorkspaces && chatWorkspaces.threads) || [];
  const threads = visibleThreads || allThreads.filter(_chatIsProductVisibleThread);
  const folderByKey = new Map();
  folders.filter(folder => _chatIsProductVisibleFolder(folder, allThreads)).forEach(folder => {
    folderByKey.set(_chatFolderKey(folder.workspace_id || 'runtime-ops', folder.folder_id || 'runtime-control'), folder);
  });
  threads.forEach(thread => {
    const key = _chatFolderKey(thread.workspace_id || 'runtime-ops', thread.folder_id || 'runtime-control');
    if (!folderByKey.has(key)) {
      folderByKey.set(key, {
        workspace_id: thread.workspace_id || 'runtime-ops',
        folder_id: thread.folder_id || 'runtime-control',
        label: thread.folder_label || thread.folder_id || 'Chats',
      });
    }
  });
  const ensureFolder = (workspaceId, folderId, label) => {
    const key = _chatFolderKey(workspaceId, folderId);
    if (!folderByKey.has(key)) {
      folderByKey.set(key, { workspace_id: workspaceId, folder_id: folderId, label });
    }
  };
  ensureFolder('runtime-ops', 'runtime-control', 'Runtime Control');
  ensureFolder(_selectedChatWorkspaceId || 'runtime-ops', _selectedChatFolderId || 'runtime-control', _selectedChatFolderLabel || 'Runtime Control');
  const rows = Array.from(folderByKey.values());
  rows.sort((a, b) => String(a.label || a.folder_id || '').localeCompare(String(b.label || b.folder_id || '')));
  return rows;
}

function _renderChatFolderDropdown(folderRows, byFolder) {
  const button = document.getElementById('chat-folder-dropdown-button');
  const menu = document.getElementById('chat-folder-dropdown-menu');
  const selectedLabelEl = document.getElementById('chat-selected-folder-label');
  if (!button || !menu) return;
  const selectedKey = _chatFolderKey(_selectedChatWorkspaceId, _selectedChatFolderId);
  const selectedFolder = (folderRows || []).find(folder =>
    _chatFolderKey(folder.workspace_id || 'runtime-ops', folder.folder_id || 'runtime-control') === selectedKey
  );
  const selectedLabel = _chatProductFolderLabel(
    (selectedFolder && (selectedFolder.label || selectedFolder.folder_id)) || _selectedChatFolderLabel || 'Folders'
  );
  button.setAttribute('aria-expanded', _chatFolderDropdownOpen ? 'true' : 'false');
  button.textContent = selectedLabel + ' v';
  if (selectedLabelEl) selectedLabelEl.textContent = selectedLabel;
  button.title = `Folders: ${selectedLabel}`;
  menu.hidden = !_chatFolderDropdownOpen;
  if (!folderRows || !folderRows.length) {
    menu.innerHTML = '<div class="chat-folder-dropdown-empty">No folders yet</div>';
    return;
  }
  menu.innerHTML = folderRows.map(folder => {
    const workspaceId = folder.workspace_id || 'runtime-ops';
    const folderId = folder.folder_id || 'runtime-control';
    const key = _chatFolderKey(workspaceId, folderId);
    const rows = (byFolder && byFolder[key]) || [];
    const label = _chatProductFolderLabel(folder.label || folderId || 'Folder');
    const selected = key === selectedKey;
    const protectedFolder = folderId === 'runtime-control';
    return `<div class="chat-folder-menu-row ${selected ? 'is-selected' : ''}">
      <button type="button" class="chat-folder-menu-select" data-chat-folder-menu-select="true" data-chat-workspace-id="${escAttr(workspaceId)}" data-chat-folder-id="${escAttr(folderId)}" data-chat-folder-label="${escAttr(folder.label || folderId || 'Folder')}">
        <strong>${escHtml(label)}</strong><span>${rows.length}</span>
      </button>
      <button type="button" class="chat-folder-menu-action" data-chat-folder-menu-rename="true" data-chat-workspace-id="${escAttr(workspaceId)}" data-chat-folder-id="${escAttr(folderId)}" data-chat-folder-label="${escAttr(folder.label || folderId || 'Folder')}" title="Rename folder" aria-label="Rename ${escAttr(label)}">Rename</button>
      <button type="button" class="chat-folder-menu-action is-danger" ${protectedFolder ? 'disabled' : ''} data-chat-folder-menu-delete="true" data-chat-workspace-id="${escAttr(workspaceId)}" data-chat-folder-id="${escAttr(folderId)}" data-chat-folder-label="${escAttr(folder.label || folderId || 'Folder')}" title="${protectedFolder ? 'Default folder stays available' : 'Delete folder'}" aria-label="Delete ${escAttr(label)}">Delete</button>
    </div>`;
  }).join('');
}

function _renderChatThreadNavigator(chatWorkspaces) {
  const nav = document.getElementById('chat-thread-navigator');
  if (!nav) return;
  const folders = (chatWorkspaces && chatWorkspaces.folders) || [];
  const allThreads = (chatWorkspaces && chatWorkspaces.threads) || [];
  let threads = allThreads.filter(_chatIsProductVisibleThread);
  const selectedThread = threads.find(thread => thread.thread_id === _selectedChatThreadId);
  if (selectedThread && !_chatThreadMatchesAdapter(selectedThread, _selectedChatAdapter)) {
    _selectedChatThreadId = '';
    _chatFolderOnlySelection = true;
  }
  if (!_selectedChatThreadId) {
    const selectedKey = _chatFolderKey(_selectedChatWorkspaceId, _selectedChatFolderId);
    const routedThread = !_chatFolderOnlySelection
      ? threads.find(thread => thread.selected_in_route_state && _chatThreadMatchesAdapter(thread, _selectedChatAdapter))
      : null;
    const selectedFolderThread = threads.find(thread =>
      _chatThreadMatchesAdapter(thread, _selectedChatAdapter)
      && _chatFolderKey(thread.workspace_id || 'runtime-ops', thread.folder_id || 'runtime-control') === selectedKey
    );
    const runtimeThread = threads.find(thread => _chatThreadMatchesAdapter(thread, _selectedChatAdapter));
    const nextThread = routedThread || selectedFolderThread || runtimeThread || threads[0] || null;
    if (nextThread && nextThread.thread_id) {
      _selectedChatThreadId = nextThread.thread_id;
      _selectedChatWorkspaceId = nextThread.workspace_id || _selectedChatWorkspaceId || 'runtime-ops';
      _selectedChatFolderId = nextThread.folder_id || _selectedChatFolderId || 'runtime-control';
      _selectedChatFolderLabel = nextThread.folder_label || _selectedChatFolderLabel || nextThread.folder_id || 'Runtime Control';
      _selectedChatAdapter = _chatAdapterForRuntimeId(nextThread.runtime_id || nextThread.runtime_label || _selectedChatAdapter);
      _chatFolderOnlySelection = false;
    } else {
      _chatFolderOnlySelection = true;
    }
  }
  const search = String(_chatThreadSearch || '').trim().toLowerCase();
  if (search) {
    threads = threads.filter(thread => {
      const haystack = [
        thread.title,
        thread.thread_id,
        thread.workspace_id,
        thread.folder_id,
        thread.folder_label,
        thread.runtime_id,
        thread.latest_message_preview,
      ].join(' ').toLowerCase();
      return haystack.includes(search);
    });
  }
  const byFolder = {};
  threads.forEach(thread => {
    const key = _chatFolderKey(thread.workspace_id || 'runtime-ops', thread.folder_id || 'runtime-control');
    if (!byFolder[key]) byFolder[key] = [];
    byFolder[key].push(thread);
  });
  Object.values(byFolder).forEach(rows => {
    rows.sort((a, b) => {
      const selectedA = a.thread_id === _selectedChatThreadId;
      const selectedB = b.thread_id === _selectedChatThreadId;
      if (selectedA !== selectedB) return selectedA ? -1 : 1;
      const runtimeA = _chatThreadMatchesAdapter(a, _selectedChatAdapter);
      const runtimeB = _chatThreadMatchesAdapter(b, _selectedChatAdapter);
      if (runtimeA !== runtimeB) return runtimeA ? -1 : 1;
      return String(b.last_message_at_utc || b.updated_at_utc || '').localeCompare(String(a.last_message_at_utc || a.updated_at_utc || ''));
    });
  });
  let folderRows = _chatFolderRowsFromWorkspaces({ folders, threads: allThreads }, threads);
  if (search) {
    folderRows = folderRows.filter(folder => {
      const key = _chatFolderKey(folder.workspace_id || '', folder.folder_id || '');
      const folderThreads = byFolder[key] || [];
      const folderText = [folder.label, folder.folder_id, folder.workspace_id].join(' ').toLowerCase();
      return folderThreads.length || folderText.includes(search);
    });
  }
  folderRows.sort((a, b) => {
    const keyA = _chatFolderKey(a.workspace_id || '', a.folder_id || '');
    const keyB = _chatFolderKey(b.workspace_id || '', b.folder_id || '');
    const selectedA = keyA === _chatFolderKey(_selectedChatWorkspaceId, _selectedChatFolderId) || (byFolder[keyA] || []).some(thread => thread.thread_id === _selectedChatThreadId);
    const selectedB = keyB === _chatFolderKey(_selectedChatWorkspaceId, _selectedChatFolderId) || (byFolder[keyB] || []).some(thread => thread.thread_id === _selectedChatThreadId);
    if (selectedA !== selectedB) return selectedA ? -1 : 1;
    return String(a.label || a.folder_id || '').localeCompare(String(b.label || b.folder_id || ''));
  });
  const allFolderRows = folderRows.slice();
  _renderChatFolderDropdown(allFolderRows, byFolder);
  if (!folderRows.length) {
    nav.innerHTML = '<div class="chat-thread-navigator-empty"><strong>No matches.</strong><span>Try another chat or folder name.</span></div>';
    return;
  }
  if (!search) {
    const selectedKey = _chatFolderKey(_selectedChatWorkspaceId, _selectedChatFolderId);
    const selectedFolderRows = folderRows.filter(folder =>
      _chatFolderKey(folder.workspace_id || '', folder.folder_id || '') === selectedKey
    );
    folderRows = selectedFolderRows.length ? selectedFolderRows : folderRows.slice(0, 1);
  }
  nav.innerHTML = folderRows.map(folder => {
    const key = _chatFolderKey(folder.workspace_id || 'runtime-ops', folder.folder_id || 'runtime-control');
    const rows = byFolder[key] || [];
    const selectedFolder = key === _chatFolderKey(_selectedChatWorkspaceId, _selectedChatFolderId);
    const displayFolderLabel = _chatProductFolderLabel(folder.label || folder.folder_id || 'Folder');
    return `<section class="chat-thread-folder">
      <button type="button" class="chat-folder-row ${selectedFolder ? 'is-selected' : ''}" data-chat-folder-target="true" data-chat-workspace-id="${escAttr(folder.workspace_id || '')}" data-chat-folder-id="${escAttr(folder.folder_id || '')}" data-chat-folder-label="${escAttr(folder.label || folder.folder_id || 'Folder')}">
        <span>${escHtml(displayFolderLabel)}</span><b>${rows.length}</b>
      </button>
      <div>${rows.length ? rows.map(_threadNavigatorRow).join('') : '<div class="chat-folder-empty">No chats in this folder yet.</div>'}</div>
    </section>`;
  }).join('');
}

function _showChatCreatePanel(kind) {
  _chatCreateKind = kind === 'folder' ? 'folder' : 'thread';
  const panel = document.getElementById('chat-create-panel');
  const title = document.getElementById('chat-create-title');
  const input = document.getElementById('chat-create-input');
  const submit = document.getElementById('chat-create-submit-button');
  if (!panel || !input || !title || !submit) return;
  title.textContent = _chatCreateKind === 'folder' ? 'New folder' : 'New chat';
  input.value = '';
  input.placeholder = _chatCreateKind === 'folder' ? 'Folder name' : 'Chat name';
  submit.textContent = _chatCreateKind === 'folder' ? 'Create folder' : 'Create chat';
  panel.hidden = false;
  input.focus();
}

function _hideChatCreatePanel() {
  const panel = document.getElementById('chat-create-panel');
  const input = document.getElementById('chat-create-input');
  if (panel) panel.hidden = true;
  if (input) input.value = '';
}

async function _submitChatCreatePanel() {
  const input = document.getElementById('chat-create-input');
  const label = input ? input.value.trim() : '';
  if (_chatCreateKind === 'folder') {
    await _createChatFolderFromUi(label);
  } else {
    await _createChatThreadFromUi(label);
  }
}

