/** Format a short install-mode chip for display next to daemon status.
 *  Returns a string like " · Windows" or " · WSL" or "" for openclaw. */
function _hermesInstallChip(data) {
  if (!data) return '';
  const mode = data.hermes_mode;
  if (!mode || mode === 'unknown') return '';
  if (mode === 'windows') return ' · Windows';
  if (mode === 'wsl')     return ' · WSL';
  if (mode === 'unavailable') return ' · hermes not installed';
  return '';
}

async function _refreshDaemonControlState(adapterId) {
  const startBtn = document.getElementById('chat-daemon-start-btn');
  const stopBtn  = document.getElementById('chat-daemon-stop-btn');
  const label    = document.getElementById('chat-daemon-status-label');
  if (!startBtn || !stopBtn || !label) return;

  const DAEMON_RUNTIMES = { hermes: true, openclaw: true };

  if (!DAEMON_RUNTIMES[adapterId]) {
    startBtn.style.display = 'none';
    stopBtn.style.display  = 'none';
    label.textContent = '';
    label.className = 'daemon-status-label';
    return;
  }

  startBtn.style.display = '';
  if (!label.textContent || label.textContent === 'Checking…') {
    label.textContent = 'Checking';
    label.className = 'daemon-status-label';
  }

  const applyAvailabilityState = (info, data = {}) => {
    const status = _chatRuntimeStatusModel(info);
    const hasRuntimeHandle = _chatRuntimeHasManagedHandle(info)
      || data.status === 'running';
    const gatewayOnly = !!(info && info.gateway_port_online && !info.heartbeat_online);
    startBtn.textContent = gatewayOnly ? 'Sync' : 'Start';
    startBtn.title = gatewayOnly ? 'Refresh the selected runtime heartbeat' : 'Start the selected local runtime';
    stopBtn.title = 'Stop the selected local runtime';
    startBtn.style.display = status.tone === 'live' ? 'none' : '';
    stopBtn.style.display = hasRuntimeHandle ? '' : 'none';
    label.textContent = status.label;
    label.className = 'daemon-status-label status--' + (
      status.tone === 'live' ? 'running' :
      status.tone === 'warning' ? 'warning' :
      status.tone === 'offline' ? 'stopped' :
      'starting'
    );
    _updateChatThreadRuntimeBadge(adapterId, status);
  };

  const availabilityInfo = _chatAvailabilityData[adapterId];
  if (availabilityInfo) {
    applyAvailabilityState(availabilityInfo);
  }

  try {
    const resp = await window.pywebview.api.get_daemon_status(adapterId);
    const data = (resp && resp.ok && resp.data) || {};
    if (availabilityInfo) {
      label.title = _daemonRuntimeStatusLabel(data || availabilityInfo) + _hermesInstallChip(data || availabilityInfo);
      return;
    }
    const status = data.status || 'unknown';
    const modeChip = _hermesInstallChip(data);
    label.title = _daemonRuntimeStatusLabel(data) + modeChip;
    if (status === 'running') {
      const heartbeatLive = !!data.heartbeat_online;
      const gatewayOnly = !!data.gateway_port_online && !heartbeatLive;
      const threadStatus = _chatRuntimeStatusModel(data);
      startBtn.textContent = gatewayOnly ? 'Sync' : 'Start';
      startBtn.title = gatewayOnly ? 'Refresh the local heartbeat for this runtime' : 'Start the selected local runtime';
      stopBtn.title = 'Stop the selected local runtime';
      startBtn.style.display = heartbeatLive ? 'none' : '';
      stopBtn.style.display  = '';
      label.textContent = heartbeatLive ? 'Online' : (gatewayOnly ? 'Gateway online' : 'Running');
      label.className = 'daemon-status-label ' + (gatewayOnly ? 'status--warning' : 'status--running');
      _updateChatThreadRuntimeBadge(adapterId, threadStatus);
    } else {
      startBtn.textContent = 'Start';
      startBtn.title = 'Start the selected local runtime';
      startBtn.style.display = '';
      stopBtn.style.display  = 'none';
      label.textContent = 'Offline';
      label.className = 'daemon-status-label status--stopped';
      _updateChatThreadRuntimeBadge(adapterId, { label: 'Offline', tone: 'offline' });
    }
  } catch (_) {
    label.textContent = 'Unknown';
    label.className = 'daemon-status-label';
  }
}

async function _startChatDaemon() {
  const startBtn = document.getElementById('chat-daemon-start-btn');
  const label    = document.getElementById('chat-daemon-status-label');
  if (startBtn) startBtn.disabled = true;
  if (label) { label.textContent = 'Starting'; label.className = 'daemon-status-label status--starting'; }
  try {
    // Chat Connect is the operator's explicit opt-in to runtime-owned replies.
    const resp = await window.pywebview.api.start_runtime_daemon(_selectedChatAdapter, true, '');
    if (resp && resp.status === 'requires_approval' && resp.approval && resp.approval.approval_id) {
      const approvalId = resp.approval.approval_id;
        if (label) { label.textContent = 'Approval needed'; label.className = 'daemon-status-label status--starting'; }
      if (typeof showApprovalModal === 'function') {
        showApprovalModal(resp.approval, async (resolvedData) => {
          if ((resolvedData || {}).decision === 'approved') {
              if (label) { label.textContent = 'Starting'; label.className = 'daemon-status-label status--starting'; }
            try {
              const execResp = await window.pywebview.api.start_runtime_daemon(_selectedChatAdapter, true, approvalId);
              if (execResp && execResp.ok && execResp.data && execResp.data.stale_coordination_state_cleaned) {
                if (label) { label.textContent = 'Online'; label.className = 'daemon-status-label status--running'; }
                const stopBtn = document.getElementById('chat-daemon-stop-btn');
                if (startBtn) startBtn.style.display = 'none';
                if (stopBtn) stopBtn.style.display = '';
                const banner = document.getElementById('chat-runtime-offline-banner');
                if (banner) banner.classList.remove('visible');
              } else if (!execResp || !execResp.ok) {
                if (label) { label.textContent = 'Start failed'; label.className = 'daemon-status-label status--stopped'; }
              } else {
                const status = execResp.data && execResp.data.status;
                const stopBtn = document.getElementById('chat-daemon-stop-btn');
                if (label) { label.textContent = status === 'already_running' ? 'Online' : 'Online'; label.className = 'daemon-status-label status--running'; }
                if (startBtn) startBtn.style.display = 'none';
                if (stopBtn) stopBtn.style.display = '';
                const banner = document.getElementById('chat-runtime-offline-banner');
                if (banner) banner.classList.remove('visible');
              }
            } catch (err2) {
              if (label) { label.textContent = 'Start failed'; label.className = 'daemon-status-label status--stopped'; }
            }
          } else {
            if (label) { label.textContent = 'Cancelled'; label.className = 'daemon-status-label status--stopped'; }
          }
          if (startBtn) startBtn.disabled = false;
          _queueChatRuntimeControlRefresh();
        });
        return;
      }
      if (label) { label.textContent = 'Approval needed'; label.className = 'daemon-status-label status--stopped'; }
      if (startBtn) startBtn.disabled = false;
      return;
    }
    if (!resp || !resp.ok) {
      if (label) { label.textContent = 'Start failed'; label.className = 'daemon-status-label status--stopped'; }
      if (startBtn) startBtn.disabled = false;
      return;
    }
    const status = resp.data && resp.data.status;
    if (status === 'already_running') {
      if (label) { label.textContent = 'Online'; label.className = 'daemon-status-label status--running'; }
      const stopBtn = document.getElementById('chat-daemon-stop-btn');
      if (startBtn) startBtn.style.display = 'none';
      if (stopBtn) stopBtn.style.display = '';
    } else {
      if (label) { label.textContent = 'Online'; label.className = 'daemon-status-label status--running'; }
      const stopBtn = document.getElementById('chat-daemon-stop-btn');
      if (startBtn) startBtn.style.display = 'none';
      if (stopBtn) stopBtn.style.display = '';
      // Also dismiss offline banner
      const banner = document.getElementById('chat-runtime-offline-banner');
      if (banner) banner.classList.remove('visible');
    }
  } catch (err) {
    if (label) { label.textContent = 'Start failed'; label.className = 'daemon-status-label status--stopped'; }
  }
  if (startBtn) startBtn.disabled = false;
  _queueChatRuntimeControlRefresh();
}

async function _stopChatDaemon() {
  const stopBtn  = document.getElementById('chat-daemon-stop-btn');
  const label    = document.getElementById('chat-daemon-status-label');
  if (stopBtn) stopBtn.disabled = true;
  if (label) { label.textContent = 'Stopping'; label.className = 'daemon-status-label status--starting'; }
  try {
    const resp = await window.pywebview.api.stop_runtime_daemon(_selectedChatAdapter, '');
    if (resp && resp.status === 'requires_approval' && resp.approval && resp.approval.approval_id) {
      const approvalId = resp.approval.approval_id;
      if (label) { label.textContent = 'Approval needed'; label.className = 'daemon-status-label status--starting'; }
      if (typeof showApprovalModal === 'function') {
        showApprovalModal(resp.approval, async (resolvedData) => {
          if ((resolvedData || {}).decision === 'approved') {
            if (label) { label.textContent = 'Stopping'; label.className = 'daemon-status-label status--starting'; }
            try {
              const execResp = await window.pywebview.api.stop_runtime_daemon(_selectedChatAdapter, approvalId);
              const status = (execResp && execResp.ok && execResp.data && execResp.data.status) || 'stopped';
              const startBtn = document.getElementById('chat-daemon-start-btn');
              if (stopBtn) { stopBtn.disabled = false; stopBtn.style.display = 'none'; }
              if (startBtn) startBtn.style.display = '';
              if (label) { label.textContent = status === 'stopped' ? 'Stopped' : 'Offline'; label.className = 'daemon-status-label status--stopped'; }
            } catch (err2) {
              if (label) { label.textContent = 'Stop failed'; }
            }
          } else {
            if (label) { label.textContent = 'Online'; label.className = 'daemon-status-label status--running'; }
          }
          if (stopBtn) stopBtn.disabled = false;
          _queueChatRuntimeControlRefresh();
        });
        return;
      }
      if (label) { label.textContent = 'Approval needed'; label.className = 'daemon-status-label status--stopped'; }
      if (stopBtn) stopBtn.disabled = false;
      return;
    }
    const status = (resp && resp.ok && resp.data && resp.data.status) || 'stopped';
    const startBtn = document.getElementById('chat-daemon-start-btn');
    if (stopBtn) { stopBtn.disabled = false; stopBtn.style.display = 'none'; }
    if (startBtn) startBtn.style.display = '';
    if (label) { label.textContent = status === 'stopped' ? 'Stopped' : 'Offline'; label.className = 'daemon-status-label status--stopped'; }
  } catch (err) {
    if (label) { label.textContent = 'Stop failed'; }
    if (stopBtn) stopBtn.disabled = false;
  }
  _queueChatRuntimeControlRefresh();
}

async function _sendChatMessage(message) {
  if (!message || !message.trim()) return;
  const sendBtn = document.getElementById('chat-send-button');
  const input = document.getElementById('chat-message-input');
  if (sendBtn) sendBtn.disabled = true;
  let threadId = _selectedChatThreadId;
  try {
    if (!threadId && window.pywebview && window.pywebview.api && window.pywebview.api.create_chat_thread) {
      const title = message.trim().slice(0, 48) || 'New chat';
      _setChatSendStatus('Creating chat...');
      const created = await window.pywebview.api.create_chat_thread(
        title,
        _selectedChatWorkspaceId || 'runtime-ops',
        _selectedChatFolderId || 'runtime-control',
        _selectedChatFolderLabel || 'Runtime Control',
        _selectedChatAdapter || 'hermes'
      );
      if (created && created.ok && created.data && created.data.conversation) {
        const conversation = created.data.conversation;
        threadId = conversation.thread_id || threadId;
        _selectedChatWorkspaceId = conversation.workspace_id || _selectedChatWorkspaceId;
        _selectedChatFolderId = conversation.folder_id || _selectedChatFolderId;
        _selectedChatFolderLabel = conversation.folder_label || _selectedChatFolderLabel;
      } else {
        _setChatSendStatus('New chat failed.');
        if (sendBtn) sendBtn.disabled = false;
        return;
      }
    }
    if (!threadId) {
      _setChatSendStatus('New chat failed.');
      if (sendBtn) sendBtn.disabled = false;
      return;
    }
    _selectedChatThreadId = threadId;
    _chatFolderOnlySelection = false;
    _setChatSendStatus('Sending to ' + _chatRuntimeDisplayName(_selectedChatAdapter) + '...');
    const resp = await window.pywebview.api.send_chat_message(
      message.trim(),
      _selectedChatAdapter,
      threadId,
      _chatAttachments,
      _selectedChatWorkspaceId || 'runtime-ops',
      _selectedChatFolderId || 'runtime-control',
      _selectedChatFolderLabel || 'Runtime Control',
      ''
    );
    if (!resp || !resp.ok) {
      _setChatSendStatus('Send failed: ' + ((resp && resp.error && resp.error.message) || 'unknown error'));
      if (sendBtn) sendBtn.disabled = false;
      return;
    }
    const taskId = resp.data && resp.data.task_id;
    _pendingChatTaskId = taskId;
    if (input) input.value = '';
    _chatAttachments = [];
    _renderChatAttachmentTray();
    _setChatSendStatus('Sent. Waiting for ' + _chatRuntimeDisplayName(_selectedChatAdapter) + '.');
    await loadPhase11ChatPanel('', '', true);
    _startChatResultPolling(taskId, resp.data && resp.data.recipient);
  } catch (err) {
    _setChatSendStatus('Error: ' + escHtml(err.message || err));
    if (sendBtn) sendBtn.disabled = false;
  }
}

function _setChatSendStatus(text) {
  const el = document.getElementById('chat-send-status');
  if (!el) return;
  el.textContent = text;
  el.style.display = text ? '' : 'none';
}

function _startChatResultPolling(taskId, recipient) {
  if (_chatPollTimer) clearInterval(_chatPollTimer);
  if (!taskId) return;
  let attempts = 0;
  const maxAttempts = 30; // 30 × 2 s = 60 s timeout
  _chatPollTimer = setInterval(async () => {
    attempts++;
    try {
      const resp = await window.pywebview.api.poll_chat_result(taskId);
      const data = (resp && resp.ok && resp.data) || {};
      if (data.is_complete || data.is_blocked) {
        clearInterval(_chatPollTimer);
        _chatPollTimer = null;
        const sendBtn = document.getElementById('chat-send-button');
        if (sendBtn) sendBtn.disabled = false;
        if (data.is_blocked) {
          _setChatSendStatus('Runtime blocked or unavailable.');
        } else {
          _setChatSendStatus('Response received.');
        }
        _renderChatResult(data);
        await loadPhase11ChatPanel('', '', true);
        return;
      }
    } catch (_) {}
    if (attempts >= maxAttempts) {
      clearInterval(_chatPollTimer);
      _chatPollTimer = null;
      const sendBtn = document.getElementById('chat-send-button');
      if (sendBtn) sendBtn.disabled = false;
      _setChatSendStatus('Timed out waiting for runtime response.');
    }
  }, 2000);
}

function _renderChatResult(data) {
  const stream = document.getElementById('phase11-chat-conversation-stream');
  if (stream) {
    const text = _chatDisplayMessageContent(data.result_text || 'No response text returned.', _selectedChatAdapter);
    const status = data.status || 'complete';
    stream.insertAdjacentHTML('beforeend',
      '<article class="phase11-chat-message is-runtime">' +
      '<div class="phase11-chat-message-head"><strong>' + escHtml(_chatRuntimeDisplayName(_selectedChatAdapter)) + '</strong><span>' + escHtml(status) + '</span></div>' +
      '<p>' + escHtml(text) + '</p>' +
      '</article>'
    );
    stream.scrollTop = stream.scrollHeight;
    return;
  }
  const body = document.getElementById('chat-preview-body');
  if (!body) return;
  const text = _chatDisplayMessageContent(data.result_text || 'No response text returned.', _selectedChatAdapter);
  const status = data.status || 'unknown';
  body.innerHTML =
    '<div class="phase11-chat-result">' +
    '<div class="phase11-chat-result-header">Response <span class="panel-status-pill status-ok">' + escHtml(status) + '</span></div>' +
    '<div class="phase11-chat-result-text">' + escHtml(text) + '</div>' +
    '</div>';
}

function _chatPendingTaskIds(chatWorkspaces) {
  const threads = ((chatWorkspaces && chatWorkspaces.threads) || [])
    .filter(_chatIsProductVisibleThread)
    .filter(thread => !thread.thread_id || !thread.runtime_id || _chatThreadMatchesAdapter(thread, _selectedChatAdapter));
  const taskIds = [];
  const seen = new Set();
  threads.forEach(thread => {
    const messages = (thread.conversation_messages || thread.messages || []).filter(Boolean);
    const answeredTaskIds = new Set(messages
      .filter(message => String(message.role || '').toLowerCase() === 'runtime')
      .map(message => String(message.task_id || '').trim())
      .filter(Boolean));
    messages.forEach(message => {
      const taskId = String(message.task_id || '').trim();
      if (!taskId || seen.has(taskId) || answeredTaskIds.has(taskId)) return;
      if (String(message.role || '').toLowerCase() !== 'user') return;
      seen.add(taskId);
      taskIds.push(taskId);
    });
  });
  return taskIds.slice(0, 8);
}

function _refreshVisibleChatPendingResults(chatWorkspaces) {
  if (!window.pywebview || !window.pywebview.api || !window.pywebview.api.poll_chat_result) return;
  const taskIds = _chatPendingTaskIds(chatWorkspaces);
  if (!taskIds.length) return;
  let didHydrate = false;
  taskIds.forEach(taskId => {
    if (_chatPendingResultRefreshTasks.has(taskId)) return;
    _chatPendingResultRefreshTasks.add(taskId);
    window.pywebview.api.poll_chat_result(taskId)
      .then(resp => {
        const data = (resp && resp.ok && resp.data) || {};
        if (data.is_complete || data.is_blocked) didHydrate = true;
      })
      .catch(() => {})
      .finally(() => {
        _chatPendingResultRefreshTasks.delete(taskId);
        if (didHydrate && !_chatPendingResultRefreshTasks.size) {
          loadPhase11ChatPanel('', '', true);
        }
      });
  });
}

function _scrollChatTranscriptToLatest() {
  const stream = document.getElementById('phase11-chat-conversation-stream');
  const transcript = document.querySelector('.phase11-chat-transcript');
  [stream, transcript].forEach(element => {
    if (element) element.scrollTop = element.scrollHeight;
  });
}

function _startChatAvailabilityPolling() {
  _loadChatRuntimeAvailability();
  if (_chatAvailabilityTimer) clearInterval(_chatAvailabilityTimer);
  _chatAvailabilityTimer = setInterval(_loadChatRuntimeAvailability, 60000);
}

function _filterChatSlashCommandCatalog(value) {
  const raw = String(value || '');
  if (!raw.startsWith('/')) return [];
  const query = raw.toLowerCase().trim();
  return CHAT_SLASH_COMMAND_CATALOG.filter(command => {
    const haystack = [command.message, command.label, command.category, command.description].join(' ').toLowerCase();
    return !query || query === '/' || haystack.includes(query.replace(/^\//, '')) || String(command.message || '').toLowerCase().startsWith(query);
  }).slice(0, 12);
}

function _hideChatSlashCommandMenu() {
  const menu = document.getElementById('chat-slash-command-menu');
  if (!menu) return;
  menu.hidden = true;
  menu.innerHTML = '';
  _chatSlashCommandActiveIndex = 0;
}

function _renderChatSlashCommandMenu(input) {
  const menu = document.getElementById('chat-slash-command-menu');
  if (!menu || !input) return;
  const matches = _filterChatSlashCommandCatalog(input.value || '');
  if (!matches.length) {
    _hideChatSlashCommandMenu();
    return;
  }
  if (_chatSlashCommandActiveIndex >= matches.length) _chatSlashCommandActiveIndex = 0;
  if (_chatSlashCommandActiveIndex < 0) _chatSlashCommandActiveIndex = matches.length - 1;
  menu.hidden = false;
  menu.innerHTML = `<div class="chat-slash-command-menu-head">` +
    `<strong>Slash command suggestions</strong>` +
    `<span>ArrowDown / ArrowUp to scroll, Enter or Tab to Auto-fill read-only preview.</span>` +
    `</div>` +
    matches.map((command, index) => `<button type="button" role="option" class="chat-slash-command-option ${index === _chatSlashCommandActiveIndex ? 'is-active' : ''}" aria-selected="${index === _chatSlashCommandActiveIndex ? 'true' : 'false'}" data-chat-slash-command-message="${escAttr(command.message || '')}" data-chat-slash-command-index="${index}">` +
      `<span class="chat-slash-command-option-message">${escHtml(command.message || '')}</span>` +
      `<span class="chat-slash-command-option-copy"><strong>${escHtml(command.label || '')}</strong><em>${escHtml(command.description || '')}</em></span>` +
      `<span class="chat-slash-command-option-kind">${escHtml(command.kind || 'preview')}</span>` +
    `</button>`).join('');
}

function _applyChatSlashCommandSuggestion(message) {
  const input = document.getElementById('chat-message-input');
  if (!input || !message) return;
  input.value = String(message || '');
  input.focus();
  input.setSelectionRange(input.value.length, input.value.length);
  input.dispatchEvent(new Event('input', { bubbles: true }));
  _hideChatSlashCommandMenu();
  _setChatSendStatus('Auto-fill read-only preview: ' + input.value);
}

function _activeChatSlashCommandSuggestion() {
  const input = document.getElementById('chat-message-input');
  const matches = _filterChatSlashCommandCatalog(input ? input.value : '');
  return matches[_chatSlashCommandActiveIndex] || matches[0] || null;
}

function _stopChatAvailabilityPolling() {
  if (_chatAvailabilityTimer) { clearInterval(_chatAvailabilityTimer); _chatAvailabilityTimer = null; }
}

function _initPhase11ChatPanel() {
  initChatAdapterSelector();

  const sendBtn = document.getElementById('chat-send-button');
  const input = document.getElementById('chat-message-input');
  const attachFileBtn = document.getElementById('chat-attach-file-button');
  const attachImageBtn = document.getElementById('chat-attach-image-button');
  const fileInput = document.getElementById('chat-file-input');
  const imageInput = document.getElementById('chat-image-input');
  const attachmentTray = document.getElementById('chat-attachment-tray');
  const threadNav = document.getElementById('chat-thread-navigator');
  const newThreadBtn = document.getElementById('chat-new-thread-button');
  const newFolderBtn = document.getElementById('chat-new-folder-button');
  const folderDropdownBtn = document.getElementById('chat-folder-dropdown-button');
  const folderDropdownMenu = document.getElementById('chat-folder-dropdown-menu');
  const slashCommandMenu = document.getElementById('chat-slash-command-menu');
  const threadSearch = document.getElementById('chat-thread-search');
  const createInput = document.getElementById('chat-create-input');
  const createSubmit = document.getElementById('chat-create-submit-button');
  const createCancel = document.getElementById('chat-create-cancel-button');

  if (sendBtn) {
    sendBtn.addEventListener('click', () => {
      _sendChatMessage(input ? input.value : '');
    });
  }
  if (newThreadBtn) newThreadBtn.addEventListener('click', () => _showChatCreatePanel('thread'));
  if (newFolderBtn) newFolderBtn.addEventListener('click', () => _showChatCreatePanel('folder'));
  if (folderDropdownBtn) {
    folderDropdownBtn.addEventListener('click', () => {
      _chatFolderDropdownOpen = !_chatFolderDropdownOpen;
      _renderChatThreadNavigator(_lastChatWorkspacesFoundation || {});
    });
  }
  if (folderDropdownMenu) {
    folderDropdownMenu.addEventListener('click', event => {
      const selectBtn = event.target.closest('[data-chat-folder-menu-select]');
      const renameBtn = event.target.closest('[data-chat-folder-menu-rename]');
      const deleteBtn = event.target.closest('[data-chat-folder-menu-delete]');
      const action = selectBtn || renameBtn || deleteBtn;
      if (!action) return;
      event.preventDefault();
      const workspaceId = action.getAttribute('data-chat-workspace-id') || 'runtime-ops';
      const folderId = action.getAttribute('data-chat-folder-id') || 'runtime-control';
      const folderLabel = action.getAttribute('data-chat-folder-label') || folderId;
      if (selectBtn) {
        _chatFolderDropdownOpen = false;
        _selectChatFolder(workspaceId, folderId, folderLabel);
      } else if (renameBtn) {
        _renameChatFolderFromUi(workspaceId, folderId, folderLabel);
      } else if (deleteBtn) {
        _deleteChatFolderFromUi(workspaceId, folderId, folderLabel);
      }
    });
  }
  if (createSubmit) createSubmit.addEventListener('click', _submitChatCreatePanel);
  if (createCancel) createCancel.addEventListener('click', _hideChatCreatePanel);
  if (createInput) createInput.addEventListener('keydown', event => {
    if (event.key === 'Enter') {
      event.preventDefault();
      _submitChatCreatePanel();
    }
    if (event.key === 'Escape') {
      event.preventDefault();
      _hideChatCreatePanel();
    }
  });
  if (threadSearch) {
    threadSearch.addEventListener('input', () => {
      _chatThreadSearch = threadSearch.value || '';
      _renderChatThreadNavigator(_lastChatWorkspacesFoundation || {});
    });
  }
  if (attachFileBtn && fileInput) attachFileBtn.addEventListener('click', () => fileInput.click());
  if (attachImageBtn && imageInput) attachImageBtn.addEventListener('click', () => imageInput.click());
  if (fileInput) fileInput.addEventListener('change', event => {
    _stageChatAttachments(event.target.files, 'file');
    event.target.value = '';
  });
  if (imageInput) imageInput.addEventListener('change', event => {
    _stageChatAttachments(event.target.files, 'image');
    event.target.value = '';
  });
  if (attachmentTray) {
    attachmentTray.addEventListener('click', event => {
      const remove = event.target.closest('[data-chat-remove-attachment]');
      if (!remove) return;
      const index = Number(remove.getAttribute('data-chat-remove-attachment'));
      _chatAttachments.splice(index, 1);
      _renderChatAttachmentTray();
    });
  }
  if (threadNav) {
    threadNav.addEventListener('click', event => {
      const folder = event.target.closest('[data-chat-folder-target]');
      if (folder) {
        event.preventDefault();
        _selectChatFolder(
          folder.getAttribute('data-chat-workspace-id') || '',
          folder.getAttribute('data-chat-folder-id') || '',
          folder.getAttribute('data-chat-folder-label') || ''
        );
        return;
      }
      const row = event.target.closest('[data-chat-thread-id]');
      if (!row) return;
      event.preventDefault();
      _selectChatThread(
        row.getAttribute('data-chat-thread-id') || '',
        row.getAttribute('data-chat-runtime-id') || '',
        row.getAttribute('data-chat-workspace-id') || '',
        row.getAttribute('data-chat-folder-id') || '',
        row.getAttribute('data-chat-folder-label') || ''
      );
    });
  }
  if (input) {
    input.addEventListener('input', () => {
      _chatSlashCommandActiveIndex = 0;
      _renderChatSlashCommandMenu(input);
    });
    input.addEventListener('keydown', event => {
      const menuOpen = slashCommandMenu && !slashCommandMenu.hidden;
      if (menuOpen && ['ArrowDown', 'ArrowUp', 'Enter', 'Tab', 'Escape'].includes(event.key)) {
        if (event.key === 'Escape') {
          event.preventDefault();
          _hideChatSlashCommandMenu();
          return;
        }
        if (event.key === 'ArrowDown') {
          event.preventDefault();
          _chatSlashCommandActiveIndex += 1;
          _renderChatSlashCommandMenu(input);
          return;
        }
        if (event.key === 'ArrowUp') {
          event.preventDefault();
          _chatSlashCommandActiveIndex -= 1;
          _renderChatSlashCommandMenu(input);
          return;
        }
        if (event.key === 'Enter' || event.key === 'Tab') {
          const active = _activeChatSlashCommandSuggestion();
          if (active) {
            event.preventDefault();
            _applyChatSlashCommandSuggestion(active.message);
            return;
          }
        }
      }
      if ((event.ctrlKey || event.metaKey) && event.key === 'Enter') {
        event.preventDefault();
        _sendChatMessage(input.value);
      }
    });
  }
  if (slashCommandMenu) {
    slashCommandMenu.addEventListener('click', event => {
      const option = event.target.closest('[data-chat-slash-command-message]');
      if (!option) return;
      event.preventDefault();
      _applyChatSlashCommandSuggestion(option.getAttribute('data-chat-slash-command-message') || '');
    });
  }
  const body = document.getElementById('chat-preview-body');
  if (body) {
    body.addEventListener('click', event => {
      const inlineRuntimeBtn = event.target.closest('[data-chat-inline-runtime]');
      if (inlineRuntimeBtn) {
        event.preventDefault();
        _selectChatAdapter(inlineRuntimeBtn.getAttribute('data-chat-inline-runtime') || 'hermes', { resetThread: true });
        return;
      }
      const startRuntimeBtn = event.target.closest('[data-chat-start-runtime-control]');
      if (startRuntimeBtn) {
        event.preventDefault();
        _startChatDaemon();
        return;
      }
      const stopRuntimeBtn = event.target.closest('[data-chat-stop-runtime-control]');
      if (stopRuntimeBtn) {
        event.preventDefault();
        _stopChatDaemon();
        return;
      }
      const threadRow = event.target.closest('[data-chat-thread-id]');
      if (threadRow) {
        event.preventDefault();
        _selectChatThread(
          threadRow.getAttribute('data-chat-thread-id') || '',
          threadRow.getAttribute('data-chat-runtime-id') || '',
          threadRow.getAttribute('data-chat-workspace-id') || '',
          threadRow.getAttribute('data-chat-folder-id') || '',
          threadRow.getAttribute('data-chat-folder-label') || ''
        );
        return;
      }
      const moveBtn = event.target.closest('[data-chat-move-thread-folder]');
      if (moveBtn) {
        event.preventDefault();
        _moveSelectedChatToFolder(
          moveBtn.getAttribute('data-chat-workspace-id') || 'runtime-ops',
          moveBtn.getAttribute('data-chat-folder-id') || 'runtime-control',
          moveBtn.getAttribute('data-chat-folder-label') || 'Runtime Control'
        );
        return;
      }
      const renameFolderBtn = event.target.closest('[data-chat-rename-current-folder]');
      if (renameFolderBtn) {
        event.preventDefault();
        _renameChatFolderFromUi(_selectedChatWorkspaceId, _selectedChatFolderId, _selectedChatFolderLabel);
        return;
      }
      const deleteFolderBtn = event.target.closest('[data-chat-delete-current-folder]');
      if (deleteFolderBtn) {
        event.preventDefault();
        _deleteChatFolderFromUi(_selectedChatWorkspaceId, _selectedChatFolderId, _selectedChatFolderLabel);
        return;
      }
      const deleteThreadBtn = event.target.closest('[data-chat-delete-current-thread]');
      if (deleteThreadBtn) {
        event.preventDefault();
        _deleteSelectedChatThread();
        return;
      }
      const laneBtn = event.target.closest('[data-phase11-authority-target]');
      if (laneBtn) {
        event.preventDefault();
        _phase11AuthorityOpenLane(laneBtn.getAttribute('data-phase11-authority-target') || '');
        return;
      }
      const authorityExecBtn = event.target.closest('[data-phase11-authority-execution-action]');
      if (authorityExecBtn) {
        event.preventDefault();
        _phase11AuthorityExecutionRunAction(authorityExecBtn.getAttribute('data-phase11-authority-execution-action') || '');
        return;
      }
      const slashActionBtn = event.target.closest('[data-phase11-slash-action-message]');
      if (slashActionBtn) {
        event.preventDefault();
        const slashMessage = slashActionBtn.getAttribute('data-phase11-slash-action-message') || '';
        if (input) input.value = slashMessage;
        _setChatSendStatus('Run read-only preview: ' + slashMessage);
        loadPhase11ChatPanel(slashMessage, '', true);
        return;
      }
      const btn = event.target.closest('[data-phase11-schedule-action]');
      if (!btn) return;
      event.preventDefault();
      _phase11ScheduleRunAction(btn.getAttribute('data-phase11-schedule-action') || '');
    });
  }

  const daemonStartBtn = document.getElementById('chat-daemon-start-btn');
  const daemonStopBtn  = document.getElementById('chat-daemon-stop-btn');
  if (daemonStartBtn) daemonStartBtn.addEventListener('click', _startChatDaemon);
  if (daemonStopBtn)  daemonStopBtn.addEventListener('click', _stopChatDaemon);

  // Initialise daemon control state for default adapter
  _refreshDaemonControlState(_selectedChatAdapter);
}

async function loadPhase11ChatPanel(message, explicitIntent, force) {
  const body = document.getElementById('chat-preview-body');
  const provider = document.getElementById('chat-provider-readiness');
  const status = document.getElementById('chat-status');
  const input = document.getElementById('chat-message-input');
  if (!body) return;
  if (chatLoaded && !force) return;
  const text = message !== undefined ? message : (input ? input.value : '');
  const initialFoundation = _lastChatWorkspacesFoundation || { folders: [], threads: [], summary: {} };
  body.innerHTML = _phase11ChatProductShellDesk({
    product_chat_shell_only: true,
    chat_workspaces_foundation: initialFoundation,
    summary: { intent_class: explicitIntent || 'chat' },
  }, '');
  _renderChatThreadNavigator(initialFoundation);
  if (provider) { provider.innerHTML = ''; provider.hidden = true; }
  if (status) { status.textContent = 'Ready'; status.className = 'panel-status-pill status-ok'; }

  try {
    const availabilityPromise = _loadChatRuntimeAvailability().catch(() => null);
    const resp = await window.pywebview.api.get_phase11_chat_workspaces_foundation(text || '', explicitIntent || '');
    if (!resp || !resp.ok) {
      body.innerHTML = `<div style="color:var(--ts-disputed);font-size:12px">${escHtml((resp && resp.error && resp.error.message) || 'Error')}</div>`;
      if (status) { status.textContent = 'Error'; status.className = 'panel-status-pill status-error'; }
      return;
    }
    renderPhase11ChatPanel({
      product_chat_shell_only: true,
      summary: {
        intent_class: explicitIntent || 'chat',
        route_family: 'studio_chat_workspace_thread',
        route_execution_allowed: true,
      },
      router_contract: {
        route_decision: {
          next_surface: 'chat',
          route_family: 'studio_chat_workspace_thread',
          policy_execution_allowed: true,
        },
      },
      chat_workspaces_foundation: resp.data || {},
    });
    availabilityPromise.then(() => {
      _refreshDaemonControlState(_selectedChatAdapter);
      _renderChatRuntimeSyncPanel();
    }).catch(() => {});
    chatLoaded = true;
    // Apply composer prefill to the visible input after panel render
    if (text && text.trim()) {
      const chatInput = document.getElementById('chat-message-input');
      if (chatInput && !chatInput.value) {
        chatInput.value = text.trim();
        chatInput.focus();
        chatInput.dispatchEvent(new Event('input', { bubbles: true })); // trigger auto-resize
      }
    }
  } catch (err) {
    body.innerHTML = `<div style="color:var(--ts-disputed);font-size:12px">${escHtml(err.message)}</div>`;
    if (status) { status.textContent = 'Error'; status.className = 'panel-status-pill status-error'; }
  }
}

