  const browserDispatchReadiness = data.browser_dispatch_readiness_contract || {};
  const approvalConsumptionReadiness = data.approval_consumption_readiness_contract || {};
  const safetyPolicy = data.safety_policy || {};
  const safetySummary = safetyPolicy.policy_fail_closed_summary || {};
  const companionStatus = data.companion_status_contract || {};
  const companionRosterPreview = data.companion_roster_ui_preview || {};
  const companionMemoryBoundary = data.companion_memory_boundary_contract || {};
  const companionMemoryApproval = data.companion_memory_approval_preview || {};
  const companionMemoryExecution = data.companion_memory_approved_execution_proof || {};
  const companionMemoryReadback = data.companion_memory_readback_search_preview || {};
  const companionMemoryLedgerWrite = data.companion_memory_ledger_write_approval_preview || {};
  const companionMemoryLedgerExecution = data.companion_memory_approved_ledger_write_execution_proof || {};
  const companionMemoryLedgerReadModel = data.companion_memory_ledger_read_model_preview || {};
  const companionMemoryRealLedgerCloseout = data.companion_memory_real_ledger_activation_closeout || {};
