function _phase11ScheduleFieldValue(id, fallback) {
  const el = document.getElementById(id);
  if (!el) return fallback || '';
  return el.value || fallback || '';
}

function _phase11ScheduleSetField(id, value) {
  const el = document.getElementById(id);
  if (el && value !== undefined && value !== null && String(value)) el.value = String(value);
}

function _phase11SchedulePayload() {
  return {
    workflowId: _phase11ScheduleFieldValue('phase11-schedule-workflow-id', 'operator_today'),
    cronExpression: _phase11ScheduleFieldValue('phase11-schedule-cron', '0 8 * * 1-5'),
    timezoneName: _phase11ScheduleFieldValue('phase11-schedule-timezone', 'America/New_York'),
    runtimeAdapterTarget: _phase11ScheduleFieldValue('phase11-schedule-adapter', 'openclaw'),
    scheduleSummary: _phase11ScheduleFieldValue('phase11-schedule-summary', 'Schedule operator_today from Studio Chat manual controls.'),
    scheduleId: _phase11ScheduleFieldValue('phase11-schedule-id', phase11ScheduleUiState.scheduleId || ''),
    approvalId: _phase11ScheduleFieldValue('phase11-schedule-approval-id', phase11ScheduleUiState.approvalId || ''),
    scheduleDigest: _phase11ScheduleFieldValue('phase11-schedule-digest', phase11ScheduleUiState.scheduleDigest || ''),
    stagedProposalPath: _phase11ScheduleFieldValue('phase11-schedule-staged-path', phase11ScheduleUiState.stagedProposalPath || ''),
    activationDigest: _phase11ScheduleFieldValue('phase11-schedule-activation-digest', phase11ScheduleUiState.activationDigest || ''),
    exportDigest: _phase11ScheduleFieldValue('phase11-schedule-export-digest', phase11ScheduleUiState.exportDigest || ''),
    operatorApprovalStatement: _phase11ScheduleFieldValue('phase11-schedule-approval-statement', 'Approved from Studio Chat manual schedule test.'),
    operatorScheduleWriteStatement: _phase11ScheduleFieldValue('phase11-schedule-write-statement', 'Approved to write the disabled ChaseOS schedule intent from Studio Chat manual controls.'),
    operatorActivationStatement: _phase11ScheduleFieldValue('phase11-schedule-activation-statement', 'Approved to enable this ChaseOS schedule and regenerate the schedule index only.'),
    operatorExportWriteStatement: _phase11ScheduleFieldValue('phase11-schedule-export-statement', 'Approved to write the local adapter export packet only.'),
  };
}

function _phase11ScheduleSetStatus(text, statusClass) {
  const el = document.getElementById('phase11-schedule-ui-status');
  if (!el) return;
  el.textContent = text || '';
  el.className = 'phase11-schedule-ui-status ' + (statusClass || '');
}

function _phase11ScheduleStoreResponse(action, resp) {
  const data = (resp && resp.data) || {};
  phase11ScheduleUiState.lastAction = action;
  phase11ScheduleUiState.lastResponse = resp;
  const summary = data.summary || {};
  const digest = data.digest_proof || {};
  const queue = data.approval_queue_write || {};
  const target = data.target_write || data.target_write_proof || {};
  if (summary.schedule_id || target.schedule_id) phase11ScheduleUiState.scheduleId = summary.schedule_id || target.schedule_id;
  if (summary.approval_id || queue.approval_id) phase11ScheduleUiState.approvalId = summary.approval_id || queue.approval_id;
  if (digest.schedule_digest) phase11ScheduleUiState.scheduleDigest = digest.schedule_digest;
  if (digest.activation_digest) phase11ScheduleUiState.activationDigest = digest.activation_digest;
  if (digest.export_digest) phase11ScheduleUiState.exportDigest = digest.export_digest;
  if (target.staged_schedule_proposal_path) phase11ScheduleUiState.stagedProposalPath = target.staged_schedule_proposal_path;
  if (target.export_packet_path || target.target_path) phase11ScheduleUiState.exportPacketPath = target.export_packet_path || target.target_path;
  _phase11ScheduleSetField('phase11-schedule-id', phase11ScheduleUiState.scheduleId);
  _phase11ScheduleSetField('phase11-schedule-approval-id', phase11ScheduleUiState.approvalId);
  _phase11ScheduleSetField('phase11-schedule-digest', phase11ScheduleUiState.scheduleDigest);
  _phase11ScheduleSetField('phase11-schedule-staged-path', phase11ScheduleUiState.stagedProposalPath);
  _phase11ScheduleSetField('phase11-schedule-activation-digest', phase11ScheduleUiState.activationDigest);
  _phase11ScheduleSetField('phase11-schedule-export-digest', phase11ScheduleUiState.exportDigest);
  const pre = document.getElementById('phase11-schedule-ui-readback-json');
  if (pre) pre.textContent = JSON.stringify(resp, null, 2);
}

async function _phase11ScheduleRunAction(action) {
  if (!window.pywebview || !window.pywebview.api || !action) return;
  const payload = _phase11SchedulePayload();
  _phase11ScheduleSetStatus(`Running ${action}...`, 'status-loading');
  try {
    let resp = null;
    if (action === 'preview-proposal') {
      resp = await window.pywebview.api.get_phase11_chat_schedule_proposal_packet('', payload.workflowId, '', '', payload.cronExpression, payload.timezoneName, payload.runtimeAdapterTarget, '', payload.scheduleSummary);
    } else if (action === 'queue-proposal') {
      resp = await window.pywebview.api.request_phase11_chat_schedule_proposal_packet(payload.scheduleDigest, '', payload.workflowId, '', '', payload.cronExpression, payload.timezoneName, payload.runtimeAdapterTarget, '', payload.scheduleSummary);
    } else if (action === 'consume-proposal') {
      resp = await window.pywebview.api.execute_phase11_chat_schedule_proposal_consumption(payload.approvalId, payload.scheduleDigest, 'studio-operator', payload.operatorApprovalStatement);
    } else if (action === 'write-intent') {
      resp = await window.pywebview.api.execute_phase11_chat_approved_schedule_intent_writer(payload.stagedProposalPath, payload.scheduleId, payload.scheduleDigest, 'studio-operator', payload.operatorScheduleWriteStatement);
    } else if (action === 'preview-activation') {
      resp = await window.pywebview.api.get_phase11_chat_schedule_intent_activation_readiness(payload.scheduleId);
    } else if (action === 'queue-activation') {
      resp = await window.pywebview.api.request_phase11_chat_schedule_intent_activation(payload.activationDigest, payload.scheduleId, 'studio-operator');
    } else if (action === 'activate-schedule') {
      resp = await window.pywebview.api.execute_phase11_chat_approved_schedule_activation(payload.approvalId, payload.activationDigest, 'studio-operator', payload.operatorActivationStatement);
    } else if (action === 'preview-export') {
      resp = await window.pywebview.api.get_phase11_chat_schedule_adapter_export_readiness(payload.runtimeAdapterTarget, payload.scheduleId);
    } else if (action === 'queue-export') {
      resp = await window.pywebview.api.request_phase11_chat_schedule_adapter_export(payload.exportDigest, payload.runtimeAdapterTarget, payload.scheduleId, 'studio-operator');
    } else if (action === 'write-export-packet') {
      resp = await window.pywebview.api.execute_phase11_chat_approved_schedule_adapter_export_packet_writer(payload.approvalId, payload.exportDigest, 'studio-operator', payload.operatorExportWriteStatement);
    }
    _phase11ScheduleStoreResponse(action, resp || {});
    _phase11ScheduleSetStatus(resp && resp.ok ? `${action} complete` : `${action} blocked`, resp && resp.ok ? 'status-ok' : 'status-error');
  } catch (err) {
    _phase11ScheduleStoreResponse(action, { ok: false, error: { message: err.message } });
    _phase11ScheduleSetStatus(`${action} failed`, 'status-error');
  }
}

