async function _loadRuntimeIntelligencePanel(panelId, apiMethod, renderer) {
  const body = document.getElementById(`${panelId}-body`);
  const status = document.getElementById(`${panelId}-status`);
  if (!body) return false;
  renderProductSyncFallback(panelId, body, status);

  try {
    const resp = await studioApiResultWithTimeout(
      () => window.pywebview.api[apiMethod](),
      productLabel(panelId, 'Runtime intelligence'),
    );
    if (!resp || !resp.ok) {
      if (resp && resp.timed_out) {
        if (status) {
          status.textContent = 'Pending';
          status.className = 'panel-status-pill status-ok';
        }
        return true;
      }
      body.innerHTML = `<div style="color:var(--ts-disputed);font-size:12px">${escHtml((resp && resp.error && resp.error.message) || 'Error')}</div>`;
      if (status) status.textContent = 'Error';
      return false;
    }
    renderer(resp.data || {});
    return true;
  } catch (err) {
    body.innerHTML = `<div style="color:var(--ts-disputed);font-size:12px">${escHtml(err.message)}</div>`;
    if (status) status.textContent = 'Error';
    return false;
  }
}

function renderProvenanceExplorerPanel(data) {
  const body = document.getElementById('provenance-explorer-body');
  const status = document.getElementById('provenance-explorer-status');
  if (!body) return;

  const summary = data.summary || {};
  const source = data.source || {};
  const authority = data.authority || {};
  const records = data.records || [];
  const trustCounts = summary.trust_state_counts || {};
  const recordCount = summary.record_count || records.length;

  if (status) status.textContent = recordCount > 0 ? `${recordCount} records` : 'Ready';
  const overviewHtml = operatorSurfaceOverview(
    'Provenance trail',
    'Follow how content enters ChaseOS, moves through trust states, and links back to sources without changing the underlying records.',
    [
      { label: 'records', value: recordCount, note: 'origin trails' },
      { label: 'states', value: Object.keys(trustCounts).length || 0, note: 'trust groups' },
      { label: 'posture', value: authority.writes_provenance ? 'Managed' : 'Inspect', note: 'no mutation' },
    ],
  );

  // ── Trust state distribution pills ───────────────────────────────────────
  const _trustCls = (ts) => {
    const t = String(ts || '').toLowerCase();
    if (t === 'promoted') return 'ts-promoted';
    if (t === 'quarantined' || t === 'unscanned-quarantine') return 'ts-quarantined';
    if (t === 'flagged') return 'ts-disputed';
    if (t === 'suggested' || t === 'scanned-clean') return 'ts-suggested';
    if (t === 'canonical') return 'ts-canonical';
    return 'ts-raw';
  };
  const trustPills = Object.entries(trustCounts).length
    ? `<div class="provenance-trust-pills">` +
      Object.entries(trustCounts).sort((a, b) => b[1] - a[1]).map(([state, count]) =>
        `<span class="provenance-trust-pill ${_trustCls(state)}">${escHtml(productLabel(state, 'Raw'))} <b>${escHtml(count)}</b></span>`
      ).join('') +
      `</div>`
    : '';

  // ── Records list with trust state color badges ────────────────────────────
  let recordsHtml = '';
  if (records.length) {
    recordsHtml =
      `<div class="provenance-record-list">` +
      records.map(item => {
        const title = item.title || item.file_name || item.capture_id || 'record';
        const trust = item.trust_state || 'raw';
        const platform = item.source_platform || '—';
        const captured = item.captured_at ? item.captured_at.slice(0, 16) : '—';
        return `<div class="provenance-record-card">
          <div class="provenance-record-header">
            <span class="provenance-record-title" title="${escAttr(title)}">${escHtml(title.length > 55 ? title.slice(0, 52) + '…' : title)}</span>
            <span class="intake-trust-badge ${_trustCls(trust)}">${escHtml(productLabel(trust, 'Raw'))}</span>
          </div>
          <div class="provenance-record-meta">
            <span class="provenance-meta-tag">${escHtml(platform)}</span>
            <span class="provenance-meta-tag">${escHtml(captured)}</span>
          </div>
        </div>`;
      }).join('') +
      `</div>`;
  } else {
    recordsHtml = emptyState('↩', 'No provenance records', 'Captured content builds a provenance chain as it moves from quarantine to your knowledge base.', 'Use Capture to add source material.');
  }

  // ── Technical details (collapsed) ─────────────────────────────────────────
  const techDetails =
    `<details class="provenance-tech-details">` +
    `<summary>Details</summary>` +
    _runtimeIntelSection('Authority', [
      ['Inspection mode', authority.read_only],
      ['Can update provenance', authority.writes_provenance],
      ['Can update memory', authority.writes_memory],
      ['Provider calls', authority.provider_calls_allowed],
      ['Canonical updates', authority.canonical_mutation_allowed],
    ]) +
    _runtimeIntelSection('Source', [
      ['Content body read', source.content_body_read],
      ['Record count', recordCount],
    ]) +
    `</details>`;

  body.innerHTML = overviewHtml + trustPills + recordsHtml + techDetails;
  wireOperatorSurfaceCards(body, 'provenance-explorer', 'Knowledge Graph');
}

function renderMemoryLedgerPanel(data) {
  const body = document.getElementById('memory-ledger-body');
  const status = document.getElementById('memory-ledger-status');
  if (!body) return;

  const summary = data.summary || {};
  const authority = data.authority || {};
  const readiness = data.readiness || {};
  const runtimeCoverage = ((data.runtime_summary || {}).runtime_coverage || []);
  const tasks = ((data.task_summary || {}).active_task_contexts || []);
  const attention = data.attention_items || [];

  const runtimeCount = summary.runtime_count || runtimeCoverage.length || 0;
  if (status) status.textContent = runtimeCount > 0 ? `${runtimeCount} runtime${runtimeCount !== 1 ? 's' : ''}` : 'Ready';

  // ── Per-runtime memory coverage cards ─────────────────────────────────────
  let coverageHtml = '';
  if (runtimeCoverage.length) {
    coverageHtml =
      `<div class="ml-runtime-grid">` +
      runtimeCoverage.map(item => {
        const rid = item.runtime_id || 'runtime';
        const complete = item.complete;
        const present = (item.present_families || []);
        const missing = (item.missing_families || []);
        return `<div class="ml-runtime-card" data-memory-ledger-id="${escAttr(rid)}">
          <div class="ml-runtime-card-header">
            <span class="ml-runtime-name">${escHtml(rid)}</span>
            <span class="ml-runtime-status ${complete ? 'ml-status-complete' : 'ml-status-partial'}">${complete ? 'Complete' : 'Partial'}</span>
          </div>
          <div class="ml-runtime-stat-row">
            <span class="ml-runtime-stat"><b>${present.length}</b> memory files present</span>
            ${missing.length ? `<span class="ml-runtime-stat ml-stat-missing"><b>${missing.length}</b> missing</span>` : ''}
          </div>
          ${present.length ? `<div class="ml-families">${present.map(f => `<span class="ml-family-tag">${escHtml(f)}</span>`).join('')}</div>` : ''}
        </div>`;
      }).join('') +
      `</div>`;
  } else {
    coverageHtml = emptyState('◑', 'No memory records yet', 'Runtime memory builds up as your agents run tasks, learn routes, and record repairs.', 'chaseos agent-bus heartbeats');
  }

  // ── Active task contexts ───────────────────────────────────────────────────
  if (!runtimeCoverage.length) {
    coverageHtml += operatorSurfaceCards([
      {
        id: 'memory-runtime-coverage',
        title: 'Runtime Coverage',
        status: 'Waiting',
        body: 'Runtime memory coverage appears here as Hermes, OpenClaw, Codex, and future workers publish governed context records.',
        meta: ['Hermes', 'OpenClaw', 'Codex'],
      },
      {
        id: 'memory-task-context',
        title: 'Task Context',
        status: 'Ready',
        body: 'Active task context links work packets to the memory and graph surfaces they should inspect.',
        meta: ['Tasks', 'Routes', 'Context'],
      },
      {
        id: 'memory-governance',
        title: 'Memory Governance',
        status: 'Gated',
        body: 'Memory suggestions, runtime brain updates, and canonical promotion remain governed outside this page.',
        meta: ['Review', 'Approval', 'Ledger'],
      },
    ]);
  }

  let tasksHtml = '';
  if (tasks.length) {
    tasksHtml =
      `<div class="ml-section-title">Active Task Contexts (${tasks.length})</div>` +
      `<div class="ml-task-list">` +
      tasks.slice(0, 8).map(item =>
        `<div class="ml-task-item" data-memory-task-id="${escAttr(item.task_id || 'task')}">
          <span class="ml-task-id">${escHtml(item.task_id || 'task')}</span>
          <span class="ml-task-meta">${escHtml(item.runtime_id || '')} · ${escHtml(item.status || 'unknown')}</span>
          ${item.objective ? `<span class="ml-task-objective">${escHtml(item.objective)}</span>` : ''}
        </div>`
      ).join('') +
      `</div>`;
  }

  // ── Attention items ────────────────────────────────────────────────────────
  let attentionHtml = '';
  if (attention.length) {
    attentionHtml =
      `<div class="ml-attention-list">` +
      attention.slice(0, 5).map((item, idx) =>
        `<div class="ml-attention-item" data-memory-attention-id="${escAttr(item.code || item.target || 'attention-' + idx)}">
          <span class="ml-attention-code">${escHtml(item.code || item.severity || '!')}</span>
          <span class="ml-attention-msg">${escHtml((item.target ? item.target + ': ' : '') + (item.message || ''))}</span>
        </div>`
      ).join('') +
      `</div>`;
  }

  // ── Technical details (collapsed) ─────────────────────────────────────────
  const techDetails =
    `<details class="ml-tech-details">` +
    `<summary>Evidence &amp; Boundaries</summary>` +
    _runtimeIntelSection('Authority', [
      ['Read only', authority.read_only],
      ['Writes memory', authority.writes_memory],
      ['Approves memory', authority.approves_memory],
      ['Applies candidates', authority.applies_memory_candidates],
      ['Runtime brain update', authority.updates_runtime_brain],
      ['Canonical mutation', authority.canonical_mutation_allowed],
    ]) +
    `<div class="ml-tech-next">Next: ${escHtml(readiness.next_recommended_pass || 'unknown')}</div>` +
    `</details>`;

  const productOverview =
    `<div class="runtime-product-overview">
      <div class="runtime-product-copy">
        <strong>Memory is observable here, not mutated here.</strong>
        <span>Review runtime coverage, active task context, and attention signals while keeping candidate application, canonical promotion, and runtime brain updates in governed flows.</span>
      </div>
      <div class="runtime-product-metrics" aria-label="Memory ledger overview">
        <span><b>${escHtml(runtimeCount)}</b>Runtimes</span>
        <span><b>${escHtml(tasks.length)}</b>Tasks</span>
        <span><b>${escHtml(attention.length)}</b>Attention</span>
      </div>
    </div>`;

  body.innerHTML = productOverview + coverageHtml + tasksHtml + attentionHtml + techDetails;
  wireOperatorSurfaceCards(body, 'memory-ledger', 'Personal Memory');

  body.querySelectorAll('.ml-runtime-card').forEach(card => {
    card.addEventListener('click', () => {
      const rid = card.dataset.memoryLedgerId || 'runtime';
      const item = runtimeCoverage.find(row => String(row.runtime_id || 'runtime') === String(rid)) || {};
      renderObjectInspectorProductContext({
        id: rid,
        label: rid,
        type: 'Memory Ledger Runtime',
        kicker: 'Selected Memory',
        panel: 'memory-ledger',
        status: item.complete ? 'complete' : 'partial',
        ownerLabel: 'Runtime',
        owner: rid,
        timeLabel: 'Families',
        time: `${(item.present_families || []).length || 0} present`,
        ref: rid,
        openLabel: 'Open Ledger',
        note: 'Read-only memory coverage. Applying candidates, runtime brain updates, and canonical promotion remain governed elsewhere.',
      });
    });
  });
  body.querySelectorAll('.ml-task-item').forEach(card => {
    card.addEventListener('click', () => {
      const taskId = card.dataset.memoryTaskId || 'task';
      const item = tasks.find(row => String(row.task_id || 'task') === String(taskId)) || {};
      renderObjectInspectorProductContext({
        id: taskId,
        label: item.objective || taskId,
        type: 'Task Context',
        kicker: 'Selected Memory Context',
        panel: 'memory-ledger',
        status: item.status || 'unknown',
        ownerLabel: 'Runtime',
        owner: item.runtime_id || 'unknown',
        timeLabel: 'Task',
        time: taskId,
        ref: taskId,
        openLabel: 'Open Ledger',
        note: 'Task context is inspectable only. Task dispatch, retry, approval consumption, and memory mutation are not available from this panel.',
      });
    });
  });
  body.querySelectorAll('.ml-attention-item').forEach(card => {
    card.addEventListener('click', () => {
      const attentionId = card.dataset.memoryAttentionId || 'attention';
      const item = attention.find(row => String(row.code || row.target || '') === String(attentionId)) || {};
      renderObjectInspectorProductContext({
        id: attentionId,
        label: item.message || attentionId,
        type: 'Memory Attention',
        kicker: 'Selected Attention Item',
        panel: 'memory-ledger',
        status: item.severity || item.code || 'attention',
        ownerLabel: 'Target',
        owner: item.target || 'memory',
        timeLabel: 'Source',
        time: 'ledger',
        ref: item.target || attentionId,
        openLabel: 'Open Ledger',
        note: 'Attention items are review signals only. They do not apply memory or promote canonical state from the UI.',
      });
    });
  });
}

function renderAgentIdentityPanel(data) {
  const body = document.getElementById('agent-identity-body');
  const status = document.getElementById('agent-identity-status');
  if (!body) return;

  const summary = data.summary || {};
  const authority = data.authority || {};
  const readiness = data.readiness || {};
  const identities = data.identities || [];

  const runtimeCount = summary.runtime_count || identities.length || 0;
  if (status) status.textContent = runtimeCount > 0 ? `${runtimeCount} ledger${runtimeCount !== 1 ? 's' : ''}` : 'No ledgers';
  const driftTotal = identities.reduce((total, item) => total + (item.drift_signal_count || (item.drift_signals || []).length || 0), 0);
  const overviewHtml = operatorSurfaceOverview(
    'Runtime identity',
    'Track runtime roles, trust posture, permissions, and drift signals before sensitive work can proceed.',
    [
      { label: 'ledgers', value: runtimeCount, note: 'registered runtimes' },
      { label: 'drift', value: driftTotal, note: 'signals' },
      { label: 'posture', value: authority.writes_identity_ledger ? 'Managed' : 'Inspect', note: 'Studio surface' },
    ],
  );

  // ── Per-runtime identity cards ─────────────────────────────────────────────
  let identityHtml = '';
  if (identities.length) {
    identityHtml =
      `<div class="ai-ledger-grid">` +
      identities.map(item => {
        const rid = item.runtime_id || 'runtime';
        const ledgerStatus = item.status || 'unknown';
        const posture = item.current_actor_posture || '';
        const driftCount = item.drift_signal_count || (item.drift_signals || []).length || 0;
        const driftSignals = (item.drift_signals || []).slice(0, 3);
        const postureClass = ledgerStatus === 'seeded' ? 'ai-posture-seeded' : 'ai-posture-missing';
        return `<div class="ai-ledger-card">
          <div class="ai-ledger-card-header">
            <span class="ai-ledger-name">${escHtml(rid)}</span>
            <span class="ai-posture-badge ${postureClass}">${escHtml(ledgerStatus)}</span>
            ${driftCount > 0 ? `<span class="ai-drift-count">${escHtml(driftCount)} drift</span>` : ''}
          </div>
          ${posture ? `<div class="ai-posture-summary">${escHtml(posture)}</div>` : ''}
          ${driftSignals.length ? `<div class="ai-drift-signals">${driftSignals.map(s =>
            `<div class="ai-drift-signal"><span>${escHtml(s.id || s.status || 'signal')}</span><span>${escHtml(s.summary || '')}</span></div>`
          ).join('')}</div>` : ''}
        </div>`;
      }).join('') +
      `</div>`;
  } else {
    identityHtml = emptyState('ID', 'Runtime identity lanes', 'Identity ledgers appear here after a runtime declares its role, trust posture, and heartbeat source.', '');
  }

  // ── Technical details (collapsed) ─────────────────────────────────────────
  if (!identities.length) {
    identityHtml = operatorSurfaceCards([
      {
        id: 'identity-hermes',
        title: 'Hermes',
        status: 'Expected lane',
        body: 'Workspace helper identity appears here after the runtime registers its role and heartbeat source.',
        meta: ['Trust tier', 'Permission posture', 'Drift watch'],
      },
      {
        id: 'identity-openclaw',
        title: 'OpenClaw',
        status: 'Expected lane',
        body: 'Agent-control identity appears here after the runtime declares its worker boundary.',
        meta: ['Agent Bus', 'Approval posture', 'Runtime scope'],
      },
      {
        id: 'identity-codex',
        title: 'Codex',
        status: 'Expected lane',
        body: 'Repo-aware worker identity appears here when bounded activity is registered.',
        meta: ['Patch scope', 'Test runs', 'Activity record'],
      },
    ]);
  }

  const techDetails =
    `<details class="ai-tech-details">` +
    `<summary>Evidence &amp; Boundaries</summary>` +
    _runtimeIntelSection('Authority', [
      ['Read only', authority.read_only],
      ['Writes identity ledger', authority.writes_identity_ledger],
      ['Updates trust tiers', authority.updates_trust_tiers],
      ['Updates permissions', authority.updates_permission_matrix],
      ['Agent Bus writes', authority.writes_agent_bus_tasks],
      ['Canonical mutation', authority.canonical_mutation_allowed],
    ]) +
    `<div class="ai-tech-next">Next: ${escHtml(readiness.next_recommended_pass || 'unknown')}</div>` +
    `</details>`;

  body.innerHTML = overviewHtml + identityHtml + techDetails;
  wireOperatorSurfaceCards(body, 'agent-identity', 'Advanced Runtime');
}

