function renderRuntimeSupportLoopsPanel(data) {
  const body = document.getElementById('runtime-support-loops-body');
  const status = document.getElementById('runtime-support-loops-status');
  if (!body) return;

  const summary = data.summary || {};
  const authority = data.authority || {};
  const readiness = data.readiness || {};
  const packets = data.packets || {};
  const packetEntries = Object.entries(packets);
  const loopCount = summary.loop_family_count || packetEntries.length || 0;
  if (status) status.textContent = loopCount > 0 ? `${loopCount} loops` : 'No loops';

  const overview = `
    <div class="runtime-product-overview runtime-support-overview">
      <div class="runtime-product-copy">
        <strong>Support loops suggest and verify. They do not repair themselves.</strong>
        <span>Use this page to review verification queues, proactive suggestions, usage summaries, and repair candidates while keeping runtime memory, Agent Bus writes, and dispatch unavailable.</span>
      </div>
      <div class="runtime-product-metrics" aria-label="Support loop overview">
        <span><b>${escHtml(loopCount)}</b>Loops</span>
        <span><b>${summary.advisory_only ? 'yes' : 'no'}</b>Suggest only</span>
        <span><b>${summary.repair_apply_allowed ? 'yes' : 'no'}</b>Repair apply</span>
      </div>
    </div>`;

  const cards = packetEntries.length
    ? `<div class="runtime-support-grid">` +
      packetEntries.map(([packetId, packet]) => {
        const family = packet.loop_family || packetId.replace(/_packet$/, '');
        const confidence = packet.confidence || packet.status || 'review';
        const missing = (packet.missing_evidence || []).length;
        const allowed = (packet.allowed_next_actions || packet.allowed_actions || []).slice(0, 3);
        return `<article class="runtime-support-card" data-runtime-support-id="${escAttr(packetId)}" data-runtime-support-family="${escAttr(family)}" data-runtime-support-status="${escAttr(confidence)}">
          <div class="runtime-support-card-head">
            <span>${escHtml(filterLabel(family))}</span>
            <strong>${escHtml(confidence)}</strong>
          </div>
          <p>${escHtml(packet.summary || packet.operator_note || 'Review this support signal before any downstream action.')}</p>
          <div class="runtime-support-card-meta">
            <span>${escHtml(String(missing))} missing inputs</span>
            <span>${escHtml(allowed.join(', ') || 'operator review')}</span>
          </div>
        </article>`;
      }).join('') +
      `</div>`
    : emptyState('SL', 'No support loops yet', 'Runtime support suggestions appear after verification, usage, or repair signals are recorded.', 'Open Agents / Runtimes');

  const techDetails =
    `<details class="runtime-support-details">` +
    `<summary>Evidence &amp; Boundaries</summary>` +
    _runtimeIntelSection('Authority', [
      ['Suggest only', summary.advisory_only],
      ['Operator review required', summary.operator_approval_required_for_suggestions],
      ['Repair apply allowed', summary.repair_apply_allowed],
      ['Writes memory', authority.writes_memory],
      ['Writes Agent Bus tasks', authority.writes_agent_bus_tasks],
      ['Dispatches runtimes', authority.dispatches_runtimes],
      ['Consumes approvals', authority.consumes_approvals],
      ['Provider calls', authority.provider_calls_allowed],
      ['Canonical mutation', authority.canonical_mutation_allowed],
    ]) +
    `<div class="runtime-intel-next">Next: ${escHtml(readiness.next_recommended_pass || 'operator-review-support-signal')}</div>` +
    `</details>`;

  body.innerHTML = overview + cards + techDetails;

  body.querySelectorAll('.runtime-support-card').forEach(card => {
    card.addEventListener('click', () => {
      const packetId = card.dataset.runtimeSupportId || 'support-loop';
      const family = card.dataset.runtimeSupportFamily || 'support loop';
      renderObjectInspectorProductContext({
        id: packetId,
        label: filterLabel(family),
        type: 'Runtime Support Loop',
        kicker: 'Selected Support Loop',
        panel: 'runtime-support-loops',
        status: card.dataset.runtimeSupportStatus || 'review',
        ownerLabel: 'Surface',
        owner: 'Advanced Runtime',
        timeLabel: 'Mode',
        time: 'suggest only',
        ref: packetId,
        openLabel: 'Open Support Loops',
        note: 'Support loops are advisory here. Selecting a packet does not apply repairs, write memory, dispatch runtimes, create Agent Bus tasks, consume approvals, or mutate canonical state.',
      });
    });
  });
}

function _renderRuntimeIntelligenceShell(panelId, data, cards, sections) {
  const body = document.getElementById(`${panelId}-body`);
  const status = document.getElementById(`${panelId}-status`);
  const readiness = data.readiness || {};
  if (!body) return;
  if (status) status.textContent = ((data.native_panel || {}).mounted || false) ? 'Mounted' : 'Inspect only';
  body.innerHTML =
    '<div class="runtime-intel-summary">' +
    cards.map(card =>
      `<div class="dash-card">` +
      `<div class="dash-card-title">${escHtml(card.title)}</div>` +
      `<div class="dash-card-value runtime-intel-card-value">${escHtml(String(card.value))}</div>` +
      `<div class="dash-card-sub">${escHtml(card.sub)}</div>` +
      `</div>`
    ).join('') +
    '</div>' +
    sections.join('') +
    `<div class="runtime-intel-next">Next: ${escHtml(readiness.next_recommended_pass || 'unknown')}</div>`;
}

function _runtimeIntelSection(title, rows) {
  return `<div class="runtime-intel-section"><h3>${escHtml(title)}</h3>` +
    rows.map(([label, value]) =>
      `<div class="runtime-intel-row"><span>${escHtml(label)}</span><strong>${escHtml(String(value))}</strong></div>`
    ).join('') +
    '</div>';
}

function _runtimeIntelList(title, items) {
  if (!items.length) return '';
  return `<div class="runtime-intel-section"><h3>${escHtml(title)}</h3><div class="runtime-intel-list">` +
    items.slice(0, 20).map(item =>
      `<div class="runtime-intel-list-item">` +
      `<div>${escHtml(item.title || '')}</div>` +
      `<span>${escHtml(item.sub || '')}</span>` +
      `</div>`
    ).join('') +
    '</div></div>';
}

// ── Runtime Status Pill ───────────────────────────────────────────────────────
async function refreshRuntimeStatusPill() {
  if (!window.pywebview || !window.pywebview.api || !window.pywebview.api.get_runtime_status) return;
  try {
    const resp = await window.pywebview.api.get_runtime_status();
    if (!resp || !resp.ok) return;
    const d = resp.data || {};
    const modePill = document.getElementById('status-runtime-mode');
    const activePill = document.getElementById('status-active-tasks');
    if (modePill) {
      modePill.textContent = '● ' + (d.label || d.mode || 'OBSERVE');
      modePill.className = 'status-runtime-mode status-runtime-mode--' + (d.color || 'gray');
      if (d.pulse) modePill.classList.add('pulse');
      else modePill.classList.remove('pulse');
    }
    if (activePill) {
      const active = d.active_task_count || 0;
      const pending = d.pending_approval_count || 0;
      const review = d.review_queue_count || d.pending_review_count || d.pending_review_item_count || 0;
      const activeCount = document.getElementById('topbar-active-runs-count');
      const approvalCount = document.getElementById('topbar-approvals-count');
      const reviewCount = document.getElementById('topbar-review-count');
      if (activeCount) activeCount.textContent = String(active);
      if (approvalCount) approvalCount.textContent = String(pending);
      if (reviewCount) reviewCount.textContent = String(review);
      if (active > 0 || pending > 0) {
        activePill.style.display = '';
        activePill.textContent = (active > 0 ? `${active} active` : '') +
          (active > 0 && pending > 0 ? ' · ' : '') +
          (pending > 0 ? `${pending} pending approval` : '');
      } else {
        activePill.style.display = 'none';
      }
    }
  } catch (_) {}
}

// ── Project Workspace ─────────────────────────────────────────────────────────
async function loadProjectWorkspace() {
  const body = document.getElementById('project-workspace-body');
  const status = document.getElementById('project-workspace-status');
  if (!body) return;
  if (projectWorkspaceLoaded) return;
  body.innerHTML = renderProjectWorkspacePreparedShell();
  if (status) status.textContent = 'Ready';
  await waitForPaintFrame();

  try {
    const [resp, sprintResp] = await Promise.all([
      window.pywebview.api.get_project_workspace_view(),
      window.pywebview.api.get_sprint_focus ? window.pywebview.api.get_sprint_focus() : Promise.resolve(null),
    ]);
    if (!resp || !resp.ok) {
      body.innerHTML = `<div style="color:var(--ts-disputed);font-size:12px">${escHtml((resp && resp.error && resp.error.message) || 'Error')}</div>`;
      if (status) status.textContent = 'Error';
      return;
    }
    renderProjectWorkspacePanel(
      resp.data || {},
      (sprintResp && sprintResp.ok) ? (sprintResp.data || {}) : null,
    );
    projectWorkspaceLoaded = true;
  } catch (err) {
    body.innerHTML = `<div style="color:var(--ts-disputed);font-size:12px">${escHtml(err.message)}</div>`;
    if (status) status.textContent = 'Error';
  }
}

function waitForPaintFrame() {
  return new Promise(resolve => {
    if (typeof window === 'undefined' || typeof window.requestAnimationFrame !== 'function') {
      setTimeout(resolve, 0);
      return;
    }
    window.requestAnimationFrame(() => setTimeout(resolve, 0));
  });
}

function workspaceDisplayName(pathValue) {
  const raw = String(pathValue || '').trim();
  if (!raw) return '';
  const normalized = raw.replace(/\\/g, '/');
  const parts = normalized.split('/').filter(Boolean);
  return parts[parts.length - 1] || raw;
}

function workspaceUserFacingMessage(message) {
  const raw = String(message || '');
  if (raw.includes('No project OS records')) {
    return 'No workspace records were found yet. Add project records to populate this hub.';
  }
  return 'Workspace map is available for review. Changes, migrations, promotions, and task creation stay approval-aware.';
}

