function renderProjectWorkspacePanel(data, sprintData) {
  const body = document.getElementById('project-workspace-body');
  const status = document.getElementById('project-workspace-status');
  if (!body) return;

  const active = data.active_count || 0;
  if (status) status.textContent = active > 0 ? `${active} active` : 'Ready';

  const domains = data.domains || [];
  const warnings = data.warnings || [];
  const authority = data.authority || {};
  const readiness = data.readiness || {};
  const emptyStateInfo = data.empty_state || {};
  const vaultRoot = data.vault_root || '';
  const sprintSource = data.sprint_focus_source || '';
  const workspaceName = workspaceDisplayName(vaultRoot) || 'Current workspace';
  const focusName = workspaceDisplayName(sprintSource) || 'Now.md';

  // ── Stat cards ────────────────────────────────────────────────────────────
  const cards = [
    { title: 'Projects', value: data.project_count || 0, sub: 'total' },
    { title: 'Active',   value: active,                  sub: 'in progress' },
    { title: 'Paused',   value: data.paused_count || 0,  sub: 'parked/deferred' },
    { title: 'Domains',  value: data.domain_count || 0,  sub: 'grouped' },
  ];

  let html = `<div class="workspace-hub-hero">
    <div>
      <div class="panel-kicker">WORKSPACE HUB</div>
      <h3>${escHtml(active > 0 ? `${active} active workspaces` : 'Workspace index ready')}</h3>
      <p>Orient projects, current focus, domain clusters, docs, tasks, runs, memory, and artifacts from one local workspace hub.</p>
      <div class="workspace-hub-actions">
        <button class="btn-secondary" onclick="showPanel('chat',{updateHash:true})">Open Chat</button>
        <button class="btn-secondary" onclick="showPanel('graph',{updateHash:true})">Open Graph</button>
        <button class="btn-secondary" onclick="showPanel('node-inspector',{updateHash:true})">Open Docs / Inspector</button>
        <button class="btn-secondary" onclick="showPanel('aor',{updateHash:true})">Open Tasks &amp; Runs</button>
      </div>
    </div>
    <div class="workspace-hub-stats">` +
    cards.map(c =>
      `<div class="workspace-hub-stat">` +
      `<span>${escHtml(c.title)}</span>` +
      `<strong>${escHtml(String(c.value))}</strong>` +
      `<em>${escHtml(c.sub)}</em>` +
      `</div>`
    ).join('') + `</div></div>`;

  const contextCards = [
    { label: 'Workspace', value: workspaceName, sub: 'local-first' },
    { label: 'Focus note', value: focusName, sub: readiness.sprint_focus_available ? 'current focus loaded' : 'focus note not found' },
    { label: 'Next action', value: 'Review workspace', sub: 'opens safely' },
    { label: 'Change mode', value: authority.read_only === false ? 'Workspace actions available' : 'Approval required', sub: authority.writes_vault ? 'workspace changes available' : 'changes stay gated' },
  ];
  html += `<section class="pw-section workspace-context-strip">` +
    `<div class="pw-section-header">` +
    `<span class="pw-section-title">Workspace Operating Context</span>` +
    `<span class="pw-sprint-chip">Local-first</span>` +
    `<span class="pw-sprint-chip">${warnings.length ? `${warnings.length} warnings` : 'Approval-aware'}</span>` +
    `</div>` +
    `<div class="workspace-context-grid">` +
    contextCards.map(card =>
      `<div class="workspace-context-card">` +
      `<span>${escHtml(card.label)}</span>` +
      `<strong>${escHtml(String(card.value))}</strong>` +
      `<em>${escHtml(card.sub)}</em>` +
      `</div>`
    ).join('') +
    `</div>` +
    `<div class="workspace-context-note">${escHtml(workspaceUserFacingMessage(emptyStateInfo.message))}</div>` +
    `</section>`;

  const readinessItems = [
    ['Projects', readiness.projects_dir_found ? 'Ready' : 'Needs setup', _readinessTone(readiness.projects_dir_found)],
    ['Workspace records', readiness.project_count_ok ? `${data.project_count || 0} indexed` : 'No records yet', _readinessTone(readiness.project_count_ok)],
    ['Focus note', readiness.now_md_found ? 'Found' : 'Needs setup', _readinessTone(readiness.now_md_found)],
    ['Current focus', readiness.sprint_focus_available ? 'Available' : 'Not set', _readinessTone(readiness.sprint_focus_available)],
    ['Workspace edits', authority.writes_vault ? 'Available' : 'Approval required', authority.writes_vault ? 'warn' : 'ready'],
    ['Agent actions', authority.provider_calls_allowed ? 'Available' : 'Approval required', authority.provider_calls_allowed ? 'warn' : 'ready'],
  ];
  html += `<section class="pw-section workspace-readiness-panel">` +
    `<div class="pw-section-header"><span class="pw-section-title">Workspace Readiness</span></div>` +
    `<div class="workspace-readiness-grid">` +
    readinessItems.map(item =>
      `<div class="workspace-readiness-card" data-tone="${escAttr(item[2])}">` +
      `<span>${escHtml(item[0])}</span>` +
      `<strong>${escHtml(item[1])}</strong>` +
      `</div>`
    ).join('') +
    `</div>` +
    `</section>`;

  const surfaceShortcuts = [
    { label: 'Docs', panel: 'node-inspector', value: 'Markdown, backlinks, local graph', sub: 'Open formatted docs and node context.' },
    { label: 'Files', panel: 'node-inspector', value: 'Vault files', sub: 'Browse and edit Markdown in Docs / Inspector.' },
    { label: 'Tasks', panel: 'aor', value: 'Tasks & Runs', sub: 'Review operator tasks, runs, and evidence.' },
    { label: 'Memory', panel: 'runtime-memory-inspector', value: 'Memory Manager', sub: 'Inspect profiles, ledgers, and memory posture.' },
    { label: 'Artifacts', panel: 'build-logs', value: 'History / Audit', sub: 'Open build logs, proof, and activity records.' },
    { label: 'Settings', panel: 'settings', value: 'Workspace preferences', sub: 'Review appearance, runtime controls, and local config.' },
  ];
  html += `<section class="pw-section workspace-surface-panel">` +
    `<div class="pw-section-header"><span class="pw-section-title">Workspace Surfaces</span></div>` +
    `<div class="workspace-surface-grid">` +
    surfaceShortcuts.map(item =>
      `<button class="workspace-surface-card" type="button" data-workspace-surface="${escAttr(item.panel)}">` +
      `<span>${escHtml(item.label)}</span>` +
      `<strong>${escHtml(item.value)}</strong>` +
      `<em>${escHtml(item.sub)}</em>` +
      `</button>`
    ).join('') +
    `</div>` +
    `</section>`;

  // ── Sprint focus — structured task checklist ───────────────────────────────
  if (sprintData) {
    const tasks    = sprintData.tasks || [];
    const openCount = sprintData.open_count || 0;
    const doneCount = sprintData.done_count || 0;
    html += `<div class="pw-section">` +
      `<div class="pw-section-header">` +
      `<span class="pw-section-title">Current Sprint Focus</span>` +
      `<span class="pw-sprint-chip">${openCount} open</span>` +
      (doneCount > 0 ? `<span class="pw-sprint-chip pw-sprint-chip--done">${doneCount} done</span>` : '') +
      `</div>`;
    if (tasks.length) {
      html += `<div class="pw-task-list">` +
        tasks.slice(0, 20).map(t =>
          `<div class="pw-task${t.done ? ' pw-task--done' : ''}">` +
          `<span class="pw-task-check">${t.done ? '✓' : '○'}</span>` +
          `<span class="pw-task-text">${escHtml(t.text || '')}</span>` +
          `</div>`
        ).join('') +
        (tasks.length > 20 ? `<div class="pw-task-more">+${tasks.length - 20} more tasks</div>` : '') +
        `</div>`;
    } else if (sprintData.sprint_focus_available) {
      const focusLines = (sprintData.sprint_focus || '').split('\n')
        .filter(l => l.trim() && !l.startsWith('#'));
      html += focusLines.length
        ? `<div class="pw-sprint-label">${escHtml(focusLines[0].trim())}</div>`
        : `<div class="pw-empty-hint">No task items found in current sprint</div>`;
    } else {
      html += `<div class="pw-empty-hint">No Now.md sprint focus found</div>`;
    }
    html += `</div>`;
  }

  // ── Active projects ────────────────────────────────────────────────────────
  const activeProjects = (data.projects || []).filter(p => _projStatusClass(p.status) === 'proj-status--active');
  if (activeProjects.length) {
    html += `<div class="pw-section">` +
      `<div class="pw-section-header"><span class="pw-section-title">Pinned Active Workspaces</span></div>` +
      `<div class="pw-proj-list">` +
      activeProjects.slice(0, 6).map(proj =>
        `<div class="pw-proj-card" role="button" tabindex="0" data-project-workspace-card="project" data-project="${escAttr(proj.project || '')}" data-domain="${escAttr(proj.domain || 'unknown')}" data-status="${escAttr(proj.status || 'unknown')}" data-updated="${escAttr(proj.updated || '')}" data-path="${escAttr(proj.workspace_path || proj.file_name || '')}">` +
        `<span class="pw-proj-name">${escHtml(proj.project)}</span>` +
        `<span class="pw-proj-domain">${escHtml(proj.domain || 'unknown')}</span>` +
        `<span class="proj-status ${_projStatusClass(proj.status)}">${escHtml(proj.status)}</span>` +
        (proj.updated ? `<span class="pw-proj-date">${escHtml(proj.updated)}</span>` : '') +
        `</div>`
      ).join('') +
      `</div></div>`;
  }

  // ── All domains (collapsible when many) ───────────────────────────────────
  if (domains.length) {
    const domainHtml = `<div class="project-workspace-domain-list">` +
      domains.map(domain =>
        `<div class="project-workspace-domain" role="button" tabindex="0" data-project-workspace-card="domain" data-domain="${escAttr(domain.domain || 'unknown')}" data-count="${escAttr(String(domain.project_count || 0))}">` +
        `<div class="project-workspace-domain-label">${escHtml(domain.domain)} <span class="domain-count">${domain.project_count}</span></div>` +
        (domain.projects || []).map(proj =>
          `<div class="project-workspace-project" role="button" tabindex="0" data-project-workspace-card="project" data-project="${escAttr(proj.project || '')}" data-domain="${escAttr(proj.domain || domain.domain || 'unknown')}" data-status="${escAttr(proj.status || 'unknown')}" data-updated="${escAttr(proj.updated || '')}" data-path="${escAttr(proj.workspace_path || proj.file_name || '')}">` +
          `<span class="proj-name">${escHtml(proj.project)}</span>` +
          `<span class="proj-status ${_projStatusClass(proj.status)}">${escHtml(proj.status)}</span>` +
          `</div>`
        ).join('') +
        `</div>`
      ).join('') + `</div>`;
    if (domains.length > 4) {
      html += `<details class="pw-domains-details workspace-domain-board"><summary class="pw-domains-summary">Workspace domains (${domains.length})</summary>${domainHtml}</details>`;
    } else {
      html += `<div class="pw-section workspace-domain-board"><div class="pw-section-header"><span class="pw-section-title">Workspace Domains</span></div>${domainHtml}</div>`;
    }
  } else {
    html += `<div class="pw-section workspace-domain-board"><div class="pw-section-header"><span class="pw-section-title">Workspace Domains</span></div><div class="pw-empty-hint">No workspace domains returned by the index.</div></div>`;
  }

  if (warnings.length) {
    html += `<div class="pw-section"><div class="pw-section-header"><span class="pw-section-title">Warnings</span></div>` +
      warnings.map(w => `<div class="project-workspace-warning">${escHtml(w)}</div>`).join('') +
      `</div>`;
  }

  body.innerHTML = html;
  _wireProjectWorkspaceInspector(body);
}

function _readinessTone(value) {
  return value ? 'ready' : 'warn';
}

function _wireProjectWorkspaceInspector(root) {
  if (!root) return;
  root.querySelectorAll('[data-project-workspace-card="project"]').forEach(card => {
    const selectProject = event => {
      if (event) event.stopPropagation();
      const project = card.dataset.project || 'Workspace';
      const domain = card.dataset.domain || 'unknown';
      const status = card.dataset.status || 'unknown';
      const updated = card.dataset.updated || 'not dated';
      const ref = card.dataset.path || `01_PROJECTS/${domain}/${project}`;
      renderObjectInspectorProductContext({
        id: `workspace:${domain}:${project}`,
        label: project,
        type: 'Workspace',
        kicker: 'Selected Workspace',
        panel: 'project-workspace',
        status,
        ownerLabel: 'Domain',
        owner: domain,
        timeLabel: 'Updated',
        time: updated || 'not dated',
        ref,
        openLabel: 'Open Workspaces',
        note: 'Workspace selection scopes the current project context. Edits, migrations, source promotion, and task creation stay approval-aware.',
      });
    };
    card.addEventListener('click', selectProject);
    card.addEventListener('keydown', event => {
      if (event.key === 'Enter' || event.key === ' ') {
        event.preventDefault();
        selectProject(event);
      }
    });
  });
  root.querySelectorAll('[data-workspace-surface]').forEach(card => {
    const openSurface = event => {
      if (event) event.stopPropagation();
      const panel = card.dataset.workspaceSurface || 'project-workspace';
      showPanel(panel, { updateHash: true });
    };
    card.addEventListener('click', openSurface);
    card.addEventListener('keydown', event => {
      if (event.key === 'Enter' || event.key === ' ') {
        event.preventDefault();
        openSurface(event);
      }
    });
  });
  root.querySelectorAll('[data-project-workspace-card="domain"]').forEach(card => {
    const selectDomain = event => {
      if (event && event.target && event.target.closest('[data-project-workspace-card="project"]')) return;
      const domain = card.dataset.domain || 'unknown';
      const count = card.dataset.count || '0';
      renderObjectInspectorProductContext({
        id: `workspace-domain:${domain}`,
        label: domain,
        type: 'Workspace Domain',
        kicker: 'Selected Domain',
        panel: 'project-workspace',
        status: `${count} projects`,
        ownerLabel: 'Surface',
        owner: 'Workspaces',
        timeLabel: 'Authority',
        time: 'approval-aware',
        ref: `01_PROJECTS/${domain}`,
        openLabel: 'Open Workspaces',
        note: 'Domain selection scopes the local project map without creating, migrating, promoting, or dispatching workspace actions.',
      });
    };
    card.addEventListener('click', selectDomain);
    card.addEventListener('keydown', event => {
      if (event.key === 'Enter' || event.key === ' ') {
        event.preventDefault();
        selectDomain(event);
      }
    });
  });
}

function _projStatusClass(status) {
  const s = String(status || '').toLowerCase();
  if (s.includes('active')) return 'proj-status--active';
  if (s.includes('pause') || s.includes('parked') || s.includes('defer')) return 'proj-status--paused';
  return 'proj-status--unknown';
}

// ── Intake / Quarantine panel (Pass 10G) ─────────────────────────────────────

// Capture to Markdown panel (VCMI Pass 3)

function captureMarkdownPayload() {
  return {
    profile: (document.getElementById('capture-markdown-profile-select') || {}).value || 'research_note',
    source_mode: (document.getElementById('capture-markdown-source-select') || {}).value || 'manual_text',
    title: (document.getElementById('capture-markdown-title-input') || {}).value || '',
    raw_text: (document.getElementById('capture-markdown-raw-text') || {}).value || '',
    file_path: (document.getElementById('capture-markdown-file-input') || {}).value || '',
    local_ocr_command: (document.getElementById('capture-markdown-local-ocr-command-input') || {}).value || '',
    source_url: (document.getElementById('capture-markdown-source-url-input') || {}).value || '',
    user_intent: (document.getElementById('capture-markdown-intent-input') || {}).value || '',
    structured_notes: (document.getElementById('capture-markdown-notes-text') || {}).value || '',
    generated_summary: (document.getElementById('capture-markdown-summary-input') || {}).value || '',
    generated_interpretation: (document.getElementById('capture-markdown-interpretation-text') || {}).value || '',
    allow_secret_redaction: Boolean((document.getElementById('capture-markdown-redaction-check') || {}).checked),
    controlled_source: 'browser_runtime_artifact',
  };
}

function setCaptureMarkdownControlValue(id, value) {
  const element = document.getElementById(id);
  if (!element) return false;
  element.value = value == null ? '' : String(value);
  element.dispatchEvent(new Event('input', { bubbles: true }));
  element.dispatchEvent(new Event('change', { bubbles: true }));
  return true;
}

function setCaptureMarkdownControlChecked(id, checked) {
  const element = document.getElementById(id);
  if (!element) return false;
  element.checked = Boolean(checked);
  element.dispatchEvent(new Event('input', { bubbles: true }));
  element.dispatchEvent(new Event('change', { bubbles: true }));
  return true;
}

function setCaptureMarkdownFormValues(payload) {
  const data = payload || {};
  setCaptureMarkdownControlValue('capture-markdown-title-input', data.title || '');
  setCaptureMarkdownControlValue('capture-markdown-raw-text', data.raw_text || '');
  setCaptureMarkdownControlValue('capture-markdown-local-ocr-command-input', data.local_ocr_command || '');
  setCaptureMarkdownControlValue('capture-markdown-source-url-input', data.source_url || '');
  setCaptureMarkdownControlValue('capture-markdown-intent-input', data.user_intent || '');
  setCaptureMarkdownControlValue('capture-markdown-summary-input', data.generated_summary || '');
  setCaptureMarkdownControlValue('capture-markdown-notes-text', data.structured_notes || '');
  setCaptureMarkdownControlValue('capture-markdown-interpretation-text', data.generated_interpretation || '');
  if (Object.prototype.hasOwnProperty.call(data, 'allow_secret_redaction')) {
    setCaptureMarkdownControlChecked('capture-markdown-redaction-check', data.allow_secret_redaction);
  }
  _syncCaptureMarkdownSourceMode();
  return captureMarkdownPayload();
}

function installCaptureMarkdownProofBridge() {
  if (!window.__CHASEOS_STUDIO_QA_MODE__) return;
  window.__CHASEOS_CAPTURE_MARKDOWN_PROOF__ = {
    setFormValues: setCaptureMarkdownFormValues,
    getPayload: captureMarkdownPayload,
    preview: previewCaptureMarkdown,
    save: saveCaptureMarkdown,
    captureScreen: captureCurrentScreenForMarkdown,
    captureDisplayRegion: captureDisplayRegionForMarkdown,
    captureActiveWindow: captureActiveWindowForMarkdown,
    captureClipboard: captureClipboardTextForMarkdown,
    captureAmbientClipboard: toggleAmbientClipboardMonitorForMarkdown,
    captureSelectedText: captureSelectedTextForMarkdown,
    captureAccessibilityTree: captureAccessibilityTreeForMarkdown,
    captureBrowserExtension: captureBrowserExtensionArtifactForMarkdown,
  };
}

async function loadCaptureMarkdownPanel(force) {
  const recent = document.getElementById('capture-markdown-recent-body');
  const status = document.getElementById('capture-markdown-status');
  if (!recent) return;
  if (captureMarkdownLoaded && !force) return;
  recent.innerHTML = panelLoading();
  if (status) status.textContent = 'Syncing';

  try {
    const resp = await window.pywebview.api.get_capture_to_markdown_panel(10);
    if (!resp || !resp.ok) {
      recent.innerHTML = `<div style="color:var(--ts-disputed);font-size:12px">${escHtml((resp && resp.error && resp.error.message) || 'Error')}</div>`;
      if (status) status.textContent = 'Error';
      return;
    }
    renderCaptureMarkdownPanel(resp.data || {});
    captureMarkdownLoaded = true;
  } catch (err) {
    recent.innerHTML = `<div style="color:var(--ts-disputed);font-size:12px">${escHtml(err.message)}</div>`;
    if (status) status.textContent = 'Error';
  }
}

function renderCaptureMarkdownPanel(data) {
  const profileSelect = document.getElementById('capture-markdown-profile-select');
  const sourceSelect = document.getElementById('capture-markdown-source-select');
  const status = document.getElementById('capture-markdown-status');
  if (profileSelect && !profileSelect.dataset.loaded) {
    profileSelect.innerHTML = (data.profiles || []).map(profile =>
      `<option value="${escAttr(profile.profile_id)}">${escHtml(profile.label || profile.profile_id)}</option>`
    ).join('');
    profileSelect.value = data.default_profile || 'research_note';
    profileSelect.dataset.loaded = '1';
  }
  if (sourceSelect && !sourceSelect.dataset.loaded) {
    sourceSelect.innerHTML = (data.source_modes || []).map(mode =>
      `<option value="${escAttr(mode.id)}">${escHtml(mode.label || mode.id)}</option>`
    ).join('');
    sourceSelect.value = 'manual_text';
    sourceSelect.dataset.loaded = '1';
  }
  if (status) {
    const count = (data.recent_captures || []).length;
    status.textContent = count ? `${count} recent` : 'Ready';
  }
  renderCaptureMarkdownSourceOptions(data.capture_source_options || []);
  renderCaptureMarkdownReleaseReadiness(data.release_readiness || {});
  if (data.capture_hotkeys) {
    captureHotkeySettings = data.capture_hotkeys;
  }
  if (data.capture_collectors) {
    captureCollectorSettings = data.capture_collectors;
  }
  if (data.capture_local_image_text) {
    captureLocalImageTextSettings = data.capture_local_image_text;
    const configuredCommand = data.capture_local_image_text.local_ocr_command || '';
    const commandInput = document.getElementById('capture-markdown-local-ocr-command-input');
    if (commandInput && !commandInput.value && configuredCommand) commandInput.value = configuredCommand;
  }
  renderCaptureMarkdownAttachmentPolicy(
    data.attachment_disposition_policy || {},
    data.source_pack_approval_preview_policy || {},
    data.source_pack_aor_dispatch_readiness_policy || {},
    data.source_pack_aor_dispatch_approval_design_policy || {},
    data.source_pack_aor_dispatch_approval_request_writer_policy || {},
    data.source_pack_aor_dispatch_approval_consumption_readiness_policy || {},
    data.source_pack_aor_dispatch_approval_decision_writer_policy || {}
  );
  renderCaptureMarkdownRecent(data.recent_captures || []);
  _syncCaptureMarkdownSourceMode();
}

function renderCaptureMarkdownSourceOptions(options) {
  const body = document.getElementById('capture-markdown-source-options');
  if (!body) return;
  captureMarkdownSourceOptionsCache = Array.isArray(options) ? options : [];
  if (!options.length) {
    body.innerHTML = '';
    return;
  }
  const statusLabel = value => productLabel(value);
  body.innerHTML = `<div class="capture-markdown-source-option-head">` +
    `<div class="capture-markdown-section-title">Capture Sources</div>` +
    `<div class="capture-markdown-source-option-actions">` +
    `<button class="btn-secondary capture-markdown-palette-btn" type="button" title="Open Capture palette">Palette</button>` +
    `<button class="btn-secondary capture-markdown-source-settings-btn" type="button" title="Open Capture shortcut settings">Shortcut Settings</button>` +
    `</div>` +
    `</div>` +
    `<div class="capture-markdown-source-option-grid">` +
    options.map(option => {
      const mode = option.source_mode || '';
      const enabled = option.action === 'select_source_mode' && mode;
      const palette = option.action === 'open_capture_palette';
      const settings = option.action === 'open_settings_shortcuts';
      const collectorSettings = option.action === 'open_settings_collectors';
      const runnableCollector = option.action === 'run_screen_capture_collector'
        || option.action === 'run_display_region_collector'
        || option.action === 'run_active_window_collector'
        || option.action === 'run_clipboard_text_collector'
        || option.action === 'run_ambient_clipboard_monitor'
        || option.action === 'run_selected_text_collector'
        || option.action === 'run_accessibility_tree_collector'
        || option.action === 'run_browser_artifact_collector'
        || option.action === 'run_browser_extension_collector'
        || option.action === 'run_active_browser_collector'
        || option.action === 'run_chaseos_browser_page_collector'
        || option.action === 'run_discord_artifact_collector'
        || option.action === 'run_live_discord_command_collector';
      const blocked = String(option.status || '').includes('blocked');
      const unavailable = !(enabled || palette || settings || collectorSettings || runnableCollector) || blocked;
      const label = captureMarkdownOperatorText(option.label || option.id || 'Capture source');
      const description = captureMarkdownOperatorText(option.description || '');
      return `<button class="capture-markdown-source-card${unavailable ? ' capture-markdown-source-card--blocked' : ''}${(settings || collectorSettings) ? ' capture-markdown-source-card--settings' : ''}" type="button" data-capture-source-option="${escAttr(option.id || '')}" data-source-mode="${escAttr(mode)}" data-source-action="${escAttr(option.action || '')}" data-source-status="${escAttr(option.status || '')}">` +
        `<span>${escHtml(label)}</span>` +
        `<strong>${escHtml(statusLabel(option.status || 'unknown'))}</strong>` +
        `<em>${escHtml(description)}</em>` +
        (blocked ? `<small>Blocked</small>` : '') +
        `</button>`;
    }).join('') +
    `</div>`;

  body.querySelectorAll('.capture-markdown-source-card').forEach(card => {
    card.addEventListener('click', () => {
      const action = card.dataset.sourceAction || '';
      const mode = card.dataset.sourceMode || '';
      if (action === 'open_capture_palette') {
        openCapturePalette();
        return;
      }
      if (action === 'select_source_mode' && mode) {
        const select = document.getElementById('capture-markdown-source-select');
        if (select) {
          select.value = mode;
          _syncCaptureMarkdownSourceMode();
        }
        return;
      }
      if (action === 'open_settings_shortcuts') {
        openCaptureShortcutSettings();
        return;
      }
      if (action === 'open_settings_collectors') {
        openCaptureCollectorSettings();
        return;
      }
      if (action === 'run_screen_capture_collector') {
        captureCurrentScreenForMarkdown();
        return;
      }
      if (action === 'run_display_region_collector') {
        captureDisplayRegionForMarkdown();
        return;
      }
      if (action === 'run_active_window_collector') {
        captureActiveWindowForMarkdown();
        return;
      }
      if (action === 'run_clipboard_text_collector') {
        captureClipboardTextForMarkdown();
        return;
      }
      if (action === 'run_ambient_clipboard_monitor') {
        toggleAmbientClipboardMonitorForMarkdown();
        return;
      }
      if (action === 'run_selected_text_collector') {
        captureSelectedTextForMarkdown();
        return;
      }
      if (action === 'run_accessibility_tree_collector') {
        captureAccessibilityTreeForMarkdown();
        return;
      }
      if (action === 'run_browser_artifact_collector') {
        captureBrowserArtifactForMarkdown();
        return;
      }
      if (action === 'run_browser_extension_collector') {
        captureBrowserExtensionArtifactForMarkdown();
        return;
      }
      if (action === 'run_chaseos_browser_page_collector') {
        captureChaseosBrowserPageForMarkdown();
        return;
      }
      if (action === 'run_discord_artifact_collector') {
        captureDiscordArtifactForMarkdown();
        return;
      }
      if (action === 'run_live_discord_command_collector') {
        captureLiveDiscordCommandForMarkdown();
        return;
      }
      const msg = document.getElementById('capture-markdown-action-msg');
      if (msg) {
        const label = card.querySelector('span')?.textContent || 'Capture source';
        const detail = card.querySelector('em')?.textContent || 'This collector is blocked until its permission adapter exists.';
        msg.textContent = `${label}: ${detail}`;
        msg.className = 'capture-markdown-action-msg capture-markdown-msg-error';
      }
    });
  });
  const settingsBtn = body.querySelector('.capture-markdown-source-settings-btn');
  if (settingsBtn) settingsBtn.addEventListener('click', openCaptureShortcutSettings);
  const paletteBtn = body.querySelector('.capture-markdown-palette-btn');
  if (paletteBtn) paletteBtn.addEventListener('click', openCapturePalette);
  _syncCaptureMarkdownSourceOptionCards();
}

function closeCapturePalette() {
  const palette = document.getElementById('capture-markdown-palette');
  if (palette) palette.remove();
}

function openCapturePalette() {
  closeCapturePalette();
  const options = captureMarkdownSourceOptionsCache.filter(option => {
    const action = option.action || '';
    return action && action !== 'open_capture_palette' && !String(option.status || '').includes('blocked');
  });
  const overlay = document.createElement('div');
  overlay.id = 'capture-markdown-palette';
  overlay.className = 'capture-markdown-palette';
  overlay.innerHTML = `<div class="capture-markdown-palette-panel" role="dialog" aria-modal="true" aria-label="Capture palette">` +
    `<div class="capture-markdown-palette-head"><strong>Capture palette</strong><button class="btn-secondary capture-markdown-palette-close" type="button">Close</button></div>` +
    `<div class="capture-markdown-palette-grid">` +
    options.map(option => `<button class="capture-markdown-palette-action" type="button" data-source-action="${escAttr(option.action || '')}" data-source-mode="${escAttr(option.source_mode || '')}">` +
      `<span>${escHtml(captureMarkdownOperatorText(option.label || option.id || 'Capture source'))}</span>` +
      `<em>${escHtml(productLabel(option.status || 'available'))}</em>` +
      `</button>`).join('') +
    `</div>` +
    `</div>`;
  overlay.addEventListener('click', event => {
    if (event.target === overlay || event.target.closest('.capture-markdown-palette-close')) {
      closeCapturePalette();
      return;
    }
    const button = event.target.closest('.capture-markdown-palette-action');
    if (!button) return;
    const action = button.dataset.sourceAction || '';
    const mode = button.dataset.sourceMode || '';
    closeCapturePalette();
    runCaptureMarkdownSourceAction(action, mode, button.querySelector('span')?.textContent || 'Capture source', '');
  });
  document.body.appendChild(overlay);
}

function runCaptureMarkdownSourceAction(action, mode, label, detail) {
  if (action === 'select_source_mode' && mode) {
    const select = document.getElementById('capture-markdown-source-select');
    if (select) {
      select.value = mode;
      _syncCaptureMarkdownSourceMode();
    }
    return true;
  }
  if (action === 'open_settings_shortcuts') { openCaptureShortcutSettings(); return true; }
  if (action === 'open_settings_collectors') { openCaptureCollectorSettings(); return true; }
  if (action === 'run_screen_capture_collector') { captureCurrentScreenForMarkdown(); return true; }
  if (action === 'run_display_region_collector') { captureDisplayRegionForMarkdown(); return true; }
  if (action === 'run_active_window_collector') { captureActiveWindowForMarkdown(); return true; }
  if (action === 'run_clipboard_text_collector') { captureClipboardTextForMarkdown(); return true; }
  if (action === 'run_ambient_clipboard_monitor') { toggleAmbientClipboardMonitorForMarkdown(); return true; }
  if (action === 'run_selected_text_collector') { captureSelectedTextForMarkdown(); return true; }
  if (action === 'run_accessibility_tree_collector') { captureAccessibilityTreeForMarkdown(); return true; }
  if (action === 'run_browser_artifact_collector') { captureBrowserArtifactForMarkdown(); return true; }
  if (action === 'run_browser_extension_collector') { captureBrowserExtensionArtifactForMarkdown(); return true; }
  if (action === 'run_active_browser_collector') { captureActiveChaseosBrowserForMarkdown(); return true; }
  if (action === 'run_chaseos_browser_page_collector') { captureChaseosBrowserPageForMarkdown(); return true; }
  if (action === 'run_discord_artifact_collector') { captureDiscordArtifactForMarkdown(); return true; }
  if (action === 'run_live_discord_command_collector') { captureLiveDiscordCommandForMarkdown(); return true; }
  const msg = document.getElementById('capture-markdown-action-msg');
  if (msg) {
    msg.textContent = `${label || 'Capture source'}: ${detail || 'This collector is unavailable.'}`;
    msg.className = 'capture-markdown-action-msg capture-markdown-msg-error';
  }
  return false;
}

function renderCaptureMarkdownReleaseReadiness(readiness) {
  const body = document.getElementById('capture-markdown-release-readiness');
  if (!body) return;
  const data = readiness || {};
  const groups = Array.isArray(data.groups) ? data.groups : [];
  if (!groups.length) {
    body.innerHTML = '';
    return;
  }
  const summary = data.summary || {};
  const metrics = [
    ['Core capture', summary.core_capture_verified ? 'Verified' : 'Open'],
    ['Settings shortcuts', summary.settings_shortcuts_visible ? 'Visible' : 'Open'],
    ['Local image text engine', summary.local_image_text_engine_available ? 'Available' : 'Required'],
    ['Public signing', summary.public_signing_ready_to_attempt ? 'Ready' : 'Certificate required'],
    ['Manual or covered paths', summary.manual_or_covered_collector_count ?? 0],
    ['Open proof items', summary.release_proof_open_count ?? 0],
  ];
  body.innerHTML = `<details class="capture-markdown-release-card capture-markdown-advanced" data-capture-release-readiness="${escAttr(data.status || '')}" open>` +
    `<summary class="capture-markdown-release-summary">` +
      `<span>Capture readiness</span>` +
      `<strong>${escHtml(productLabel(data.status || 'release_ready_explicit_capture_paths_verified'))}</strong>` +
    `</summary>` +
    `<div class="capture-markdown-release-head">` +
      `<div>` +
        `<div class="capture-markdown-section-title">${escHtml(captureMarkdownOperatorText(data.label || 'Capture release readiness'))}</div>` +
        `<p>Core Markdown capture is usable now. Explicit collectors, local image text extraction, and downstream approval paths stay visible with their current authority state.</p>` +
      `</div>` +
    `</div>` +
    `<div class="capture-markdown-release-metrics">` +
      metrics.map(([label, value]) =>
        `<span><em>${escHtml(label)}</em><strong>${escHtml(String(value))}</strong></span>`
      ).join('') +
    `</div>` +
    `<div class="capture-markdown-release-groups">` +
      groups.map(group => {
        const items = Array.isArray(group.items) ? group.items : [];
        return `<section class="capture-markdown-release-group" data-capture-release-group="${escAttr(group.id || '')}">` +
          `<h3>${escHtml(captureMarkdownOperatorText(group.label || group.id || 'Readiness group'))}</h3>` +
          items.map(item =>
            `<article class="capture-markdown-release-item" data-capture-release-item="${escAttr(item.id || '')}" data-capture-release-status="${escAttr(item.status || '')}">` +
              `<div><span>${escHtml(captureMarkdownOperatorText(item.label || item.id || 'Readiness item'))}</span><p>${escHtml(captureMarkdownOperatorText(item.detail || ''))}</p></div>` +
              `<strong>${escHtml(productLabel(item.status || 'unknown'))}</strong>` +
            `</article>`
          ).join('') +
        `</section>`;
      }).join('') +
    `</div>` +
    `</details>`;
}

function renderCaptureMarkdownAttachmentPolicy(policy, sourcePackPolicy = {}, sourcePackAorPolicy = {}, sourcePackAorApprovalPolicy = {}, sourcePackAorApprovalRequestPolicy = {}, sourcePackAorApprovalConsumptionPolicy = {}, sourcePackAorApprovalDecisionPolicy = {}) {
  const body = document.getElementById('capture-markdown-policy-body');
  if (!body) return;
  const supported = (policy.supported_dispositions || []).filter(Boolean);
  const displayValue = value => productLabel(value);
  const chips = [
    ['Attachment disposition', policy.status || 'metadata_policy_only'],
    ['Default', policy.default_disposition || 'not-applicable'],
    ['Delete', policy.runtime_delete_allowed ? 'runtime allowed' : 'blocked'],
    ['Controls', policy.studio_delete_controls_allowed ? 'enabled' : 'blocked'],
    ['Source package preview', sourcePackPolicy.status || 'approval_preview_only'],
    ['Source package write', sourcePackPolicy.authority && sourcePackPolicy.authority.source_pack_write_allowed ? 'allowed' : 'blocked'],
    ['Agent Orchestration Runtime readiness', sourcePackAorPolicy.status || 'readiness_only'],
    ['Agent Orchestration Runtime approval', sourcePackAorApprovalPolicy.status || 'design_only'],
    ['Approval request', sourcePackAorApprovalRequestPolicy.status || 'request_writer'],
    ['Decision readiness', sourcePackAorApprovalConsumptionPolicy.status || 'readiness_only'],
    ['Decision writer', sourcePackAorApprovalDecisionPolicy.status || 'decision_writer'],
  ];
  body.innerHTML = `<details class="capture-markdown-policy-details">` +
    `<summary>Attachment and routing</summary>` +
    `<div class="capture-markdown-policy-strip">` +
    chips.map(([label, value]) =>
      `<span class="capture-markdown-policy-chip"><em>${escHtml(label)}</em><strong>${escHtml(displayValue(value))}</strong></span>`
    ).join('') +
    (supported.length
      ? `<span class="capture-markdown-policy-chip capture-markdown-policy-chip--wide"><em>States</em><strong>${escHtml(supported.map(displayValue).join(', '))}</strong></span>`
      : '') +
    `</div>` +
    `</details>`;
}

function renderCaptureMarkdownRecent(items) {
  const recent = document.getElementById('capture-markdown-recent-body');
  if (!recent) return;
  if (!items.length) {
    recent.innerHTML = emptyState('CM', 'No captures yet', 'Saved capture Markdown will appear here after it lands in quarantine.');
    return;
  }
  recent.innerHTML = `<div class="capture-markdown-recent-list">` + items.map(item => {
    const title = item.title || item.content_path || '(untitled)';
    const captured = item.captured_at ? item.captured_at.slice(0, 16).replace('T', ' ') : 'unknown';
    const reviewStatus = item.review_status || 'pending-review';
    const reviewStatusLabel = productLabel(reviewStatus, 'Pending review');
    const reviewPath = item.sidecar_path || item.content_path || item.visual_capture_packet_path || '';
    const attachmentCount = Number(item.attachment_count || 0);
    const attachmentDisposition = item.attachment_disposition || 'not-applicable';
    return `<div class="capture-markdown-recent-item" data-capture-ref="${escAttr(reviewPath || item.content_path || title)}">` +
      `<div class="capture-markdown-recent-title" title="${escAttr(title)}">${escHtml(title)}</div>` +
      `<div class="capture-markdown-recent-meta">` +
      `<span>${escHtml(item.profile || 'profile')}</span>` +
      `<span>${escHtml(item.input_class || 'class')}</span>` +
      `<span>${escHtml(reviewStatusLabel)}</span>` +
      `<span>${escHtml(captured)}</span>` +
      `</div>` +
      `<div class="capture-markdown-recent-path mono">${escHtml(item.content_path || '')}</div>` +
      `<div class="capture-markdown-review-row" data-capture-review-path="${escAttr(reviewPath)}">` +
      `<label class="capture-markdown-review-field">` +
      `<span>Review</span>` +
      `<select class="capture-markdown-review-decision" title="Review decision">` +
      captureMarkdownReviewOptions(reviewStatus) +
      `</select>` +
      `</label>` +
      `<label class="capture-markdown-review-field capture-markdown-review-note-field">` +
      `<span>Note</span>` +
      `<input class="capture-markdown-review-note" type="text" autocomplete="off" spellcheck="true" title="Review note">` +
      `</label>` +
      `<button class="btn-secondary capture-markdown-review-btn" type="button" title="Apply review decision">Apply</button>` +
      `<button class="btn-secondary capture-markdown-approval-preview-btn" type="button" title="Preview source-pack approval">Approval Preview</button>` +
      `<span class="capture-markdown-review-msg"></span>` +
      `</div>` +
      (attachmentCount > 0 ? `<div class="capture-markdown-attachment-row" data-capture-attachment-path="${escAttr(reviewPath)}">` +
        `<label class="capture-markdown-review-field">` +
        `<span>Attachments</span>` +
        `<select class="capture-markdown-attachment-disposition" title="Attachment retention decision">` +
        captureMarkdownAttachmentDispositionOptions(attachmentDisposition) +
        `</select>` +
        `</label>` +
        `<button class="btn-secondary capture-markdown-attachment-disposition-btn" type="button" title="Apply attachment retention decision">Apply retention</button>` +
        `<button class="btn-secondary capture-markdown-attachment-cleanup-btn" type="button" title="Delete copied quarantine attachments after exact confirmation">Delete copied files</button>` +
        `<span class="capture-markdown-attachment-msg">${escHtml(attachmentCount)} copied attachment${attachmentCount === 1 ? '' : 's'}</span>` +
        `</div>` : '') +
      `</div>`;
  }).join('') + `</div>`;
  recent.querySelectorAll('.capture-markdown-review-btn').forEach(button => {
    button.addEventListener('click', reviewCaptureMarkdown);
  });
  recent.querySelectorAll('.capture-markdown-approval-preview-btn').forEach(button => {
    button.addEventListener('click', previewCaptureMarkdownSourcePackApproval);
  });
  recent.querySelectorAll('.capture-markdown-attachment-disposition-btn').forEach(button => {
    button.addEventListener('click', updateCaptureMarkdownAttachmentDisposition);
  });
  recent.querySelectorAll('.capture-markdown-attachment-cleanup-btn').forEach(button => {
    button.addEventListener('click', cleanupCaptureMarkdownAttachments);
  });
  recent.querySelectorAll('.capture-markdown-recent-item').forEach(card => {
    card.addEventListener('click', event => {
      if (event.target.closest('button,input,select,textarea,label')) return;
      const ref = card.dataset.captureRef || '';
      const item = items.find(row => String(row.sidecar_path || row.content_path || row.visual_capture_packet_path || '') === String(ref)) || {};
      renderObjectInspectorProductContext({
        id: ref || item.title || 'capture',
        label: item.title || item.content_path || 'Capture',
        type: 'Capture',
        kicker: 'Selected Capture',
        panel: 'capture-markdown',
        status: productLabel(item.review_status || 'pending-review', 'Pending review'),
        ownerLabel: 'Profile',
        owner: item.profile || 'capture',
        time: item.captured_at ? item.captured_at.slice(0, 16).replace('T', ' ') : 'unknown',
        ref: ref || item.content_path || '',
        openLabel: 'Open Capture',
        note: 'Capture records stay in raw quarantine. Review updates sidecar/packet evidence only; source-pack write, Agent Orchestration Runtime dispatch, Source Intelligence Core ingestion, and canonical promotion remain governed downstream.',
      });
    });
  });
}

function captureMarkdownAttachmentDispositionOptions(current) {
  const options = [
    ['retain', 'Retain'],
    ['retain-until-downstream-review', 'Retain until downstream review'],
    ['needs-redaction', 'Needs redaction'],
    ['delete-requested', 'Request deletion'],
  ];
  return options.map(([value, label]) =>
    `<option value="${escAttr(value)}"${value === current ? ' selected' : ''}>${escHtml(label)}</option>`
  ).join('');
}

function captureMarkdownReviewOptions(currentStatus) {
  const statuses = [
    ['reviewed', 'Reviewed'],
    ['rejected', 'Rejected'],
    ['needs-redaction', 'Needs redaction'],
    ['pending-review', 'Pending review'],
  ];
  return statuses.map(([value, label]) =>
    `<option value="${escAttr(value)}"${value === currentStatus ? ' selected' : ''}>${escHtml(label)}</option>`
  ).join('');
}

async function previewCaptureMarkdown() {
  const output = document.getElementById('capture-markdown-preview-body');
  const msg = document.getElementById('capture-markdown-action-msg');
  const saveBtn = document.getElementById('capture-markdown-save-btn');
  if (!output) return;
  output.innerHTML = panelLoading('Previewing');
  if (msg) { msg.textContent = ''; msg.className = 'capture-markdown-action-msg'; }
  try {
    const resp = await window.pywebview.api.preview_capture_to_markdown(captureMarkdownPayload());
    if (!resp || !resp.ok) {
      const error = (resp && resp.error && resp.error.message) || 'Preview failed.';
      output.innerHTML = `<div class="capture-markdown-error">${escHtml(error)}</div>`;
      if (msg) { msg.textContent = error; msg.className = 'capture-markdown-action-msg capture-markdown-msg-error'; }
      if (saveBtn) saveBtn.disabled = true;
      return;
    }
    const data = resp.data || {};
    output.innerHTML = `<pre class="capture-markdown-markdown">${escHtmlRaw(data.markdown || '')}</pre>`;
    if (saveBtn) saveBtn.disabled = !data.save_allowed;
    if (msg && data.blockers && data.blockers.length) {
      msg.textContent = captureMarkdownBlockerText(data.blockers);
      msg.className = 'capture-markdown-action-msg capture-markdown-msg-error';
    }
  } catch (err) {
    output.innerHTML = `<div class="capture-markdown-error">${escHtml(err.message)}</div>`;
    if (msg) { msg.textContent = err.message; msg.className = 'capture-markdown-action-msg capture-markdown-msg-error'; }
    if (saveBtn) saveBtn.disabled = true;
  }
}

async function saveCaptureMarkdown() {
  const output = document.getElementById('capture-markdown-preview-body');
  const msg = document.getElementById('capture-markdown-action-msg');
  const saveBtn = document.getElementById('capture-markdown-save-btn');
  if (saveBtn) saveBtn.disabled = true;
  if (msg) { msg.textContent = 'Saving...'; msg.className = 'capture-markdown-action-msg'; }
  try {
    const resp = await window.pywebview.api.save_capture_to_markdown(captureMarkdownPayload());
    if (!resp || !resp.ok) {
      const error = (resp && resp.error && resp.error.message) || 'Save failed.';
      if (msg) { msg.textContent = error; msg.className = 'capture-markdown-action-msg capture-markdown-msg-error'; }
      if (saveBtn) saveBtn.disabled = false;
      return;
    }
    const data = resp.data || {};
    if (output) output.innerHTML = `<pre class="capture-markdown-markdown">${escHtmlRaw(data.markdown || '')}</pre>`;
    if (msg) {
      msg.textContent = data.status === 'duplicate' ? 'Duplicate found.' : 'Saved to quarantine.';
      msg.className = 'capture-markdown-action-msg capture-markdown-msg-ok';
    }
    captureMarkdownLoaded = false;
    renderCaptureMarkdownRecent(data.recent_captures || []);
    loadIntake();
  } catch (err) {
    if (msg) { msg.textContent = err.message; msg.className = 'capture-markdown-action-msg capture-markdown-msg-error'; }
  } finally {
    if (saveBtn) saveBtn.disabled = false;
  }
}

async function reviewCaptureMarkdown(event) {
  if (event && event.stopPropagation) event.stopPropagation();
  const button = event.target.closest('.capture-markdown-review-btn');
  if (!button) return;
  const row = button.closest('.capture-markdown-review-row');
  if (!row) return;
  const msg = row.querySelector('.capture-markdown-review-msg');
  const path = row.dataset.captureReviewPath || '';
  const decision = (row.querySelector('.capture-markdown-review-decision') || {}).value || 'reviewed';
  const reviewNote = (row.querySelector('.capture-markdown-review-note') || {}).value || '';
  if (!path) {
    if (msg) { msg.textContent = 'Missing capture path.'; msg.className = 'capture-markdown-review-msg capture-markdown-msg-error'; }
    return;
  }
  button.disabled = true;
  if (msg) { msg.textContent = 'Reviewing...'; msg.className = 'capture-markdown-review-msg'; }
  try {
    const resp = await window.pywebview.api.review_capture_to_markdown({
      sidecar_path: path,
      decision,
      review_note: reviewNote,
      reviewed_by: 'studio-operator',
    });
    if (!resp || !resp.ok) {
      const error = (resp && resp.error && resp.error.message) || 'Review failed.';
      if (msg) { msg.textContent = error; msg.className = 'capture-markdown-review-msg capture-markdown-msg-error'; }
      return;
    }
    const data = resp.data || {};
    const reviewStatus = data.new_status || 'Updated';
    captureMarkdownLoaded = false;
    renderCaptureMarkdownRecent(data.recent_captures || []);
    const actionMsg = document.getElementById('capture-markdown-action-msg');
    if (actionMsg) {
      actionMsg.textContent = `Review: ${productLabel(reviewStatus, 'Updated')}.`;
      actionMsg.className = 'capture-markdown-action-msg capture-markdown-msg-ok';
    }
    loadIntake();
  } catch (err) {
    if (msg) { msg.textContent = err.message; msg.className = 'capture-markdown-review-msg capture-markdown-msg-error'; }
  } finally {
    button.disabled = false;
  }
}

async function updateCaptureMarkdownAttachmentDisposition(event) {
  if (event && event.stopPropagation) event.stopPropagation();
  const button = event.target.closest('.capture-markdown-attachment-disposition-btn');
  if (!button) return;
  const row = button.closest('.capture-markdown-attachment-row');
  if (!row) return;
  const msg = row.querySelector('.capture-markdown-attachment-msg');
  const path = row.dataset.captureAttachmentPath || '';
  const requestedDisposition = (row.querySelector('.capture-markdown-attachment-disposition') || {}).value || 'retain';
  if (!path) {
    if (msg) { msg.textContent = 'Missing capture path.'; msg.className = 'capture-markdown-attachment-msg capture-markdown-msg-error'; }
    return;
  }
  button.disabled = true;
  if (msg) { msg.textContent = 'Updating retention...'; msg.className = 'capture-markdown-attachment-msg'; }
  try {
    const resp = await window.pywebview.api.update_capture_to_markdown_attachment_disposition({
      sidecar_path: path,
      requested_disposition: requestedDisposition,
      reviewed_by: 'studio-operator',
    });
    if (!resp || !resp.ok || !((resp.data || {}).ok)) {
      const error = captureMarkdownResponseError(resp, resp && resp.data, 'Attachment retention update failed.');
      if (msg) { msg.textContent = error; msg.className = 'capture-markdown-attachment-msg capture-markdown-msg-error'; }
      return;
    }
    renderCaptureMarkdownRecent((resp.data || {}).recent_captures || []);
    const actionMsg = document.getElementById('capture-markdown-action-msg');
    if (actionMsg) {
      actionMsg.textContent = `Attachment retention: ${productLabel(requestedDisposition)}.`;
      actionMsg.className = 'capture-markdown-action-msg capture-markdown-msg-ok';
    }
  } catch (err) {
    if (msg) { msg.textContent = err.message; msg.className = 'capture-markdown-attachment-msg capture-markdown-msg-error'; }
  } finally {
    button.disabled = false;
  }
}

async function cleanupCaptureMarkdownAttachments(event) {
  if (event && event.stopPropagation) event.stopPropagation();
  const button = event.target.closest('.capture-markdown-attachment-cleanup-btn');
  if (!button) return;
  const row = button.closest('.capture-markdown-attachment-row');
  if (!row) return;
  const msg = row.querySelector('.capture-markdown-attachment-msg');
  const path = row.dataset.captureAttachmentPath || '';
  const requestedDisposition = (row.querySelector('.capture-markdown-attachment-disposition') || {}).value || '';
  if (!path) {
    if (msg) { msg.textContent = 'Missing capture path.'; msg.className = 'capture-markdown-attachment-msg capture-markdown-msg-error'; }
    return;
  }
  if (requestedDisposition !== 'delete-requested') {
    if (msg) { msg.textContent = 'Choose Request deletion first.'; msg.className = 'capture-markdown-attachment-msg capture-markdown-msg-error'; }
    return;
  }
  const confirmationPhrase = window.prompt('Type DELETE CAPTURE ATTACHMENTS to delete copied quarantine attachments.');
  if (confirmationPhrase !== 'DELETE CAPTURE ATTACHMENTS') {
    if (msg) { msg.textContent = 'Exact confirmation was not entered.'; msg.className = 'capture-markdown-attachment-msg capture-markdown-msg-error'; }
    return;
  }
  button.disabled = true;
  if (msg) { msg.textContent = 'Deleting copied attachments...'; msg.className = 'capture-markdown-attachment-msg'; }
  try {
    const resp = await window.pywebview.api.cleanup_capture_to_markdown_attachments({
      sidecar_path: path,
      operator_confirmed: true,
      confirmation_phrase: confirmationPhrase,
    });
    if (!resp || !resp.ok || !((resp.data || {}).ok)) {
      const error = captureMarkdownResponseError(resp, resp && resp.data, 'Attachment cleanup failed.');
      if (msg) { msg.textContent = error; msg.className = 'capture-markdown-attachment-msg capture-markdown-msg-error'; }
      return;
    }
    renderCaptureMarkdownRecent((resp.data || {}).recent_captures || []);
    const actionMsg = document.getElementById('capture-markdown-action-msg');
    if (actionMsg) {
      actionMsg.textContent = `Deleted ${(resp.data || {}).deleted_count || 0} copied attachment file(s).`;
      actionMsg.className = 'capture-markdown-action-msg capture-markdown-msg-ok';
    }
  } catch (err) {
    if (msg) { msg.textContent = err.message; msg.className = 'capture-markdown-attachment-msg capture-markdown-msg-error'; }
  } finally {
    button.disabled = false;
  }
}

async function previewCaptureMarkdownSourcePackApproval(event) {
  if (event && event.stopPropagation) event.stopPropagation();
  const button = event.target.closest('.capture-markdown-approval-preview-btn');
  if (!button) return;
  const row = button.closest('.capture-markdown-review-row');
  if (!row) return;
  const output = document.getElementById('capture-markdown-source-pack-preview-body');
  const msg = row.querySelector('.capture-markdown-review-msg');
  const path = row.dataset.captureReviewPath || '';
  if (!path) {
    if (msg) { msg.textContent = 'Missing capture path.'; msg.className = 'capture-markdown-review-msg capture-markdown-msg-error'; }
    return;
  }
  button.disabled = true;
  if (output) output.innerHTML = panelLoading('Previewing approval');
  if (msg) { msg.textContent = 'Previewing...'; msg.className = 'capture-markdown-review-msg'; }
  try {
    const resp = await window.pywebview.api.preview_capture_to_markdown_source_pack_approval({
      sidecar_path: path,
      reviewed_by: 'studio-operator',
    });
    if (!resp || !resp.ok) {
      const error = (resp && resp.error && resp.error.message) || 'Approval preview failed.';
      if (output) output.innerHTML = `<div class="capture-markdown-error">${escHtml(error)}</div>`;
      if (msg) { msg.textContent = error; msg.className = 'capture-markdown-review-msg capture-markdown-msg-error'; }
      return;
    }
    const data = resp.data || {};
    renderCaptureMarkdownSourcePackApprovalPreview(data, path);
    if (msg) {
      msg.textContent = data.ok ? 'Approval preview ready.' : 'Approval preview blocked.';
      msg.className = data.ok
        ? 'capture-markdown-review-msg capture-markdown-msg-ok'
        : 'capture-markdown-review-msg capture-markdown-msg-error';
    }
  } catch (err) {
    if (output) output.innerHTML = `<div class="capture-markdown-error">${escHtml(err.message)}</div>`;
    if (msg) { msg.textContent = err.message; msg.className = 'capture-markdown-review-msg capture-markdown-msg-error'; }
  } finally {
    button.disabled = false;
  }
}

function renderCaptureMarkdownSourcePackApprovalPreview(data, capturePath) {
  const output = document.getElementById('capture-markdown-source-pack-preview-body');
  if (!output) return;
  const approval = data.approval_preview || {};
  const digest = data.request_digest || approval.request_digest || '';
  const writeCount = approval.write_scope_count != null
    ? approval.write_scope_count
    : ((approval.write_scope || []).length || 0);
  const blockers = data.blockers || [];
  const blockerLabels = captureMarkdownBlockerList(blockers);
  const requiredStatement = data.required_operator_statement || '';
  const writeReady = Boolean(data.ok && digest && requiredStatement);
  const chips = [
    ['Approval preview', data.status || 'unknown'],
    ['Digest', digest ? digest.slice(0, 18) : 'not-ready'],
    ['Write targets', String(writeCount)],
    ['Source-pack write', data.source_pack_write_allowed_now ? 'allowed' : 'blocked'],
    ['Approval artifact', data.approval_artifact_written ? 'written' : 'not written'],
  ];
  output.innerHTML = `<div class="capture-markdown-source-pack-preview">` +
    `<div class="capture-markdown-section-title">Source-Pack Approval Preview</div>` +
    `<div class="capture-markdown-policy-strip">` +
    chips.map(([label, value]) =>
      `<span class="capture-markdown-policy-chip"><em>${escHtml(label)}</em><strong>${escHtml(String(value))}</strong></span>`
    ).join('') +
    `</div>` +
    (requiredStatement
      ? `<label class="capture-markdown-source-pack-write-field">` +
        `<span>Statement</span>` +
        `<input class="capture-markdown-source-pack-write-statement mono" type="text" autocomplete="off" spellcheck="false" value="${escAttr(requiredStatement)}" title="Approval statement">` +
        `</label>`
      : '') +
    `<div class="capture-markdown-source-pack-write-row">` +
    `<button class="btn-secondary capture-markdown-source-pack-write-btn" type="button" title="Write approved source pack" data-capture-review-path="${escAttr(capturePath || data.capture_path || '')}" data-request-digest="${escAttr(digest)}"${writeReady ? '' : ' disabled'}>Write Pack</button>` +
    `<span class="capture-markdown-source-pack-write-msg"></span>` +
    `</div>` +
    `<div class="capture-markdown-source-pack-write-result"></div>` +
    (blockers.length
      ? `<div class="capture-markdown-approval-blockers">${blockerLabels.map(item => `<span>${escHtml(item)}</span>`).join('')}</div>`
      : '') +
    `</div>`;
  const writeButton = output.querySelector('.capture-markdown-source-pack-write-btn');
  if (writeButton) writeButton.addEventListener('click', executeCaptureMarkdownSourcePackWrite);
}

function renderCaptureMarkdownGuardFailure(output, title, error, blockers = [], details = []) {
  if (!output) return;
  const cleanBlockers = captureMarkdownBlockerList(blockers);
  const cleanError = captureMarkdownOperatorText(error || 'The guarded action was blocked.');
  const cleanDetails = (details || [])
    .filter(item => item && item.label)
    .map(item => [
      captureMarkdownOperatorText(item.label || ''),
      productLabel(item.value || '', captureMarkdownOperatorText(item.value || '')),
    ]);
  output.innerHTML =
    `<div class="capture-markdown-guard-failure" data-capture-guard-failure="true">` +
    `<div class="capture-markdown-source-pack-written">` +
    `<span>${escHtml(captureMarkdownOperatorText(title || 'Blocked by guard'))}</span>` +
    `<strong>blocked</strong>` +
    `<em>No downstream write</em>` +
    `</div>` +
    `<div class="capture-markdown-guard-failure-message">${escHtml(cleanError)}</div>` +
    (cleanDetails.length
      ? `<div class="capture-markdown-policy-strip">` +
        cleanDetails.map(([label, value]) =>
          `<span class="capture-markdown-policy-chip"><em>${escHtml(label)}</em><strong>${escHtml(value)}</strong></span>`
        ).join('') +
        `</div>`
      : '') +
    (cleanBlockers.length
      ? `<div class="capture-markdown-approval-blockers">${cleanBlockers.map(item => `<span>${escHtml(item)}</span>`).join('')}</div>`
      : '') +
    `</div>`;
}

async function executeCaptureMarkdownSourcePackWrite(event) {
  if (event && event.stopPropagation) event.stopPropagation();
  const button = event.target.closest('.capture-markdown-source-pack-write-btn');
  if (!button) return;
  const card = button.closest('.capture-markdown-source-pack-preview');
  const msg = card ? card.querySelector('.capture-markdown-source-pack-write-msg') : null;
  const result = card ? card.querySelector('.capture-markdown-source-pack-write-result') : null;
  const statementInput = card ? card.querySelector('.capture-markdown-source-pack-write-statement') : null;
  const path = button.dataset.captureReviewPath || '';
  const digest = button.dataset.requestDigest || '';
  const operatorStatement = (statementInput && statementInput.value) || '';
  if (!path || !digest) {
    if (msg) { msg.textContent = 'Missing approval data.'; msg.className = 'capture-markdown-source-pack-write-msg capture-markdown-msg-error'; }
    renderCaptureMarkdownGuardFailure(result, 'Source-pack write blocked', 'Missing approval data.', [], [
      { label: 'Guard', value: 'exact approval required' },
      { label: 'Write', value: 'not performed' },
    ]);
    return;
  }
  button.disabled = true;
  if (msg) { msg.textContent = 'Writing...'; msg.className = 'capture-markdown-source-pack-write-msg'; }
  try {
    const resp = await window.pywebview.api.execute_capture_to_markdown_source_pack_write({
      sidecar_path: path,
      request_digest: digest,
      operator_statement: operatorStatement,
      reviewed_by: 'studio-operator',
      written_by: 'studio-operator',
    });
    const data = (resp && resp.data) || {};
    if (!resp || !resp.ok || !data.ok) {
      const error = captureMarkdownResponseError(resp, data, 'Source-pack write blocked.');
      if (msg) { msg.textContent = error; msg.className = 'capture-markdown-source-pack-write-msg capture-markdown-msg-error'; }
      renderCaptureMarkdownGuardFailure(result, 'Source-pack write blocked', error, data.blockers || [], [
        { label: 'Guard', value: 'exact digest and statement' },
        { label: 'Source package', value: data.source_pack_written ? 'written' : 'not written' },
        { label: 'Approval artifact', value: data.approval_artifact_written ? 'written' : 'not written' },
      ]);
      button.disabled = false;
      return;
    }
    if (msg) { msg.textContent = 'Written.'; msg.className = 'capture-markdown-source-pack-write-msg capture-markdown-msg-ok'; }
    if (result) {
      const paths = data.written_paths || [];
      const downstreamChips = [
        ['Agent Orchestration Runtime dispatch', data.authority && data.authority.aor_dispatch_allowed ? 'allowed' : 'approval required'],
        ['Source Intelligence Core ingestion', data.authority && data.authority.sic_ingestion_allowed ? 'allowed' : 'not performed'],
        ['Canonical promotion', data.authority && data.authority.canonical_mutation_allowed ? 'allowed' : 'not performed'],
        ['Provider calls', data.authority && data.authority.provider_call_allowed ? 'allowed' : 'blocked'],
      ];
      result.innerHTML =
        `<div class="capture-markdown-source-pack-written">` +
        `<span>Source-Pack Write</span>` +
        `<strong>${escHtml(data.status || 'written')}</strong>` +
        `<em>${escHtml(String(paths.length))} paths</em>` +
        `</div>` +
        `<div class="capture-markdown-policy-strip capture-markdown-source-pack-boundary">` +
        downstreamChips.map(([label, value]) =>
          `<span class="capture-markdown-policy-chip"><em>${escHtml(label)}</em><strong>${escHtml(String(value))}</strong></span>`
        ).join('') +
        `</div>` +
        `<div class="capture-markdown-source-pack-written-paths">` +
        paths.slice(0, 5).map(pathItem => `<code>${escHtml(pathItem)}</code>`).join('') +
        `</div>` +
        `<div class="capture-markdown-source-pack-aor-row">` +
        `<button class="btn-secondary capture-markdown-source-pack-aor-readiness-btn" type="button" title="Preview Agent Orchestration Runtime dispatch readiness" data-capture-review-path="${escAttr(path)}" data-request-digest="${escAttr(digest)}">Agent Orchestration Runtime Readiness</button>` +
        `<span class="capture-markdown-source-pack-aor-readiness-msg"></span>` +
        `</div>` +
        `<div class="capture-markdown-source-pack-aor-readiness-result"></div>`;
      const aorButton = result.querySelector('.capture-markdown-source-pack-aor-readiness-btn');
      if (aorButton) aorButton.addEventListener('click', previewCaptureMarkdownSourcePackAorDispatchReadiness);
    }
  } catch (err) {
    if (msg) { msg.textContent = err.message; msg.className = 'capture-markdown-source-pack-write-msg capture-markdown-msg-error'; }
    renderCaptureMarkdownGuardFailure(result, 'Source-pack write blocked', err.message || String(err), [], [
      { label: 'Guard', value: 'runtime error' },
      { label: 'Write', value: 'not performed' },
    ]);
    button.disabled = false;
  }
}

