async function writeCaptureMarkdownSourcePackAorDispatchApprovalDecision(event) {
  if (event && event.stopPropagation) event.stopPropagation();
  const button = event.target.closest('.capture-markdown-source-pack-aor-approval-decision-btn');
  if (!button) return;
  const card = button.closest('.capture-markdown-source-pack-aor-approval-decision-card');
  const container = button.closest('.capture-markdown-source-pack-aor-approval-consumption-readiness');
  const msg = card ? card.querySelector('.capture-markdown-source-pack-aor-approval-decision-msg') : null;
  const output = container ? container.querySelector('.capture-markdown-source-pack-aor-approval-decision-result') : null;
  const statementInput = card ? card.querySelector('.capture-markdown-source-pack-aor-approval-decision-statement') : null;
  const path = button.dataset.captureReviewPath || '';
  const digest = button.dataset.requestDigest || '';
  const approvalRequestDigest = button.dataset.approvalRequestDigest || '';
  const approvalArtifactPath = button.dataset.approvalArtifactPath || '';
  const decision = button.dataset.decision || '';
  const approvalDecisionDigest = button.dataset.approvalDecisionDigest || '';
  const operatorStatement = (statementInput && statementInput.value) || '';
  if (!path || !digest || !approvalRequestDigest || !approvalArtifactPath || !decision || !approvalDecisionDigest) {
    if (msg) { msg.textContent = 'Missing decision data.'; msg.className = 'capture-markdown-source-pack-aor-approval-decision-msg capture-markdown-msg-error'; }
    return;
  }
  button.disabled = true;
  if (msg) { msg.textContent = 'Writing decision...'; msg.className = 'capture-markdown-source-pack-aor-approval-decision-msg'; }
  try {
    const resp = await window.pywebview.api.write_capture_to_markdown_source_pack_aor_dispatch_approval_decision({
      sidecar_path: path,
      request_digest: digest,
      expected_approval_request_digest: approvalRequestDigest,
      approval_artifact_path: approvalArtifactPath,
      decision,
      expected_approval_decision_digest: approvalDecisionDigest,
      operator_statement: operatorStatement,
      write_approval_decision: true,
      reviewed_by: 'studio-operator',
      decided_by: 'studio-operator',
    });
    const data = (resp && resp.data) || {};
    if (!resp || !resp.ok || !data.ok) {
      const error = captureMarkdownResponseError(resp, data, 'Approval decision blocked.');
      if (msg) { msg.textContent = error; msg.className = 'capture-markdown-source-pack-aor-approval-decision-msg capture-markdown-msg-error'; }
      if (output) output.innerHTML = '';
      button.disabled = false;
      return;
    }
    if (msg) { msg.textContent = 'Decision written.'; msg.className = 'capture-markdown-source-pack-aor-approval-decision-msg capture-markdown-msg-ok'; }
    if (output) {
      const chips = [
        ['Approval Decision', data.status || 'written'],
        ['Decision', data.decision || 'unknown'],
        ['Decision written', data.approval_decision_written ? 'yes' : 'no'],
        ['Consumption', data.approval_consumed ? 'consumed' : 'blocked'],
        ['Agent Orchestration Runtime dispatch', data.aor_dispatch_allowed_now ? 'allowed' : 'blocked'],
        ['Agent Bus', data.agent_bus_task_written ? 'written' : 'blocked'],
      ];
      output.innerHTML = `<div class="capture-markdown-source-pack-aor-approval-decision">` +
        `<div class="capture-markdown-policy-strip">` +
        chips.map(([label, value]) =>
          `<span class="capture-markdown-policy-chip"><em>${escHtml(label)}</em><strong>${escHtml(String(value))}</strong></span>`
        ).join('') +
        `</div>` +
        `<div class="capture-markdown-source-pack-written-paths">` +
        (data.written_paths || []).map(pathItem => `<code>${escHtml(pathItem)}</code>`).join('') +
        `</div>` +
        (data.approval_decision_written
          ? `<div class="capture-markdown-source-pack-aor-approval-consume-row">` +
            `<button class="btn-secondary capture-markdown-source-pack-aor-approval-consume-preview-btn" type="button" title="Preview approval decision consumption" data-capture-review-path="${escAttr(path)}" data-request-digest="${escAttr(digest)}" data-approval-request-digest="${escAttr(approvalRequestDigest)}" data-approval-artifact-path="${escAttr(approvalArtifactPath)}" data-decision="${escAttr(data.decision || decision)}" data-approval-decision-artifact-path="${escAttr(data.approval_decision_artifact_path || '')}" data-approval-decision-digest="${escAttr(data.approval_decision_digest || approvalDecisionDigest)}">Consumption Preview</button>` +
            `<span class="capture-markdown-source-pack-aor-approval-consume-preview-msg"></span>` +
            `</div>` +
            `<div class="capture-markdown-source-pack-aor-approval-consume-preview-result"></div>`
          : '') +
        `</div>`;
      const consumePreviewButton = output.querySelector('.capture-markdown-source-pack-aor-approval-consume-preview-btn');
      if (consumePreviewButton) consumePreviewButton.addEventListener('click', previewCaptureMarkdownSourcePackAorDispatchApprovalConsumption);
    }
    const siblingButtons = container ? container.querySelectorAll('.capture-markdown-source-pack-aor-approval-decision-btn') : [];
    siblingButtons.forEach(item => {
      if (item !== button) item.disabled = true;
    });
  } catch (err) {
    if (msg) { msg.textContent = err.message; msg.className = 'capture-markdown-source-pack-aor-approval-decision-msg capture-markdown-msg-error'; }
    button.disabled = false;
  }
}

