async function executeCaptureMarkdownSourcePackSicIngestion(event) {
  if (event && event.stopPropagation) event.stopPropagation();
  const button = event.target.closest('.capture-markdown-source-pack-sic-ingestion-btn');
  if (!button) return;
  const card = button.closest('.capture-markdown-source-pack-sic-ingestion-preview');
  const msg = card ? card.querySelector('.capture-markdown-source-pack-sic-ingestion-msg') : null;
  const output = card ? card.querySelector('.capture-markdown-source-pack-sic-ingestion-result') : null;
  const statementInput = card ? card.querySelector('.capture-markdown-source-pack-sic-ingestion-statement') : null;
  const path = button.dataset.captureReviewPath || '';
  const digest = button.dataset.requestDigest || '';
  const fullDispatchArtifactPath = button.dataset.fullDispatchArtifactPath || '';
  const fullDispatchArtifactDigest = button.dataset.fullDispatchArtifactDigest || '';
  const fullDispatchPacketDigest = button.dataset.fullDispatchPacketDigest || '';
  const readinessPacketDigest = button.dataset.sicIngestionReadinessPacketDigest || '';
  const approvalRequestDigest = button.dataset.sicIngestionApprovalRequestDigest || '';
  const approvalArtifactPath = button.dataset.approvalArtifactPath || '';
  const decision = button.dataset.decision || '';
  const decisionArtifactPath = button.dataset.approvalDecisionArtifactPath || '';
  const decisionDigest = button.dataset.sicIngestionApprovalDecisionDigest || '';
  const consumptionArtifactPath = button.dataset.approvalConsumptionArtifactPath || '';
  const consumptionDigest = button.dataset.sicIngestionApprovalConsumptionDigest || '';
  const ingestionDigest = button.dataset.sicIngestionDigest || button.dataset.sourceIntelligenceCoreIngestionDigest || '';
  const operatorStatement = (statementInput && statementInput.value) || '';
  if (!path || !digest || !fullDispatchArtifactPath || !fullDispatchArtifactDigest || !readinessPacketDigest || !approvalRequestDigest || !approvalArtifactPath || !decision || !decisionArtifactPath || !decisionDigest || !consumptionArtifactPath || !consumptionDigest || !ingestionDigest) {
    if (msg) { msg.textContent = 'Missing Source Intelligence Core ingestion data.'; msg.className = 'capture-markdown-source-pack-sic-ingestion-msg capture-markdown-msg-error'; }
    const missing = [
      ['Capture review path', path],
      ['Request digest', digest],
      ['Full dispatch artifact path', fullDispatchArtifactPath],
      ['Full dispatch artifact digest', fullDispatchArtifactDigest],
      ['Readiness packet digest', readinessPacketDigest],
      ['Approval request digest', approvalRequestDigest],
      ['Approval artifact path', approvalArtifactPath],
      ['Decision', decision],
      ['Decision artifact path', decisionArtifactPath],
      ['Decision digest', decisionDigest],
      ['Consumption artifact path', consumptionArtifactPath],
      ['Consumption digest', consumptionDigest],
      ['Ingestion digest', ingestionDigest],
    ].filter(([, value]) => !value).map(([label]) => `${label} missing`);
    renderCaptureMarkdownGuardFailure(output, 'Source Intelligence Core ingestion blocked', 'Missing Source Intelligence Core ingestion data.', missing, [
      { label: 'Guard', value: 'exact approval consumption required' },
      { label: 'Write', value: 'not performed' },
    ]);
    const blockedCard = output ? output.querySelector('.capture-markdown-guard-failure') : null;
    if (blockedCard) blockedCard.classList.add('capture-markdown-source-pack-sic-ingestion-blocked');
    return;
  }
  button.disabled = true;
  if (msg) { msg.textContent = 'Ingesting into Source Intelligence Core...'; msg.className = 'capture-markdown-source-pack-sic-ingestion-msg'; }
  try {
    const resp = await window.pywebview.api.ingest_capture_to_markdown_source_pack_sic_ingestion({
      sidecar_path: path,
      request_digest: digest,
      full_dispatch_artifact_path: fullDispatchArtifactPath,
      expected_full_dispatch_artifact_digest: fullDispatchArtifactDigest,
      expected_full_dispatch_packet_digest: fullDispatchPacketDigest,
      expected_sic_ingestion_readiness_packet_digest: readinessPacketDigest,
      expected_sic_ingestion_approval_request_digest: approvalRequestDigest,
      approval_artifact_path: approvalArtifactPath,
      decision,
      approval_decision_artifact_path: decisionArtifactPath,
      expected_sic_ingestion_approval_decision_digest: decisionDigest,
      approval_consumption_artifact_path: consumptionArtifactPath,
      expected_sic_ingestion_approval_consumption_digest: consumptionDigest,
      expected_sic_ingestion_digest: ingestionDigest,
      operator_statement: operatorStatement,
      target_workspace_id: 'vcmi-reviewed-captures',
      source_type: 'markdown',
      user_trust_level: 'reviewed',
      reviewed_by: 'studio-operator',
      ingested_by: 'studio-operator',
      write_ingestion_marker: true,
      run_source_intelligence_core_ingestion: true,
      write_ingestion_artifact: true,
    });
    const data = (resp && resp.data) || {};
    if (!resp || !resp.ok || !data.ok) {
      const error = captureMarkdownResponseError(resp, data, 'Source Intelligence Core ingestion blocked.');
      if (msg) { msg.textContent = error; msg.className = 'capture-markdown-source-pack-sic-ingestion-msg capture-markdown-msg-error'; }
      renderCaptureMarkdownGuardFailure(output, 'Source Intelligence Core ingestion blocked', error, data.blockers || [], [
        { label: 'Guard', value: 'Source Intelligence Core write gate' },
        { label: 'Write', value: 'not performed' },
      ]);
      const blockedCard = output ? output.querySelector('.capture-markdown-guard-failure') : null;
      if (blockedCard) blockedCard.classList.add('capture-markdown-source-pack-sic-ingestion-blocked');
      button.disabled = false;
      return;
    }
    if (msg) { msg.textContent = 'Source Intelligence Core ingestion complete.'; msg.className = 'capture-markdown-source-pack-sic-ingestion-msg capture-markdown-msg-ok'; }
    if (output) {
      const chips = [
        ['Source Intelligence Core Ingestion', data.status || 'complete'],
        ['Ingested', data.source_intelligence_core_ingestion_performed ? 'yes' : 'no'],
        ['Workspace written', data.source_intelligence_core_workspace_written ? 'yes' : 'no'],
        ['Source package written', data.source_intelligence_core_source_package_written ? 'yes' : 'no'],
        ['Workspace membership', data.source_intelligence_core_workspace_membership_written ? 'yes' : 'no'],
        ['Graph', data.graph_index_mutation_performed ? 'yes' : 'no'],
        ['Canonical', data.canonical_mutation_performed ? 'yes' : 'no'],
      ];
      output.innerHTML = `<div class="capture-markdown-source-pack-sic-ingestion">` +
        `<div class="capture-markdown-policy-strip">` +
        chips.map(([label, value]) =>
          `<span class="capture-markdown-policy-chip"><em>${escHtml(label)}</em><strong>${escHtml(String(value))}</strong></span>`
        ).join('') +
        `</div>` +
        `<div class="capture-markdown-source-pack-written-paths">` +
        (data.written_paths || []).map(pathItem => `<code>${escHtml(pathItem)}</code>`).join('') +
        `</div>` +
        `<div class="capture-markdown-source-pack-sic-graph-readiness-row">` +
        `<button class="btn-secondary capture-markdown-source-pack-sic-graph-readiness-btn" type="button" title="Preview Source Intelligence Core graph indexing readiness" data-sic-ingestion-artifact-path="${escAttr(data.source_intelligence_core_ingestion_artifact_path || '')}" data-sic-ingestion-artifact-digest="${escAttr((data.source_intelligence_core_ingestion_artifact || {}).artifact_digest || '')}" data-sic-ingestion-digest="${escAttr(data.source_intelligence_core_ingestion_digest || '')}">Graph Indexing Readiness Preview</button>` +
        `<span class="capture-markdown-source-pack-sic-graph-readiness-msg"></span>` +
        `</div>` +
        `<div class="capture-markdown-source-pack-sic-graph-readiness-result"></div>` +
        `</div>`;
      const graphReadinessButton = output.querySelector('.capture-markdown-source-pack-sic-graph-readiness-btn');
      if (graphReadinessButton) graphReadinessButton.addEventListener('click', previewCaptureMarkdownSourcePackSicGraphIndexingReadiness);
    }
  } catch (err) {
    if (msg) { msg.textContent = err.message; msg.className = 'capture-markdown-source-pack-sic-ingestion-msg capture-markdown-msg-error'; }
    renderCaptureMarkdownGuardFailure(output, 'Source Intelligence Core ingestion blocked', err.message || 'Source Intelligence Core ingestion failed.', [], [
      { label: 'Guard', value: 'Source Intelligence Core write gate' },
      { label: 'Write', value: 'not performed' },
    ]);
    const blockedCard = output ? output.querySelector('.capture-markdown-guard-failure') : null;
    if (blockedCard) blockedCard.classList.add('capture-markdown-source-pack-sic-ingestion-blocked');
    button.disabled = false;
  }
}

