let pivotLogLoaded = false;
let pivotDetailFile = null;
let _pivotsAll = [];

async function loadPivotLog() {
  if (pivotLogLoaded) return;
  const status = document.getElementById('pivot-log-status');
  const list = document.getElementById('pivot-log-list');
  if (!list) return;
  list.innerHTML = panelLoading();
  try {
    const resp = await pywebview.api.get_pivot_log(100);
    if (!resp || !resp.ok) {
      list.innerHTML = `<div class="pivot-log-empty">Error: ${escHtml((resp && resp.error && resp.error.message) || 'Failed')}</div>`;
      if (status) status.textContent = 'Error';
      return;
    }
    _pivotsAll = resp.data.pivots || [];
    renderPivotList(_pivotsAll);
    if (status) status.textContent = `${resp.data.pivot_count} pivots`;
    pivotLogLoaded = true;
  } catch (err) {
    list.innerHTML = `<div class="pivot-log-empty">${escHtml(err.message)}</div>`;
    if (status) status.textContent = 'Error';
  }
}

function renderPivotList(pivots) {
  const list = document.getElementById('pivot-log-list');
  if (!list) return;
  if (!pivots.length) {
    list.innerHTML = '<div class="pivot-log-empty">No pivot records found</div>';
    return;
  }
  list.innerHTML = pivots.map(p => `
    <div class="pivot-item${pivotDetailFile === p.filename ? ' pivot-item--active' : ''}"
         data-filename="${escAttr(p.filename)}">
      <div class="pivot-date">${escHtml(p.date || '')}${p.approved_by ? ' - ' + escHtml(p.approved_by) : ''}</div>
      <div class="pivot-title">${escHtml(p.title || p.filename)}</div>
    </div>`).join('');
}

async function loadPivotDetail(filename) {
  const viewer = document.getElementById('pivot-log-viewer');
  const viewerTitle = document.getElementById('pivot-log-viewer-title');
  const viewerContent = document.getElementById('pivot-log-viewer-content');
  if (!viewer || !viewerContent) return;
  pivotDetailFile = filename;
  viewer.style.display = 'flex';
  viewerContent.innerHTML = panelLoading();
  if (viewerTitle) viewerTitle.textContent = filename;
  renderPivotList(_pivotsAll);
  try {
    const resp = await pywebview.api.get_pivot_detail(filename);
    if (!resp || !resp.ok) {
      viewerContent.innerHTML = `<div class="pivot-log-empty">${escHtml((resp && resp.error && resp.error.message) || 'Error')}</div>`;
      return;
    }
    if (viewerTitle) viewerTitle.textContent = resp.data.filename || filename;
    viewerContent.textContent = resp.data.content;
  } catch (err) {
    viewerContent.innerHTML = `<div class="pivot-log-empty">${escHtml(err.message)}</div>`;
  }
}

function _initPivotLogPanel() {
  const search = document.getElementById('pivot-log-search');
  if (search) {
    search.addEventListener('input', () => {
      const q = search.value.trim().toLowerCase();
      renderPivotList(q
        ? _pivotsAll.filter(p =>
            (p.title || '').toLowerCase().includes(q) ||
            (p.pivot_id || '').toLowerCase().includes(q) ||
            (p.approved_by || '').toLowerCase().includes(q))
        : _pivotsAll);
    });
  }
  const closeBtn = document.getElementById('pivot-log-viewer-close');
  if (closeBtn) {
    closeBtn.addEventListener('click', () => {
      const viewer = document.getElementById('pivot-log-viewer');
      if (viewer) viewer.style.display = 'none';
      pivotDetailFile = null;
      renderPivotList(_pivotsAll);
    });
  }
  const list = document.getElementById('pivot-log-list');
  if (list) {
    list.addEventListener('click', e => {
      const item = e.target.closest('.pivot-item');
      if (item && item.dataset.filename) loadPivotDetail(item.dataset.filename);
    });
  }
}

