function renderWorkflowPackInspectorContext(item, kind) {
  if (!item) return;
  const id = item.id || item.run_id || item.item_id || item.title || kind || 'mission';
  const label = missionDisplayTitle(item.name || item.title || item.id || item.item_id || id);
  const status = item.status || item.category || item.provider_mode || 'local';
  renderObjectInspectorProductContext({
    id: `workflow-packs:${id}`,
    label,
    type: kind || 'Mission',
    kicker: `Selected ${kind || 'Mission'}`,
    panel: 'workflow-packs',
    status,
    ownerLabel: 'Surface',
    owner: 'Missions',
    timeLabel: 'Mode',
    time: missionDisplayMode(item.provider_mode || item.kind || item.category || 'local'),
    ref: item.path || item.local_path || item.id || id,
    openLabel: 'Open Missions',
    note: 'Mission selection is direct-safe. Local artifact writes and approved local resume use existing gated paths; external execution, provider calls, browser actions, Agent Bus writes, runtime dispatch, graph promotion, and canonical mutation stay unavailable here.',
  });
}

function renderWorkflowPacksPanel(data) {
  const packs = (((data || {}).registry || {}).packs) || [];
  const runs = (data || {}).runs || [];
  const reviewQueue = (data || {}).review_queue || [];
  const proofCards = (data || {}).proof_cards || [];
  const summary = (data || {}).summary || {};
  const newRun = (data || {}).new_run || {};
  const defaultPackId = (((data || {}).new_run || {}).default_pack_id) || 'founder_personal_automation_audit';
  const select = document.getElementById('workflow-packs-pack-select');
  const overview = document.getElementById('workflow-packs-overview');
  const contextEl = document.getElementById('workflow-packs-operating-context');
  const boardEl = document.getElementById('workflow-packs-board');
  const readinessEl = document.getElementById('workflow-packs-readiness');
  const coverageEl = document.getElementById('workflow-packs-feature-coverage');
  const runsEl = document.getElementById('workflow-packs-runs');
  const reviewEl = document.getElementById('workflow-packs-review-queue');
  const proofEl = document.getElementById('workflow-packs-proof-cards');
  if (select) {
    const previous = select.value;
    select.innerHTML = packs.map(pack => `<option value="${escAttr(pack.id)}">${escHtml(pack.name)}</option>`).join('');
    if (previous && packs.some(pack => pack.id === previous)) select.value = previous;
    else if (packs.some(pack => pack.id === defaultPackId)) select.value = defaultPackId;
    updateWorkflowPacksQuestionnaireVisibility();
  }
  renderWorkflowPacksOperatingContext((data || {}).operating_context, summary, contextEl);
  renderWorkflowPacksMissionBoard(packs, runs, reviewQueue, proofCards, boardEl);
  renderWorkflowPacksReadiness((data || {}).readiness, readinessEl);
  renderWorkflowPacksFeatureCoverage((data || {}).feature_family_coverage, coverageEl);
  if (overview) {
    const localResumeStatus = `
      <section class="workflow-pack-card workflow-pack-card--status">
        <div class="workflow-pack-card-head">
          <strong>Approval-Gated Resume</strong>
          <span>${escHtml(summary.approved_local_resume_executor_ready ? 'Ready' : 'Blocked')}</span>
        </div>
        <p>Resume a local mission only after a scoped operator decision. External work remains unavailable from this page.</p>
        <div class="workflow-pack-chip-row">
          <span>Review ${escHtml(summary.approval_review_artifact_writer_ready ? 'ready' : 'blocked')}</span>
          <span>Duplicate protection ${escHtml(summary.approval_marker_reservation_ready ? 'ready' : 'blocked')}</span>
          <span>Resume ${escHtml(summary.resume_executor_built ? 'ready' : 'blocked')}</span>
          <span>External work ${escHtml(summary.external_actions_blocked ? 'blocked' : 'unavailable')}</span>
        </div>
      </section>`;
    overview.innerHTML = localResumeStatus + packs.map(pack => `
      <section class="workflow-pack-card" data-mission-pack-card="pack" data-pack-id="${escAttr(pack.id)}" role="button" tabindex="0">
        <div class="workflow-pack-card-head">
          <strong>${escHtml(missionDisplayTitle(pack.name))}</strong>
          <span>${escHtml(pack.category || '')}</span>
        </div>
        <p>${escHtml(pack.description || '')}</p>
        <div class="workflow-pack-chip-row">
          ${(pack.artifact_types || []).map(type => `<span>${escHtml(type)}</span>`).join('')}
        </div>
        <div class="workflow-pack-boundary">${escHtml((pack.safety_notes || []).join(' ') || 'Local artifacts only. External execution requires separate governed approval.')}</div>
      </section>
    `).join('');
    overview.querySelectorAll('[data-mission-pack-card="pack"]').forEach(card => {
      const openCard = () => {
        const pack = packs.find(item => String(item.id || '') === String(card.dataset.packId || ''));
        renderWorkflowPackInspectorContext(pack || { id: card.dataset.packId }, 'Mission Pack');
      };
      card.addEventListener('click', openCard);
      card.addEventListener('keydown', event => {
        if (event.key === 'Enter' || event.key === ' ') {
          event.preventDefault();
          openCard();
        }
      });
    });
  }
  if (runsEl) {
    runsEl.innerHTML = runs.length ? runs.map(run => `
      <article class="workflow-pack-row" data-mission-run-card="run" data-run-id="${escAttr(run.id || '')}" role="button" tabindex="0">
        <div>
          <strong>${escHtml(missionDisplayTitle(run.title || run.id))}</strong>
          <span>${escHtml(missionPackLabel(run.pack_id, packs))}</span>
        </div>
        <div class="workflow-pack-row-meta">
          <span>${escHtml(missionDisplayStatus(run.status))}</span>
          <span>${escHtml(missionDisplayMode(run.provider_mode))}</span>
          <span>${escHtml(run.created_at || '')}</span>
        </div>
      </article>
    `).join('') : '<div class="workflow-packs-empty">No runs yet</div>';
    runsEl.querySelectorAll('[data-mission-run-card="run"]').forEach(card => {
      const openCard = () => {
        const run = runs.find(item => String(item.id || '') === String(card.dataset.runId || ''));
        renderWorkflowPackInspectorContext(run || { id: card.dataset.runId }, 'Mission Run');
      };
      card.addEventListener('click', openCard);
      card.addEventListener('keydown', event => {
        if (event.key === 'Enter' || event.key === ' ') {
          event.preventDefault();
          openCard();
        }
      });
    });
  }
  if (reviewEl) {
    reviewEl.innerHTML = reviewQueue.length ? reviewQueue.map(item => `
      <article class="workflow-pack-row workflow-pack-row--review" data-mission-review-card="review" data-item-id="${escAttr(item.item_id || '')}" role="button" tabindex="0">
        <div>
          <strong>${escHtml(missionDisplayTitle(item.title || item.item_id))}</strong>
          <span>${escHtml(item.kind === 'approval_gate' ? 'Approval required' : 'Review item')} / ${escHtml(missionDisplayStatus(item.status))}</span>
          ${renderWorkflowPackApprovalActions(item)}
        </div>
        <div class="workflow-pack-row-meta"><span>${escHtml(missionPackLabel(item.pack_id, packs))}</span></div>
      </article>
    `).join('') : '<div class="workflow-packs-empty">No review items</div>';
    reviewEl.querySelectorAll('[data-mission-review-card="review"]').forEach(card => {
      const openCard = () => {
        const item = reviewQueue.find(entry => String(entry.item_id || '') === String(card.dataset.itemId || ''));
        renderWorkflowPackInspectorContext(item || { item_id: card.dataset.itemId }, 'Mission Review Item');
      };
      card.addEventListener('click', openCard);
      card.addEventListener('keydown', event => {
        if (event.key === 'Enter' || event.key === ' ') {
          event.preventDefault();
          openCard();
        }
      });
    });
  }
  if (proofEl) {
    proofEl.innerHTML = proofCards.length ? proofCards.map(card => `
      <article class="workflow-pack-row workflow-pack-row--proof" data-mission-proof-card="proof" data-proof-id="${escAttr(card.id || card.title || '')}" role="button" tabindex="0">
        <div>
          <strong>${escHtml(missionDisplayTitle(card.title || card.id))}</strong>
          <span>${escHtml(missionDisplayStatus(card.status))} / ${escHtml(missionPackLabel(card.pack_id, packs))}</span>
        </div>
        <div class="workflow-pack-row-meta">
          <span>${escHtml((card.approval_summary || {}).pending_gate_count || 0)} pending gates</span>
          <span>${escHtml((card.metrics || {}).artifact_count || 0)} artifacts</span>
        </div>
      </article>
    `).join('') : '<div class="workflow-packs-empty">No results yet</div>';
    proofEl.querySelectorAll('[data-mission-proof-card="proof"]').forEach(cardEl => {
      const openCard = () => {
        const proof = proofCards.find(card => String(card.id || card.title || '') === String(cardEl.dataset.proofId || ''));
        renderWorkflowPackInspectorContext(proof || { id: cardEl.dataset.proofId }, 'Mission Result');
      };
      cardEl.addEventListener('click', openCard);
      cardEl.addEventListener('keydown', event => {
        if (event.key === 'Enter' || event.key === ' ') {
          event.preventDefault();
          openCard();
        }
      });
    });
  }
}

function renderWorkflowPackApprovalActions(item) {
  if (!item || item.kind !== 'approval_gate' || item.status !== 'pending') return '';
  const runId = item.run_id || '';
  const gateId = item.item_id || '';
  if (!runId || !gateId) return '';
  return `
    <div class="workflow-pack-approval-actions">
      <button
        type="button"
        class="workflow-pack-approval-action btn-approve"
        data-run-id="${escAttr(runId)}"
        data-gate-id="${escAttr(gateId)}"
        data-decision="approved"
        title="Approve this local Workflow Pack gate"
      >Approve Local</button>
      <button
        type="button"
        class="workflow-pack-approval-action btn-reject"
        data-run-id="${escAttr(runId)}"
        data-gate-id="${escAttr(gateId)}"
        data-decision="rejected"
        title="Reject this local Workflow Pack gate"
      >Reject Local</button>
    </div>
    <div class="workflow-pack-approval-result" data-approval-result-for="${escAttr(gateId)}" aria-live="polite"></div>
  `;
}

function workflowPackAssertOk(resp, label) {
  if (!resp || !resp.ok) {
    const message = (resp && resp.error && resp.error.message) || `${label} failed`;
    throw new Error(message);
  }
  const data = resp.data || {};
  if (data.ok === false) {
    const blockers = (data.blockers || resp.warnings || []).filter(Boolean).join('; ');
    throw new Error(blockers || `${label} blocked`);
  }
  return data;
}

async function runWorkflowPackLocalResume(runId, gateId, decision, statusEl) {
  if (!window.pywebview || !window.pywebview.api) {
    throw new Error('Studio API unavailable');
  }
  const api = window.pywebview.api;
  const normalizedDecision = decision === 'rejected' ? 'rejected' : 'approved';
  const decisionLabel = normalizedDecision === 'approved' ? 'approval' : 'rejection';
  if (statusEl) statusEl.textContent = `Preparing local ${decisionLabel}...`;

  const contract = workflowPackAssertOk(
    await api.get_workflow_pack_approval_resume_contract(runId, gateId),
    'Mission approval check',
  );
  const digest = ((contract.summary || {}).request_digest) || '';
  if (!digest) throw new Error('Mission approval request is missing a verification code');

  const reviewPreview = workflowPackAssertOk(
    await api.review_workflow_pack_approval_artifact(
      runId,
      gateId,
      digest,
      'studio-operator',
      '',
      normalizedDecision,
      false,
    ),
    'Mission review check',
  );
  const reviewStatement = ((reviewPreview.approval_artifact || {}).required_operator_statement) || '';
  if (!reviewStatement) throw new Error('Mission review statement is missing');

  const confirmed = window.confirm
    ? window.confirm(`Apply local ${decisionLabel} for ${gateId}?\n\n${reviewStatement}`)
    : true;
  if (!confirmed) {
    if (statusEl) statusEl.textContent = 'Cancelled';
    return;
  }

  if (statusEl) statusEl.textContent = `Saving local ${decisionLabel}...`;
  const reviewWrite = workflowPackAssertOk(
    await api.review_workflow_pack_approval_artifact(
      runId,
      gateId,
      digest,
      'studio-operator',
      reviewStatement,
      normalizedDecision,
      true,
    ),
    'Mission review save',
  );
  const approvalPath = ((reviewWrite.approval_artifact || {}).path) || '';
  if (!approvalPath) throw new Error('Mission decision record is missing');

  if (statusEl) statusEl.textContent = 'Checking duplicate protection...';
  workflowPackAssertOk(
    await api.get_workflow_pack_approval_consumption_dry_run(
      runId,
      gateId,
      digest,
      approvalPath,
      normalizedDecision,
    ),
    'Mission decision check',
  );

  const markerPreview = workflowPackAssertOk(
    await api.reserve_workflow_pack_exact_once_marker(
      runId,
      gateId,
      digest,
      approvalPath,
      normalizedDecision,
      false,
    ),
    'Mission duplicate-protection check',
  );
  const markerStatement = ((markerPreview.exact_once_marker || {}).required_operator_statement) || '';
  if (!markerStatement) throw new Error('Duplicate-protection statement is missing');

  if (statusEl) statusEl.textContent = 'Locking this decision...';
  const markerWrite = workflowPackAssertOk(
    await api.reserve_workflow_pack_exact_once_marker(
      runId,
      gateId,
      digest,
      approvalPath,
      normalizedDecision,
      true,
      markerStatement,
      'studio-operator',
    ),
    'Mission decision lock',
  );
  const markerPath = ((markerWrite.exact_once_marker || {}).path) || '';
  if (!markerPath) throw new Error('Mission decision lock is missing');

  const resumePreview = workflowPackAssertOk(
    await api.execute_workflow_pack_approved_local_resume(
      runId,
      gateId,
      digest,
      approvalPath,
      markerPath,
      normalizedDecision,
      false,
    ),
    'Mission resume check',
  );
  const resumeStatement = ((resumePreview.local_resume_evidence || {}).required_operator_statement) || '';
  if (!resumeStatement) throw new Error('Mission resume statement is missing');

  if (statusEl) statusEl.textContent = `Applying local ${decisionLabel}...`;
  const resume = workflowPackAssertOk(
    await api.execute_workflow_pack_approved_local_resume(
      runId,
      gateId,
      digest,
      approvalPath,
      markerPath,
      normalizedDecision,
      true,
      resumeStatement,
      'studio-operator',
    ),
    'Mission resume',
  );

  const summary = resume.summary || {};
  if (statusEl) {
    statusEl.dataset.state = 'complete';
    statusEl.textContent = `Local ${decisionLabel} complete: ${summary.gate_status_after || normalizedDecision}`;
  }
  workflowPacksLoaded = false;
  await loadWorkflowPacksPanel(true);
}

function updateWorkflowPacksQuestionnaireVisibility() {
  const select = document.getElementById('workflow-packs-pack-select');
  const automationFields = document.getElementById('workflow-packs-automation-audit-fields');
  const creativeFields = document.getElementById('workflow-packs-creative-studio-fields');
  const researchFields = document.getElementById('workflow-packs-research-intelligence-fields');
  const governanceFields = document.getElementById('workflow-packs-agent-governance-fields');
  const createBtn = document.getElementById('workflow-packs-create-demo-run');
  const packId = select?.value || 'founder_personal_automation_audit';
  const isAutomationAudit = packId === 'founder_personal_automation_audit';
  const isCreativeStudio = packId === 'visual_product_creative_studio';
  const isResearchIntelligence = packId === 'research_to_product_intelligence';
  const isAgentGovernance = packId === 'safe_agent_runtime_governance_kit';
  if (automationFields) automationFields.style.display = isAutomationAudit ? 'grid' : 'none';
  if (creativeFields) creativeFields.style.display = isCreativeStudio ? 'grid' : 'none';
  if (researchFields) researchFields.style.display = isResearchIntelligence ? 'grid' : 'none';
  if (governanceFields) governanceFields.style.display = isAgentGovernance ? 'grid' : 'none';
  if (createBtn) {
    createBtn.textContent = isAutomationAudit ? 'Create Audit Mission' : isCreativeStudio ? 'Create Creative Mission' : isResearchIntelligence ? 'Create Research Mission' : isAgentGovernance ? 'Create Governance Mission' : 'Create Local Mission';
  }
}

function _initWorkflowPacksPanel() {
  document.querySelectorAll('.workflow-packs-tab').forEach(tab => {
    tab.addEventListener('click', () => {
      const selected = tab.dataset.workflowPacksTab;
      document.querySelectorAll('.workflow-packs-tab').forEach(item => {
        const active = item.dataset.workflowPacksTab === selected;
        item.classList.toggle('workflow-packs-tab--active', active);
        item.setAttribute('aria-selected', active ? 'true' : 'false');
      });
      document.querySelectorAll('.workflow-packs-tab-body').forEach(body => {
        body.style.display = body.id === `workflow-packs-tab-${selected}` ? 'block' : 'none';
      });
    });
  });
  const packSelect = document.getElementById('workflow-packs-pack-select');
  if (packSelect) {
    packSelect.addEventListener('change', updateWorkflowPacksQuestionnaireVisibility);
  }
  const createBtn = document.getElementById('workflow-packs-create-demo-run');
  if (createBtn) {
    createBtn.addEventListener('click', async () => {
      const result = document.getElementById('workflow-packs-create-result');
      const packId = document.getElementById('workflow-packs-pack-select')?.value || 'founder_personal_automation_audit';
      const title = document.getElementById('workflow-packs-title-input')?.value || '';
      const goal = document.getElementById('workflow-packs-goal-input')?.value || '';
      if (result) result.textContent = 'Creating mission...';
      try {
        let resp = null;
        if (packId === 'founder_personal_automation_audit') {
          const repeatedTasks = document.getElementById('workflow-packs-repeated-tasks-input')?.value || '';
          const workDomains = document.getElementById('workflow-packs-work-domains-input')?.value || '';
          const painPoints = document.getElementById('workflow-packs-pain-points-input')?.value || '';
          resp = await pywebview.api.create_automation_audit_run(title, goal, repeatedTasks, workDomains, painPoints);
        } else if (packId === 'visual_product_creative_studio') {
          const campaignType = document.getElementById('workflow-packs-campaign-type-input')?.value || '';
          const brandProfile = document.getElementById('workflow-packs-brand-profile-input')?.value || '';
          const offer = document.getElementById('workflow-packs-offer-input')?.value || '';
          const audience = document.getElementById('workflow-packs-audience-input')?.value || '';
          const tone = document.getElementById('workflow-packs-tone-input')?.value || '';
          const channels = document.getElementById('workflow-packs-channels-input')?.value || '';
          const primaryCta = document.getElementById('workflow-packs-primary-cta-input')?.value || '';
          resp = await pywebview.api.create_creative_studio_run(title, goal, campaignType, brandProfile, offer, audience, tone, channels, primaryCta);
        } else if (packId === 'research_to_product_intelligence') {
          const researchMode = document.getElementById('workflow-packs-research-mode-input')?.value || '';
          const sourceMaterial = document.getElementById('workflow-packs-source-material-input')?.value || '';
          const sourceUrls = document.getElementById('workflow-packs-source-urls-input')?.value || '';
          const productContext = document.getElementById('workflow-packs-product-context-input')?.value || '';
          const decisionGoal = document.getElementById('workflow-packs-decision-goal-input')?.value || '';
          const audience = document.getElementById('workflow-packs-research-audience-input')?.value || '';
          const outputFocus = document.getElementById('workflow-packs-output-focus-input')?.value || '';
          resp = await pywebview.api.create_research_intelligence_run(title, goal, researchMode, sourceMaterial, sourceUrls, productContext, decisionGoal, audience, outputFocus);
        } else if (packId === 'safe_agent_runtime_governance_kit') {
          const agentName = document.getElementById('workflow-packs-agent-name-input')?.value || '';
          const runtimeName = document.getElementById('workflow-packs-runtime-name-input')?.value || '';
          const runtimeStatus = document.getElementById('workflow-packs-runtime-status-input')?.value || '';
          const tools = document.getElementById('workflow-packs-tools-input')?.value || '';
          const readsFrom = document.getElementById('workflow-packs-reads-from-input')?.value || '';
          const writesTo = document.getElementById('workflow-packs-writes-to-input')?.value || '';
          const externalActions = document.getElementById('workflow-packs-external-actions-input')?.value || '';
          const permissionSurfaces = document.getElementById('workflow-packs-permission-surfaces-input')?.value || '';
          const workflowManifest = document.getElementById('workflow-packs-workflow-manifest-input')?.value || '';
          const approvalMode = document.getElementById('workflow-packs-approval-mode-input')?.value || '';
          resp = await pywebview.api.create_agent_governance_run(title, goal, agentName, runtimeName, runtimeStatus, tools, readsFrom, writesTo, externalActions, permissionSurfaces, workflowManifest, approvalMode);
        } else {
          resp = await pywebview.api.create_workflow_pack_demo_run(packId, title, goal);
        }
        if (!resp || !resp.ok) {
          if (result) result.textContent = (resp && resp.error && resp.error.message) || 'Create failed';
          return;
        }
        if (result) result.textContent = 'Mission created. Open Active to review outputs and approvals.';
        workflowPacksLoaded = false;
        await loadWorkflowPacksPanel(true);
      } catch (err) {
        if (result) result.textContent = err.message || String(err);
      }
    });
  }
  const reviewList = document.getElementById('workflow-packs-review-queue');
  if (reviewList) {
    reviewList.addEventListener('click', async event => {
      const button = event.target.closest('.workflow-pack-approval-action');
      if (!button) return;
      const runId = button.dataset.runId || '';
      const gateId = button.dataset.gateId || '';
      const decision = button.dataset.decision || 'approved';
      const row = button.closest('.workflow-pack-row');
      const statusEl = row ? row.querySelector('.workflow-pack-approval-result') : null;
      const originalLabel = button.textContent;
      button.disabled = true;
      button.textContent = 'Working...';
      if (statusEl) {
        statusEl.dataset.state = 'running';
        statusEl.textContent = 'Starting local approval flow...';
      }
      try {
        await runWorkflowPackLocalResume(runId, gateId, decision, statusEl);
      } catch (err) {
        if (statusEl) {
          statusEl.dataset.state = 'error';
          statusEl.textContent = err.message || String(err);
        }
      } finally {
        button.disabled = false;
        button.textContent = originalLabel;
      }
    });
  }
}

let roleCardsLoaded = false;
let roleCardDetailFile = null;
let _roleCardsAll = [];

async function loadRoleCards() {
  const status = document.getElementById('role-cards-status');
  const list   = document.getElementById('role-cards-list');
  if (roleCardsLoaded) return;
  if (status) status.textContent = 'Syncing role cards';
  try {
    const res = await window.pywebview.api.get_role_cards();
    if (!res.ok) {
      if (status) status.textContent = 'Error: ' + (res.error?.message || 'unknown');
      return;
    }
    _roleCardsAll = res.data.role_cards || [];
    renderRoleCardList(_roleCardsAll);
    if (status) status.textContent = `${_roleCardsAll.length} role card(s) loaded`;
    roleCardsLoaded = true;
  } catch (e) {
    if (status) status.textContent = 'Failed to load role cards: ' + e;
  }
}

function roleCardSafeText(value) {
  return String(value || '').replace(/read[-_\s]?only/gi, 'inspection').trim();
}

function roleCardTitleFromSlug(value) {
  const base = roleCardSafeText(value)
    .replace(/\.ya?ml$/i, '')
    .replace(/[_-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  return base ? base.replace(/\b\w/g, char => char.toUpperCase()) : 'Role Card';
}

function roleCardDisplayName(card) {
  const explicitName = roleCardSafeText(card && card.name);
  if (explicitName) return explicitName;
  return roleCardTitleFromSlug((card && (card.id || card.filename)) || 'Role Card');
}

function renderRoleCardDetailSummary(detail) {
  const label = roleCardDisplayName(detail || {});
  return `
    <div class="role-card-detail-summary">
      <div class="role-card-detail-row"><span>Name</span><strong>${escHtml(label)}</strong></div>
      <div class="role-card-detail-row"><span>Owner</span><strong>${escHtml(roleCardSafeText(detail.owner) || 'Unassigned')}</strong></div>
      <div class="role-card-detail-row"><span>Version</span><strong>${escHtml(roleCardSafeText(detail.version) || 'Current')}</strong></div>
      <div class="role-card-detail-grid">
        <div><span>Allowed Actions</span><strong>${escHtml(detail.allowed_action_count || 0)}</strong></div>
        <div><span>Blocked Actions</span><strong>${escHtml(detail.forbidden_action_count || 0)}</strong></div>
        <div><span>Write Scopes</span><strong>${escHtml(detail.write_scope_count || 0)}</strong></div>
      </div>
      <p>Permission reference only. Selection does not change trust tiers, permission matrices, runtime roles, or allowed action sets.</p>
    </div>
  `;
}

function renderRoleCardList(cards) {
  const list = document.getElementById('role-cards-list');
  if (!list) return;
  list.innerHTML = '';
  cards.forEach(card => {
    const label = roleCardDisplayName(card);
    const el = document.createElement('div');
    el.className = 'role-card-item' + (card.filename === roleCardDetailFile ? ' role-card-item--active' : '');
    el.dataset.filename = card.filename;
    el.innerHTML = `<div class="role-card-item__id">${escHtml(label)}</div>` +
      `<div class="role-card-item__meta">Allowed ${escHtml(card.allowed_action_count || 0)} / Blocked ${escHtml(card.forbidden_action_count || 0)} / Scopes ${escHtml(card.write_scope_count || 0)}</div>`;
    el.addEventListener('click', () => {
      renderObjectInspectorProductContext({
        id: card.id || card.filename,
        label,
        type: 'Role Card',
        kicker: 'Selected Role Card',
        panel: 'role-cards',
        status: `${card.allowed_action_count || 0} allowed / ${card.forbidden_action_count || 0} forbidden`,
        ownerLabel: 'Owner',
        owner: card.owner || 'unknown',
        timeLabel: 'Write Scopes',
        time: String(card.write_scope_count || 0),
        ref: card.filename,
        openLabel: 'Open Role Cards',
        note: 'Role Cards are permission reference records. Selection does not change trust tiers, permission matrices, runtime roles, or allowed action sets.',
      });
      loadRoleCardDetail(card.filename);
    });
    list.appendChild(el);
  });
}

async function loadRoleCardDetail(filename) {
  roleCardDetailFile = filename;
  renderRoleCardList(_roleCardsAll);
  const viewer  = document.getElementById('role-cards-viewer');
  const title   = document.getElementById('role-cards-viewer-title');
  const content = document.getElementById('role-cards-viewer-content');
  if (!viewer || !content) return;
  viewer.style.display = 'block';
  const selectedCard = _roleCardsAll.find(card => card.filename === filename);
  if (title) title.textContent = roleCardDisplayName(selectedCard || { filename });
  content.textContent = 'Syncing';
  try {
    const res = await window.pywebview.api.get_role_card_detail(filename);
    if (!res.ok) { content.textContent = 'Error: ' + (res.error?.message || 'unknown'); return; }
    const d = res.data;
    const meta = document.getElementById('role-cards-viewer-meta');
    if (meta) {
      meta.innerHTML = `<table class="role-card-meta-table">` +
        `<tr><td>ID</td><td>${escAttr(d.id || '')}</td></tr>` +
        `<tr><td>Name</td><td>${escAttr(d.name || '')}</td></tr>` +
        `<tr><td>Version</td><td>${escAttr(d.version || '')}</td></tr>` +
        `<tr><td>Owner</td><td>${escAttr(d.owner || '')}</td></tr>` +
        `<tr><td>Allowed Actions</td><td>${d.allowed_action_count}</td></tr>` +
        `<tr><td>Forbidden Actions</td><td>${d.forbidden_action_count}</td></tr>` +
        `<tr><td>Write Scope</td><td>${d.write_scope_count}</td></tr>` +
        `</table>`;
    }
    content.innerHTML = renderRoleCardDetailSummary(d || {});
  } catch (e) {
    content.textContent = 'Failed: ' + e;
  }
}

function _initRoleCardsPanel() {
  const search = document.getElementById('role-cards-search');
  if (search) {
    search.addEventListener('input', () => {
      const q = search.value.trim().toLowerCase();
      const filtered = q ? _roleCardsAll.filter(c =>
        (c.id || '').toLowerCase().includes(q) ||
        (c.name || '').toLowerCase().includes(q) ||
        (c.owner || '').toLowerCase().includes(q) ||
        roleCardDisplayName(c).toLowerCase().includes(q)
      ) : _roleCardsAll;
      renderRoleCardList(filtered);
    });
  }
  const closeBtn = document.getElementById('role-cards-viewer-close');
  if (closeBtn) {
    closeBtn.addEventListener('click', () => {
      const viewer = document.getElementById('role-cards-viewer');
      if (viewer) viewer.style.display = 'none';
      roleCardDetailFile = null;
      renderRoleCardList(_roleCardsAll);
    });
  }
}

// -- Pass 10W: Runtime Memory/RNM Detail Inspector --------------------------
let runtimeMemoryInspectorLoaded = false;
let runtimeMemorySelectedId = null;
let _runtimeMemoryRuntimesAll = [];

async function loadRuntimeMemoryInspector() {
  const status = document.getElementById('runtime-memory-inspector-status');
  const list = document.getElementById('runtime-memory-list');
  if (runtimeMemoryInspectorLoaded) return;
  if (status) status.textContent = 'Syncing runtimes';
  if (list) list.innerHTML = '<div class="runtime-memory-empty">Syncing runtimes</div>';
  try {
    const res = await window.pywebview.api.get_runtime_memory_runtimes();
    if (!res.ok) {
      if (status) status.textContent = 'Failed';
      if (list) list.innerHTML = `<div class="runtime-memory-error">${escHtml(res.error?.message || 'Unable to load runtime memory list')}</div>`;
      return;
    }
    _runtimeMemoryRuntimesAll = (res.data && res.data.runtimes) || [];
    renderRuntimeMemoryList(_runtimeMemoryRuntimesAll);
    if (status) status.textContent = `${_runtimeMemoryRuntimesAll.length} runtime(s) loaded`;
    runtimeMemoryInspectorLoaded = true;
    if (_runtimeMemoryRuntimesAll.length && !runtimeMemorySelectedId) {
      loadRuntimeMemoryDetail(_runtimeMemoryRuntimesAll[0].runtime_id);
    }
  } catch (e) {
    if (status) status.textContent = 'Failed';
    if (list) list.innerHTML = `<div class="runtime-memory-error">${escHtml(String(e))}</div>`;
  }
}

function renderRuntimeMemoryList(runtimes) {
  const list = document.getElementById('runtime-memory-list');
  if (!list) return;
  list.innerHTML = '';
  if (!runtimes.length) {
    list.innerHTML = '<div class="runtime-memory-empty">No runtime memory adapters found.</div>';
    return;
  }
  runtimes.forEach(runtime => {
    const runtimeId = runtime.runtime_id || '';
    const el = document.createElement('div');
    el.className = 'runtime-memory-item' + (runtimeMemorySelectedId === runtimeId ? ' runtime-memory-item--active' : '');
    el.setAttribute('data-runtime-id', runtimeId);
    el.innerHTML = `
      <div class="runtime-memory-item__id">${escHtml(runtimeId)}</div>
      <div class="runtime-memory-badges">
        ${runtimeMemoryPresenceBadge('profile', runtime.has_profile)}
        ${runtimeMemoryPresenceBadge('identity', runtime.has_identity_ledger)}
        ${runtimeMemoryPresenceBadge('nav', runtime.has_nav_map)}
        ${runtimeMemoryPresenceBadge('score', runtime.has_scorecard)}
        ${runtimeMemoryPresenceBadge('repair', runtime.has_repair)}
      </div>
    `;
    el.addEventListener('click', () => {
      renderObjectInspectorProductContext({
        id: runtimeId,
        label: runtimeId,
        type: 'Runtime Memory',
        kicker: 'Selected Memory Runtime',
        panel: 'runtime-memory-inspector',
        runtimeId,
        status: runtime.has_profile ? 'profile present' : 'profile missing',
        ownerLabel: 'Runtime',
        owner: runtimeId,
        timeLabel: 'Coverage',
        time: [
          runtime.has_identity_ledger,
          runtime.has_nav_map,
          runtime.has_scorecard,
          runtime.has_repair,
        ].filter(Boolean).length + '/4',
        ref: runtimeId,
        openLabel: 'Open Memory',
        note: 'Runtime memory is inspectable only. Profile, ledger, navigation, scorecard, and repair writes remain governed by runtime memory lanes.',
      });
      loadRuntimeMemoryDetail(runtimeId);
    });
    list.appendChild(el);
  });
}

function runtimeMemoryPresenceBadge(label, present) {
  const cls = present ? 'runtime-memory-badge runtime-memory-badge--present' : 'runtime-memory-badge runtime-memory-badge--missing';
  return `<span class="${cls}" title="${escAttr(label)} ${present ? 'present' : 'missing'}">${escHtml(label)}</span>`;
}

async function loadRuntimeMemoryDetail(runtimeId) {
  const status = document.getElementById('runtime-memory-inspector-status');
  const viewer = document.getElementById('runtime-memory-viewer');
  if (!viewer) return;
  runtimeMemorySelectedId = runtimeId;
  renderRuntimeMemoryList(_runtimeMemoryRuntimesAll);
  viewer.innerHTML = '<div class="runtime-memory-empty">Opening runtime detail</div>';
  if (status) status.textContent = `Opening ${runtimeId}`;
  try {
    const res = await window.pywebview.api.get_runtime_memory_detail(runtimeId);
    if (!res.ok) {
      if (status) status.textContent = 'Missing runtime';
      viewer.innerHTML = `<div class="runtime-memory-error">${escHtml(res.error?.message || 'Runtime not found')}</div>`;
      return;
    }
    renderRuntimeMemoryDetail(res.data || {});
    if (status) status.textContent = `${runtimeId} loaded`;
  } catch (e) {
    if (status) status.textContent = 'Failed';
    viewer.innerHTML = `<div class="runtime-memory-error">${escHtml(String(e))}</div>`;
  }
}

function renderRuntimeMemoryDetail(detail) {
  const viewer = document.getElementById('runtime-memory-viewer');
  if (!viewer) return;
  const runtimeId = detail.runtime_id || runtimeMemorySelectedId || '';
  const files = detail.files_present || {};
  renderObjectInspectorProductContext({
    id: runtimeId,
    label: runtimeId,
    type: 'Runtime Memory',
    kicker: 'Selected Memory Runtime',
    panel: 'runtime-memory-inspector',
    runtimeId,
    status: files.profile ? 'profile present' : 'profile missing',
    ownerLabel: 'Runtime',
    owner: runtimeId,
    timeLabel: 'Files',
    time: Object.values(files).filter(Boolean).length + '/' + Object.keys(files).length,
    ref: runtimeId,
    openLabel: 'Open Memory',
    note: 'This view reads runtime memory posture only. It does not update runtime brain, write memory, mutate trust, or promote canonical state.',
  });
  viewer.innerHTML = `
    <div class="runtime-memory-detail-header">
      <div>
        <div class="runtime-memory-detail-label">Runtime</div>
        <div class="runtime-memory-detail-id">${escHtml(runtimeId)}</div>
      </div>
      <div class="runtime-memory-badges runtime-memory-badges--detail">
        ${runtimeMemoryPresenceBadge('profile', files.profile)}
        ${runtimeMemoryPresenceBadge('identity', files.identity_ledger)}
        ${runtimeMemoryPresenceBadge('nav', files.nav_map)}
        ${runtimeMemoryPresenceBadge('score', files.scorecard)}
        ${runtimeMemoryPresenceBadge('repair', files.repair)}
      </div>
    </div>
    ${runtimeMemorySection('Behavioral Profile', detail.profile)}
    ${runtimeMemorySection('Identity Ledger', detail.identity_ledger)}
    ${runtimeMemorySection('Runtime Navigation Map', detail.nav_map)}
    ${runtimeMemorySection('Scorecard', detail.scorecard)}
    ${runtimeMemorySection('Repair Patterns', detail.repair)}
    ${runtimeMemorySection('Files Present', detail.files_present)}
    ${runtimeMemorySection('Authority Boundary', detail.boundary)}
  `;
}

function runtimeMemorySection(title, value) {
  const body = value ? escHtml(JSON.stringify(value, null, 2)) : 'missing';
  const missingClass = value ? '' : ' runtime-memory-section--missing';
  return `
    <section class="runtime-memory-section${missingClass}">
      <div class="runtime-memory-section-title">${escHtml(title)}</div>
      <pre class="runtime-memory-section-body">${body}</pre>
    </section>
  `;
}

function _initRuntimeMemoryInspectorPanel() {
  const search = document.getElementById('runtime-memory-search');
  if (search) {
    search.addEventListener('input', () => {
      const q = search.value.trim().toLowerCase();
      const filtered = q ? _runtimeMemoryRuntimesAll.filter(runtime =>
        (runtime.runtime_id || '').toLowerCase().includes(q)
      ) : _runtimeMemoryRuntimesAll;
      renderRuntimeMemoryList(filtered);
    });
  }
}

const _graphSearch = document.getElementById('graph-search');
if (_graphSearch) {
  _graphSearch.addEventListener('input', () => {
    if (!graph3d) return;
    graphFilters.query = _graphSearch.value.trim().toLowerCase();
    if (window.GraphFilters) {
      window.GraphFilters.renderActiveFilterChips(graphFilters);
    }
    applyGraphFilters();
  });
}

// ── Settings modal ────────────────────────────────────────────────────────────
function initSettingsModal() {
  const settingsBtn = document.getElementById('topbar-settings-btn');
  const modal = document.getElementById('settings-modal');
  const closeBtn = document.getElementById('settings-modal-close');
  const saveBtn = document.getElementById('settings-save-btn');
  const resetBtn = document.getElementById('settings-reset-btn');

  if (!modal) return;

  if (settingsBtn) {
    settingsBtn.addEventListener('click', () => openSettingsModal());
  }
  if (closeBtn) {
    closeBtn.addEventListener('click', () => { modal.style.display = 'none'; });
  }
  modal.addEventListener('click', evt => {
    if (evt.target === modal) modal.style.display = 'none';
  });

  if (saveBtn) {
    saveBtn.addEventListener('click', async () => {
      if (!_currentSettings) return;
      const result = await window.pywebview.api.save_graph_settings(_currentSettings);
      if (result.ok) {
        modal.style.display = 'none';
        if (graph3d) graph3d.nodeColor(_graphNodeColor);
        if (window.InspectorTabs) window.InspectorTabs.setInspectorSettings((_currentSettings && _currentSettings.inspector) || {});
        graphLoaded = false;
        await loadGraph();
      } else {
        alert('Settings invalid: ' + ((result.error && result.error.message) || 'unknown error'));
      }
    });
  }

  if (resetBtn) {
    resetBtn.addEventListener('click', async () => {
      if (!confirm('Reset all graph settings to defaults?')) return;
      const result = await window.pywebview.api.reset_graph_settings();
      if (result.ok) {
        _currentSettings = result.data.defaults;
        if (window.GraphStyles) {
          window.GraphStyles.setStyleSettings(_currentSettings);
          if (graph3d) graph3d.nodeColor(_graphNodeColor);
        }
        if (window.InspectorTabs) window.InspectorTabs.setInspectorSettings((_currentSettings && _currentSettings.inspector) || {});
        modal.style.display = 'none';
        graphLoaded = false;
        await loadGraph();
      }
    });
  }
}

async function openSettingsModal(options = {}) {
  const modal = document.getElementById('settings-modal');
  if (!modal) return;
  if (options.tab) _activeSettingsTab = options.tab;

  const resp = await window.pywebview.api.get_graph_settings();
  if (resp && resp.ok) {
    _currentSettings = resp.data;
    if (window.GraphStyles) window.GraphStyles.setStyleSettings(_currentSettings);
  }

  _renderSettingsTabs(_currentSettings || {});
  modal.style.display = 'flex';
  if (options.focusId) {
    setTimeout(() => _focusSettingsTarget(options.focusId), 50);
  }
}

window.openGraphSettings = openSettingsModal;
window.GraphFilters = window.GraphFilters || {};
window.GraphFilters.applyGraphFilters = applyGraphFilters;

function _focusSettingsTarget(focusId) {
  const target = document.querySelector(`[data-settings-target="${escAttr(focusId)}"]`);
  if (!target) return;
  target.classList.add('settings-subsection--focus');
  target.scrollIntoView({ block: 'center', behavior: 'smooth' });
  setTimeout(() => target.classList.remove('settings-subsection--focus'), 1400);
}

const _SETTINGS_TABS = [
  { id: 'appearance', label: 'Appearance' },
  { id: 'node_families', label: 'Node Types' },
  { id: 'trust_states', label: 'Trust States' },
  { id: 'node_scope', label: 'Node Scope' },
  { id: 'layout', label: 'Layout' },
  { id: 'edge_layers', label: 'Edge Layers' },
  { id: 'accessibility', label: 'Accessibility' },
  { id: 'inspector', label: 'Inspector' },
];

let _activeSettingsTab = 'appearance';

function _renderSettingsTabs(settings) {
  const tabsEl = document.getElementById('settings-tabs');
  const bodyEl = document.getElementById('settings-body');
  if (!tabsEl || !bodyEl) return;
  if (window.GraphSettings) {
    window.GraphSettings.renderSettingsTabs({
      settings,
      activeTab: _activeSettingsTab,
      onTabSelect: tab => {
        _activeSettingsTab = tab;
        _renderSettingsTabs(settings);
      },
      onInputChange: input => _onSettingChange(input),
      onAction: button => _onSettingAction(button),
    });
    return;
  }

  tabsEl.innerHTML = _SETTINGS_TABS.map(t =>
    `<button class="settings-tab-btn${t.id === _activeSettingsTab ? ' active' : ''}" data-tab="${escAttr(t.id)}">${escHtml(t.label)}</button>`
  ).join('');

  tabsEl.querySelectorAll('.settings-tab-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      _activeSettingsTab = btn.dataset.tab;
      tabsEl.querySelectorAll('.settings-tab-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      _renderSettingsTabContent(_activeSettingsTab, settings);
    });
  });

  _renderSettingsTabContent(_activeSettingsTab, settings);
}

function _renderSettingsTabContent(tabId, settings) {
  const bodyEl = document.getElementById('settings-body');
  if (!bodyEl) return;

  const section = settings[tabId] || {};
  let html = `<div class="settings-section">`;

  switch (tabId) {
    case 'appearance':
      html += _settingToggle('Show labels', 'show_labels', section, tabId);
      html += _settingToggle('Show badges', 'show_badges', section, tabId);
      html += _settingToggle('Animate runtime edges', 'animate_runtime_edges', section, tabId);
      html += _settingRange('Label font size', 'label_font_size', section, tabId, 6, 32);
      html += _settingRange('Node opacity', 'node_opacity', section, tabId, 0.1, 1.0, 0.05);
      break;
    case 'node_scope':
      html += _settingToggle('Files / pages', 'files_pages', section, tabId);
      html += _settingToggle('Headings', 'headings', section, tabId);
      html += _settingToggle('Blocks', 'blocks', section, tabId);
      html += _settingToggle('Tasks', 'tasks', section, tabId);
      html += _settingToggle('Show entity objects', 'show_entity_objects', section, tabId);
      html += _settingToggle('Show unresolved links', 'show_unresolved_links', section, tabId);
      html += _settingToggle('Show external resources', 'show_external_resources', section, tabId);
      html += _settingRange('Max nodes', 'max_nodes', section, tabId, 10, 5000, 50);
      html += _settingRange('Max edges', 'max_edges', section, tabId, 10, 15000, 50);
      break;
    case 'node_families':
      html += _renderNodeFamilySettings(section);
      break;
    case 'trust_states':
      html += _renderTrustStateSettings(section);
      break;
    case 'layout':
      html += _settingToggle('Animate layout', 'animate_layout', section, tabId);
      html += _settingSelect('Algorithm', 'algorithm', section, tabId,
        ['cose', 'grid', 'circle', 'concentric', 'breadthfirst', 'random']);
      break;
    case 'edge_layers':
      for (const [layer, cfg] of Object.entries(section)) {
        html += _settingToggle(`Show ${filterLabel(layer)} edges`, 'visible', cfg, `edge_layers_${layer}`, layer);
        html += _settingRange(`${filterLabel(layer)} width`, 'width', cfg, `edge_layers_${layer}`, 0.25, 12, 0.25, layer);
        html += _settingRange(`${filterLabel(layer)} opacity`, 'opacity', cfg, `edge_layers_${layer}`, 0.05, 1, 0.05, layer);
      }
      break;
    case 'accessibility':
      html += _settingToggle('High contrast', 'high_contrast', section, tabId);
      html += _settingToggle('Reduce motion', 'motion_reduce', section, tabId);
      html += _settingSelect('Colorblind mode', 'colorblind_mode', section, tabId,
        ['none', 'deuteranopia', 'protanopia', 'tritanopia']);
      break;
    case 'inspector':
      html += _settingToggle('Show raw metadata', 'show_raw_metadata', section, tabId);
      html += _settingToggle('Show source content', 'show_source_content', section, tabId);
      html += _settingSelect('Default tab', 'default_tab', section, tabId,
        ['overview', 'relations', 'provenance', 'trust', 'runtime', 'source', 'debug']);
      break;
    default:
      html += `<div style="color:var(--text-muted);font-size:12px">No settings for this section.</div>`;
  }

  html += '</div>';
  bodyEl.innerHTML = html;

  bodyEl.querySelectorAll('[data-settings-key]').forEach(input => {
    input.addEventListener('change', () => _onSettingChange(input));
  });
}

function _settingToggle(label, key, section, tabId, edgeLayer) {
  const checked = section[key] !== false ? 'checked' : '';
  const dataset = edgeLayer
    ? `data-settings-tab="edge_layers" data-edge-layer="${escAttr(edgeLayer)}" data-settings-key="${escAttr(key)}"`
    : `data-settings-tab="${escAttr(tabId)}" data-settings-key="${escAttr(key)}"`;
  return `<label class="settings-row"><span>${escHtml(label)}</span><input type="checkbox" ${dataset} ${checked}></label>`;
}

function _settingRange(label, key, section, tabId, min, max, step, edgeLayer) {
  const val = section[key] != null ? section[key] : '';
  const stepAttr = step ? `step="${step}"` : '';
  const edgeAttr = edgeLayer ? ` data-edge-layer="${escAttr(edgeLayer)}"` : '';
  return `<label class="settings-row"><span>${escHtml(label)}</span><input type="number" min="${min}" max="${max}" ${stepAttr} value="${escAttr(String(val))}" data-settings-tab="${escAttr(tabId)}" data-settings-key="${escAttr(key)}"${edgeAttr}></label>`;
}

function _settingSelect(label, key, section, tabId, options) {
  const val = section[key] || '';
  const opts = options.map(o => `<option value="${escAttr(o)}"${o === val ? ' selected' : ''}>${escHtml(o)}</option>`).join('');
  return `<label class="settings-row"><span>${escHtml(label)}</span><select data-settings-tab="${escAttr(tabId)}" data-settings-key="${escAttr(key)}">${opts}</select></label>`;
}

function _renderNodeFamilySettings(section) {
  const registry = (window.GraphStyles && window.GraphStyles.getRegistry && window.GraphStyles.getRegistry()) || {};
  const families = registry.node_families || {};
  return Object.entries(families).map(([family, defaults]) => {
    const cfg = section[family] || {};
    const shape = cfg.shape || defaults.shape || 'ellipse';
    const fill = cfg.fill_color || defaults.fill_color || '#334155';
    return `
      <div class="settings-subsection">
        <div class="settings-subtitle" data-settings-target="${escAttr(family)}">${escHtml(defaults.label || filterLabel(family))}</div>
        ${_settingSelect('Shape', 'shape', { shape }, `node_families_${family}`, ['ellipse','rectangle','round-rectangle','cut-rectangle','barrel','rhomboid','diamond','hexagon','pentagon','octagon','star','tag','vee'])}
        <label class="settings-row"><span>Fill color</span><input type="color" value="${escAttr(fill)}" data-settings-tab="node_families_${escAttr(family)}" data-settings-key="fill_color"></label>
      </div>`;
  }).join('');
}

function _renderTrustStateSettings(section) {
  const registry = (window.GraphStyles && window.GraphStyles.getRegistry && window.GraphStyles.getRegistry()) || {};
  const states = registry.trust_states || {};
  return Object.entries(states).map(([trust, defaults]) => {
    const cfg = section[trust] || {};
    const color = cfg.ring_color || defaults.ring_color || '#94a3b8';
    const width = cfg.ring_width || defaults.ring_width || 3;
    const badgeVisible = cfg.badge_visible !== false ? 'checked' : '';
    return `
      <div class="settings-subsection">
        <div class="settings-subtitle" data-settings-target="${escAttr(trust)}">${escHtml(defaults.label || filterLabel(trust))}</div>
        <label class="settings-row"><span>Ring color</span><input type="color" value="${escAttr(color)}" data-settings-tab="trust_states_${escAttr(trust)}" data-settings-key="ring_color"></label>
        <label class="settings-row"><span>Ring width</span><input type="number" min="1" max="12" step="1" value="${escAttr(String(width))}" data-settings-tab="trust_states_${escAttr(trust)}" data-settings-key="ring_width"></label>
        ${_settingSelect('Ring style', 'ring_style', { ring_style: cfg.ring_style || defaults.ring_style || 'solid' }, `trust_states_${trust}`, ['solid','dashed','dotted','double'])}
        <label class="settings-row"><span>Badge visible</span><input type="checkbox" data-settings-tab="trust_states_${escAttr(trust)}" data-settings-key="badge_visible" ${badgeVisible}></label>
      </div>`;
  }).join('');
}

function _onSettingChange(input) {
  if (!_currentSettings) return;
  if (window.GraphSettings) {
    window.GraphSettings.applyInputChange(_currentSettings, input);
    _applyLiveGraphSettings();
    return;
  }

  const tabId = input.dataset.settingsTab;
  const key = input.dataset.settingsKey;

  if (!_currentSettings[tabId]) _currentSettings[tabId] = {};

  let value;
  if (input.type === 'checkbox') value = input.checked;
  else if (input.type === 'number') value = parseFloat(input.value);
  else value = input.value;

  // Handle edge_layers nested key
  if (tabId === 'edge_layers' || tabId.startsWith('edge_layers_')) {
    const layer = input.dataset.edgeLayer;
    const inferredLayer = layer || tabId.replace(/^edge_layers_/, '');
    if (inferredLayer && inferredLayer !== 'edge_layers') {
      if (!_currentSettings.edge_layers) _currentSettings.edge_layers = {};
      if (!_currentSettings.edge_layers[inferredLayer]) _currentSettings.edge_layers[inferredLayer] = {};
      _currentSettings.edge_layers[inferredLayer][key] = value;
      _applyLiveGraphSettings();
      return;
    }
  }

  if (tabId.startsWith('node_families_')) {
    const family = tabId.replace(/^node_families_/, '');
    if (!_currentSettings.node_families) _currentSettings.node_families = {};
    if (!_currentSettings.node_families[family]) _currentSettings.node_families[family] = {};
    _currentSettings.node_families[family][key] = value;
    _applyLiveGraphSettings();
    return;
  }

  if (tabId.startsWith('trust_states_')) {
    const trust = tabId.replace(/^trust_states_/, '');
    if (!_currentSettings.trust_states) _currentSettings.trust_states = {};
    if (!_currentSettings.trust_states[trust]) _currentSettings.trust_states[trust] = {};
    _currentSettings.trust_states[trust][key] = value;
    _applyLiveGraphSettings();
    return;
  }

  _currentSettings[tabId][key] = value;

  _applyLiveGraphSettings();
}

function _onSettingAction(button) {
  if (!_currentSettings) return;
  const action = button.dataset.settingsAction;
  const target = button.dataset.settingsTargetId || '';
  if (action === 'reset-node-family' && target) {
    if (!_currentSettings.node_families) _currentSettings.node_families = {};
    _currentSettings.node_families[target] = {};
    _applyLiveGraphSettings();
    _renderSettingsTabs(_currentSettings);
    _focusSettingsTarget(target);
    return;
  }
  if (action === 'reset-all-node-styles') {
    if (!confirm('Reset all node family style overrides?')) return;
    const registry = (window.GraphStyles && window.GraphStyles.getRegistry && window.GraphStyles.getRegistry()) || {};
    const families = registry.node_families || {};
    _currentSettings.node_families = {};
    Object.keys(families).forEach(family => { _currentSettings.node_families[family] = {}; });
    _applyLiveGraphSettings();
    _renderSettingsTabs(_currentSettings);
    return;
  }
  if (action === 'duplicate-node-style' && target) {
    const registry = (window.GraphStyles && window.GraphStyles.getRegistry && window.GraphStyles.getRegistry()) || {};
    const families = Object.keys(registry.node_families || {});
    const destination = prompt(`Duplicate ${target} style to which node family?`, families.find(f => f !== target) || '');
    if (!destination) return;
    if (!families.includes(destination)) {
      alert('Unknown node family: ' + destination);
      return;
    }
    if (!_currentSettings.node_families) _currentSettings.node_families = {};
    _currentSettings.node_families[destination] = Object.assign({}, _currentSettings.node_families[target] || {});
    _applyLiveGraphSettings();
    _renderSettingsTabs(_currentSettings);
    _focusSettingsTarget(destination);
    return;
  }
  if (action === 'export-node-style' && target) {
    _copySettingsText(`${target} node style`, JSON.stringify({
      node_families: { [target]: (_currentSettings.node_families || {})[target] || {} },
    }, null, 2));
    return;
  }
  if (action === 'export-node-style-map') {
    _copySettingsText('node style map', JSON.stringify({ node_families: _currentSettings.node_families || {} }, null, 2));
    return;
  }
  if (action === 'export-settings') {
    _copySettingsText('graph settings', JSON.stringify(_currentSettings, null, 2));
    return;
  }
  if (action === 'import-settings') {
    const raw = prompt('Paste graph settings JSON. It will be applied in memory; use Save Settings to validate and persist.');
    if (!raw) return;
    try {
      const parsed = JSON.parse(raw);
      if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) throw new Error('Settings JSON must be an object.');
      _currentSettings = parsed;
      if (window.GraphStyles) window.GraphStyles.setStyleSettings(_currentSettings);
      _applyLiveGraphSettings();
      _renderSettingsTabs(_currentSettings);
      alert('Imported settings into the current session. Use Save Settings to validate and persist to Studio user state.');
    } catch (err) {
      alert('Import failed: ' + err.message);
    }
  }
  if (['apply-quality-ultra', 'apply-quality-balanced', 'apply-quality-performance', 'apply-quality-minimal'].includes(action)) {
    const preset = action.replace('apply-quality-', '');
    _applyQualityPreset(preset);
    return;
  }
  if (action === 'pin-selected-node') {
    if (!_currentSettings.layout) _currentSettings.layout = {};
    if (!Array.isArray(_currentSettings.layout.pinned_nodes)) _currentSettings.layout.pinned_nodes = [];
    if (!_focusedGraphNodeId) {
      alert('Click a graph node to select it before pinning.');
      return;
    }
    const id = _focusedGraphNodeId;
    if (!_currentSettings.layout.pinned_nodes.map(String).includes(id)) {
      _currentSettings.layout.pinned_nodes.push(id);
    }
    _renderSettingsTabs(_currentSettings);
    return;
  }
  if (action === 'clear-pinned-nodes') {
    if (!_currentSettings.layout) _currentSettings.layout = {};
    _currentSettings.layout.pinned_nodes = [];
    _renderSettingsTabs(_currentSettings);
    return;
  }
  if (action === 'reset-graph-layout') {
    if (graph3d) {
      graph3d.zoomToFit(400, 30);
    }
    return;
  }
}

async function _copySettingsText(label, text) {
  try {
    if (navigator.clipboard && navigator.clipboard.writeText) {
      await navigator.clipboard.writeText(text);
      alert(`Exported ${label} JSON to clipboard.`);
      return;
    }
  } catch (_) {}
  prompt(`Copy ${label} JSON`, text);
}

function _applyLiveGraphSettings() {
  if (window.GraphStyles) {
    window.GraphStyles.setStyleSettings(_currentSettings);
    if (graph3d) graph3d.nodeColor(_graphNodeColor);
  }
  applyGraphAppearanceSurface();
  // Reflect any performance/quality changes
  if (_currentSettings && _currentSettings.performance) {
    _applyGraphPerf3D(_currentSettings.performance);
  }
  if (window.InspectorTabs) {
    window.InspectorTabs.setInspectorSettings((_currentSettings && _currentSettings.inspector) || {});
  }
  if (_lastGraphContract && graph3d) {
    const graphData = buildForceGraphData(_lastGraphContract);
    _graphAllNodes = graphData.nodes;
    _graphAllLinks = graphData.links;
    applyGraphFilters();
    updateGraphLabelVisibility();
  }
}

// ── Helpers ───────────────────────────────────────────────────────────────────
function escHtml(s) {
  return productizeUiCopy(String(s))
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function escHtmlRaw(s) {
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function escAttr(s) {
  return String(s).replace(/'/g, '&#39;').replace(/"/g, '&quot;');
}

// ── Phase 6: Shared UI components ─────────────────────────

function emptyState(icon, title, body, hint = '') {
  return `<div class="empty-state">` +
    `<div class="empty-state-icon">${icon}</div>` +
    `<div class="empty-state-title">${escHtml(title)}</div>` +
    `<div class="empty-state-body">${escHtml(body)}</div>` +
    (hint ? `<div class="empty-state-hint">${escHtml(hint)}</div>` : '') +
    `</div>`;
}

function panelLoading(msg = 'Syncing local state') {
  return `<div class="panel-loading">${escHtml(msg)}</div>`;
}

// ── Phase 6: Keyboard shortcuts ────────────────────────────

// Expose graph node list globally for WikiLink resolution
Object.defineProperty(window, '_graphAllNodes', {
  get() { return _graphAllNodes; },
  configurable: true,
});
Object.defineProperty(window, '_graphAllLinks', {
  get() { return _graphAllLinks; },
  configurable: true,
});

function captureHotkeyEventChord(event) {
  const key = captureHotkeyEventKey(event);
  if (!key) return '';
  const parts = [];
  if (event.ctrlKey) parts.push('Ctrl');
  if (event.shiftKey) parts.push('Shift');
  if (event.altKey) parts.push('Alt');
  if (event.metaKey) parts.push('Meta');
  if (!parts.length) return '';
  parts.push(key);
  return parts.join('+');
}

function captureHotkeyEventKey(event) {
  const raw = String(event.key || '');
  if (!raw || ['Control', 'Shift', 'Alt', 'Meta'].includes(raw)) return '';
  if (raw.length === 1 && /[a-z0-9]/i.test(raw)) return raw.toUpperCase();
  const named = {
    ' ': 'Space',
    Spacebar: 'Space',
    Enter: 'Enter',
    Escape: 'Escape',
    Esc: 'Escape',
    Tab: 'Tab',
  };
  if (named[raw]) return named[raw];
  if (/^F([1-9]|1[0-9]|2[0-4])$/i.test(raw)) return raw.toUpperCase();
  return '';
}

function captureHotkeyActionForEvent(event) {
  const chord = captureHotkeyEventChord(event);
  if (!chord || !captureHotkeySettings) return null;
  const actions = captureHotkeySettings.actions || [];
  return actions.find(action =>
    action.available_in_studio &&
    action.chord &&
    action.chord === chord
  ) || null;
}

function runCaptureHotkeyIfMatched(event) {
  const action = captureHotkeyActionForEvent(event);
  if (!action) return false;
  if (action.id === 'open_capture_markdown') {
    event.preventDefault();
    showPanel('capture-markdown', { updateHash: true });
    return true;
  }
  if (action.id === 'focus_capture_raw_text') {
    event.preventDefault();
    showPanel('capture-markdown', { updateHash: true });
    setTimeout(() => {
      const rawText = document.getElementById('capture-markdown-raw-text');
      if (rawText) rawText.focus();
    }, 80);
    return true;
  }
  if (action.id === 'preview_capture_markdown' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    previewCaptureMarkdown();
    return true;
  }
  if (action.id === 'save_capture_markdown' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    saveCaptureMarkdown();
    return true;
  }
  if (action.id === 'run_screen_capture_collector' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    captureCurrentScreenForMarkdown();
    return true;
  }
  if (action.id === 'run_display_region_collector' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    captureDisplayRegionForMarkdown();
    return true;
  }
  if (action.id === 'run_active_window_collector' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    captureActiveWindowForMarkdown();
    return true;
  }
  if (action.id === 'run_clipboard_text_collector' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    captureClipboardTextForMarkdown();
    return true;
  }
  if (action.id === 'run_ambient_clipboard_monitor' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    toggleAmbientClipboardMonitorForMarkdown();
    return true;
  }
  if (action.id === 'run_selected_text_collector' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    captureSelectedTextForMarkdown();
    return true;
  }
  if (action.id === 'run_accessibility_tree_collector' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    captureAccessibilityTreeForMarkdown();
    return true;
  }
  if (action.id === 'run_browser_artifact_collector' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    captureBrowserArtifactForMarkdown();
    return true;
  }
  if (action.id === 'run_browser_extension_collector' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    captureBrowserExtensionArtifactForMarkdown();
    return true;
  }
  if (action.id === 'run_active_browser_collector' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    captureActiveChaseosBrowserForMarkdown();
    return true;
  }
  if (action.id === 'run_chaseos_browser_page_collector' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    captureChaseosBrowserPageForMarkdown();
    return true;
  }
  if (action.id === 'run_discord_artifact_collector' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    captureDiscordArtifactForMarkdown();
    return true;
  }
  if (action.id === 'run_live_discord_command_collector' && currentPanel === 'capture-markdown') {
    event.preventDefault();
    captureLiveDiscordCommandForMarkdown();
    return true;
  }
  return false;
}

function initKeyboardShortcuts() {
  const NAV_PANELS = [
    'dashboard', 'chat', 'graph', 'intake',
    'approval-center', 'runtime-cockpit', 'schedules', 'aor',
  ];
  document.addEventListener('keydown', e => {
    const inInput = e.target.matches('input, textarea, select, [contenteditable="true"]');

    // Escape — always close quick switch / graph filter, even when an input is focused
    if (e.key === 'Escape') {
      const qsModal = document.getElementById('quick-switch-modal');
      if (qsModal && !qsModal.hidden) {
        e.preventDefault();
        _closeQuickSwitch();
        return;
      }
      const filterPanel = document.getElementById('graph-filter-panel');
      if (filterPanel && !filterPanel.hidden) {
        e.preventDefault();
        setGraphFilterPanelOpen(false);
        return;
      }
    }

    if (runCaptureHotkeyIfMatched(e)) return;

    // Ctrl+O — Quick Switch (only on graph + node-inspector panels)
    if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'k') {
      e.preventDefault();
      const commandInput = document.getElementById('global-command-input');
      if (commandInput) commandInput.focus();
      _openQuickSwitch();
      return;
    }

    if ((e.ctrlKey || e.metaKey) && e.key === 'o') {
      if (['graph', 'node-inspector'].includes(currentPanel)) {
        e.preventDefault();
        _openQuickSwitch();
        return;
      }
    }

    // Ctrl+F — toggle graph filters (only on graph panel)
    if ((e.ctrlKey || e.metaKey) && e.key === 'f' && currentPanel === 'graph') {
      e.preventDefault();
      toggleGraphFilterPanel();
      return;
    }

    if (inInput) return;
    if (e.metaKey || e.ctrlKey || e.altKey) return;

    const num = parseInt(e.key, 10);
    if (!isNaN(num) && num >= 1 && num <= NAV_PANELS.length) {
      e.preventDefault();
      showPanel(NAV_PANELS[num - 1], { updateHash: true });
      return;
    }
    if (e.key === '/') {
      const search = document.getElementById('graph-search');
      if (search) {
        e.preventDefault();
        showPanel('graph', { updateHash: true });
        setTimeout(() => search.focus(), 50);
      }
    }

    // G — open graph quality / performance settings (graph panel only)
    if (e.key === 'g' && currentPanel === 'graph') {
      e.preventDefault();
      openSettingsModal({ tab: 'performance' });
    }

    // D — toggle 2D / 3D view (graph panel only)
    if (e.key === 'd' && currentPanel === 'graph') {
      e.preventDefault();
      setGraphDimensions(_graph2DMode ? 3 : 2);
    }
  });
}

// ── Quick Switch overlay ──────────────────────────────────────────────────────

let _qsSelectedIndex = 0;
let _qsResults = [];

function _openQuickSwitch() {
  const modal = document.getElementById('quick-switch-modal');
  const input = document.getElementById('quick-switch-input');
  if (!modal) return;
  modal.hidden = false;
  if (input) { input.value = ''; input.focus(); }
  _qsSelectedIndex = 0;
  _renderQSResults('');

  // Re-attach listeners (idempotent via replace)
  if (input && !input._qsWired) {
    input._qsWired = true;
    input.addEventListener('input', () => {
      _qsSelectedIndex = 0;
      _renderQSResults(input.value);
    });
    input.addEventListener('keydown', e => {
      if (e.key === 'ArrowDown') { e.preventDefault(); _qsMoveSelection(1); }
      else if (e.key === 'ArrowUp') { e.preventDefault(); _qsMoveSelection(-1); }
      else if (e.key === 'Enter') { e.preventDefault(); _qsOpenSelected(); }
      else if (e.key === 'Escape') { e.preventDefault(); _closeQuickSwitch(); }
    });
  }
  // Close on click outside
  modal.onclick = e => { if (e.target === modal) _closeQuickSwitch(); };
}

function _closeQuickSwitch() {
  const modal = document.getElementById('quick-switch-modal');
  if (modal) modal.hidden = true;
}

function _renderQSResults(query) {
  const resultsEl = document.getElementById('quick-switch-results');
  if (!resultsEl) return;

  if (!_graphAllNodes.length) {
    resultsEl.innerHTML = '<div class="qs-hint">Open Graph View first to enable search.</div>';
    _qsResults = [];
    return;
  }

  const q = query.trim().toLowerCase();
  _qsResults = q
    ? _graphAllNodes.filter(n => {
        const label = (n.label || '').toLowerCase();
        const path  = ((n.properties || {}).path || '').toLowerCase();
        return label.includes(q) || path.includes(q);
      }).slice(0, 20)
    : _graphAllNodes.slice(0, 20);

  if (!_qsResults.length) {
    resultsEl.innerHTML = `<div class="qs-hint">No nodes matching "${escHtml(query)}"</div>`;
    return;
  }

  resultsEl.innerHTML = _qsResults.map((n, i) => {
    const path = (n.properties || {}).path || '';
    const active = i === _qsSelectedIndex ? ' qs-result--active' : '';
    return `<div class="qs-result${active}" data-qs-idx="${i}">
      <span class="qs-result-label">${escHtml(n.label || n.id)}</span>
      ${path ? `<span class="qs-result-path">${escHtml(path)}</span>` : ''}
    </div>`;
  }).join('');

  resultsEl.querySelectorAll('.qs-result').forEach(el => {
    el.addEventListener('click', () => {
      _qsSelectedIndex = parseInt(el.dataset.qsIdx, 10);
      _qsOpenSelected();
    });
  });
}

function _qsMoveSelection(delta) {
  _qsSelectedIndex = Math.max(0, Math.min(_qsResults.length - 1, _qsSelectedIndex + delta));
  _renderQSResults(document.getElementById('quick-switch-input')?.value || '');
}

function _qsOpenSelected() {
  const node = _qsResults[_qsSelectedIndex];
  if (!node) return;
  _closeQuickSwitch();
  if (window.InspectorTabs) {
    window.InspectorTabs.openNodeTab(node, { source: 'quick-switch', navigate: true });
    showPanel('node-inspector', { updateHash: true });
  } else {
    inspectNode(String(node.id), node.label || String(node.id));
  }
}
